const normalizeSessionHealthError = (rawError) => {
  const normalized = String(rawError || '')
    .replace(/\s+/g, ' ')
    .trim();
  if (normalized.length <= 220) return normalized;
  return `${normalized.slice(0, 217)}...`;
};

const sessionHealthState = {
  ok: true,
  table: sessionStoreDriver === 'redis' ? 'redis' : sessionTableName,
  lastCheckedAt: null,
  lastOkAt: null,
  lastErrorAt: null,
  lastError: null,
  checks: 0,
  failures: 0,
  lastDurationMs: null,
};

const logSessionHealth = (event, payload = {}) => {
  const record = {
    type: 'session_health',
    event,
    ...payload,
  };
  if (event === 'probe_failed' || event === 'store_error' || event === 'probe_crashed') {
    console.error('SESSION_HEALTH', JSON.stringify(record));
    return;
  }
  console.log('SESSION_HEALTH', JSON.stringify(record));
};

const probeSessionStoreHealth = async (reason = 'interval') => {
  const startedAt = Date.now();
  const wasOk = sessionHealthState.ok;
  try {
    await new Promise((resolve, reject) => {
      sessionStore.get('__healthcheck__', (err) => {
        if (err) return reject(err);
        return resolve();
      });
    });
    const nowIso = new Date().toISOString();
    const durationMs = Date.now() - startedAt;
    sessionHealthState.ok = true;
    sessionHealthState.lastCheckedAt = nowIso;
    sessionHealthState.lastOkAt = nowIso;
    sessionHealthState.lastDurationMs = durationMs;
    sessionHealthState.lastError = null;
    sessionHealthState.checks += 1;
    logSessionHealth(wasOk ? 'probe_ok' : 'probe_recovered', { reason, duration_ms: durationMs });
  } catch (err) {
    const nowIso = new Date().toISOString();
    const durationMs = Date.now() - startedAt;
    const message = normalizeSessionHealthError(err && err.message ? err.message : err);
    sessionHealthState.ok = false;
    sessionHealthState.lastCheckedAt = nowIso;
    sessionHealthState.lastErrorAt = nowIso;
    sessionHealthState.lastError = message;
    sessionHealthState.lastDurationMs = durationMs;
    sessionHealthState.checks += 1;
    sessionHealthState.failures += 1;
    pushRuntimeErrorEvent('session', `probe:${reason}`, message);
    logSessionHealth('probe_failed', { reason, duration_ms: durationMs, error: message });
  }
};

const buildSessionStoreErrorLogger = (...args) => {
  const nowIso = new Date().toISOString();
  const message = normalizeSessionHealthError(args
    .map((item) => (item && item.message ? item.message : String(item)))
    .join(' | '));
  sessionHealthState.ok = false;
  sessionHealthState.lastCheckedAt = nowIso;
  sessionHealthState.lastErrorAt = nowIso;
  sessionHealthState.lastError = message;
  sessionHealthState.failures += 1;
  pushRuntimeErrorEvent('session', 'store_error', message);
  console.error('SESSION_STORE_ERROR', ...args);
  logSessionHealth('store_error', { error: message });
};

let redisSessionClient = null;
let sessionStore = null;
if (sessionStoreDriver === 'redis') {
  redisSessionClient = createClient({
    url: redisUrl,
    socket: {
      connectTimeout: redisConnectTimeoutMs,
      keepAlive: redisSocketKeepAliveMs,
      reconnectStrategy: (attempt) => Math.min(attempt * 50, 1000),
    },
  });
  redisSessionClient.on('error', (err) => {
    buildSessionStoreErrorLogger(err);
  });
  sessionStore = new RedisStore({
    client: redisSessionClient,
    prefix: sessionRedisPrefix,
    ttl: Math.floor(resolveSessionAbsoluteTimeoutMs(DEFAULT_SETTINGS.session_absolute_timeout_hours) / 1000),
  });
} else {
  sessionStore = new PgSession({
    pool,
    tableName: sessionTableName,
    createTableIfMissing: true,
    pruneSessionInterval: pruneIntervalSeconds,
    ttl: Math.floor(resolveSessionAbsoluteTimeoutMs(DEFAULT_SETTINGS.session_absolute_timeout_hours) / 1000),
    errorLog: (...args) => {
      buildSessionStoreErrorLogger(...args);
    },
  });
}

const sessionMiddleware = session({
  name: sessionCookieName,
  store: sessionStore,
  secret: resolvedSessionSecret,
  resave: false,
  saveUninitialized: false,
  rolling: true,
  unset: 'destroy',
  cookie: {
    httpOnly: true,
    sameSite: 'lax',
    secure: isProd,
    maxAge: resolveSessionAbsoluteTimeoutMs(DEFAULT_SETTINGS.session_absolute_timeout_hours),
  },
});

syncSessionStoreSecurityState();

app.use(sessionMiddleware);

const buildSessionRoleFingerprint = (roles = []) => {
  const normalizedRoles = normalizeRoleList(roles);
  return normalizedRoles.length ? normalizedRoles.join('|') : 'student';
};

const regenerateRequestSession = (req) => new Promise((resolve, reject) => {
  if (!req.session) {
    return reject(new Error('Session is not initialized.'));
  }
  return req.session.regenerate((err) => (err ? reject(err) : resolve()));
});

const saveRequestSession = (req) => new Promise((resolve, reject) => {
  if (!req.session) return resolve();
  return req.session.save((err) => (err ? reject(err) : resolve()));
});

const destroyRequestSession = (req) => new Promise((resolve, reject) => {
  if (!req.session) return resolve();
  return req.session.destroy((err) => (err ? reject(err) : resolve()));
});

function clearSessionCookie(res) {
  if (!res || typeof res.clearCookie !== 'function') return;
  res.clearCookie(sessionCookieName, {
    httpOnly: true,
    sameSite: 'lax',
    secure: isProd,
    path: '/',
  });
}

const establishAuthenticatedSession = async (req, {
  user,
  role,
  remember = false,
  sessionData = {},
} = {}) => {
  const normalizedUser = user && typeof user === 'object' ? { ...user } : null;
  const normalizedUserId = Number(normalizedUser && normalizedUser.id);
  if (!Number.isInteger(normalizedUserId) || normalizedUserId < 1) {
    throw new Error('Authenticated session requires a valid user id.');
  }
  const safeRole = normalizeRoleKey(role || 'student');
  const existingLang = req.session && req.session.lang ? req.session.lang : null;
  const nowIso = new Date().toISOString();
  await regenerateRequestSession(req);
  req.session.user = normalizedUser;
  req.session.role = safeRole;
  req.session.roles = normalizeRoleList([safeRole]);
  req.session.role_fingerprint = buildSessionRoleFingerprint(req.session.roles);
  req.session.lang = normalizedUser.language || existingLang || getPreferredLang(req);
  req.session.rememberMe = remember;
  Object.assign(req.session, {
    session_created_at: nowIso,
    last_seen_at: nowIso,
    last_activity_at: nowIso,
    last_sensitive_reauth_at: nowIso,
  }, sessionData);
  applyRememberMe(req, remember);
};

const rotateSessionForRoleChange = async (req, nextRoleKeys = [], nextLegacyRole = 'student') => {
  if (!req.session || !req.session.user) return false;
  const nextRoles = normalizeRoleList(nextRoleKeys);
  const nextFingerprint = buildSessionRoleFingerprint(nextRoles);
  if (!req.session.role_fingerprint || req.session.role_fingerprint === nextFingerprint) {
    req.session.role_fingerprint = nextFingerprint;
    return false;
  }
  const remember = Boolean(req.session.rememberMe);
  const sessionUser = { ...req.session.user };
  const preservedState = {
    adminCourse: Number.isFinite(Number(req.session.adminCourse)) ? Number(req.session.adminCourse) : null,
    viewAs: req.session.viewAs || null,
    viewAsMode: req.session.viewAsMode || null,
    viewAsCourseId: Number.isFinite(Number(req.session.viewAsCourseId)) ? Number(req.session.viewAsCourseId) : null,
    viewAsGroupNumber: Number.isFinite(Number(req.session.viewAsGroupNumber)) ? Number(req.session.viewAsGroupNumber) : null,
    lang: req.session.lang || null,
    last_seen_route: req.session.last_seen_route || null,
    last_seen_at: req.session.last_seen_at || null,
    last_seen_ip: req.session.last_seen_ip || null,
    last_seen_user_agent: req.session.last_seen_user_agent || null,
    session_created_at: req.session.session_created_at || null,
    last_activity_at: req.session.last_activity_at || null,
    last_sensitive_reauth_at: req.session.last_sensitive_reauth_at || null,
  };
  await regenerateRequestSession(req);
  req.session.user = sessionUser;
  req.session.role = normalizeRoleKey(nextLegacyRole || 'student');
  req.session.roles = nextRoles;
  req.session.role_fingerprint = nextFingerprint;
  Object.entries(preservedState).forEach(([key, value]) => {
    if (value !== null && value !== undefined && value !== '') {
      req.session[key] = value;
    }
  });
  req.session.rememberMe = remember;
  applyRememberMe(req, remember);
  return true;
};

app.use((req, _res, next) => {
  if (req.session && req.session.cookie) {
    if (req.session.rememberMe) {
      req.session.cookie.maxAge = resolveSessionAbsoluteTimeoutMs(settingsCache.session_absolute_timeout_hours);
    } else {
      req.session.cookie.expires = false;
      req.session.cookie.maxAge = null;
    }
  }
  return next();
});

app.use(async (req, res, next) => {
  if (!req.session || !req.session.user) {
    return next();
  }
  const nowMs = Date.now();
  const nowIso = new Date(nowMs).toISOString();
  if (!req.session.session_created_at) {
    req.session.session_created_at = nowIso;
  }
  if (!req.session.last_activity_at) {
    req.session.last_activity_at = req.session.last_seen_at || nowIso;
  }

  const createdAtMs = new Date(req.session.session_created_at).getTime();
  const lastActivityMs = new Date(req.session.last_activity_at).getTime();
  const absoluteTimeoutMs = resolveSessionAbsoluteTimeoutMs(settingsCache.session_absolute_timeout_hours);
  const idleTimeoutMs = resolveSessionIdleTimeoutMs(settingsCache.session_idle_timeout_minutes);
  const idleExpired = Number.isFinite(lastActivityMs) && (nowMs - lastActivityMs) > idleTimeoutMs;
  const absoluteExpired = Number.isFinite(createdAtMs) && (nowMs - createdAtMs) > absoluteTimeoutMs;

  if (idleExpired || absoluteExpired) {
    try {
      await destroyRequestSession(req);
    } catch (destroyErr) {
      console.error('Session destroy after timeout failed', destroyErr);
    }
    clearSessionCookie(res);
    const timeoutCode = idleExpired ? 'idle-timeout' : 'absolute-timeout';
    if (req.headers.accept && req.headers.accept.includes('application/json')) {
      return res.status(440).json({ error: timeoutCode });
    }
    return res.redirect(`/login?error=${encodeURIComponent(timeoutCode)}`);
  }

  if (
    !Number.isFinite(lastActivityMs)
    || (nowMs - lastActivityMs) >= SESSION_ACTIVITY_TOUCH_INTERVAL_MS
    || req.method !== 'GET'
  ) {
    req.session.last_activity_at = nowIso;
  }
  res.locals.sessionSecurity = {
    last_sensitive_reauth_at: req.session.last_sensitive_reauth_at || null,
    idle_timeout_minutes: resolveSessionIdleTimeoutMinutes(settingsCache.session_idle_timeout_minutes),
    absolute_timeout_hours: resolveSessionAbsoluteTimeoutHours(settingsCache.session_absolute_timeout_hours),
  };
  return next();
});

app.use((req, res, next) => {
  const lang = getPreferredLang(req);
  res.locals.messages = {
    error: req.query && req.query.err ? req.query.err : '',
    success: req.query && req.query.ok ? req.query.ok : '',
    operationId: req.query && req.query.op ? req.query.op : '',
  };
  res.locals.appVersion = appVersion;
  res.locals.buildStamp = buildStamp;
  res.locals.authorName = 'Andrii Marchenko';
  res.locals.changelog = appChangelog;
  res.locals.settings = settingsCache;
  res.locals.sessionSecurity = Object.assign({
    last_sensitive_reauth_at: req && req.session ? (req.session.last_sensitive_reauth_at || null) : null,
    idle_timeout_minutes: resolveSessionIdleTimeoutMinutes(settingsCache.session_idle_timeout_minutes),
    absolute_timeout_hours: resolveSessionAbsoluteTimeoutHours(settingsCache.session_absolute_timeout_hours),
  }, res.locals.sessionSecurity || {});
  res.locals.lang = lang;
  res.locals.t = (key) => translate(lang, key);
  next();
});

const CSRF_MUTATING_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);

function resolveRequestHostForCsrf(req) {
  const hostHeader = String(req && req.headers && req.headers.host ? req.headers.host : '')
    .split(',')[0]
    .trim()
    .toLowerCase();
  return hostHeader;
}

function matchesRequestHost(rawUrl, expectedHost) {
  if (!rawUrl || !expectedHost) return false;
  try {
    const parsed = new URL(String(rawUrl).trim());
    return String(parsed.host || '').toLowerCase() === expectedHost;
  } catch (_err) {
    return false;
  }
}

function hasTrustedCsrfSource(req) {
  const expectedHost = resolveRequestHostForCsrf(req);
  if (!expectedHost) return false;

  const originHeader = String(req && req.headers && req.headers.origin ? req.headers.origin : '').trim();
  if (originHeader) {
    return matchesRequestHost(originHeader, expectedHost);
  }

  const refererHeader = String(req && req.headers && req.headers.referer ? req.headers.referer : '').trim();
  if (refererHeader) {
    return matchesRequestHost(refererHeader, expectedHost);
  }

  const fetchSite = String(req && req.headers && req.headers['sec-fetch-site'] ? req.headers['sec-fetch-site'] : '')
    .trim()
    .toLowerCase();
  return fetchSite === 'same-origin' || fetchSite === 'same-site' || fetchSite === 'none';
}

app.use((req, res, next) => {
  const method = String(req && req.method ? req.method : '').toUpperCase();
  if (!CSRF_MUTATING_METHODS.has(method)) {
    return next();
  }
  if (!req.session || !req.session.user) {
    return next();
  }
  if (req.path === '/_bootstrap') {
    return next();
  }
  if (hasTrustedCsrfSource(req)) {
    return next();
  }
  if (req.accepts('json') || req.path.startsWith('/api') || req.path.startsWith('/admin/api')) {
    return res.status(403).json({ error: 'csrf_blocked' });
  }
  return res.status(403).send('Forbidden (csrf)');
});

function normalizeSocketChannel(rawValue) {
  const normalized = String(rawValue || '').trim().toLowerCase();
  if (!SOCKET_CHANNELS.has(normalized)) return '';
  return normalized;
}

function getRequestedSocketChannel(req) {
  try {
    const parsed = new URL(String(req && req.url ? req.url : '/'), 'http://localhost');
    if (parsed.pathname !== '/ws') return '';
    return normalizeSocketChannel(parsed.searchParams.get('channel'));
  } catch (_err) {
    return '';
  }
}

function rejectWebSocketUpgrade(socket, statusCode = 403, statusText = 'Forbidden') {
  if (!socket || socket.destroyed) return;
  try {
    socket.write(`HTTP/1.1 ${statusCode} ${statusText}\r\nConnection: close\r\n\r\n`);
  } catch (_err) {
    // ignore write failures and close below
  }
  socket.destroy();
}

function getExpectedRequestHost(req) {
  const forwardedHost = String(req && req.headers && req.headers['x-forwarded-host'] ? req.headers['x-forwarded-host'] : '').split(',')[0].trim();
  const hostHeader = String(req && req.headers && req.headers.host ? req.headers.host : '').split(',')[0].trim();
  return (forwardedHost || hostHeader).toLowerCase();
}

function isAllowedWebSocketOrigin(req) {
  const originHeader = String(req && req.headers && req.headers.origin ? req.headers.origin : '').trim();
  const expectedHost = getExpectedRequestHost(req);
  if (!originHeader || !expectedHost) {
    return false;
  }
  try {
    const parsedOrigin = new URL(originHeader);
    return String(parsedOrigin.host || '').toLowerCase() === expectedHost;
  } catch (_err) {
    return false;
  }
}

async function canUseSocketChannel(req, channel) {
  if (!req || !req.session || !req.session.user) return false;
  if (channel === SOCKET_CHANNEL_MESSAGES) {
    return true;
  }
  if (channel !== SOCKET_CHANNEL_ADMIN) {
    return false;
  }
  const roleKeys = getSessionRoleList(req);
  if (roleKeys.includes('admin')) {
    return true;
  }
  try {
    await ensureDbReady();
    const allowedSections = await getRoleAllowedSectionsForRoleKeys(
      roleKeys,
      req.session.role || roleKeys[0] || 'student'
    );
    return Array.isArray(allowedSections) && allowedSections.length > 0;
  } catch (_err) {
    const fallbackSections = getRoleAllowedSections(req.session.role || roleKeys[0] || 'student');
    return Array.isArray(fallbackSections) && fallbackSections.length > 0;
  }
}

function resolveBroadcastChannels(type, requestedChannels = null) {
  const normalizedRequested = Array.isArray(requestedChannels)
    ? requestedChannels.map((channel) => normalizeSocketChannel(channel)).filter(Boolean)
    : [];
  if (normalizedRequested.length) {
    return normalizedRequested;
  }
  if (type === 'messages_updated') {
    return [SOCKET_CHANNEL_MESSAGES];
  }
  return [SOCKET_CHANNEL_ADMIN];
}

const websocketSessionResponseShim = {
  getHeader() {
    return undefined;
  },
  setHeader() {},
  removeHeader() {},
  writeHead() {},
  end() {},
};

server.on('upgrade', (req, socket, head) => {
  const channel = getRequestedSocketChannel(req);
  if (!channel) {
    rejectWebSocketUpgrade(socket, 404, 'Not Found');
    return;
  }
  if (!isAllowedWebSocketOrigin(req)) {
    rejectWebSocketUpgrade(socket, 403, 'Forbidden');
    return;
  }
  sessionMiddleware(req, websocketSessionResponseShim, (sessionErr) => {
    if (sessionErr) {
      console.error('WebSocket session error', sessionErr);
      rejectWebSocketUpgrade(socket, 500, 'Internal Server Error');
      return;
    }
    (async () => {
      try {
        const allowed = await canUseSocketChannel(req, channel);
        if (!allowed) {
          rejectWebSocketUpgrade(socket, 403, 'Forbidden');
          return;
        }
        wss.handleUpgrade(req, socket, head, (client) => {
          client.studerriaChannel = channel;
          client.studerriaUserId = Number(req.session?.user?.id || 0);
          client.studerriaRoles = getSessionRoleList(req);
          wss.emit('connection', client, req);
        });
      } catch (err) {
        console.error('WebSocket upgrade failed', err);
        rejectWebSocketUpgrade(socket, 500, 'Internal Server Error');
      }
    })();
  });
});

wss.on('connection', (client) => {
  client.on('error', (err) => {
    console.error('WebSocket client error', err);
  });
});

const convertPlaceholders = (sql) => {
  let index = 0;
  return sql.replace(/\?/g, () => {
    index += 1;
    return `$${index}`;
  });
};

const normalizeArgs = (sql, params, cb) => {
  let finalParams = params;
  let callback = cb;
  if (typeof params === 'function') {
    callback = params;
    finalParams = [];
  }
  return { sql, params: finalParams || [], cb: callback };
};

const db = {
  async run(sql, params, cb) {
    const { params: finalParams, cb: callback } = normalizeArgs(sql, params, cb);
    const query = convertPlaceholders(sql);
    try {
      const result = await pool.query(query, finalParams);
      const lastID = result.rows && result.rows[0] ? result.rows[0].id : undefined;
      if (callback) {
        callback.call({ lastID }, null);
      }
      return { changes: result.rowCount, lastID };
    } catch (err) {
      if (callback) {
        callback(err);
        return { changes: 0 };
      }
      throw err;
    }
  },
  async get(sql, params, cb) {
    const { params: finalParams, cb: callback } = normalizeArgs(sql, params, cb);
    const query = convertPlaceholders(sql);
    try {
      const result = await pool.query(query, finalParams);
      const row = result.rows[0];
      if (callback) {
        callback(null, row);
      }
      return row;
    } catch (err) {
      if (callback) {
        callback(err);
        return undefined;
      }
      throw err;
    }
  },
  async all(sql, params, cb) {
    const { params: finalParams, cb: callback } = normalizeArgs(sql, params, cb);
    const query = convertPlaceholders(sql);
    try {
      const result = await pool.query(query, finalParams);
      if (callback) {
        callback(null, result.rows);
      }
      return result.rows;
    } catch (err) {
      if (callback) {
        callback(err, []);
        return [];
      }
      throw err;
    }
  },
  prepare(sql) {
    const pending = [];
    return {
      run: (...params) => {
        const promise = db.run(sql, params);
        pending.push(promise);
        return promise;
      },
      get: (...params) => db.get(sql, params),
      all: (...params) => db.all(sql, params),
      finalize: async (cb) => {
        try {
          await Promise.all(pending);
          if (cb) cb();
        } catch (err) {
          if (cb) cb(err);
        }
      },
    };
  },
};

const txRun = async (client, sql, params = []) => {
  const result = await client.query(convertPlaceholders(sql), params);
  const lastID = result.rows && result.rows[0] ? result.rows[0].id : undefined;
  return { changes: result.rowCount, lastID };
};

const withTransaction = async (work) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const result = await work(client);
    await client.query('COMMIT');
    return result;
  } catch (err) {
    try {
      await client.query('ROLLBACK');
    } catch (_) {
      // ignore rollback errors and return original error
    }
    throw err;
  } finally {
    client.release();
  }
};

let usersHasIsActive = true;
function syncSessionStoreSecurityState() {
  if (!sessionStore) return;
  sessionStore.ttl = Math.max(
    60,
    Math.floor(resolveSessionAbsoluteTimeoutMs(settingsCache.session_absolute_timeout_hours) / 1000)
  );
}

const refreshSettingsCache = async () => {
  const settingsRows = await pool.query('SELECT key, value FROM settings');
  const parsed = { ...DEFAULT_SETTINGS };
  for (const row of settingsRows.rows) {
    if (!row || !row.key) continue;
    if (row.key === 'session_duration_days') {
      const n = Number(row.value);
      if (!Number.isNaN(n) && n > 0) {
        parsed.session_duration_days = n;
        parsed.session_absolute_timeout_hours = Math.max(
          SESSION_ABSOLUTE_TIMEOUT_HOURS_MIN,
          Math.min(SESSION_ABSOLUTE_TIMEOUT_HOURS_MAX, n * 24)
        );
      }
    } else if (row.key === 'session_idle_timeout_minutes') {
      parsed.session_idle_timeout_minutes = resolveSessionIdleTimeoutMinutes(row.value);
    } else if (row.key === 'session_absolute_timeout_hours') {
      parsed.session_absolute_timeout_hours = resolveSessionAbsoluteTimeoutHours(row.value);
    } else if (row.key === 'max_file_size_mb') {
      const n = Number(row.value);
      if (!Number.isNaN(n) && n > 0) parsed.max_file_size_mb = n;
    } else if (row.key === 'allow_homework_creation') {
      parsed.allow_homework_creation = String(row.value).toLowerCase() === 'true';
    } else if (row.key === 'min_team_members') {
      const n = Number(row.value);
      if (!Number.isNaN(n) && n > 0) parsed.min_team_members = n;
    } else if (row.key === 'allow_custom_deadlines') {
      parsed.allow_custom_deadlines = String(row.value).toLowerCase() === 'true';
    } else if (row.key === 'myday_show_student_homework') {
      parsed.myday_show_student_homework = String(row.value).toLowerCase() === 'true';
    } else if (row.key === 'allow_messages') {
      parsed.allow_messages = String(row.value).toLowerCase() === 'true';
    } else if (row.key === 'schedule_refresh_minutes') {
      const n = Number(row.value);
      if (!Number.isNaN(n) && n > 0) parsed.schedule_refresh_minutes = n;
    } else if (row.key === 'site_visit_retention_days') {
      parsed.site_visit_retention_days = normalizeSiteVisitRetentionDays(
        row.value,
        DEFAULT_SETTINGS.site_visit_retention_days
      );
    } else if (row.key === 'security_logs_retention_days') {
      parsed.security_logs_retention_days = normalizeSecurityLogsRetentionDays(
        row.value,
        DEFAULT_SETTINGS.security_logs_retention_days
      );
    } else if (row.key === 'login_history_retention_days') {
      parsed.login_history_retention_days = normalizeLoginHistoryRetentionDays(
        row.value,
        DEFAULT_SETTINGS.login_history_retention_days
      );
    } else if (row.key === 'activity_log_retention_days') {
      parsed.activity_log_retention_days = normalizeActivityLogRetentionDays(
        row.value,
        DEFAULT_SETTINGS.activity_log_retention_days
      );
    } else if (row.key === 'security_admin_ip_allowlist') {
      parsed.security_admin_ip_allowlist = normalizeSecurityAdminIpAllowlist(row.value);
    } else if (row.key === 'security_stepup_reauth_minutes') {
      parsed.security_stepup_reauth_minutes = resolveStepUpReauthMinutes(row.value);
    } else if (row.key === 'security_risk_threshold_low') {
      parsed.security_risk_threshold_low = normalizeSecurityRiskThresholdValue(
        row.value,
        DEFAULT_SETTINGS.security_risk_threshold_low
      );
    } else if (row.key === 'security_risk_threshold_medium') {
      parsed.security_risk_threshold_medium = normalizeSecurityRiskThresholdValue(
        row.value,
        DEFAULT_SETTINGS.security_risk_threshold_medium
      );
    } else if (row.key === 'security_risk_threshold_high') {
      parsed.security_risk_threshold_high = normalizeSecurityRiskThresholdValue(
        row.value,
        DEFAULT_SETTINGS.security_risk_threshold_high
      );
    } else if (row.key === 'security_registration_alert_threshold') {
      parsed.security_registration_alert_threshold = normalizeSecurityRegistrationAlertThreshold(
        row.value,
        DEFAULT_SETTINGS.security_registration_alert_threshold
      );
    } else if (row.key === 'security_registration_alert_window_minutes') {
      parsed.security_registration_alert_window_minutes = normalizeSecurityRegistrationAlertWindowMinutes(
        row.value,
        DEFAULT_SETTINGS.security_registration_alert_window_minutes
      );
    } else if (row.key === 'security_auto_quarantine_enabled') {
      parsed.security_auto_quarantine_enabled = String(row.value).toLowerCase() === 'true';
    } else if (row.key === 'security_ip_retention_days') {
      parsed.security_ip_retention_days = normalizeSecurityIpRetentionDays(
        row.value,
        DEFAULT_SETTINGS.security_ip_retention_days
      );
    } else if (row.key === 'security_user_agent_retention_days') {
      parsed.security_user_agent_retention_days = normalizeSecurityDeviceRetentionDays(
        row.value,
        DEFAULT_SETTINGS.security_user_agent_retention_days
      );
      parsed.security_device_retention_days = parsed.security_user_agent_retention_days;
    } else if (row.key === 'security_device_retention_days') {
      parsed.security_device_retention_days = normalizeSecurityDeviceRetentionDays(
        row.value,
        DEFAULT_SETTINGS.security_device_retention_days
      );
      parsed.security_user_agent_retention_days = parsed.security_device_retention_days;
    } else if (row.key === 'role_permissions') {
      try {
        const raw = JSON.parse(row.value);
        if (raw && typeof raw === 'object') {
          const allowedIds = new Set(ADMIN_SECTION_OPTIONS.map((item) => item.id));
          const normalized = {};
          Object.keys(DEFAULT_ROLE_PERMISSIONS).forEach((role) => {
            if (!Object.prototype.hasOwnProperty.call(raw, role)) return;
            const input = raw[role];
            const list = Array.isArray(input)
              ? input
              : typeof input === 'string'
                ? [input]
                : [];
            normalized[role] = list
              .map((id) => String(id))
              .filter((id) => allowedIds.has(id));
          });
          const restrictedForStaff = new Set([
            'admin-settings',
            'admin-role-access',
            'admin-users',
            'admin-students',
            'admin-import-export',
            'admin-schedule-generator',
          ]);
          ['teacher', 'student'].forEach((role) => {
            if (!normalized[role]) return;
            normalized[role] = normalized[role].filter((id) => !restrictedForStaff.has(id));
          });
          parsed.role_permissions = {
            ...DEFAULT_ROLE_PERMISSIONS,
            ...normalized,
          };
        }
      } catch (err) {
        // ignore invalid role permissions payload
      }
    }
  }
  const normalizedThresholds = securityHelpers.buildRiskThresholds({
    low: parsed.security_risk_threshold_low,
    medium: parsed.security_risk_threshold_medium,
    high: parsed.security_risk_threshold_high,
  }, SECURITY_RISK_THRESHOLDS_DEFAULTS);
  parsed.security_risk_threshold_low = normalizedThresholds.low;
  parsed.security_risk_threshold_medium = normalizedThresholds.medium;
  parsed.security_risk_threshold_high = normalizedThresholds.high;
  parsed.session_duration_days = resolveSessionCompatibilityDays(parsed.session_absolute_timeout_hours);
  parsed.security_user_agent_retention_days = normalizeSecurityDeviceRetentionDays(
    parsed.security_device_retention_days,
    DEFAULT_SETTINGS.security_user_agent_retention_days
  );
  parsed.security_device_retention_days = parsed.security_user_agent_retention_days;
  settingsCache = parsed;
  syncSessionStoreSecurityState();
};

function normalizeRoleKey(rawRole) {
  const normalized = String(rawRole || 'student').trim().toLowerCase();
  return ROLE_KEY_ALIASES[normalized] || normalized || 'student';
}

function normalizeRoleList(input) {
  const list = Array.isArray(input) ? input : (typeof input === 'string' ? [input] : []);
  const seen = new Set();
  const normalized = [];
  list.forEach((role) => {
    const key = normalizeRoleKey(role);
    if (!key || seen.has(key)) return;
    seen.add(key);
    normalized.push(key);
  });
  return normalized;
}

function resolveLegacySessionRole(roleKeys = [], currentRole = 'student') {
  const normalizedRoles = normalizeRoleList(roleKeys);
  const normalizedCurrent = normalizeRoleKey(currentRole || 'student');
  if (
    normalizedCurrent
    && LEGACY_SESSION_ROLES.has(normalizedCurrent)
    && normalizedRoles.includes(normalizedCurrent)
  ) {
    return normalizedCurrent;
  }
  return normalizedRoles.find((key) => LEGACY_SESSION_ROLES.has(key)) || 'student';
}

function resolveMyDayRole(primaryRole = 'student', roleKeys = []) {
  const normalizedPrimary = normalizeRoleKey(primaryRole || 'student');
  const normalizedRoles = normalizeRoleList([normalizedPrimary, ...(Array.isArray(roleKeys) ? roleKeys : [])]);
  if (normalizedPrimary === 'deanery' && normalizedRoles.includes('teacher')) {
    return 'teacher';
  }
  return normalizedPrimary;
}

function getSessionRoleList(req) {
  if (!req || !req.session) return ['student'];
  const roleList = normalizeRoleList(req.session.roles);
  if (roleList.length) return roleList;
  if (req.session.role) return normalizeRoleList([req.session.role]);
  return ['student'];
}

function hasSessionRole(req, roleKey) {
  return getSessionRoleList(req).includes(normalizeRoleKey(roleKey));
}

function canSessionCreateHomework(req) {
  if (hasSessionRole(req, 'admin')) return true;
  if (hasSessionRole(req, 'teacher')) return true;
  if (hasSessionRole(req, 'deanery')) return true;
  return Boolean(settingsCache.allow_homework_creation);
}

function canSessionUseCustomDeadlines(req) {
  if (!settingsCache.allow_custom_deadlines) {
    return hasSessionRole(req, 'admin');
  }
  return canSessionCreateHomework(req);
}

function canRenderCustomDeadlinesUi(req, roleKey = null) {
  const currentRole = normalizeRoleKey(roleKey || '');
  if (!['student', 'starosta', 'teacher'].includes(currentRole)) {
    return false;
  }
  if (currentRole === 'teacher') {
    return Boolean(settingsCache.allow_custom_deadlines);
  }
  return Boolean(settingsCache.allow_custom_deadlines) && Boolean(settingsCache.allow_homework_creation);
}

async function getUserRoleKeys(userId, fallbackRole = 'student') {
  const fallback = normalizeRoleKey(fallbackRole);
  if (!Number.isFinite(Number(userId))) {
    return [fallback];
  }
  try {
    const rows = await db.all(
      `
        SELECT ar.key, ur.is_primary
        FROM user_roles ur
        JOIN access_roles ar ON ar.id = ur.role_id
        WHERE ur.user_id = ? AND ar.is_active = true
        ORDER BY ur.is_primary DESC, ar.key ASC
      `,
      [userId]
    );
    const keys = normalizeRoleList((rows || []).map((row) => row.key));
    if (keys.length) return keys;
  } catch (err) {
    // fallback to legacy single-role field if RBAC tables are not available yet
  }
  return [fallback];
}

async function getRoleAllowedSectionsForRoleKeys(roleKeys = [], fallbackRole = 'student') {
  const normalizedRoles = normalizeRoleList(roleKeys);
  if (normalizedRoles.includes('admin')) return null;
  if (!normalizedRoles.length) {
    return getRoleAllowedSections(fallbackRole);
  }
  try {
    const rows = await db.all(
      `
        SELECT DISTINCT p.key
        FROM access_role_permissions rp
        JOIN access_roles ar ON ar.id = rp.role_id
        JOIN access_permissions p ON p.id = rp.permission_id
        WHERE rp.allowed = true
          AND ar.is_active = true
          AND p.category = 'admin_section'
          AND ar.key = ANY(?)
        ORDER BY p.key
      `,
      [normalizedRoles]
    );
    const list = (rows || []).map((row) => String(row.key));
    if (list.length) return list;
  } catch (err) {
    // fallback below
  }
  if (normalizedRoles.length === 1) {
    return getRoleAllowedSections(normalizedRoles[0]);
  }
  const merged = new Set();
  normalizedRoles.forEach((role) => {
    const sections = getRoleAllowedSections(role);
    if (Array.isArray(sections)) {
      sections.forEach((section) => merged.add(section));
    }
  });
  return Array.from(merged);
}

async function getRolePermissionKeysForRoleKeys(roleKeys = [], categories = []) {
  const normalizedRoles = normalizeRoleList(roleKeys);
  if (!normalizedRoles.length) {
    return new Set();
  }
  const normalizedCategories = Array.from(
    new Set((Array.isArray(categories) ? categories : []).map((value) => String(value || '').trim()).filter(Boolean))
  );
  try {
    const whereCategory = normalizedCategories.length ? 'AND p.category = ANY(?)' : '';
    const rows = await db.all(
      `
        SELECT DISTINCT p.key
        FROM access_role_permissions rp
        JOIN access_roles ar ON ar.id = rp.role_id
        JOIN access_permissions p ON p.id = rp.permission_id
        WHERE rp.allowed = true
          AND ar.is_active = true
          AND ar.key = ANY(?)
          ${whereCategory}
        ORDER BY p.key
      `,
      normalizedCategories.length ? [normalizedRoles, normalizedCategories] : [normalizedRoles]
    );
    return new Set((rows || []).map((row) => String(row.key)));
  } catch (err) {
    return new Set();
  }
}

async function getJournalAccessScope(req) {
  const roleKeys = getSessionRoleList(req);
  if (roleKeys.includes('admin')) {
    return { canUseJournal: true, ownOnly: false, fullAccess: true, permissionKeys: new Set([JOURNAL_OWN_PERMISSION, JOURNAL_FULL_PERMISSION]) };
  }
  const permissionKeys = await getRolePermissionKeysForRoleKeys(roleKeys, ['feature']);
  const fullAccess = permissionKeys.has(JOURNAL_FULL_PERMISSION);
  const ownByPermission = permissionKeys.has(JOURNAL_OWN_PERMISSION);
  const teacherFallback = roleKeys.includes('teacher');
  const studentFallback = roleKeys.includes('student') || roleKeys.includes('starosta');
  const canUseJournal = fullAccess || ownByPermission || teacherFallback || studentFallback;
  return {
    canUseJournal,
    ownOnly: !fullAccess,
    fullAccess,
    permissionKeys,
  };
}

const getRoleAllowedSections = (role) => {
  if (role === 'admin') return null;
  const permissions = settingsCache.role_permissions || {};
  if (Object.prototype.hasOwnProperty.call(permissions, role)) {
    return permissions[role];
  }
  return DEFAULT_ROLE_PERMISSIONS[role] || [];
};

const isTeacherCourseRow = (course) =>
  course && (course.is_teacher_course === true || Number(course.is_teacher_course) === 1);

const isEnabledRoleFlag = (value) => {
  const normalized = String(value ?? '').trim().toLowerCase();
  return value === true
    || Number(value) === 1
    || ['1', 'true', 't', 'yes', 'on'].includes(normalized);
};

function getDefaultAllowedCourseKindsForRoleKeys(roleKeys = []) {
  const normalizedRoles = normalizeRoleList(roleKeys);
  const allowedKinds = new Set();
  normalizedRoles.forEach((roleKey) => {
    const defaults = Array.isArray(DEFAULT_ROLE_COURSE_KINDS[roleKey])
      ? DEFAULT_ROLE_COURSE_KINDS[roleKey]
      : ['regular'];
    defaults.forEach((kind) => {
      if (kind === 'regular' || kind === 'teacher') {
        allowedKinds.add(kind);
      }
    });
  });
  if (!allowedKinds.size) {
    allowedKinds.add('regular');
  }
  return allowedKinds;
}

function getDefaultMulticourseEnabledForRoleKeys(roleKeys = []) {
  const normalizedRoles = normalizeRoleList(roleKeys);
  return normalizedRoles.some((roleKey) => DEFAULT_ROLE_MULTICOURSE[roleKey] === true);
}

async function getRoleCourseAccessPolicy(roleKeys = []) {
  const normalizedRoles = normalizeRoleList(roleKeys);
  if (!normalizedRoles.length) {
    return {
      allowedKinds: new Set(['regular']),
      multicourseEnabled: false,
    };
  }
  try {
    const rows = await db.all(
      `
        SELECT
          ar.key AS role_key,
          ar.multicourse_enabled,
          rca.course_kind
        FROM access_roles ar
        LEFT JOIN access_role_course_access rca
          ON rca.role_id = ar.id
         AND rca.allowed = true
        WHERE ar.is_active = true
          AND ar.key = ANY(?)
      `,
      [normalizedRoles]
    );
    if (Array.isArray(rows) && rows.length) {
      const allowedKinds = new Set(
        (rows || [])
          .map((row) => String(row.course_kind || ''))
          .filter((kind) => kind === 'regular' || kind === 'teacher')
      );
      return {
        allowedKinds: allowedKinds.size
          ? allowedKinds
          : getDefaultAllowedCourseKindsForRoleKeys(normalizedRoles),
        multicourseEnabled: (rows || []).some((row) => isEnabledRoleFlag(row.multicourse_enabled)),
      };
    }
  } catch (err) {
    // fallback below
  }
  return {
    allowedKinds: getDefaultAllowedCourseKindsForRoleKeys(normalizedRoles),
    multicourseEnabled: getDefaultMulticourseEnabledForRoleKeys(normalizedRoles),
  };
}

async function getAllowedCourseKindsForRoleKeys(roleKeys = []) {
  const policy = await getRoleCourseAccessPolicy(roleKeys);
  return policy.allowedKinds;
}

async function buildStaffCourseAccess(userCourseId, courses, roleOrRoles = '') {
  const roleKeys = normalizeRoleList(roleOrRoles);
  const {
    allowedKinds,
    multicourseEnabled,
  } = await getRoleCourseAccessPolicy(roleKeys);
  const allowedCourseIds = new Set();
  const baseCourseId = Number(userCourseId);
  if (Number.isFinite(baseCourseId)) {
    const baseCourse = (courses || []).find((course) => Number(course.id) === baseCourseId);
    const baseKind = isTeacherCourseRow(baseCourse) ? 'teacher' : 'regular';
    if (allowedKinds.has(baseKind)) {
      allowedCourseIds.add(baseCourseId);
    }
  }
  if (multicourseEnabled) {
    (courses || []).forEach((course) => {
      const courseKind = isTeacherCourseRow(course) ? 'teacher' : 'regular';
      if (allowedKinds.has(courseKind)) {
        allowedCourseIds.add(Number(course.id));
      }
    });
  }
  const allowedCourses = (courses || []).filter((course) => allowedCourseIds.has(Number(course.id)));
  return {
    allowedCourseIds,
    allowedCourses,
    allowedKinds,
    multicourseEnabled,
  };
}

async function getRbacRolesDetailed() {
  try {
    const [roleRows, permissionRows, courseRows, memberRows] = await Promise.all([
      db.all(
        `
          SELECT id, key, label, description, is_system, is_active, multicourse_enabled
          FROM access_roles
          ORDER BY is_system DESC, key ASC
        `
      ),
      db.all(
        `
          SELECT ar.key AS role_key, p.key AS permission_key
          FROM access_role_permissions rp
          JOIN access_roles ar ON ar.id = rp.role_id
          JOIN access_permissions p ON p.id = rp.permission_id
          WHERE rp.allowed = true
        `
      ),
      db.all(
        `
          SELECT ar.key AS role_key, rca.course_kind
          FROM access_role_course_access rca
          JOIN access_roles ar ON ar.id = rca.role_id
          WHERE rca.allowed = true
        `
      ),
      db.all(
        `
          SELECT ar.key AS role_key, COUNT(*)::int AS members_count
          FROM user_roles ur
          JOIN access_roles ar ON ar.id = ur.role_id
          GROUP BY ar.key
        `
      ),
    ]);
    const permissionsByRole = {};
    (permissionRows || []).forEach((row) => {
      if (!permissionsByRole[row.role_key]) permissionsByRole[row.role_key] = new Set();
      permissionsByRole[row.role_key].add(String(row.permission_key));
    });
    const courseByRole = {};
    (courseRows || []).forEach((row) => {
      if (!courseByRole[row.role_key]) courseByRole[row.role_key] = new Set();
      courseByRole[row.role_key].add(String(row.course_kind));
    });
    const membersByRole = {};
    (memberRows || []).forEach((row) => {
      membersByRole[row.role_key] = Number(row.members_count || 0);
    });
    return (roleRows || []).map((row) => ({
      id: Number(row.id),
      key: String(row.key),
      label: String(row.label || row.key),
      description: String(row.description || ''),
      is_system: row.is_system === true || Number(row.is_system) === 1,
      is_active: row.is_active === true || Number(row.is_active) === 1,
      multicourse_enabled: isEnabledRoleFlag(row.multicourse_enabled),
      permission_keys: Array.from(permissionsByRole[row.key] || []).sort(),
      course_kinds: Array.from(courseByRole[row.key] || []).sort(),
      members_count: membersByRole[row.key] || 0,
    }));
  } catch (err) {
    return [];
  }
}

async function getUserRoleAssignmentsForUserIds(userIds = []) {
  const numericIds = Array.from(
    new Set(
      (Array.isArray(userIds) ? userIds : [])
        .map((id) => Number(id))
        .filter((id) => Number.isFinite(id))
    )
  );
  const roleKeysByUser = {};
  const primaryRoleByUser = {};
  if (!numericIds.length) {
    return { roleKeysByUser, primaryRoleByUser };
  }
  try {
    const rows = await pool.query(
      `
        SELECT ur.user_id, ar.key, ur.is_primary
        FROM user_roles ur
        JOIN access_roles ar ON ar.id = ur.role_id
        WHERE ur.user_id = ANY($1::int[])
          AND ar.is_active = true
        ORDER BY ur.user_id ASC, ur.is_primary DESC, ar.key ASC
      `,
      [numericIds]
    );
    rows.rows.forEach((row) => {
      const userId = Number(row.user_id);
      if (!roleKeysByUser[userId]) roleKeysByUser[userId] = [];
      const key = normalizeRoleKey(row.key);
      if (!roleKeysByUser[userId].includes(key)) {
        roleKeysByUser[userId].push(key);
      }
      if (!primaryRoleByUser[userId] && (row.is_primary === true || Number(row.is_primary) === 1)) {
        primaryRoleByUser[userId] = key;
      }
    });
  } catch (err) {
    // fallback below
  }
  if (Object.keys(roleKeysByUser).length !== numericIds.length) {
    const missing = numericIds.filter((id) => !roleKeysByUser[id]);
    if (missing.length) {
      const fallbackRows = await pool.query(
        'SELECT id, role FROM users WHERE id = ANY($1::int[])',
        [missing]
      );
      fallbackRows.rows.forEach((row) => {
        const userId = Number(row.id);
        const key = normalizeRoleKey(row.role || 'student');
        roleKeysByUser[userId] = [key];
        primaryRoleByUser[userId] = key;
      });
    }
  }
  return { roleKeysByUser, primaryRoleByUser };
}

async function assignUserRoles(userId, roleKeysInput, options = {}) {
  const userIdNum = Number(userId);
  if (!Number.isFinite(userIdNum) || userIdNum < 1) {
    throw new Error('Invalid user');
  }
  let roleKeys = normalizeRoleList(roleKeysInput);
  if (!roleKeys.length) {
    throw new Error('At least one role is required');
  }
  if (!roleKeys.some((role) => LEGACY_SESSION_ROLES.has(role))) {
    roleKeys.push('student');
  }
  roleKeys = normalizeRoleList(roleKeys);

  const preferredPrimary = options.preferredPrimary ? normalizeRoleKey(options.preferredPrimary) : '';
  let primaryRoleKey = preferredPrimary && roleKeys.includes(preferredPrimary)
    ? preferredPrimary
    : (roleKeys.find((role) => LEGACY_SESSION_ROLES.has(role)) || roleKeys[0]);
  if (!primaryRoleKey) {
    primaryRoleKey = 'student';
  }

  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const currentRows = await client.query(
      `
        SELECT ar.key
        FROM user_roles ur
        JOIN access_roles ar ON ar.id = ur.role_id
        WHERE ur.user_id = $1
      `,
      [userIdNum]
    );
    const currentRoles = normalizeRoleList(currentRows.rows.map((row) => row.key));
    const currentHasAdmin = currentRoles.includes('admin');
    const nextHasAdmin = roleKeys.includes('admin');
    if (currentHasAdmin && !nextHasAdmin) {
      const adminCountRow = await client.query(
        `
          SELECT COUNT(DISTINCT ur.user_id)::int AS count
          FROM user_roles ur
          JOIN access_roles ar ON ar.id = ur.role_id
          WHERE ar.key = 'admin'
        `
      );
      if (Number(adminCountRow.rows[0]?.count || 0) <= 1) {
        throw new Error('At least one admin required');
      }
    }
    const roleRows = await client.query(
      `
        SELECT id, key
        FROM access_roles
        WHERE is_active = true
          AND key = ANY($1::text[])
      `,
      [roleKeys]
    );
    if (roleRows.rows.length !== roleKeys.length) {
      throw new Error('Invalid role selection');
    }
    const roleIdByKey = new Map(roleRows.rows.map((row) => [String(row.key), Number(row.id)]));
    const roleIds = roleKeys.map((key) => roleIdByKey.get(key)).filter((id) => Number.isFinite(id));
    const primaryRoleId = roleIdByKey.get(primaryRoleKey);
    if (!Number.isFinite(primaryRoleId)) {
      throw new Error('Invalid primary role');
    }

    await client.query(
      'DELETE FROM user_roles WHERE user_id = $1 AND NOT (role_id = ANY($2::int[]))',
      [userIdNum, roleIds]
    );
    for (const roleId of roleIds) {
      await client.query(
        `
          INSERT INTO user_roles (user_id, role_id, is_primary, created_at, updated_at)
          VALUES ($1, $2, false, NOW(), NOW())
          ON CONFLICT (user_id, role_id)
          DO UPDATE SET updated_at = EXCLUDED.updated_at
        `,
        [userIdNum, roleId]
      );
    }
    await client.query(
      'UPDATE user_roles SET is_primary = false, updated_at = NOW() WHERE user_id = $1',
      [userIdNum]
    );
    await client.query(
      'UPDATE user_roles SET is_primary = true, updated_at = NOW() WHERE user_id = $1 AND role_id = $2',
      [userIdNum, primaryRoleId]
    );
    const legacyRole = LEGACY_SESSION_ROLES.has(primaryRoleKey)
      ? primaryRoleKey
      : (roleKeys.find((key) => LEGACY_SESSION_ROLES.has(key)) || 'student');
    await client.query(
      'UPDATE users SET role = $1 WHERE id = $2',
      [legacyRole, userIdNum]
    );
    await client.query('COMMIT');
    return { roleKeys, primaryRoleKey, legacyRole };
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release();
  }
}

const ensureUser = async (fullName, role, passwordHash, options = {}) => {
  const { courseId = 1 } = options;
  const { forcePassword = false, forceRole = false } = options;
  if (!passwordHash) {
    return;
  }
  const existing = await db.get('SELECT id, password_hash, role FROM users WHERE full_name = ?', [fullName]);
  if (!existing) {
    await db.run(
      'INSERT INTO users (full_name, role, password_hash, is_active, schedule_group, course_id, language) VALUES (?, ?, ?, ?, ?, ?, ?)',
      [fullName, role, passwordHash, 1, 'A', courseId, 'uk']
    );
    return;
  }
  if (forcePassword || !existing.password_hash) {
    await db.run('UPDATE users SET password_hash = ?, is_active = 1 WHERE id = ?', [
      passwordHash,
      existing.id,
    ]);
  } else {
    await db.run('UPDATE users SET is_active = 1 WHERE id = ?', [existing.id]);
  }
  if (forceRole && existing.role !== role) {
    await db.run('UPDATE users SET role = ? WHERE id = ?', [role, existing.id]);
  }
};

const syncRbacPermissionCatalog = async () => {
  for (const permission of RBAC_PERMISSION_OPTIONS) {
    await db.run(
      `
        INSERT INTO access_permissions (key, label, category)
        VALUES (?, ?, ?)
        ON CONFLICT (key) DO UPDATE
        SET label = EXCLUDED.label,
            category = EXCLUDED.category
      `,
      [permission.key, permission.label, permission.category]
    );
  }
  await pool.query(
    `
      INSERT INTO access_role_permissions (role_id, permission_id, allowed, created_at, updated_at)
      SELECT r.id, p.id, true, NOW(), NOW()
      FROM access_roles r
      JOIN access_permissions p ON p.category IN ('admin_section', 'feature')
      WHERE r.key = 'admin'
      ON CONFLICT (role_id, permission_id) DO NOTHING
    `
  );
};

const initDb = async () => {
  await runMigrations(pool);
  await syncRbacPermissionCatalog();

  await pool.query('UPDATE subjects SET is_required = true WHERE is_required IS NULL');

  try {
    await pool.query("UPDATE courses SET location = 'kyiv' WHERE location IS NULL");
  } catch (err) {
    if (!(err && err.code === '42703')) {
      throw err;
    }
  }
  await pool.query('UPDATE users SET course_id = 1 WHERE course_id IS NULL');
  await pool.query("UPDATE users SET language = 'uk' WHERE language IS NULL");
  await pool.query('UPDATE users SET created_at = NOW() WHERE created_at IS NULL');
  await pool.query(
    `
      UPDATE users u
      SET study_track = CASE
        WHEN c.is_teacher_course = true THEN 'teacher'
        ELSE 'bachelor'
      END
      FROM courses c
      WHERE u.course_id = c.id
        AND (u.study_track IS NULL OR TRIM(u.study_track) = '')
    `
  );
  await pool.query('UPDATE subjects SET course_id = 1 WHERE course_id IS NULL');
  await pool.query('UPDATE subjects SET visible = 1 WHERE visible IS NULL');
  await pool.query('UPDATE schedule_entries SET course_id = 1 WHERE course_id IS NULL');
  await pool.query('UPDATE homework SET course_id = 1 WHERE course_id IS NULL');
  await pool.query("UPDATE homework SET status = 'published' WHERE status IS NULL");
  await pool.query('UPDATE history_log SET course_id = 1 WHERE course_id IS NULL');
  await pool.query('UPDATE login_history SET course_id = 1 WHERE course_id IS NULL');
  await pool.query('UPDATE teamwork_tasks SET course_id = 1 WHERE course_id IS NULL');
  await pool.query('UPDATE messages SET course_id = 1 WHERE course_id IS NULL');
  await pool.query("UPDATE messages SET status = 'published' WHERE status IS NULL");
  await pool.query('UPDATE personal_reminders SET course_id = 1 WHERE course_id IS NULL');
  await pool.query('UPDATE personal_reminders SET updated_at = created_at WHERE updated_at IS NULL');
  try {
    await pool.query("UPDATE subject_materials SET material_type = 'lecture' WHERE material_type IS NULL");
    await pool.query('UPDATE subject_materials SET course_id = 1 WHERE course_id IS NULL');
    await pool.query('UPDATE subject_materials SET is_syllabus = 0 WHERE is_syllabus IS NULL');
    await pool.query('UPDATE subject_materials SET updated_at = created_at WHERE updated_at IS NULL');
  } catch (err) {
    if (!(err && (err.code === '42P01' || err.code === '42703'))) {
      throw err;
    }
  }
  await pool.query('UPDATE users SET password = NULL WHERE password IS NOT NULL');

  const courseRows = await pool.query('SELECT id, name FROM courses ORDER BY id');
  for (const course of courseRows.rows) {
    const activeRow = await pool.query(
      'SELECT id, is_active FROM semesters WHERE course_id = $1 ORDER BY is_active DESC, id ASC LIMIT 1',
      [course.id]
    );
    if (!activeRow.rows.length) {
      await pool.query(
        'INSERT INTO semesters (course_id, title, start_date, weeks_count, is_active, is_archived) VALUES ($1, $2, $3, $4, 1, 0)',
        [course.id, `${course.name} семестр`, '2026-01-19', 15]
      );
    } else if (activeRow.rows[0].is_active !== 1) {
      await pool.query('UPDATE semesters SET is_active = 1 WHERE id = $1', [activeRow.rows[0].id]);
    }

    const currentActive = await pool.query(
      'SELECT id FROM semesters WHERE course_id = $1 AND is_active = 1 ORDER BY id ASC LIMIT 1',
      [course.id]
    );
    if (currentActive.rows.length) {
      const semesterId = currentActive.rows[0].id;
      await pool.query('UPDATE schedule_entries SET semester_id = $1 WHERE semester_id IS NULL AND course_id = $2', [
        semesterId,
        course.id,
      ]);
      await pool.query('UPDATE homework SET semester_id = $1 WHERE semester_id IS NULL AND course_id = $2', [
        semesterId,
        course.id,
      ]);
      await pool.query('UPDATE teamwork_tasks SET semester_id = $1 WHERE semester_id IS NULL AND course_id = $2', [
        semesterId,
        course.id,
      ]);
      await pool.query('UPDATE messages SET semester_id = $1 WHERE semester_id IS NULL AND course_id = $2', [
        semesterId,
        course.id,
      ]);
      await pool.query('UPDATE personal_reminders SET semester_id = $1 WHERE semester_id IS NULL AND course_id = $2', [
        semesterId,
        course.id,
      ]);
    }
  }

  for (const user of userSeed) {
    const isAdmin = user.role === 'admin';
    await ensureUser(user.full_name, user.role, user.password_hash, {
      forcePassword: isAdmin,
      forceRole: isAdmin,
    });
  }

  await refreshSettingsCache();
};

let initPromise;
let initStatus = 'pending';
let initError = null;
const ensureDbReady = async () => {
  if (initPromise) {
    return initPromise;
  }
  initPromise = (async () => {
    const maxAttempts = 8;
    let lastError;
    for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
      try {
        initStatus = 'pending';
        await initDb();
        initStatus = 'ok';
        initError = null;
        return true;
      } catch (err) {
        lastError = err;
        initStatus = 'error';
        initError = err;
        const delay = Math.min(1000 * 2 ** (attempt - 1), 15000);
        console.error(`DB init attempt ${attempt} failed, retrying in ${delay}ms`, err);
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
    throw lastError;
  })();
  try {
    return await initPromise;
  } catch (err) {
    initPromise = null;
    throw err;
  }
};

app.use(async (req, res, next) => {
  if (!req.session || !req.session.user) {
    return next();
  }
  try {
    await ensureDbReady();
    const roleKeys = await getUserRoleKeys(req.session.user.id, req.session.role || 'student');
    const legacyRole = resolveLegacySessionRole(roleKeys, req.session.role || 'student');
    const rotated = await rotateSessionForRoleChange(req, roleKeys, legacyRole);
    req.session.roles = roleKeys;
    req.session.role = legacyRole;
    req.session.role_fingerprint = buildSessionRoleFingerprint(roleKeys);
    res.locals.userRoles = roleKeys;
    if (rotated) {
      req.session.last_seen_route = req.originalUrl || req.path || req.session.last_seen_route || null;
    }
  } catch (err) {
    req.session.roles = getSessionRoleList(req);
    req.session.role = normalizeRoleKey(req.session.role || req.session.roles[0] || 'student');
    req.session.role_fingerprint = buildSessionRoleFingerprint(req.session.roles);
    res.locals.userRoles = req.session.roles;
  }
  return next();
});

function getSensitiveReauthWindowMs() {
  return resolveStepUpReauthMinutes(settingsCache.security_stepup_reauth_minutes) * SESSION_MINUTE_MS;
}

function hasFreshSensitiveReauth(req, nowMs = Date.now()) {
  const lastReauthAt = req && req.session ? req.session.last_sensitive_reauth_at : null;
  const lastReauthMs = lastReauthAt ? new Date(lastReauthAt).getTime() : NaN;
  if (!Number.isFinite(lastReauthMs)) return false;
  return (nowMs - lastReauthMs) <= getSensitiveReauthWindowMs();
}

async function ensureSensitiveActionReauth(req) {
  if (!req || !req.session || !req.session.user) {
    return { ok: false, error: 'Login required' };
  }
  if (hasFreshSensitiveReauth(req)) {
    return {
      ok: true,
      reused: true,
      last_sensitive_reauth_at: req.session.last_sensitive_reauth_at || null,
    };
  }

  const confirmPassword = String(req.body?.confirm_password || req.query?.confirm_password || '').trim();
  if (!confirmPassword) {
    return {
      ok: false,
      error: 'Sensitive action requires password confirmation',
      code: 'reauth_required',
    };
  }

  await ensureDbReady();
  const actorId = Number(req.session.user.id || 0);
  const actorRow = await db.get(
    'SELECT password_hash FROM users WHERE id = ? LIMIT 1',
    [actorId]
  );
  const valid = actorRow && actorRow.password_hash
    ? bcrypt.compareSync(confirmPassword, actorRow.password_hash)
    : false;
  if (!valid) {
    return {
      ok: false,
      error: 'Password confirmation failed',
      code: 'reauth_failed',
    };
  }

  req.session.last_sensitive_reauth_at = new Date().toISOString();
  await saveRequestSession(req);
  return {
    ok: true,
    reused: false,
    last_sensitive_reauth_at: req.session.last_sensitive_reauth_at,
  };
}

function requireSensitiveActionReauth({ tab = 'admin-settings', json = false } = {}) {
  return async (req, res, next) => {
    try {
      const state = await ensureSensitiveActionReauth(req);
      if (state.ok) {
        req.sensitiveReauth = state;
        return next();
      }
      const wantsJson = json || (req.headers.accept && req.headers.accept.includes('application/json'));
      if (wantsJson) {
        return res.status(403).json({
          error: state.error || 'Sensitive action requires password confirmation',
          sensitive_reauth_required: true,
        });
      }
      return res.redirect(buildAdminScopedNoticeUrl(
        req,
        'err',
        state.error || 'Sensitive action requires password confirmation',
        { tab }
      ));
    } catch (err) {
      console.error('Sensitive reauth failed', err);
      if (json || (req.headers.accept && req.headers.accept.includes('application/json'))) {
        return res.status(500).json({ error: 'Sensitive reauth failed' });
      }
      return res.redirect(buildAdminScopedNoticeUrl(req, 'err', 'Sensitive reauth failed', { tab }));
    }
  };
}

function requireAdminPanelAccess(req, res, next) {
  if (!req.session || !req.session.user) {
    return res.status(403).send('Forbidden (update page)');
  }
  if (hasSessionRole(req, 'admin') || req.canAccessAdminPanel) {
    return next();
  }
  return res.status(403).send('Forbidden (update page)');
}

function hasAdminSectionAccess(req, sectionId) {
  if (!req || !req.session || !req.session.user) return false;
  if (hasSessionRole(req, 'admin')) return true;
  const allowedSections = Array.isArray(req.allowedAdminSections) ? req.allowedAdminSections : [];
  if (!sectionId) {
    return allowedSections.length > 0;
  }
  return allowedSections.includes(sectionId);
}

function requireAdminSectionAccess(sectionId) {
  return (req, res, next) => {
    if (!hasAdminSectionAccess(req, sectionId)) {
      return res.status(403).send('Forbidden (update page)');
    }
    return next();
  };
}

function hasUsersSectionAccess(req) {
  return hasAdminSectionAccess(req, 'admin-users');
}

function hasStudentsSectionAccess(req) {
  return hasAdminSectionAccess(req, 'admin-students');
}

function requireUsersOrStudentsSectionAccess(req, res, next) {
  if (hasUsersSectionAccess(req) || hasStudentsSectionAccess(req)) {
    return next();
  }
  return res.status(403).send('Forbidden (update page)');
}

function requirePathwaysSectionAccess(req, res, next) {
  if (hasAdminSectionAccess(req, 'admin-subjects') || hasAdminSectionAccess(req, 'admin-courses')) {
    return next();
  }
  return res.status(403).send('Forbidden (update page)');
}

function isStudentLikeLegacyRole(rawRole) {
  const normalized = normalizeRoleKey(rawRole);
  return normalized === 'student' || normalized === 'starosta';
}

function canManageStudentOnlyScope(req) {
  return !hasUsersSectionAccess(req) && hasStudentsSectionAccess(req);
}

