function buildTeacherSubjectsLegacyUrl({
  courseId = null,
  studyContextId = null,
  semesterId = null,
  ok = '',
  error = '',
} = {}) {
  const params = new URLSearchParams();
  params.set('legacy', '1');
  const normalizedCourseId = parsePositiveIntStrict(courseId);
  const normalizedStudyContextId = parsePositiveIntStrict(studyContextId);
  const normalizedSemesterId = parsePositiveIntStrict(semesterId);
  if (normalizedCourseId) {
    params.set('course', String(normalizedCourseId));
  }
  if (normalizedStudyContextId) {
    params.set('study_context_id', String(normalizedStudyContextId));
  }
  if (normalizedSemesterId) {
    params.set('semester_id', String(normalizedSemesterId));
  }
  if (ok) {
    params.set('ok', String(ok));
  }
  if (error) {
    params.set('error', String(error));
  }
  return `/teacher/subjects?${params.toString()}`;
}

function buildTeacherWorkspaceUrl({
  courseId = null,
  studyContextId = null,
  semesterId = null,
  ok = '',
  error = '',
} = {}) {
  const params = new URLSearchParams();
  const normalizedCourseId = parsePositiveIntStrict(courseId);
  const normalizedStudyContextId = parsePositiveIntStrict(studyContextId);
  const normalizedSemesterId = parsePositiveIntStrict(semesterId);
  if (normalizedCourseId) {
    params.set('course', String(normalizedCourseId));
  }
  if (normalizedStudyContextId) {
    params.set('study_context_id', String(normalizedStudyContextId));
  }
  if (normalizedSemesterId) {
    params.set('semester_id', String(normalizedSemesterId));
  }
  if (ok) {
    params.set('ok', String(ok));
  }
  if (error) {
    params.set('error', String(error));
  }
  const query = params.toString();
  return query ? `/teacher/workspace?${query}` : '/teacher/workspace';
}

function getTeacherWorkspaceRedirectState(source = {}, fallbackCourseId = null) {
  const normalizedSource = source && typeof source === 'object' ? source : {};
  return {
    courseId: parsePositiveIntStrict(
      normalizedSource.course
      || normalizedSource.course_id
      || normalizedSource.courseId
      || normalizedSource.course_id_context,
      parsePositiveIntStrict(fallbackCourseId)
    ),
    studyContextId: parsePositiveIntStrict(
      normalizedSource.study_context_id
      || normalizedSource.studyContextId
      || normalizedSource.study_context_id_context
    ),
    semesterId: parsePositiveIntStrict(
      normalizedSource.semester_id
      || normalizedSource.semesterId
      || normalizedSource.semester_id_context
    ),
  };
}

async function hydrateTeacherWorkspaceRedirectState(state = {}) {
  const nextState = {
    courseId: parsePositiveIntStrict(state.courseId),
    studyContextId: parsePositiveIntStrict(state.studyContextId),
    semesterId: parsePositiveIntStrict(state.semesterId),
  };
  if (!nextState.courseId && nextState.studyContextId) {
    try {
      const context = await getStudyContextById(nextState.studyContextId);
      if (context && parsePositiveIntStrict(context.course_id)) {
        nextState.courseId = parsePositiveIntStrict(context.course_id);
      }
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
    }
  }
  return nextState;
}

app.get('/teacher/workspace', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId, username } = req.session.user;
  const decodeMessage = (value) => {
    if (!value) return '';
    try {
      return decodeURIComponent(String(value));
    } catch (err) {
      return String(value);
    }
  };
  try {
    const workspaceTemplateOnlyMode = true;
    if (workspaceTemplateOnlyMode) {
      const teacherScopeRows = await getTeacherAssignedSubjects(userId).catch((err) => {
        if (isDbSchemaCompatibilityError(err)) {
          return [];
        }
        throw err;
      });
      const teacherCourses = buildTeacherCourseList(teacherScopeRows);
      const templateCourseIds = Array.from(new Set(
        (teacherCourses || [])
          .map((course) => Number(course && course.id ? course.id : 0))
          .filter((value) => Number.isInteger(value) && value > 0)
      ));
      const subjectMap = new Map();
      (teacherScopeRows || []).forEach((subject) => {
        const subjectId = Number(subject && subject.subject_id ? subject.subject_id : 0);
        if (!Number.isFinite(subjectId) || subjectId < 1 || subjectMap.has(subjectId)) return;
        subjectMap.set(subjectId, {
          id: subjectId,
          name: String(subject && subject.subject_name ? subject.subject_name : '').trim(),
          course_id: Number(subject && (subject.owner_course_id || subject.course_id) ? (subject.owner_course_id || subject.course_id) : 0) || null,
          course_name: String(subject && subject.course_name ? subject.course_name : ''),
        });
      });
      const teacherSubjects = Array.from(subjectMap.values()).sort((a, b) => {
        const byCourse = Number(a.course_id) - Number(b.course_id);
        if (byCourse !== 0) return byCourse;
        return String(a.name || '').localeCompare(String(b.name || ''), 'uk', { sensitivity: 'base' });
      });
      const [templates, assets] = await Promise.all([
        getTeacherHomeworkTemplates(userId, {
          courseIds: templateCourseIds,
          limit: 300,
        }),
        listTeacherAssets(userId, { courseIds: templateCourseIds }),
      ]);

      return res.render('teacher-workspace', {
        role: 'teacher',
        username,
        settings: settingsCache,
        teacherCourses,
        workspaceCourseOptions: [],
        selectedCourseId: null,
        workspaceContextOptions: [],
        workspaceContextCatalog: [],
        selectedWorkspaceContextId: null,
        workspaceSemesterOptions: [],
        selectedWorkspaceSemesterId: null,
        teacherOfferings: [],
        workspaceCatalogOfferings: [],
        workspaceOfferingSelections: new Map(),
        workspaceAssignedOfferingDetails: new Map(),
        workspaceTemplatePlan: {
          visible_count: 0,
          selected_count: 0,
          counts: { create: 0, update: 0, deactivate: 0, keep: 0, idle: 0 },
          items: [],
        },
        teacherSubjects,
        teacherSubjectsAll: teacherSubjects,
        templates,
        assets,
        recentHomework: [],
        showWorkspaceAdvancedPanels: false,
        showWorkspaceTemplateOnly: true,
        error: decodeMessage(req.query.error),
        success: decodeMessage(req.query.ok),
      });
    }

    const showWorkspaceAdvancedPanels = String(req.query.advanced || '').trim() === '1';
    const [teacherAssignedOfferings, teacherOfferingCatalog, teacherOfferingSelections] = await Promise.all([
      getTeacherAssignedOfferings(userId),
      listTeacherOfferingCatalog({
        allowLegacyBootstrap: true,
        allowPresetBootstrap: true,
        requirePresetStageSubject: false,
        allowedTrackKeys: ['bachelor', 'master'],
      }),
      getTeacherOfferingSelections(userId),
    ]);
    let teacherScopeRows = buildTeacherAssignedSubjectRowsFromOfferings(teacherAssignedOfferings);
    if (!teacherScopeRows.length) {
      teacherScopeRows = await getTeacherAssignedSubjects(userId);
    }
    const teacherScopedSubjectIdSet = new Set(
      (teacherScopeRows || [])
        .map((row) => parsePositiveIntStrict(row && (row.subject_id || row.legacy_subject_id)))
        .filter((value) => Number.isInteger(value) && value > 0)
    );
    const teacherWorkspaceOfferingCatalog = teacherScopedSubjectIdSet.size
      ? (teacherOfferingCatalog || []).filter((offering) => {
          const legacySubjectId = parsePositiveIntStrict(offering && offering.legacy_subject_id);
          return legacySubjectId && teacherScopedSubjectIdSet.has(legacySubjectId);
        })
      : (teacherOfferingCatalog || []);
    const teacherCourses = buildTeacherCourseList(
      (teacherAssignedOfferings || []).length ? teacherAssignedOfferings : teacherScopeRows
    );
    const requestedCourseId = parsePositiveIntStrict(req.query.course);
    const requestedStudyContextId = parsePositiveIntStrict(req.query.study_context_id);
    const requestedSemesterId = parsePositiveIntStrict(req.query.semester_id);
    const workspaceCourseOptions = Array.from(new Map(
      (teacherWorkspaceOfferingCatalog || [])
        .flatMap((offering) => Array.isArray(offering.contexts) ? offering.contexts : [])
        .map((context) => [Number(context.course_id || 0), {
          id: Number(context.course_id || 0) || null,
          name: String(context.course_name || ''),
        }])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    ).values()).sort((a, b) => {
      const byId = Number(a.id || 0) - Number(b.id || 0);
      if (byId !== 0) return byId;
      return String(a.name || '').localeCompare(String(b.name || ''), 'uk', { sensitivity: 'base' });
    });
    const allWorkspaceContextOptions = Array.from(new Map(
      (teacherWorkspaceOfferingCatalog || [])
        .flatMap((offering) => Array.isArray(offering.contexts) ? offering.contexts : [])
        .map((context) => [Number(context.id || 0), {
          id: Number(context.id || 0) || null,
          label: String(context.label || ''),
          course_id: Number(context.course_id || 0) || null,
          course_name: String(context.course_name || ''),
          course_location: String(context.course_location || ''),
          program_name: String(context.program_name || ''),
          program_code: String(context.program_code || ''),
          admission_year: Number(context.admission_year || 0) || null,
          stage_number: Number(context.stage_number || 0) || null,
          campus_key: String(context.campus_key || ''),
          semester_ids: Array.isArray(context.semester_ids) ? context.semester_ids.slice() : [],
          semester_numbers: Array.isArray(context.semester_numbers) ? context.semester_numbers.slice() : [],
          semester_titles: Array.isArray(context.semester_titles) ? context.semester_titles.slice() : [],
        }])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    ).values());
    const requestedWorkspaceCourse = requestedCourseId
      ? (workspaceCourseOptions.find((course) => Number(course.id || 0) === Number(requestedCourseId || 0)) || null)
      : null;
    const requestedTeacherCourse = requestedCourseId
      ? (teacherCourses.find((course) => Number(course.id || 0) === Number(requestedCourseId || 0)) || null)
      : null;
    let selectedCourseId = requestedWorkspaceCourse
      ? Number(requestedWorkspaceCourse.id || 0) || null
      : (requestedTeacherCourse
        ? Number(requestedTeacherCourse.id || 0) || null
        : null);
    let selectedWorkspaceContext = allWorkspaceContextOptions.find((item) => Number(item.id || 0) === Number(requestedStudyContextId || 0)) || null;
    if (
      selectedWorkspaceContext
      && selectedCourseId
      && Number(selectedWorkspaceContext.course_id || 0) !== Number(selectedCourseId || 0)
    ) {
      // Keep course as the primary selector; stale context values from another course are dropped.
      selectedWorkspaceContext = null;
    }
    if (!selectedCourseId && selectedWorkspaceContext && Number(selectedWorkspaceContext.course_id || 0) > 0) {
      selectedCourseId = Number(selectedWorkspaceContext.course_id || 0);
    }
    const workspaceContextOptions = (selectedCourseId
      ? allWorkspaceContextOptions.filter((context) => Number(context.course_id || 0) === Number(selectedCourseId || 0))
      : allWorkspaceContextOptions);
    let selectedWorkspaceContextId = selectedWorkspaceContext ? Number(selectedWorkspaceContext.id || 0) || null : null;
    if (
      selectedWorkspaceContextId
      && !workspaceContextOptions.some((context) => Number(context.id || 0) === Number(selectedWorkspaceContextId || 0))
    ) {
      selectedWorkspaceContext = null;
      selectedWorkspaceContextId = null;
    }
    if (!selectedWorkspaceContextId && workspaceContextOptions.length === 1) {
      selectedWorkspaceContext = workspaceContextOptions[0];
      selectedWorkspaceContextId = Number(selectedWorkspaceContext.id || 0) || null;
      selectedCourseId = Number(selectedWorkspaceContext.course_id || 0) || selectedCourseId;
    }

    const semesterSourceContexts = selectedWorkspaceContext
      ? [selectedWorkspaceContext]
      : workspaceContextOptions;
    const workspaceSemesterOptions = Array.from(new Map(
      (selectedWorkspaceContext
        ? (selectedWorkspaceContext.semester_ids || []).map((semesterId, index) => ({
            id: Number(semesterId || 0) || null,
            title: String((selectedWorkspaceContext.semester_titles || [])[index] || `Semester ${(selectedWorkspaceContext.semester_numbers || [])[index] || index + 1}`),
            semester_number: Number((selectedWorkspaceContext.semester_numbers || [])[index] || 0) || null,
          }))
        : (semesterSourceContexts || []).flatMap((context) => (
            (context.semester_ids || []).map((semesterId, index) => ({
              id: Number(semesterId || 0) || null,
              title: String((context.semester_titles || [])[index] || `Semester ${(context.semester_numbers || [])[index] || index + 1}`),
              semester_number: Number((context.semester_numbers || [])[index] || 0) || null,
            }))
          )))
        .filter((item) => Number.isInteger(Number(item.id || 0)) && Number(item.id || 0) > 0)
        .map((item) => [Number(item.id || 0), item])
    ).values()).sort((a, b) => {
      const numberDiff = Number(a.semester_number || 0) - Number(b.semester_number || 0);
      if (numberDiff !== 0) return numberDiff;
      return String(a.title || '').localeCompare(String(b.title || ''));
    });
    const selectedWorkspaceSemesterId = workspaceSemesterOptions.find((item) => Number(item.id || 0) === requestedSemesterId)
      ? Number(requestedSemesterId || 0)
      : null;

    const matchesWorkspaceScope = (offering) => {
      const contexts = Array.isArray(offering.contexts) ? offering.contexts : [];
      const courseMatch = !selectedCourseId
        || contexts.some((context) => Number(context.course_id || 0) === Number(selectedCourseId || 0));
      if (!courseMatch) {
        return false;
      }
      const contextMatch = !selectedWorkspaceContextId
        || contexts.some((context) => Number(context.id || 0) === Number(selectedWorkspaceContextId || 0));
      if (!contextMatch) {
        return false;
      }
      const semesterMatch = !selectedWorkspaceSemesterId
        || contexts.some((context) => {
          const semesterIds = Array.isArray(context && context.semester_ids) ? context.semester_ids : [];
          if (!semesterIds.length) {
            return true;
          }
          return semesterIds.some((semesterId) => Number(semesterId || 0) === Number(selectedWorkspaceSemesterId || 0));
        });
      if (!semesterMatch) {
        return false;
      }
      return true;
    };
    const scopedTeacherOfferings = (teacherAssignedOfferings || []).filter(matchesWorkspaceScope);
    const workspaceCatalogOfferings = (teacherWorkspaceOfferingCatalog || []).filter(matchesWorkspaceScope);
    const workspaceAssignedOfferingDetails = new Map(
      (teacherAssignedOfferings || [])
        .map((offering) => [Number(offering.id || 0), offering])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    );
    const workspaceTemplatePlan = await buildTeacherWorkspaceTemplateScopePlan(
      userId,
      workspaceCatalogOfferings,
      teacherOfferingSelections,
      workspaceAssignedOfferingDetails,
    );
    const selectedWorkspaceSemesterRow = selectedWorkspaceSemesterId
      ? await db.get(
          'SELECT legacy_semester_id FROM study_context_semesters WHERE id = ? LIMIT 1',
          [selectedWorkspaceSemesterId]
        ).catch((err) => {
          if (isDbSchemaCompatibilityError(err)) {
            return null;
          }
          throw err;
        })
      : null;
    const selectedWorkspaceLegacySemesterIds = Array.from(new Set(
      [Number(selectedWorkspaceSemesterRow && selectedWorkspaceSemesterRow.legacy_semester_id ? selectedWorkspaceSemesterRow.legacy_semester_id : 0)]
        .filter((value) => Number.isInteger(value) && value > 0)
    ));
    const selectedWorkspaceStorageScope = selectedCourseId
      ? await getCourseSharedStorageScope(selectedCourseId, {
          fallbackSemesterId: selectedWorkspaceLegacySemesterIds[0] || null,
          visibleOnly: false,
        })
      : {
          subjects: [],
          subject_ids: [],
          owner_course_ids: [],
          owner_semester_ids: selectedWorkspaceLegacySemesterIds,
        };
    const workspaceTemplateCourseIds = Array.from(new Set(
      [
        ...(Array.isArray(selectedWorkspaceStorageScope.owner_course_ids) ? selectedWorkspaceStorageScope.owner_course_ids : []),
        selectedCourseId,
      ]
        .map((value) => Number(value || 0))
        .filter((value) => Number.isInteger(value) && value > 0)
    ));
    const workspaceHomeworkScopeSource = scopedTeacherOfferings.length
      ? scopedTeacherOfferings
      : workspaceCatalogOfferings;
    const workspaceScopedSubjectIds = Array.from(new Set(
      ((workspaceHomeworkScopeSource || []).length
        ? workspaceHomeworkScopeSource
        : (teacherScopeRows || []))
        .map((offering) => Number(
          offering && (offering.legacy_subject_id || offering.subject_id)
            ? (offering.legacy_subject_id || offering.subject_id)
            : 0
        ))
        .filter((value) => Number.isInteger(value) && value > 0)
    ));
    const workspaceScopedOwnerCourseIds = workspaceScopedSubjectIds.length
      ? Array.from(new Set(
          (Array.isArray(selectedWorkspaceStorageScope.subjects) ? selectedWorkspaceStorageScope.subjects : [])
            .filter((subject) => workspaceScopedSubjectIds.includes(Number(subject.id || 0)))
            .map((subject) => Number(subject.owner_course_id || subject.course_id || 0))
            .filter((value) => Number.isInteger(value) && value > 0)
        ))
      : workspaceTemplateCourseIds;

    const recentHomeworkCourseIds = workspaceScopedOwnerCourseIds.length
      ? workspaceScopedOwnerCourseIds
      : workspaceTemplateCourseIds;
    const canLoadRecentHomework = recentHomeworkCourseIds.length > 0 && workspaceScopedSubjectIds.length > 0;
    let templates = [];
    let assets = [];
    let recentHomework = [];
    if (showWorkspaceAdvancedPanels) {
      const recentHomeworkPromise = canLoadRecentHomework
        ? db.all(
            `
              SELECT
                h.id,
                h.description,
                h.class_date,
                h.custom_due_date,
                h.subject_id,
                h.group_number,
                h.course_id,
                h.semester_id,
                s.name AS subject_name
              FROM homework h
              LEFT JOIN subjects s ON s.id = h.subject_id
              WHERE h.created_by_id = ?
                AND COALESCE(h.is_teacher_homework, 0) = 1
                AND h.course_id = ANY(?::int[])
                AND h.subject_id = ANY(?::int[])
                ${selectedWorkspaceLegacySemesterIds.length
                  ? 'AND (h.semester_id = ANY(?::int[]) OR h.semester_id IS NULL)'
                  : ''}
              ORDER BY COALESCE(NULLIF(TRIM(CAST(h.custom_due_date AS TEXT)), ''), NULLIF(TRIM(CAST(h.class_date AS TEXT)), '')) DESC NULLS LAST, CAST(h.created_at AS TEXT) DESC
              LIMIT 8
            `,
            selectedWorkspaceLegacySemesterIds.length
              ? [
                  userId,
                  recentHomeworkCourseIds,
                  workspaceScopedSubjectIds,
                  selectedWorkspaceLegacySemesterIds,
                ]
              : [
                  userId,
                  recentHomeworkCourseIds,
                  workspaceScopedSubjectIds,
                ]
          ).catch((err) => {
            if (isDbSchemaCompatibilityError(err)) {
              return [];
            }
            throw err;
          })
        : Promise.resolve([]);
      [templates, assets, recentHomework] = await Promise.all([
        getTeacherHomeworkTemplates(userId, {
          courseIds: workspaceTemplateCourseIds,
          limit: 300,
        }),
        listTeacherAssets(userId, { courseIds: workspaceTemplateCourseIds }),
        recentHomeworkPromise,
      ]);
    }

    const subjectMap = new Map();
    teacherScopeRows.forEach((subject) => {
      const subjectId = Number(subject.subject_id);
      if (!Number.isFinite(subjectId) || subjectId < 1 || subjectMap.has(subjectId)) return;
      subjectMap.set(subjectId, {
        id: subjectId,
        name: String(subject.subject_name || '').trim(),
        course_id: Number(subject.owner_course_id || subject.course_id || 0) || null,
        course_name: String(subject.course_name || ''),
      });
    });
    const allTeacherSubjects = Array.from(subjectMap.values()).sort((a, b) => {
      const byCourse = Number(a.course_id) - Number(b.course_id);
      if (byCourse !== 0) return byCourse;
      return String(a.name || '').localeCompare(String(b.name || ''), 'uk', { sensitivity: 'base' });
    });
    const scopedTeacherSubjects = selectedCourseId
      ? allTeacherSubjects.filter((subject) => Number(subject.course_id) === Number(selectedCourseId))
      : allTeacherSubjects;

    return res.render('teacher-workspace', {
      role: 'teacher',
      username,
      settings: settingsCache,
      teacherCourses,
      workspaceCourseOptions,
      selectedCourseId,
      workspaceContextOptions,
      workspaceContextCatalog: allWorkspaceContextOptions,
      selectedWorkspaceContextId,
      workspaceSemesterOptions,
      selectedWorkspaceSemesterId,
      teacherOfferings: scopedTeacherOfferings,
      workspaceCatalogOfferings,
      workspaceOfferingSelections: teacherOfferingSelections,
      workspaceAssignedOfferingDetails,
      workspaceTemplatePlan,
      teacherSubjects: scopedTeacherSubjects,
      teacherSubjectsAll: allTeacherSubjects,
      templates,
      assets,
      recentHomework,
      showWorkspaceAdvancedPanels,
      error: decodeMessage(req.query.error),
      success: decodeMessage(req.query.ok),
    });
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace');
  }
});

app.post('/teacher/workspace/offering-templates/sync', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.offeringTemplates.sync.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const userId = Number(req.session.user.id || 0);
  const redirectState = await hydrateTeacherWorkspaceRedirectState({
    courseId: parsePositiveIntStrict(req.body.course),
    studyContextId: parsePositiveIntStrict(req.body.study_context_id),
    semesterId: parsePositiveIntStrict(req.body.semester_id),
  });
  try {
    const scopeOfferingIds = Array.from(new Set(
      (Array.isArray(req.body.visible_offering_ids) ? req.body.visible_offering_ids : [req.body.visible_offering_ids])
        .map((value) => parsePositiveIntStrict(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    ));
    if (!scopeOfferingIds.length) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'No visible offering scope to sync',
      }));
    }
    const [teacherOfferingCatalog, teacherOfferingSelections, teacherAssignedOfferings] = await Promise.all([
      listTeacherOfferingCatalog({
        allowLegacyBootstrap: true,
        allowPresetBootstrap: true,
        requirePresetStageSubject: false,
        allowedTrackKeys: ['bachelor', 'master'],
      }),
      getTeacherOfferingSelections(userId),
      getTeacherAssignedOfferings(userId),
    ]);
    const scopedOfferings = (teacherOfferingCatalog || [])
      .filter((offering) => scopeOfferingIds.includes(Number(offering.id || 0)));
    for (const offering of scopedOfferings) {
      const hasSubjectCatalog = parsePositiveIntStrict(offering && offering.subject_catalog_id);
      const hasContexts = Array.isArray(offering && offering.contexts) && offering.contexts.length > 0;
      if (hasSubjectCatalog && hasContexts) {
        continue;
      }
      await queueAcademicModerationItem(academicSetupHelpers.buildInvalidTeacherTemplateMatchIssue({
        teacherId: userId,
        offeringId: Number(offering && offering.id || 0) || null,
        subjectCatalogId: parsePositiveIntStrict(offering && offering.subject_catalog_id),
        studyContextId: redirectState.studyContextId || null,
        semesterId: redirectState.semesterId || null,
        courseId: redirectState.courseId || null,
        hasContexts,
      }));
    }
    const workspaceAssignedOfferingDetails = new Map(
      (teacherAssignedOfferings || [])
        .map((offering) => [Number(offering.id || 0), offering])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    );
    const plan = await buildTeacherWorkspaceTemplateScopePlan(
      userId,
      scopedOfferings,
      teacherOfferingSelections,
      workspaceAssignedOfferingDetails,
    );
    const result = await applyTeacherWorkspaceTemplateScopePlan(userId, plan);
    logAction(db, req, 'teacher_workspace_template_scope_sync', {
      user_id: userId,
      course_id: redirectState.courseId || null,
      study_context_id: redirectState.studyContextId || null,
      semester_id: redirectState.semesterId || null,
      create_count: Number(result.create || 0),
      update_count: Number(result.update || 0),
      deactivate_count: Number(result.deactivate || 0),
      keep_count: Number(result.keep || 0),
    });
    broadcast('users_updated');
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      ok: 'Recurring template rules synced',
    }));
  } catch (err) {
    console.error('Teacher workspace template scope sync failed', err);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

app.post('/teacher/workspace/offerings', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.offerings.save.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const userId = Number(req.session.user.id || 0);
  const redirectState = await hydrateTeacherWorkspaceRedirectState({
    courseId: parsePositiveIntStrict(req.body.course),
    studyContextId: parsePositiveIntStrict(req.body.study_context_id),
    semesterId: parsePositiveIntStrict(req.body.semester_id),
  });
  try {
    const result = await saveTeacherWorkspaceOfferingAssignments(userId, req.body, {
      allowLegacyBootstrap: true,
      allowPresetBootstrap: true,
      requirePresetStageSubject: false,
      allowedTrackKeys: ['bachelor', 'master'],
    });
    if (!result.ok) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: result.error || 'Database error',
      }));
    }
    logAction(db, req, 'teacher_workspace_offering_assignments_save', {
      user_id: userId,
      course_id: redirectState.courseId || null,
      study_context_id: redirectState.studyContextId || null,
      semester_id: redirectState.semesterId || null,
      scope_count: Number(result.scope_count || 0),
      assignment_count: Number(result.assignment_count || 0),
      template_count: Number(result.template_count || 0),
      templates_synced: result.templates_synced ? 1 : 0,
    });
    broadcast('users_updated');
    const okMessage = result.templates_synced
      ? 'Assignments and recurring templates updated'
      : 'Live assignments updated';
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      ok: okMessage,
    }));
  } catch (err) {
    console.error('Teacher workspace offering save failed', err);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

app.post('/teacher/workspace/assets', requireLogin, uploadLimiter, upload.single('asset'), async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.assets.create.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect('/schedule');
  }
  const userId = Number(req.session.user.id || 0);
  const requestedCourseId = Number(req.body.course_id || req.session.user.course_id || 0);
  const redirectState = await hydrateTeacherWorkspaceRedirectState(
    getTeacherWorkspaceRedirectState(req.body, requestedCourseId)
  );
  if (!req.file) {
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Select a file',
    }));
  }
  try {
    const assetId = await createAssetFromUpload({
      file: req.file,
      userId,
      courseId: requestedCourseId || null,
      name: req.body.name,
      kind: 'template_attachment',
    });
    if (!assetId) {
      if (req.file) fs.unlink(req.file.path, () => {});
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Asset storage is unavailable',
      }));
    }
    logAction(db, req, 'teacher_workspace_asset_create', {
      asset_id: assetId,
      course_id: requestedCourseId || null,
      original_name: req.file.originalname ? String(req.file.originalname) : '',
    });
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      ok: 'Asset uploaded',
    }));
  } catch (err) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

app.post('/teacher/workspace/assets/:id/delete', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.assets.delete.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const assetId = Number(req.params.id);
  const requestedCourseId = Number(req.body.course_id || req.session.user.course_id || 0);
  const redirectState = await hydrateTeacherWorkspaceRedirectState(
    getTeacherWorkspaceRedirectState(req.body, requestedCourseId)
  );
  if (!Number.isInteger(assetId) || assetId < 1) {
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Invalid asset',
    }));
  }
  try {
    const asset = await db.get(
      'SELECT id, user_id, file_path, original_name FROM assets WHERE id = ? LIMIT 1',
      [assetId]
    );
    if (!asset || Number(asset.user_id) !== Number(req.session.user.id)) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Asset not found',
      }));
    }
    const usage = await db.get(
      `
        SELECT
          (SELECT COUNT(*) FROM teacher_template_asset_map WHERE asset_id = ?) AS template_count,
          (SELECT COUNT(*) FROM homework_asset_map WHERE asset_id = ?) AS homework_count
      `,
      [assetId, assetId]
    );
    if (Number(usage?.template_count || 0) > 0 || Number(usage?.homework_count || 0) > 0) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Asset is still linked to templates or homework',
      }));
    }
    await db.run('DELETE FROM assets WHERE id = ?', [assetId]);
    logAction(db, req, 'teacher_workspace_asset_delete', {
      asset_id: assetId,
      original_name: asset.original_name ? String(asset.original_name) : '',
    });
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      ok: 'Asset deleted',
    }));
  } catch (err) {
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

app.post('/teacher/workspace/templates', requireLogin, uploadLimiter, upload.array('template_files', 8), async (req, res) => {
  const uploadedFiles = Array.isArray(req.files) ? req.files : [];
  try {
    await ensureDbReady();
  } catch (err) {
    unlinkUploadedFiles(uploadedFiles);
    return handleDbError(res, err, 'teacher.workspace.templates.create.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect('/schedule');
  }
  const { id: userId, course_id: fallbackCourseId } = req.session.user;
  const title = String(req.body.title || '').trim();
  const description = String(req.body.description || '').trim();
  const requestedCourseId = Number(req.body.course_id);
  const requestedSubjectId = Number(req.body.subject_id);
  const isControl = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_control || '').toLowerCase()) ? 1 : 0;
  const isCredit = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_credit || '').toLowerCase()) ? 1 : 0;
  const tags = normalizeTemplateTagsInput(req.body.tags).join(', ');
  const assetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(req.body.asset_ids, 48);
  const linkUrl = normalizeExternalUrl(req.body.link_url) || null;
  const meetingUrl = normalizeExternalUrl(req.body.meeting_url) || null;
  const redirectState = await hydrateTeacherWorkspaceRedirectState(
    getTeacherWorkspaceRedirectState(req.body, requestedCourseId || fallbackCourseId || null)
  );

  if (!title || !description) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Title and description are required',
    }));
  }

  let uploadedAssetIds = [];
  try {
    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok) {
      unlinkUploadedFiles(uploadedFiles);
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: resolvedScope.error || 'Invalid template scope',
      }));
    }
    const { courseId, subjectId, validatedCourseId } = resolvedScope;
    uploadedAssetIds = await createAssetsFromUploads({
      files: uploadedFiles,
      userId,
      courseId: courseId || validatedCourseId || fallbackCourseId || null,
      kind: 'template_attachment',
    });
    const combinedAssetIds = teacherTemplateHelpers.buildAppliedHomeworkAssetIds({
      templateAssetIds: assetIds,
      uploadedAssetIds,
    });

    const inserted = await db.get(
      `
        INSERT INTO teacher_homework_templates
          (
            user_id,
            course_id,
            subject_id,
            title,
            description,
            link_url,
            meeting_url,
            tags,
            is_control,
            is_credit,
            created_at,
            updated_at
          )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
        RETURNING id
      `,
      [
        userId,
        courseId,
        subjectId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
      ]
    );
    if (inserted && inserted.id) {
      await syncTemplateAssetMap(inserted.id, userId, combinedAssetIds);
    }

    logAction(db, req, 'teacher_homework_template_create', {
      template_id: inserted && inserted.id ? Number(inserted.id) : null,
      course_id: courseId,
      subject_id: subjectId,
      title,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
      asset_ids: combinedAssetIds,
      uploaded_asset_ids: uploadedAssetIds,
    });

    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      courseId: courseId || validatedCourseId || redirectState.courseId,
      ok: 'Template saved',
    }));
  } catch (err) {
    console.error('Teacher workspace template create failed', err);
    await cleanupFailedUploadedAssets({
      files: uploadedFiles,
      assetIds: uploadedAssetIds.length ? uploadedAssetIds : (err && Array.isArray(err.assetIds) ? err.assetIds : []),
    });
    const errorMessage = err && err.code === 'ASSET_STORAGE_UNAVAILABLE'
      ? 'Asset%20storage%20is%20unavailable'
      : 'Database%20error';
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: errorMessage === 'Database%20error' ? 'Database error' : 'Asset storage is unavailable',
    }));
  }
});

app.post('/teacher/workspace/templates/:id/update', requireLogin, uploadLimiter, upload.array('template_files', 8), async (req, res) => {
  const uploadedFiles = Array.isArray(req.files) ? req.files : [];
  try {
    await ensureDbReady();
  } catch (err) {
    unlinkUploadedFiles(uploadedFiles);
    return handleDbError(res, err, 'teacher.workspace.templates.update.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  const requestedCourseId = Number(req.body.course_id);
  const requestedSubjectId = Number(req.body.subject_id);
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0
    ? contextCourseId
    : (Number.isInteger(requestedCourseId) && requestedCourseId > 0 ? requestedCourseId : null);
  const redirectState = await hydrateTeacherWorkspaceRedirectState(
    getTeacherWorkspaceRedirectState(req.body, fallbackCourseId)
  );
  if (!Number.isInteger(templateId) || templateId < 1) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Invalid template',
    }));
  }
  const title = String(req.body.title || '').trim();
  const description = String(req.body.description || '').trim();
  const tags = normalizeTemplateTagsInput(req.body.tags).join(', ');
  const assetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(req.body.asset_ids, 48);
  const linkUrl = normalizeExternalUrl(req.body.link_url) || null;
  const meetingUrl = normalizeExternalUrl(req.body.meeting_url) || null;
  const isControl = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_control || '').toLowerCase()) ? 1 : 0;
  const isCredit = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_credit || '').toLowerCase()) ? 1 : 0;

  if (!title || !description) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Title and description are required',
    }));
  }

  let uploadedAssetIds = [];
  try {
    const existing = await db.get(
      `
        SELECT id, user_id, course_id, subject_id, title
        FROM teacher_homework_templates
        WHERE id = ?
        LIMIT 1
      `,
      [templateId]
    );
    if (!existing) {
      unlinkUploadedFiles(uploadedFiles);
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Template not found',
      }));
    }
    if (Number(existing.user_id) !== Number(userId)) {
      unlinkUploadedFiles(uploadedFiles);
      return res.status(403).send('Forbidden');
    }

    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok) {
      unlinkUploadedFiles(uploadedFiles);
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: resolvedScope.error || 'Invalid template scope',
      }));
    }
    const { courseId, subjectId, validatedCourseId } = resolvedScope;
    uploadedAssetIds = await createAssetsFromUploads({
      files: uploadedFiles,
      userId,
      courseId: courseId || validatedCourseId || fallbackCourseId || null,
      kind: 'template_attachment',
    });
    const combinedAssetIds = teacherTemplateHelpers.buildAppliedHomeworkAssetIds({
      templateAssetIds: assetIds,
      uploadedAssetIds,
    });

    await db.run(
      `
        UPDATE teacher_homework_templates
        SET
          course_id = ?,
          subject_id = ?,
          title = ?,
          description = ?,
          link_url = ?,
          meeting_url = ?,
          tags = ?,
          is_control = ?,
          is_credit = ?,
          updated_at = NOW()
        WHERE id = ?
      `,
      [
        courseId,
        subjectId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
        templateId,
      ]
    );
    await syncTemplateAssetMap(templateId, userId, combinedAssetIds);

    logAction(db, req, 'teacher_homework_template_update', {
      template_id: templateId,
      previous_title: existing.title ? String(existing.title) : '',
      title,
      course_id: courseId,
      subject_id: subjectId,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
      asset_ids: combinedAssetIds,
      uploaded_asset_ids: uploadedAssetIds,
    });

    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      courseId: courseId || validatedCourseId || redirectState.courseId,
      ok: 'Template updated',
    }));
  } catch (err) {
    console.error('Teacher workspace template update failed', err);
    await cleanupFailedUploadedAssets({
      files: uploadedFiles,
      assetIds: uploadedAssetIds.length ? uploadedAssetIds : (err && Array.isArray(err.assetIds) ? err.assetIds : []),
    });
    const errorMessage = err && err.code === 'ASSET_STORAGE_UNAVAILABLE'
      ? 'Asset%20storage%20is%20unavailable'
      : 'Database%20error';
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: errorMessage === 'Database%20error' ? 'Database error' : 'Asset storage is unavailable',
    }));
  }
});

app.post('/teacher/workspace/templates/:id/clone', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.clone.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  const contextCourseId = Number(req.body.course_id_context);
  const redirectState = await hydrateTeacherWorkspaceRedirectState(
    getTeacherWorkspaceRedirectState(req.body, contextCourseId)
  );
  if (!Number.isInteger(templateId) || templateId < 1) {
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Invalid template',
    }));
  }
  const rawTargetSubjectIds = req.body.target_subject_ids;
  const targetSubjectIds = Array.from(
    new Set(
      (Array.isArray(rawTargetSubjectIds) ? rawTargetSubjectIds : [rawTargetSubjectIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 240);

  if (!targetSubjectIds.length) {
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Select at least one subject',
    }));
  }

  try {
    const sourceTemplate = await db.get(
      `
        SELECT
          id,
          user_id,
          course_id,
          subject_id,
          title,
          description,
          link_url,
          meeting_url,
          tags,
          is_control,
          is_credit
        FROM teacher_homework_templates
        WHERE id = ?
        LIMIT 1
      `,
      [templateId]
    );
    if (!sourceTemplate) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Template not found',
      }));
    }
    if (Number(sourceTemplate.user_id) !== Number(userId)) {
      return res.status(403).send('Forbidden');
    }

    const placeholders = targetSubjectIds.map(() => '?').join(', ');
    const rows = await teacherTemplateHelpers.listTeacherTemplateTargetSubjects(
      getTeacherTemplateStore(),
      userId,
      targetSubjectIds
    );
    const targetMap = new Map();
    (rows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const courseId = Number(row.course_id);
      if (!Number.isInteger(subjectId) || subjectId < 1 || !Number.isInteger(courseId) || courseId < 1) {
        return;
      }
      if (!targetMap.has(subjectId)) {
        targetMap.set(subjectId, {
          subject_id: subjectId,
          course_id: courseId,
          subject_name: row.subject_name ? String(row.subject_name) : '',
          course_name: row.course_name ? String(row.course_name) : '',
        });
      }
    });
    if (!targetMap.size) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Invalid subject selection',
      }));
    }

    const sourceTitle = String(sourceTemplate.title || '').trim();
    const sourceDescription = String(sourceTemplate.description || '').trim();
    const sourceLinkUrl = sourceTemplate.link_url ? String(sourceTemplate.link_url) : null;
    const sourceMeetingUrl = sourceTemplate.meeting_url ? String(sourceTemplate.meeting_url) : null;
    const sourceTags = sourceTemplate.tags ? String(sourceTemplate.tags) : '';
    const sourceIsControl = sourceTemplate.is_control === true || Number(sourceTemplate.is_control) === 1 ? 1 : 0;
    const sourceIsCredit = sourceTemplate.is_credit === true || Number(sourceTemplate.is_credit) === 1 ? 1 : 0;

    let createdCount = 0;
    let duplicateCount = 0;
    for (const target of targetMap.values()) {
      const duplicate = await db.get(
        `
          SELECT id
          FROM teacher_homework_templates
          WHERE user_id = ?
            AND subject_id = ?
            AND COALESCE(course_id, 0) = COALESCE(?, 0)
            AND LOWER(title) = LOWER(?)
            AND COALESCE(description, '') = COALESCE(?, '')
          LIMIT 1
        `,
        [
          userId,
          Number(target.subject_id),
          Number(target.course_id),
          sourceTitle,
          sourceDescription,
        ]
      );
      if (duplicate) {
        duplicateCount += 1;
        continue;
      }

      const inserted = await db.get(
        `
          INSERT INTO teacher_homework_templates
            (user_id, course_id, subject_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
          RETURNING id
        `,
        [
          userId,
          Number(target.course_id),
          Number(target.subject_id),
          sourceTitle,
          sourceDescription,
          sourceLinkUrl,
          sourceMeetingUrl,
          sourceTags,
          sourceIsControl,
          sourceIsCredit,
        ]
      );
      if (inserted && inserted.id) {
        await db.run(
          `
            INSERT INTO teacher_template_asset_map (template_id, asset_id, sort_order, created_at)
            SELECT ?, asset_id, sort_order, NOW()
            FROM teacher_template_asset_map
            WHERE template_id = ?
          `,
          [Number(inserted.id), templateId]
        ).catch((err) => {
          if (!isDbSchemaCompatibilityError(err)) throw err;
        });
        createdCount += 1;
      }
    }

    const invalidCount = Math.max(0, Number(targetSubjectIds.length) - Number(targetMap.size));
    logAction(db, req, 'teacher_homework_template_clone', {
      source_template_id: templateId,
      source_subject_id: sourceTemplate.subject_id ? Number(sourceTemplate.subject_id) : null,
      source_course_id: sourceTemplate.course_id ? Number(sourceTemplate.course_id) : null,
      created_count: createdCount,
      duplicate_count: duplicateCount,
      invalid_count: invalidCount,
      target_subject_ids: Array.from(targetMap.keys()),
    });

    const suffixes = [];
    if (duplicateCount > 0) {
      suffixes.push(`${duplicateCount} duplicates skipped`);
    }
    if (invalidCount > 0) {
      suffixes.push(`${invalidCount} invalid selections skipped`);
    }
    const baseMessage = createdCount > 0
      ? `Template cloned to ${createdCount} subject${createdCount === 1 ? '' : 's'}`
      : 'No templates were cloned';
    const fullMessage = suffixes.length ? `${baseMessage} (${suffixes.join(', ')})` : baseMessage;
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      courseId: redirectState.courseId || parsePositiveIntStrict(sourceTemplate.course_id),
      ok: fullMessage,
    }));
  } catch (err) {
    console.error('Teacher workspace template clone failed', err);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

app.post('/teacher/workspace/templates/bulk-clone', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.bulkClone.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const contextCourseId = Number(req.body.course_id_context);
  const redirectState = await hydrateTeacherWorkspaceRedirectState(
    getTeacherWorkspaceRedirectState(req.body, contextCourseId)
  );
  const rawSourceTemplateIds = req.body.source_template_ids;
  const sourceTemplateIds = Array.from(
    new Set(
      (Array.isArray(rawSourceTemplateIds) ? rawSourceTemplateIds : [rawSourceTemplateIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 120);
  const rawTargetSubjectIds = req.body.target_subject_ids;
  const targetSubjectIds = Array.from(
    new Set(
      (Array.isArray(rawTargetSubjectIds) ? rawTargetSubjectIds : [rawTargetSubjectIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 240);

  if (!sourceTemplateIds.length || !targetSubjectIds.length) {
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Select templates and subjects for bulk clone',
    }));
  }

  try {
    const sourcePlaceholders = sourceTemplateIds.map(() => '?').join(', ');
    const sourceRows = await db.all(
      `
        SELECT
          id,
          user_id,
          course_id,
          subject_id,
          title,
          description,
          link_url,
          meeting_url,
          tags,
          is_control,
          is_credit
        FROM teacher_homework_templates
        WHERE user_id = ?
          AND id IN (${sourcePlaceholders})
        ORDER BY updated_at DESC, id DESC
      `,
      [userId, ...sourceTemplateIds]
    );
    if (!sourceRows.length) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'No source templates found',
      }));
    }

    const targetRows = await teacherTemplateHelpers.listTeacherTemplateTargetSubjects(
      getTeacherTemplateStore(),
      userId,
      targetSubjectIds
    );
    const targetMap = new Map();
    (targetRows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const courseId = Number(row.course_id);
      if (!Number.isInteger(subjectId) || subjectId < 1 || !Number.isInteger(courseId) || courseId < 1) {
        return;
      }
      if (!targetMap.has(subjectId)) {
        targetMap.set(subjectId, {
          subject_id: subjectId,
          course_id: courseId,
          subject_name: row.subject_name ? String(row.subject_name) : '',
          course_name: row.course_name ? String(row.course_name) : '',
        });
      }
    });
    if (!targetMap.size) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: 'Invalid target subjects',
      }));
    }

    let createdCount = 0;
    let duplicateCount = 0;
    for (const source of sourceRows) {
      const sourceTitle = String(source.title || '').trim();
      const sourceDescription = String(source.description || '').trim();
      const sourceLinkUrl = source.link_url ? String(source.link_url) : null;
      const sourceMeetingUrl = source.meeting_url ? String(source.meeting_url) : null;
      const sourceTags = source.tags ? String(source.tags) : '';
      const sourceIsControl = source.is_control === true || Number(source.is_control) === 1 ? 1 : 0;
      const sourceIsCredit = source.is_credit === true || Number(source.is_credit) === 1 ? 1 : 0;

      for (const target of targetMap.values()) {
        const duplicate = await db.get(
          `
            SELECT id
            FROM teacher_homework_templates
            WHERE user_id = ?
              AND subject_id = ?
              AND COALESCE(course_id, 0) = COALESCE(?, 0)
              AND LOWER(title) = LOWER(?)
              AND COALESCE(description, '') = COALESCE(?, '')
            LIMIT 1
          `,
          [
            userId,
            Number(target.subject_id),
            Number(target.course_id),
            sourceTitle,
            sourceDescription,
          ]
        );
        if (duplicate) {
          duplicateCount += 1;
          continue;
        }

        const inserted = await db.get(
          `
            INSERT INTO teacher_homework_templates
              (user_id, course_id, subject_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
            RETURNING id
          `,
          [
            userId,
            Number(target.course_id),
            Number(target.subject_id),
            sourceTitle,
            sourceDescription,
            sourceLinkUrl,
            sourceMeetingUrl,
            sourceTags,
            sourceIsControl,
            sourceIsCredit,
          ]
        );
        if (inserted && inserted.id) {
          await db.run(
            `
              INSERT INTO teacher_template_asset_map (template_id, asset_id, sort_order, created_at)
              SELECT ?, asset_id, sort_order, NOW()
              FROM teacher_template_asset_map
              WHERE template_id = ?
            `,
            [Number(inserted.id), Number(source.id)]
          ).catch((err) => {
            if (!isDbSchemaCompatibilityError(err)) throw err;
          });
          createdCount += 1;
        }
      }
    }

    const invalidSourceCount = Math.max(0, sourceTemplateIds.length - sourceRows.length);
    const invalidTargetCount = Math.max(0, targetSubjectIds.length - targetMap.size);
    logAction(db, req, 'teacher_homework_template_bulk_clone', {
      source_template_ids: sourceRows.map((row) => Number(row.id)).filter((value) => Number.isInteger(value) && value > 0),
      target_subject_ids: Array.from(targetMap.keys()),
      source_count: sourceRows.length,
      target_count: targetMap.size,
      created_count: createdCount,
      duplicate_count: duplicateCount,
      invalid_source_count: invalidSourceCount,
      invalid_target_count: invalidTargetCount,
    });

    const suffixes = [];
    if (duplicateCount > 0) {
      suffixes.push(`${duplicateCount} duplicates skipped`);
    }
    if (invalidSourceCount > 0) {
      suffixes.push(`${invalidSourceCount} missing sources skipped`);
    }
    if (invalidTargetCount > 0) {
      suffixes.push(`${invalidTargetCount} invalid targets skipped`);
    }
    const baseMessage = createdCount > 0
      ? `Bulk clone created ${createdCount} template copies`
      : 'Bulk clone created no new templates';
    const scopeMessage = ` from ${sourceRows.length} source template${sourceRows.length === 1 ? '' : 's'} to ${targetMap.size} subject${targetMap.size === 1 ? '' : 's'}`;
    const fullMessage = suffixes.length
      ? `${baseMessage}${scopeMessage} (${suffixes.join(', ')})`
      : `${baseMessage}${scopeMessage}`;
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      ok: fullMessage,
    }));
  } catch (err) {
    console.error('Teacher workspace template bulk clone failed', err);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

