const resolveStoredUploadAbsolutePath = (storedPath) => {
  const normalized = String(storedPath || '').trim();
  if (!normalized) return '';
  const relative = normalized.replace(/^\/+/, '');
  if (!relative) return '';
  const absolutePath = path.resolve(__dirname, relative);
  const allowedRoot = path.resolve(uploadsDir);
  if (absolutePath !== allowedRoot && !absolutePath.startsWith(`${allowedRoot}${path.sep}`)) return '';
  return absolutePath;
};

const normalizeStoredUploadPath = (storedPath) => {
  const rawValue = String(storedPath || '').trim().replace(/\\/g, '/');
  if (!rawValue) return '';
  const withLeadingSlash = rawValue.startsWith('/') ? rawValue : `/${rawValue}`;
  if (!withLeadingSlash.startsWith('/uploads/')) return '';
  return withLeadingSlash;
};

const isStaffUploadViewer = (req) => (
  hasSessionRole(req, 'admin')
  || hasSessionRole(req, 'teacher')
  || hasSessionRole(req, 'deanery')
);

async function resolveStoredUploadAccess(req, storedPath) {
  const normalizedPath = normalizeStoredUploadPath(storedPath);
  if (!normalizedPath || !req || !req.session || !req.session.user) {
    return { allowed: false, absolutePath: '' };
  }

  const absolutePath = resolveStoredUploadAbsolutePath(normalizedPath);
  if (!absolutePath || !fs.existsSync(absolutePath)) {
    return { allowed: false, absolutePath: '' };
  }

  if (hasSessionRole(req, 'admin')) {
    return { allowed: true, absolutePath };
  }

  const viewerUserId = Number(req.session.user.id || 0);
  const runtimeAudienceScope = await buildAcademicRuntimeAudienceScope(req, {
    userId: viewerUserId,
    courseId: getSessionAcademicCourseId(req),
    fallbackToLegacyCourse: true,
    routeKey: 'uploads.read',
  }).catch(() => ({
    courseTargets: [],
  }));
  const allowedCourseIds = Array.from(new Set(
    (Array.isArray(runtimeAudienceScope && runtimeAudienceScope.courseTargets) ? runtimeAudienceScope.courseTargets : [])
      .map((target) => parsePositiveIntStrict(target && target.course_id))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));
  const allowedCourseIdSet = new Set(allowedCourseIds);
  const allowedCourseIdsSql = allowedCourseIds.length ? allowedCourseIds : [0];
  const nowIso = new Date().toISOString();
  const nowMs = Date.now();
  const isVisibleHomeworkRow = (row) => {
    const status = String(row && row.status ? row.status : 'published').trim().toLowerCase();
    if (status !== 'published') return false;
    const scheduledAt = String(row && row.scheduled_at ? row.scheduled_at : '').trim();
    if (!scheduledAt) return true;
    const scheduledAtMs = new Date(scheduledAt).getTime();
    if (!Number.isFinite(scheduledAtMs)) return false;
    return scheduledAtMs <= nowMs;
  };

  const [assetRow, homeworkRow, submissionRow, materialRow, journalExportRow] = await Promise.all([
    db.get(
      `
        SELECT
          a.id,
          a.user_id,
          a.course_id,
          EXISTS (
            SELECT 1
            FROM homework_asset_map ham
            JOIN homework h ON h.id = ham.homework_id
            WHERE ham.asset_id = a.id
              AND h.course_id = ANY(?::int[])
              AND COALESCE(h.status, 'published') = 'published'
              AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}
          ) AS linked_visible_homework_in_course
        FROM assets a
        WHERE a.file_path = ?
        LIMIT 1
      `,
      [allowedCourseIdsSql, nowIso, normalizedPath]
    ),
    db.get(
      `
        SELECT id, course_id, status, scheduled_at
        FROM homework
        WHERE file_path = ?
        LIMIT 1
      `,
      [normalizedPath]
    ),
    db.get(
      `
        SELECT hs.id, hs.student_id, h.course_id
        FROM homework_submissions hs
        JOIN homework h ON h.id = hs.homework_id
        WHERE hs.file_path = ?
        LIMIT 1
      `,
      [normalizedPath]
    ),
    db.get(
      `
        SELECT id, course_id
        FROM subject_materials
        WHERE file_path = ?
        LIMIT 1
      `,
      [normalizedPath]
    ),
    db.get(
      `
        SELECT j.id, COALESCE(j.course_id, s.course_id) AS course_id
        FROM journal_subject_close_events j
        LEFT JOIN subjects s ON s.id = j.subject_id
        WHERE j.export_file_path = ?
        LIMIT 1
      `,
      [normalizedPath]
    ),
  ]);

  if (assetRow) {
    const assetOwnerId = Number(assetRow.user_id || 0);
    const assetCourseId = Number(assetRow.course_id || 0);
    const linkedHomeworkInCourse = Number(assetRow.linked_visible_homework_in_course || 0) === 1;
    if (assetOwnerId > 0 && assetOwnerId === viewerUserId) {
      return { allowed: true, absolutePath };
    }
    if (linkedHomeworkInCourse) {
      return { allowed: true, absolutePath };
    }
    if (isStaffUploadViewer(req) && assetCourseId > 0 && allowedCourseIdSet.has(assetCourseId)) {
      return { allowed: true, absolutePath };
    }
    return { allowed: false, absolutePath };
  }

  if (homeworkRow) {
    const homeworkCourseId = Number(homeworkRow.course_id || 0);
    if (
      homeworkCourseId > 0
      && allowedCourseIdSet.has(homeworkCourseId)
      && (isStaffUploadViewer(req) || isVisibleHomeworkRow(homeworkRow))
    ) {
      return { allowed: true, absolutePath };
    }
    return { allowed: false, absolutePath };
  }

  if (submissionRow) {
    const submissionStudentId = Number(submissionRow.student_id || 0);
    const submissionCourseId = Number(submissionRow.course_id || 0);
    if (submissionStudentId > 0 && submissionStudentId === viewerUserId) {
      return { allowed: true, absolutePath };
    }
    if (isStaffUploadViewer(req) && submissionCourseId > 0 && allowedCourseIdSet.has(submissionCourseId)) {
      return { allowed: true, absolutePath };
    }
    return { allowed: false, absolutePath };
  }

  if (materialRow) {
    const materialCourseId = Number(materialRow.course_id || 0);
    if (materialCourseId > 0 && allowedCourseIdSet.has(materialCourseId)) {
      return { allowed: true, absolutePath };
    }
    return { allowed: false, absolutePath };
  }

  if (journalExportRow) {
    const exportCourseId = Number(journalExportRow.course_id || 0);
    if (isStaffUploadViewer(req) && exportCourseId > 0 && allowedCourseIdSet.has(exportCourseId)) {
      return { allowed: true, absolutePath };
    }
    return { allowed: false, absolutePath };
  }

  return { allowed: false, absolutePath };
}

app.get(/^\/uploads\/(.+)$/, requireLogin, async (req, res) => {
  const requestedPath = normalizeStoredUploadPath(`/uploads/${String(req.params[0] || '')}`);
  if (!requestedPath) {
    return res.status(400).send('Invalid upload path');
  }
  try {
    await ensureDbReady();
    const access = await resolveStoredUploadAccess(req, requestedPath);
    if (!access.allowed || !access.absolutePath) {
      return res.status(403).send('Forbidden (upload access)');
    }
    const absolutePath = access.absolutePath;
    const extension = path.extname(absolutePath).toLowerCase();
    res.setHeader('Cache-Control', 'private, max-age=0, must-revalidate');
    res.setHeader('Cross-Origin-Resource-Policy', 'same-origin');
    res.setHeader('X-Content-Type-Options', 'nosniff');
    if (DANGEROUS_UPLOAD_EXTENSIONS.has(extension)) {
      res.setHeader('Content-Disposition', `attachment; filename="${path.basename(absolutePath).replace(/"/g, '')}"`);
      res.setHeader('Content-Security-Policy', "default-src 'none'; sandbox");
    }
    return res.sendFile(absolutePath);
  } catch (err) {
    return handleDbError(res, err, 'uploads.read');
  }
});

const getAttendanceClassOptions = () => (
  Object.entries(bellSchedule)
    .map(([classNumber, slot]) => ({
      value: Number(classNumber),
      start: slot.start || '',
      end: slot.end || '',
      label: `Пара ${classNumber}${slot.start && slot.end ? ` (${slot.start}-${slot.end})` : ''}`,
    }))
    .sort((a, b) => a.value - b.value)
);

const parseBellTimeToMinutes = (rawValue) => {
  const value = String(rawValue || '').trim();
  const match = value.match(/^(\d{2}):(\d{2})$/);
  if (!match) return null;
  const hours = Number(match[1]);
  const minutes = Number(match[2]);
  if (!Number.isFinite(hours) || !Number.isFinite(minutes)) return null;
  if (hours < 0 || hours > 23 || minutes < 0 || minutes > 59) return null;
  return hours * 60 + minutes;
};

async function resolveJournalCurrentAttendanceSlot({
  subjectId,
  courseId,
  semesterId,
  semester = null,
  allowedGroupNumbers = [],
  hasAllGroups = false,
}) {
  const response = {
    available: false,
    class_date: formatLocalDate(new Date()),
    class_number: null,
    day_of_week: null,
    start: '',
    end: '',
    label: '',
    group_numbers: [],
  };
  if (!Number.isFinite(Number(subjectId)) || !Number.isFinite(Number(courseId))) {
    return response;
  }
  const now = new Date();
  const classDate = formatLocalDate(now);
  response.class_date = classDate;
  const dayName = getDayNameFromDate(classDate);
  response.day_of_week = dayName;
  if (!dayName) return response;
  const weekNumber = getAcademicWeekForSemester(
    new Date(`${classDate}T12:00:00`),
    semester || null
  );
  const semesterFilter = buildExactSemesterCondition('se', semesterId);
  const normalizedGroups = Array.isArray(allowedGroupNumbers)
    ? allowedGroupNumbers
      .map((value) => Number(value))
      .filter((value) => Number.isInteger(value) && value > 0)
    : [];
  const uniqueGroups = Array.from(new Set(normalizedGroups));
  const applyGroupFilter = !hasAllGroups && uniqueGroups.length > 0;
  const groupFilter = applyGroupFilter
    ? ` AND se.group_number IN (${uniqueGroups.map(() => '?').join(',')})`
    : '';
  const groupFilterParams = applyGroupFilter ? uniqueGroups : [];
  const rows = await db.all(
    `
      SELECT se.class_number, se.group_number
      FROM schedule_entries se
      WHERE se.subject_id = ?
        AND se.course_id = ?
        AND se.day_of_week = ?
        AND se.week_number = ?
        ${semesterFilter.clause}
        ${groupFilter}
      ORDER BY se.class_number ASC
    `,
    [Number(subjectId), Number(courseId), dayName, Number(weekNumber), ...semesterFilter.params, ...groupFilterParams]
  );
  if (!rows || !rows.length) return response;

  const nowMinutes = now.getHours() * 60 + now.getMinutes();
  const byClass = new Map();
  (rows || []).forEach((row) => {
    const classNumber = Number(row.class_number || 0);
    if (!Number.isInteger(classNumber) || classNumber < 1 || !bellSchedule[classNumber]) return;
    if (!byClass.has(classNumber)) {
      byClass.set(classNumber, new Set());
    }
    const groupNumber = Number(row.group_number || 0);
    if (Number.isInteger(groupNumber) && groupNumber > 0) {
      byClass.get(classNumber).add(groupNumber);
    }
  });

  const orderedClasses = Array.from(byClass.keys()).sort((a, b) => a - b);
  for (const classNumber of orderedClasses) {
    const slot = bellSchedule[classNumber];
    if (!slot) continue;
    const startMinutes = parseBellTimeToMinutes(slot.start);
    const endMinutes = parseBellTimeToMinutes(slot.end);
    if (!Number.isFinite(startMinutes) || !Number.isFinite(endMinutes)) continue;
    if (nowMinutes < startMinutes || nowMinutes > endMinutes) continue;
    const groups = Array.from(byClass.get(classNumber) || []).sort((a, b) => a - b);
    const groupLabel = groups.length ? ` · Група ${groups.join(', ')}` : '';
    return {
      available: true,
      class_date: classDate,
      class_number: classNumber,
      day_of_week: dayName,
      start: slot.start || '',
      end: slot.end || '',
      label: `Пара ${classNumber}${slot.start && slot.end ? ` (${slot.start}-${slot.end})` : ''}${groupLabel}`,
      group_numbers: groups,
    };
  }
  return response;
}

const normalizeBatchToken = (rawValue) => String(rawValue || '').trim().toLowerCase();

const buildHomeworkBatchKey = (row) => {
  const parts = [
    Number(row?.created_by_id || row?.created_by || 0),
    String(row?.created_at || ''),
    Number(row?.subject_id || 0),
    Number(row?.course_id || 0),
    Number(row?.semester_id || 0),
    Number(row?.is_custom_deadline || 0),
    Number(row?.is_credit || 0),
    Number(row?.is_control || 0),
    normalizeBatchToken(row?.description),
    String(row?.custom_due_date || row?.class_date || ''),
    normalizeBatchToken(row?.day_of_week),
    Number(row?.class_number || 0),
    normalizeBatchToken(row?.meeting_url),
    normalizeBatchToken(row?.link_url),
    normalizeBatchToken(row?.file_path),
  ];
  return parts.join('|');
};

const buildHomeworkBatchKeyFromColumnRow = (row) => {
  return buildHomeworkBatchKey({
    created_by_id: row?.homework_created_by_id,
    created_by: row?.homework_created_by,
    created_at: row?.homework_created_at,
    subject_id: row?.subject_id,
    course_id: row?.course_id,
    semester_id: row?.semester_id,
    is_custom_deadline: row?.homework_is_custom_deadline,
    is_credit: row?.homework_is_credit,
    is_control: row?.homework_is_control,
    description: row?.homework_description,
    custom_due_date: row?.custom_due_date || row?.homework_custom_due_date,
    class_date: row?.class_date || row?.homework_class_date,
    day_of_week: row?.homework_day_of_week,
    class_number: row?.homework_class_number,
    meeting_url: row?.homework_meeting_url,
    link_url: row?.homework_link_url,
    file_path: row?.homework_file_path,
  });
};

const dedupeTeacherHomeworkItems = (items) => {
  const deduped = [];
  const byBatchKey = new Map();
  (Array.isArray(items) ? items : []).forEach((item) => {
    const isTeacherHomework = Number(item?.is_teacher_homework || 0) === 1;
    if (!isTeacherHomework) {
      deduped.push(item);
      return;
    }
    const batchKey = buildHomeworkBatchKey(item);
    if (!byBatchKey.has(batchKey)) {
      const groupNumbers = Number.isInteger(Number(item.group_number)) ? [Number(item.group_number)] : [];
      const next = {
        ...item,
        group_numbers: groupNumbers,
      };
      byBatchKey.set(batchKey, next);
      deduped.push(next);
      return;
    }
    const target = byBatchKey.get(batchKey);
    const groupNumber = Number(item.group_number);
    if (Number.isInteger(groupNumber) && groupNumber > 0) {
      const set = new Set([...(target.group_numbers || []), groupNumber]);
      target.group_numbers = Array.from(set).sort((a, b) => a - b);
      target.group_number = target.group_numbers[0] || target.group_number;
    }
  });
  return deduped;
};

const selectPreferredHomeworkBatchRow = (currentRow, candidateRow, existingByHomeworkId = new Map()) => {
  if (!currentRow) return candidateRow;
  if (!candidateRow) return currentRow;
  const currentColumn = existingByHomeworkId.get(Number(currentRow.id));
  const candidateColumn = existingByHomeworkId.get(Number(candidateRow.id));
  if (currentColumn && !candidateColumn) return currentRow;
  if (candidateColumn && !currentColumn) return candidateRow;
  if (currentColumn && candidateColumn) {
    const currentGrades = Number(currentColumn.grades_count || 0);
    const candidateGrades = Number(candidateColumn.grades_count || 0);
    if (candidateGrades > currentGrades) return candidateRow;
    if (currentGrades > candidateGrades) return currentRow;
  }
  return Number(candidateRow.id || 0) < Number(currentRow.id || 0) ? candidateRow : currentRow;
};

const buildTeacherHomeworkBatchLookup = (rows = []) => {
  const byBatchGroup = new Map();
  const byHomeworkId = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const homeworkId = Number(row?.id || 0);
    if (!Number.isFinite(homeworkId) || homeworkId < 1) return;
    const groupNumber = Number(row?.group_number || 0);
    const batchKey = Number(row?.is_teacher_homework || 0) === 1 ? buildHomeworkBatchKey(row) : '';
    const item = {
      id: homeworkId,
      group_number: Number.isInteger(groupNumber) && groupNumber > 0 ? groupNumber : null,
      batch_key: batchKey,
      custom_due_date: toDateOnly(row?.custom_due_date),
      class_date: toDateOnly(row?.class_date),
    };
    byHomeworkId.set(homeworkId, item);
    if (batchKey && item.group_number) {
      byBatchGroup.set(`${batchKey}|${item.group_number}`, item);
    }
  });
  return {
    byHomeworkId,
    byBatchGroup,
  };
};

const parsePositiveDecimal = (rawValue, fallbackValue) => {
  if (rawValue === null || typeof rawValue === 'undefined' || rawValue === '') return fallbackValue;
  const normalized = Number(String(rawValue).replace(',', '.'));
  if (!Number.isFinite(normalized) || normalized <= 0) return fallbackValue;
  return Math.round(normalized * 100) / 100;
};

const parseNonNegativeDecimal = (rawValue, fallbackValue) => {
  if (rawValue === null || typeof rawValue === 'undefined' || rawValue === '') return fallbackValue;
  const normalized = Number(String(rawValue).replace(',', '.'));
  if (!Number.isFinite(normalized) || normalized < 0) return fallbackValue;
  return Math.round(normalized * 100) / 100;
};

const parseBinaryFlag = (rawValue, fallbackValue = 0) => {
  const candidateValue = Array.isArray(rawValue)
    ? rawValue[rawValue.length - 1]
    : rawValue;
  if (candidateValue === null || typeof candidateValue === 'undefined' || candidateValue === '') {
    return Number(fallbackValue) === 1 ? 1 : 0;
  }
  const normalized = String(candidateValue).trim().toLowerCase();
  if (['1', 'true', 'on', 'yes'].includes(normalized)) return 1;
  if (['0', 'false', 'off', 'no'].includes(normalized)) return 0;
  return Number(fallbackValue) === 1 ? 1 : 0;
};

const normalizeColumnType = (rawValue) => {
  const normalized = String(rawValue || '').trim().toLowerCase();
  return JOURNAL_COLUMN_TYPES.has(normalized) ? normalized : 'custom';
};

const getGradingTypeEnabled = (gradingSettings, columnType) => {
  const safeType = normalizeColumnType(columnType);
  const field = `${safeType}_enabled`;
  const fallback = Number(DEFAULT_SUBJECT_GRADING_SETTINGS[field] || 0);
  return parseBinaryFlag(gradingSettings?.[field], fallback) === 1;
};

const getGradingTypeWeightPoints = (gradingSettings, columnType) => {
  const safeType = normalizeColumnType(columnType);
  const field = `${safeType}_weight_points`;
  const fallback = Number(DEFAULT_SUBJECT_GRADING_SETTINGS[field] || 0);
  return parseNonNegativeDecimal(gradingSettings?.[field], fallback);
};

const getDefaultMaxPointsByType = (gradingSettings, columnType) => {
  const safeSettings = {
    ...DEFAULT_SUBJECT_GRADING_SETTINGS,
    ...(gradingSettings || {}),
  };
  if (columnType === 'homework') return Number(safeSettings.homework_max_points || 10);
  if (columnType === 'seminar') return Number(safeSettings.seminar_max_points || 10);
  if (columnType === 'exam') return Number(safeSettings.exam_max_points || 40);
  if (columnType === 'credit') return Number(safeSettings.credit_max_points || 20);
  return Number(safeSettings.custom_max_points || 10);
};

const isJournalModerationRequiredColumn = (column) => {
  const type = normalizeColumnType(column?.column_type);
  if (type === 'exam' || type === 'credit') return true;
  return Number(column?.is_credit || 0) === 1;
};

const resolveEffectiveGradeScore = (grade, moderation) => {
  const originalScore = Number(grade?.score);
  const moderatedScore = Number(moderation?.moderated_score);
  const moderationStatus = normalizeJournalModerationStatus(moderation?.status);
  if (moderationStatus === 'adjusted' && Number.isFinite(moderatedScore)) {
    return moderatedScore;
  }
  return Number.isFinite(originalScore) ? originalScore : null;
};

async function upsertJournalModerationPending({
  column,
  studentId,
  score,
  actorUserId,
}) {
  if (!isJournalModerationRequiredColumn(column)) return;
  const safeScore = Number(score);
  if (!Number.isFinite(safeScore)) return;
  await db.run(
    `
      INSERT INTO journal_grade_moderations
      (
        subject_id,
        course_id,
        semester_id,
        column_id,
        student_id,
        status,
        original_score,
        moderated_score,
        moderation_comment,
        created_by,
        created_at,
        reviewed_by,
        reviewed_at,
        updated_at
      )
      VALUES (?, ?, ?, ?, ?, 'pending', ?, NULL, NULL, ?, NOW(), NULL, NULL, NOW())
      ON CONFLICT (column_id, student_id)
      DO UPDATE SET
        status = 'pending',
        original_score = EXCLUDED.original_score,
        moderated_score = NULL,
        moderation_comment = NULL,
        reviewed_by = NULL,
        reviewed_at = NULL,
        updated_at = NOW()
    `,
    [
      Number(column.subject_id || 0),
      Number(column.course_id || 0) || null,
      column.semester_id ? Number(column.semester_id) : null,
      Number(column.id || 0),
      Number(studentId || 0),
      safeScore,
      Number(actorUserId || 0) || null,
    ]
  );
}

const buildCompetencyProfileFromSignalRows = ({
  signalRows = [],
  includeEmpty = true,
  now = new Date(),
}) => {
  const safeRows = Array.isArray(signalRows) ? signalRows : [];
  const nowMs = now.getTime();
  const recentSince = nowMs - (30 * 24 * 60 * 60 * 1000);
  const previousSince = nowMs - (60 * 24 * 60 * 60 * 1000);

  const marksByKey = new Map();
  COMPETENCY_DEFINITIONS.forEach((item) => {
    marksByKey.set(item.key, {
      total: 0,
      recent: 0,
      previous: 0,
      manual_total: 0,
      auto_total: 0,
    });
  });

  safeRows.forEach((row) => {
    const key = normalizeCompetencyKey(row?.competency_key);
    if (!key || !marksByKey.has(key)) return;
    const score = Number(row?.score);
    if (!Number.isFinite(score)) return;
    const mark = score > 0 ? 1 : 0;
    if (mark < 1) return;
    const sourceType = String(row?.source_type || 'manual').trim().toLowerCase() || 'manual';
    const isAutoSource = sourceType.startsWith('auto_');
    const createdAtMs = row?.created_at ? new Date(row.created_at).getTime() : Number.NaN;
    const bucket = marksByKey.get(key);
    bucket.total += 1;
    if (isAutoSource) {
      bucket.auto_total += 1;
    } else {
      bucket.manual_total += 1;
    }
    if (Number.isFinite(createdAtMs) && createdAtMs >= recentSince) {
      bucket.recent += 1;
    } else if (Number.isFinite(createdAtMs) && createdAtMs >= previousSince && createdAtMs < recentSince) {
      bucket.previous += 1;
    }
  });

  const competencies = COMPETENCY_DEFINITIONS.map((definition) => {
    const bucket = marksByKey.get(definition.key) || { total: 0, recent: 0, previous: 0 };
    const count = Number(bucket.total || 0);
    const delta = Number(bucket.recent || 0) - Number(bucket.previous || 0);
    const manualCount = Number(bucket.manual_total || 0);
    const autoCount = Number(bucket.auto_total || 0);
    return {
      key: definition.key,
      label: definition.label,
      count,
      manual_count: manualCount,
      auto_count: autoCount,
      score: count,
      share_percent: 0,
      bar_percent: 0,
      delta: Math.round(delta),
      trend: delta >= 1 ? 'up' : (delta <= -1 ? 'down' : 'steady'),
      has_data: count > 0,
    };
  }).filter((item) => includeEmpty || item.has_data);

  const totalMarks = competencies.reduce((sum, item) => sum + Number(item.count || 0), 0);
  const manualTotalMarks = competencies.reduce((sum, item) => sum + Number(item.manual_count || 0), 0);
  const autoTotalMarks = competencies.reduce((sum, item) => sum + Number(item.auto_count || 0), 0);
  const equalShare = competencies.length ? (100 / competencies.length) : 0;
  competencies.forEach((item) => {
    const share = totalMarks > 0
      ? (Number(item.count || 0) / totalMarks) * 100
      : equalShare;
    item.share_percent = Math.round(share * 100) / 100;
    item.bar_percent = totalMarks > 0 ? item.share_percent : 0;
  });

  const withData = competencies.filter((item) => item.has_data);
  const sortedByScore = [...competencies].sort((a, b) => {
    if (Number(b.count || 0) !== Number(a.count || 0)) return Number(b.count || 0) - Number(a.count || 0);
    if (Number(b.delta || 0) !== Number(a.delta || 0)) return Number(b.delta || 0) - Number(a.delta || 0);
    return String(a.label || '').localeCompare(String(b.label || ''));
  });
  const sortedByWeakest = [...competencies].sort((a, b) => {
    if (Number(a.count || 0) !== Number(b.count || 0)) return Number(a.count || 0) - Number(b.count || 0);
    if (Number(a.delta || 0) !== Number(b.delta || 0)) return Number(a.delta || 0) - Number(b.delta || 0);
    return String(a.label || '').localeCompare(String(b.label || ''));
  });
  const sortedByDelta = [...withData].sort((a, b) => b.delta - a.delta);
  const strongest = totalMarks > 0 ? (sortedByScore[0] || null) : null;
  const weakest = totalMarks > 0 ? (sortedByWeakest[0] || null) : null;
  const fastestGrowth = sortedByDelta.length && Number(sortedByDelta[0].delta || 0) > 0
    ? sortedByDelta[0]
    : null;
  const average = competencies.length
    ? Math.round(totalMarks / competencies.length)
    : 0;

  return {
    competencies: competencies.map((item) => ({
      key: item.key,
      label: item.label,
      count: Math.max(0, Math.floor(Number(item.count || 0))),
      manual_count: Math.max(0, Math.floor(Number(item.manual_count || 0))),
      auto_count: Math.max(0, Math.floor(Number(item.auto_count || 0))),
      score: Math.max(0, Math.floor(Number(item.score || 0))),
      share_percent: Math.max(0, Math.min(100, Number(item.share_percent || 0))),
      bar_percent: Math.max(0, Math.min(100, Number(item.bar_percent || 0))),
      delta: Number(item.delta || 0),
      trend: item.trend || 'steady',
      has_data: Boolean(item.has_data),
    })),
    strongest,
    weakest,
    fastest_growth: fastestGrowth,
    average,
    total_marks: Math.max(0, Math.floor(totalMarks)),
    manual_total_marks: Math.max(0, Math.floor(manualTotalMarks)),
    auto_total_marks: Math.max(0, Math.floor(autoTotalMarks)),
    has_marks: totalMarks > 0,
    populated_count: withData.length,
  };
};

const buildHomeworkJournalTitle = (homeworkRow) => {
  const base = String(homeworkRow?.description || 'Завдання')
    .replace(/\s+/g, ' ')
    .trim();
  const shortBase = base.length > 78 ? `${base.slice(0, 75)}...` : base;
  const dueDate = toDateOnly(homeworkRow?.custom_due_date || homeworkRow?.class_date);
  return dueDate ? `${shortBase} (${dueDate})` : shortBase;
};

const SESSION_HOMEWORK_PREFIX = '[сесія]';
const SESSION_HOMEWORK_CONSULTATION_PREFIX = '[сесія] консультація';
const SESSION_COLUMN_POSITION_BASE = 900000;
const isSessionHomeworkRow = (row) => {
  const text = String(row?.description || row?.homework_description || row?.source_homework_description || '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
  return text.startsWith(SESSION_HOMEWORK_PREFIX);
};
const isSessionConsultationHomeworkRow = (row) => {
  const text = String(row?.description || row?.homework_description || row?.source_homework_description || '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
  return text.startsWith(SESSION_HOMEWORK_CONSULTATION_PREFIX);
};

const resolveHomeworkSubmissionStatus = (homeworkRow, submissionRow) => {
  if (!submissionRow) return 'missing';
  const dueDate = toDateOnly(homeworkRow?.custom_due_date || homeworkRow?.class_date);
  if (!dueDate) return 'manual';
  const submittedDate = toDateOnly(submissionRow.submitted_at);
  if (!submittedDate) return 'manual';
  return submittedDate <= dueDate ? 'on_time' : 'late';
};

const isJournalColumnLocked = (column) => Number(column?.is_locked || 0) === 1;

const canUseTeacherJournalMode = (req, journalScope) => {
  const roles = getSessionRoleList(req);
  const hasTeacherContext = roles.some((roleKey) => ['teacher', 'deanery', 'admin'].includes(roleKey));
  return Boolean(
    journalScope?.fullAccess
    || (hasTeacherContext && journalScope?.permissionKeys && journalScope.permissionKeys.has(JOURNAL_OWN_PERMISSION))
    || hasTeacherContext
  );
};

const JOURNAL_INSIGHTS_PERIOD_OPTIONS = [
  { key: 'month', label: '30 days' },
  { key: 'semester', label: 'Semester' },
  { key: 'year', label: 'Year' },
  { key: 'all', label: 'All time' },
];
const JOURNAL_INSIGHTS_PERIOD_KEYS = new Set(JOURNAL_INSIGHTS_PERIOD_OPTIONS.map((item) => item.key));

const JOURNAL_INSIGHTS_SCOPE_OPTIONS = [
  { key: 'subject', label: 'Subject' },
  { key: 'group', label: 'Group' },
  { key: 'student', label: 'Student' },
  { key: 'student-course', label: 'Student (all subjects)' },
  { key: 'course', label: 'Course' },
  { key: 'all-courses', label: 'All courses' },
];
const JOURNAL_INSIGHTS_SCOPE_KEYS = new Set(JOURNAL_INSIGHTS_SCOPE_OPTIONS.map((item) => item.key));
const JOURNAL_INSIGHTS_COMPARE_OPTIONS = [
  { key: 'none', label: 'No compare' },
  { key: 'group', label: 'Compare groups' },
  { key: 'course', label: 'Compare courses' },
];
const JOURNAL_INSIGHTS_COMPARE_KEYS = new Set(JOURNAL_INSIGHTS_COMPARE_OPTIONS.map((item) => item.key));

const normalizeJournalInsightsPeriod = (rawValue, fallback = 'semester') => {
  const normalized = String(rawValue || '').trim().toLowerCase();
  if (JOURNAL_INSIGHTS_PERIOD_KEYS.has(normalized)) {
    return normalized;
  }
  return JOURNAL_INSIGHTS_PERIOD_KEYS.has(fallback) ? fallback : 'semester';
};

const normalizeJournalInsightsScope = (rawValue, fallback = 'subject') => {
  const normalized = String(rawValue || '').trim().toLowerCase();
  if (JOURNAL_INSIGHTS_SCOPE_KEYS.has(normalized)) {
    return normalized;
  }
  return JOURNAL_INSIGHTS_SCOPE_KEYS.has(fallback) ? fallback : 'subject';
};

const normalizeJournalInsightsCompare = (rawValue, fallback = 'none') => {
  const normalized = String(rawValue || '').trim().toLowerCase();
  if (JOURNAL_INSIGHTS_COMPARE_KEYS.has(normalized)) {
    return normalized;
  }
  return JOURNAL_INSIGHTS_COMPARE_KEYS.has(fallback) ? fallback : 'none';
};

const buildJournalMixedSemesterCondition = (alias, semesterId) => {
  if (semesterId) {
    return {
      clause: `AND (${alias}.semester_id = ? OR ${alias}.semester_id IS NULL)`,
      params: [semesterId],
    };
  }
  return {
    clause: `AND ${alias}.semester_id IS NULL`,
    params: [],
  };
};

const resolveJournalInsightsSince = (periodKey, semesterStartDate = '', now = new Date()) => {
  const normalizedPeriod = normalizeJournalInsightsPeriod(periodKey, 'semester');
  if (normalizedPeriod === 'all') {
    return { period: normalizedPeriod, sinceDate: '', sinceIso: '' };
  }

  let sinceDate = '';
  if (normalizedPeriod === 'month') {
    sinceDate = formatLocalDate(addDays(now, -30));
  } else if (normalizedPeriod === 'year') {
    sinceDate = formatLocalDate(addDays(now, -365));
  } else if (isValidDateString(String(semesterStartDate || ''))) {
    sinceDate = String(semesterStartDate);
  } else {
    sinceDate = formatLocalDate(addDays(now, -180));
  }
  if (!isValidDateString(sinceDate)) {
    return { period: normalizedPeriod, sinceDate: '', sinceIso: '' };
  }
  const sinceIso = new Date(`${sinceDate}T00:00:00.000Z`).toISOString();
  return { period: normalizedPeriod, sinceDate, sinceIso };
};

const roundToPrecision = (rawValue, digits = 2) => {
  const parsed = Number(rawValue);
  if (!Number.isFinite(parsed)) return 0;
  const scale = 10 ** Math.max(0, Number(digits) || 0);
  return Math.round(parsed * scale) / scale;
};

const computeMedianScore = (values = []) => {
  const list = (Array.isArray(values) ? values : [])
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value))
    .sort((a, b) => a - b);
  if (!list.length) return 0;
  const middle = Math.floor(list.length / 2);
  if (list.length % 2 === 1) {
    return roundToPrecision(list[middle], 2);
  }
  return roundToPrecision((list[middle - 1] + list[middle]) / 2, 2);
};

const getJournalInsightsBucketMode = (periodKey) => (
  normalizeJournalInsightsPeriod(periodKey, 'semester') === 'month' ? 'day' : 'month'
);

const buildJournalInsightsGradeBucketSql = (periodKey) => (
  getJournalInsightsBucketMode(periodKey) === 'day'
    ? "TO_CHAR(DATE_TRUNC('day', jg.graded_at), 'YYYY-MM-DD')"
    : "TO_CHAR(DATE_TRUNC('month', jg.graded_at), 'YYYY-MM')"
);

const buildJournalInsightsAttendanceBucketSql = (periodKey) => (
  getJournalInsightsBucketMode(periodKey) === 'day'
    ? "TO_CHAR(DATE_TRUNC('day', ar.class_date::timestamp), 'YYYY-MM-DD')"
    : "TO_CHAR(DATE_TRUNC('month', ar.class_date::timestamp), 'YYYY-MM')"
);

const buildRankingFromRows = (rows = []) => {
  const sorted = (Array.isArray(rows) ? rows : [])
    .map((row) => ({
      ...row,
      final_score: roundToPrecision(row.final_score, 2),
    }))
    .sort((a, b) => {
      const scoreDiff = Number(b.final_score || 0) - Number(a.final_score || 0);
      if (scoreDiff !== 0) return scoreDiff;
      return String(a.full_name || '').localeCompare(String(b.full_name || ''));
    });
  return sorted.map((row, index) => ({
    ...row,
    rank: index + 1,
  }));
};

async function ensureSubjectGradingSettings(subjectId, courseId, semesterId, userId) {
  try {
    await db.run(
      `
        INSERT INTO subject_grading_settings
        (
          subject_id, course_id, semester_id,
          homework_enabled, seminar_enabled, exam_enabled, credit_enabled, custom_enabled,
          homework_max_points, seminar_max_points, exam_max_points, credit_max_points, custom_max_points,
          homework_weight_points, seminar_weight_points, exam_weight_points, credit_weight_points, custom_weight_points,
          final_max_points, created_by, updated_by, created_at, updated_at
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 100, ?, ?, NOW(), NOW())
        ON CONFLICT (subject_id) DO NOTHING
      `,
      [
        subjectId,
        courseId || null,
        semesterId || null,
        DEFAULT_SUBJECT_GRADING_SETTINGS.homework_enabled,
        DEFAULT_SUBJECT_GRADING_SETTINGS.seminar_enabled,
        DEFAULT_SUBJECT_GRADING_SETTINGS.exam_enabled,
        DEFAULT_SUBJECT_GRADING_SETTINGS.credit_enabled,
        DEFAULT_SUBJECT_GRADING_SETTINGS.custom_enabled,
        DEFAULT_SUBJECT_GRADING_SETTINGS.homework_max_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.seminar_max_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.exam_max_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.credit_max_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.custom_max_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.homework_weight_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.seminar_weight_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.exam_weight_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.credit_weight_points,
        DEFAULT_SUBJECT_GRADING_SETTINGS.custom_weight_points,
        userId || null,
        userId || null,
      ]
    );
    const row = await db.get(
      `
        SELECT *
        FROM subject_grading_settings
        WHERE subject_id = ?
        LIMIT 1
      `,
      [subjectId]
    );
    if (!row) {
      return {
        ...DEFAULT_SUBJECT_GRADING_SETTINGS,
        is_closed: 0,
        closed_by: null,
        closed_at: null,
      };
    }
    return {
      homework_enabled: parseBinaryFlag(row.homework_enabled, DEFAULT_SUBJECT_GRADING_SETTINGS.homework_enabled),
      seminar_enabled: parseBinaryFlag(row.seminar_enabled, DEFAULT_SUBJECT_GRADING_SETTINGS.seminar_enabled),
      exam_enabled: parseBinaryFlag(row.exam_enabled, DEFAULT_SUBJECT_GRADING_SETTINGS.exam_enabled),
      credit_enabled: parseBinaryFlag(row.credit_enabled, DEFAULT_SUBJECT_GRADING_SETTINGS.credit_enabled),
      custom_enabled: parseBinaryFlag(row.custom_enabled, DEFAULT_SUBJECT_GRADING_SETTINGS.custom_enabled),
      homework_max_points: parsePositiveDecimal(row.homework_max_points, DEFAULT_SUBJECT_GRADING_SETTINGS.homework_max_points),
      seminar_max_points: parsePositiveDecimal(row.seminar_max_points, DEFAULT_SUBJECT_GRADING_SETTINGS.seminar_max_points),
      exam_max_points: parsePositiveDecimal(row.exam_max_points, DEFAULT_SUBJECT_GRADING_SETTINGS.exam_max_points),
      credit_max_points: parsePositiveDecimal(row.credit_max_points, DEFAULT_SUBJECT_GRADING_SETTINGS.credit_max_points),
      custom_max_points: parsePositiveDecimal(row.custom_max_points, DEFAULT_SUBJECT_GRADING_SETTINGS.custom_max_points),
      homework_weight_points: parseNonNegativeDecimal(row.homework_weight_points, DEFAULT_SUBJECT_GRADING_SETTINGS.homework_weight_points),
      seminar_weight_points: parseNonNegativeDecimal(row.seminar_weight_points, DEFAULT_SUBJECT_GRADING_SETTINGS.seminar_weight_points),
      exam_weight_points: parseNonNegativeDecimal(row.exam_weight_points, DEFAULT_SUBJECT_GRADING_SETTINGS.exam_weight_points),
      credit_weight_points: parseNonNegativeDecimal(row.credit_weight_points, DEFAULT_SUBJECT_GRADING_SETTINGS.credit_weight_points),
      custom_weight_points: parseNonNegativeDecimal(row.custom_weight_points, DEFAULT_SUBJECT_GRADING_SETTINGS.custom_weight_points),
      final_max_points: 100,
      is_closed: parseBinaryFlag(row.is_closed, 0),
      closed_by: Number.isFinite(Number(row.closed_by)) ? Number(row.closed_by) : null,
      closed_at: row.closed_at || null,
    };
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return {
        ...DEFAULT_SUBJECT_GRADING_SETTINGS,
        is_closed: 0,
        closed_by: null,
        closed_at: null,
      };
    }
    throw err;
  }
}

async function getJournalSubjectClosureState(subjectId) {
  const safeSubjectId = Number(subjectId || 0);
  if (!Number.isFinite(safeSubjectId) || safeSubjectId < 1) {
    return {
      is_closed: false,
      closed_by: null,
      closed_at: null,
      latest_event: null,
      latest_export_name: '',
      latest_export_path: '',
    };
  }

  let settingsRow = null;
  let latestEvent = null;
  try {
    settingsRow = await db.get(
      `
        SELECT is_closed, closed_by, closed_at
        FROM subject_grading_settings
        WHERE subject_id = ?
        LIMIT 1
      `,
      [safeSubjectId]
    );
  } catch (_err) {
    settingsRow = null;
  }
  try {
    latestEvent = await db.get(
      `
        SELECT
          id,
          event_type,
          export_file_name,
          export_file_path,
          export_rows_count,
          export_columns_count,
          created_by,
          created_at,
          details
        FROM journal_subject_close_events
        WHERE subject_id = ?
        ORDER BY created_at DESC, id DESC
        LIMIT 1
      `,
      [safeSubjectId]
    );
  } catch (_err) {
    latestEvent = null;
  }

  let inferredClosedFromLocks = false;
  if (!settingsRow) {
    try {
      const lockState = await db.get(
        `
          SELECT
            COUNT(*)::int AS total_columns,
            COUNT(*) FILTER (WHERE COALESCE(is_locked, 0) = 1)::int AS locked_columns
          FROM journal_columns
          WHERE subject_id = ?
            AND COALESCE(is_archived, 0) = 0
        `,
        [safeSubjectId]
      );
      const totalColumns = Number(lockState?.total_columns || 0);
      const lockedColumns = Number(lockState?.locked_columns || 0);
      inferredClosedFromLocks = totalColumns > 0 && lockedColumns >= totalColumns;
    } catch (_err) {
      inferredClosedFromLocks = false;
    }
  }

  return {
    is_closed: Number(settingsRow?.is_closed || 0) === 1 || inferredClosedFromLocks,
    closed_by: Number.isFinite(Number(settingsRow?.closed_by)) ? Number(settingsRow.closed_by) : null,
    closed_at: settingsRow?.closed_at || latestEvent?.created_at || null,
    latest_event: latestEvent
      ? {
          id: Number(latestEvent.id),
          event_type: String(latestEvent.event_type || ''),
          export_file_name: String(latestEvent.export_file_name || ''),
          export_file_path: String(latestEvent.export_file_path || ''),
          export_rows_count: Number(latestEvent.export_rows_count || 0),
          export_columns_count: Number(latestEvent.export_columns_count || 0),
          created_by: Number.isFinite(Number(latestEvent.created_by)) ? Number(latestEvent.created_by) : null,
          created_at: latestEvent.created_at || null,
          details: latestEvent.details || null,
        }
      : null,
    latest_export_name: String(latestEvent?.export_file_name || ''),
    latest_export_path: String(latestEvent?.export_file_path || ''),
  };
}

async function getPreviousSemesterForCourse(courseId, currentSemester = null) {
  const safeCourseId = Number(courseId || 0);
  if (!Number.isFinite(safeCourseId) || safeCourseId < 1) return null;

  const currentSemesterId = Number(currentSemester?.id || 0);
  const currentSemesterStart = String(currentSemester?.start_date || '').trim();
  if (!Number.isFinite(currentSemesterId) || currentSemesterId < 1) return null;

  let row = null;
  if (currentSemesterStart) {
    row = await db.get(
      `
        SELECT id, title, start_date, weeks_count, is_active, is_archived
        FROM semesters
        WHERE course_id = ?
          AND id <> ?
          AND (start_date < ? OR (start_date = ? AND id < ?))
        ORDER BY start_date DESC, id DESC
        LIMIT 1
      `,
      [safeCourseId, currentSemesterId, currentSemesterStart, currentSemesterStart, currentSemesterId]
    );
  }

  if (!row) {
    row = await db.get(
      `
        SELECT id, title, start_date, weeks_count, is_active, is_archived
        FROM semesters
        WHERE course_id = ?
          AND id <> ?
        ORDER BY start_date DESC, id DESC
        LIMIT 1
      `,
      [safeCourseId, currentSemesterId]
    );
  }

  return row || null;
}

const formatJournalClosureCsvNumber = (rawValue) => {
  const numberValue = Number(rawValue);
  if (!Number.isFinite(numberValue)) return '';
  const rounded = Math.round(numberValue * 100) / 100;
  return rounded
    .toFixed(2)
    .replace(/\.00$/, '')
    .replace(/(\.\d)0$/, '$1');
};

function buildJournalClosureCsv({
  subjectName = '',
  courseName = '',
  semesterTitle = '',
  closedAt = new Date(),
  columns = [],
  rows = [],
}) {
  const safeColumns = Array.isArray(columns) ? columns : [];
  const safeRows = Array.isArray(rows) ? rows : [];
  const closedAtIso = closedAt instanceof Date ? closedAt.toISOString() : String(closedAt || new Date().toISOString());
  const lines = [];
  lines.push([
    'Предмет',
    String(subjectName || '').trim() || 'Предмет',
  ].map((value) => escapeCsvValue(value)).join(','));
  lines.push([
    'Курс',
    String(courseName || '').trim() || '-',
  ].map((value) => escapeCsvValue(value)).join(','));
  lines.push([
    'Семестр',
    String(semesterTitle || '').trim() || '-',
  ].map((value) => escapeCsvValue(value)).join(','));
  lines.push([
    'Закрито о',
    closedAtIso,
  ].map((value) => escapeCsvValue(value)).join(','));
  lines.push('');

  const header = [
    'ПІБ',
    'Група',
    ...safeColumns.map((column) => {
      const title = String(column?.title || '').trim() || 'Колонка';
      const maxPoints = formatJournalClosureCsvNumber(column?.max_points);
      return maxPoints ? `${title} (${maxPoints} б.)` : title;
    }),
    'Сирі бали',
    'Сирий максимум',
    'Підсумок / 100',
  ];
  lines.push(header.map((value) => escapeCsvValue(value)).join(','));

  safeRows.forEach((row) => {
    const student = row?.student || {};
    const cells = Array.isArray(row?.cells) ? row.cells : [];
    const cellValues = safeColumns.map((_column, index) => {
      const score = Number(cells[index]?.score);
      return Number.isFinite(score) ? formatJournalClosureCsvNumber(score) : '';
    });
    const line = [
      String(student.full_name || '').trim() || 'Студент',
      Number.isInteger(Number(student.group_number)) && Number(student.group_number) > 0
        ? Number(student.group_number)
        : '',
      ...cellValues,
      formatJournalClosureCsvNumber(row?.raw_earned),
      formatJournalClosureCsvNumber(row?.raw_max),
      formatJournalClosureCsvNumber(row?.final_score),
    ];
    lines.push(line.map((value) => escapeCsvValue(value)).join(','));
  });

  return {
    csv: lines.join('\n'),
    exportRowsCount: safeRows.length,
    exportColumnsCount: safeColumns.length,
  };
}

function writeJournalClosureExportFile({
  subjectId,
  courseId,
  semesterId,
  csvContent,
}) {
  const safeSubjectId = Number(subjectId || 0);
  const safeCourseId = Number(courseId || 0);
  const safeSemesterId = Number(semesterId || 0);
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const directory = path.join(uploadsDir, 'journal-closures', `subject-${safeSubjectId}`);
  fs.mkdirSync(directory, { recursive: true });
  const fileName = `journal-subject-${safeSubjectId}-c${safeCourseId}-s${safeSemesterId}-${timestamp}.csv`;
  const absolutePath = path.join(directory, fileName);
  fs.writeFileSync(absolutePath, String(csvContent || ''), 'utf8');
  const relativeToUploads = path.relative(uploadsDir, absolutePath).split(path.sep).join('/');
  return {
    fileName,
    absolutePath,
    filePath: `/uploads/${relativeToUploads}`,
  };
}

const normalizeArchiveFileSlug = (rawValue, fallback = 'item') => {
  const safeFallback = String(fallback || 'item')
    .replace(/[^a-zA-Z0-9-_]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '')
    || 'item';
  const normalized = String(rawValue || '')
    .replace(/[^a-zA-Z0-9-_]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '')
    .toLowerCase();
  return normalized || safeFallback;
};

function writeSemesterArchiveFile({
  courseId,
  semesterId,
  fileName,
  content,
}) {
  const safeCourseId = Number(courseId || 0);
  const safeSemesterId = Number(semesterId || 0);
  const safeFileName = String(fileName || '').trim() || `semester-${safeSemesterId}-archive.csv`;
  const directory = path.join(
    uploadsDir,
    SEMESTER_ARCHIVE_UPLOADS_DIR,
    `course-${safeCourseId}`,
    `semester-${safeSemesterId}`
  );
  fs.mkdirSync(directory, { recursive: true });
  const absolutePath = path.join(directory, safeFileName);
  fs.writeFileSync(absolutePath, String(content || ''), 'utf8');
  const relativeToUploads = path.relative(uploadsDir, absolutePath).split(path.sep).join('/');
  return {
    fileName: safeFileName,
    absolutePath,
    filePath: `/uploads/${relativeToUploads}`,
    directory,
  };
}

async function buildSemesterJournalArchiveSnapshot({
  courseId,
  semester,
  actorUserId,
}) {
  const safeCourseId = Number(courseId || 0);
  const safeSemesterId = Number(semester?.id || 0);
  const semesterTitle = String(semester?.title || '').trim() || `Semester ${safeSemesterId}`;
  const timestamp = new Date();
  const timestampToken = timestamp.toISOString().replace(/[:.]/g, '-');

  const subjectRows = await db.all(
    `
      SELECT DISTINCT s.id AS subject_id, s.name AS subject_name
      FROM subjects s
      JOIN journal_columns jc ON jc.subject_id = s.id
      WHERE s.course_id = ?
        AND jc.course_id = ?
        AND jc.semester_id = ?
        AND COALESCE(jc.is_archived, 0) = 0
      ORDER BY s.name ASC, s.id ASC
    `,
    [safeCourseId, safeCourseId, safeSemesterId]
  );

  const summaryLines = [
    ['course_id', 'semester_id', 'semester_title', 'generated_at']
      .map((value) => escapeCsvValue(value)).join(','),
    [safeCourseId, safeSemesterId, semesterTitle, timestamp.toISOString()]
      .map((value) => escapeCsvValue(value)).join(','),
    '',
    ['subject_id', 'subject_name', 'student_id', 'student_name', 'group_number', 'final_score_100', 'weighted_earned', 'raw_earned', 'raw_max']
      .map((value) => escapeCsvValue(value)).join(','),
  ];
  const manifestLines = [
    ['subject_id', 'subject_name', 'rows', 'columns', 'file_name', 'file_path']
      .map((value) => escapeCsvValue(value)).join(','),
  ];

  let studentsRowsCount = 0;
  const subjectFiles = [];

  for (const subject of (subjectRows || [])) {
    const subjectId = Number(subject.subject_id || 0);
    if (!Number.isFinite(subjectId) || subjectId < 1) continue;
    const subjectName = String(subject.subject_name || '').trim() || `Subject ${subjectId}`;
    const matrix = await buildJournalMatrix({
      subjectId,
      courseId: safeCourseId,
      semesterId: safeSemesterId,
      actorUserId: Number(actorUserId || 0) || null,
      groupFilterSet: null,
      studentFilterIds: [],
    });
    const detailedCsv = buildJournalClosureCsv({
      subjectName,
      courseName: `Course ${safeCourseId}`,
      semesterTitle,
      closedAt: timestamp,
      columns: matrix.columns || [],
      rows: matrix.rows || [],
    });
    const subjectSlug = normalizeArchiveFileSlug(subjectName, `subject-${subjectId}`);
    const subjectFile = writeSemesterArchiveFile({
      courseId: safeCourseId,
      semesterId: safeSemesterId,
      fileName: `semester-${safeSemesterId}-subject-${subjectId}-${subjectSlug}-${timestampToken}.csv`,
      content: detailedCsv.csv,
    });
    subjectFiles.push({
      subject_id: subjectId,
      subject_name: subjectName,
      file_name: subjectFile.fileName,
      file_path: subjectFile.filePath,
      rows: Number(detailedCsv.exportRowsCount || 0),
      columns: Number(detailedCsv.exportColumnsCount || 0),
    });
    manifestLines.push(
      [
        subjectId,
        subjectName,
        Number(detailedCsv.exportRowsCount || 0),
        Number(detailedCsv.exportColumnsCount || 0),
        subjectFile.fileName,
        subjectFile.filePath,
      ].map((value) => escapeCsvValue(value)).join(',')
    );

    (matrix.rows || []).forEach((row) => {
      const student = row?.student || {};
      summaryLines.push(
        [
          subjectId,
          subjectName,
          Number(student.id || 0),
          String(student.full_name || '').trim() || 'Студент',
          Number(student.group_number || 0),
          formatJournalClosureCsvNumber(row?.final_score),
          formatJournalClosureCsvNumber(row?.weighted_earned),
          formatJournalClosureCsvNumber(row?.raw_earned),
          formatJournalClosureCsvNumber(row?.raw_max),
        ].map((value) => escapeCsvValue(value)).join(',')
      );
      studentsRowsCount += 1;
    });
  }

  const summaryContent = summaryLines.join('\n');
  const manifestContent = manifestLines.join('\n');
  const summaryFile = writeSemesterArchiveFile({
    courseId: safeCourseId,
    semesterId: safeSemesterId,
    fileName: `semester-${safeSemesterId}-archive-summary-${timestampToken}.csv`,
    content: summaryContent,
  });
  const latestSummaryFile = writeSemesterArchiveFile({
    courseId: safeCourseId,
    semesterId: safeSemesterId,
    fileName: `semester-${safeSemesterId}-archive-summary-latest.csv`,
    content: summaryContent,
  });
  const manifestFile = writeSemesterArchiveFile({
    courseId: safeCourseId,
    semesterId: safeSemesterId,
    fileName: `semester-${safeSemesterId}-archive-manifest-${timestampToken}.csv`,
    content: manifestContent,
  });
  const latestManifestFile = writeSemesterArchiveFile({
    courseId: safeCourseId,
    semesterId: safeSemesterId,
    fileName: `semester-${safeSemesterId}-archive-manifest-latest.csv`,
    content: manifestContent,
  });

  return {
    summary_file: summaryFile,
    summary_file_latest: latestSummaryFile,
    manifest_file: manifestFile,
    manifest_file_latest: latestManifestFile,
    subject_files: subjectFiles,
    subjects_count: subjectFiles.length,
    students_rows_count: studentsRowsCount,
    generated_at: timestamp.toISOString(),
  };
}

async function syncJournalColumnsFromHomework(subjectId, courseId, semesterId, gradingSettings, userId) {
  const params = [subjectId, courseId];
  let sql = `
    SELECT
      h.id,
      h.subject_id,
      h.course_id,
      h.semester_id,
      h.group_number,
      h.description,
      h.custom_due_date,
      h.class_date,
      h.day_of_week,
      h.class_number,
      h.meeting_url,
      h.link_url,
      h.file_path,
      h.is_credit,
      h.is_control,
      h.is_custom_deadline,
      h.is_teacher_homework,
      h.created_by_id,
      h.created_by,
      h.created_at
    FROM homework h
    WHERE h.subject_id = ?
      AND h.course_id = ?
      AND COALESCE(h.status, 'published') = 'published'
      AND ${buildTruthyTextCondition('h.is_teacher_homework')}
  `;
  if (semesterId) {
    sql += ' AND (h.semester_id = ? OR h.semester_id IS NULL)';
    params.push(semesterId);
  } else {
    sql += ' AND h.semester_id IS NULL';
  }
  sql += " ORDER BY COALESCE(NULLIF(TRIM(CAST(h.custom_due_date AS TEXT)), ''), NULLIF(TRIM(CAST(h.class_date AS TEXT)), ''), NULLIF(TRIM(CAST(h.created_at AS TEXT)), '')) ASC, h.id ASC";
  const rawHomeworkRows = await db.all(sql, params);
  const homeworkRowsForColumns = (rawHomeworkRows || []).filter((row) => !isSessionConsultationHomeworkRow(row));

  const columnParams = [subjectId, courseId];
  let columnsSql = `
    SELECT
      jc.id,
      jc.source_homework_id,
      jc.title,
      jc.column_type,
      jc.max_points,
      jc.include_in_final,
      jc.is_credit,
      jc.position,
      COALESCE(gc.grades_count, 0) AS grades_count,
      COALESCE(hs.is_teacher_homework, 0) AS source_is_teacher_homework,
      hs.description AS source_homework_description
    FROM journal_columns jc
    LEFT JOIN (
      SELECT column_id, COUNT(*) AS grades_count
      FROM journal_grades
      WHERE deleted_at IS NULL
      GROUP BY column_id
    ) gc ON gc.column_id = jc.id
    LEFT JOIN homework hs ON hs.id = jc.source_homework_id
    WHERE jc.subject_id = ?
      AND jc.course_id = ?
      AND jc.source_homework_id IS NOT NULL
      AND COALESCE(jc.is_archived, 0) = 0
  `;
  if (semesterId) {
    columnsSql += ' AND (jc.semester_id = ? OR jc.semester_id IS NULL)';
    columnParams.push(semesterId);
  } else {
    columnsSql += ' AND jc.semester_id IS NULL';
  }
  const existing = await db.all(columnsSql, columnParams);
  const existingByHomeworkId = new Map();
  const staleHomeworkColumnIds = [];
  let maxNonCreditPosition = 0;
  let maxCreditPosition = 0;
  let maxSessionNonCreditPosition = 0;
  let maxSessionCreditPosition = 0;
  (existing || []).forEach((row) => {
    if (Number(row.source_is_teacher_homework || 0) !== 1) {
      const staleId = Number(row.id);
      if (Number.isFinite(staleId) && staleId > 0) {
        staleHomeworkColumnIds.push(staleId);
      }
      return;
    }
    if (isSessionConsultationHomeworkRow(row)) {
      const staleId = Number(row.id);
      if (Number.isFinite(staleId) && staleId > 0) {
        staleHomeworkColumnIds.push(staleId);
      }
      return;
    }
    existingByHomeworkId.set(Number(row.source_homework_id), row);
    const position = Number(row.position || 0);
    const isSessionRow = isSessionHomeworkRow(row);
    if (Number(row.is_credit) === 1) {
      if (isSessionRow) {
        if (position > maxSessionCreditPosition) maxSessionCreditPosition = position;
      } else if (position > maxCreditPosition) {
        maxCreditPosition = position;
      }
    } else if (isSessionRow) {
      if (position > maxSessionNonCreditPosition) maxSessionNonCreditPosition = position;
    } else if (position > maxNonCreditPosition) {
      maxNonCreditPosition = position;
    }
  });
  const computedSessionBase = Math.max(
    SESSION_COLUMN_POSITION_BASE,
    maxNonCreditPosition + 1000,
    maxCreditPosition + 1000
  );
  if (maxSessionNonCreditPosition < computedSessionBase) {
    maxSessionNonCreditPosition = computedSessionBase;
  }
  if (maxSessionCreditPosition < computedSessionBase) {
    maxSessionCreditPosition = computedSessionBase;
  }
  if (staleHomeworkColumnIds.length) {
    await db.run(
      `
        UPDATE journal_columns
        SET is_archived = 1,
            updated_at = NOW()
        WHERE id = ANY(?)
      `,
      [staleHomeworkColumnIds]
    );
  }

  const dedupedHomeworkRows = [];
  const teacherBatchState = new Map();
  (homeworkRowsForColumns || []).forEach((homeworkRow) => {
    const isTeacherHomework = Number(homeworkRow.is_teacher_homework || 0) === 1;
    if (!isTeacherHomework) {
      dedupedHomeworkRows.push(homeworkRow);
      return;
    }
    const batchKey = buildHomeworkBatchKey(homeworkRow);
    if (!teacherBatchState.has(batchKey)) {
      teacherBatchState.set(batchKey, {
        index: dedupedHomeworkRows.length,
        preferred: homeworkRow,
        rows: [homeworkRow],
      });
      dedupedHomeworkRows.push(homeworkRow);
      return;
    }
    const state = teacherBatchState.get(batchKey);
    state.rows.push(homeworkRow);
    state.preferred = selectPreferredHomeworkBatchRow(state.preferred, homeworkRow, existingByHomeworkId);
    dedupedHomeworkRows[state.index] = state.preferred;
  });

  for (const state of teacherBatchState.values()) {
    if (!state || !state.rows || state.rows.length < 2 || !state.preferred) continue;
    const preferredHomeworkId = Number(state.preferred.id);
    const targetColumn = existingByHomeworkId.get(preferredHomeworkId);
    if (!targetColumn) continue;
    for (const row of state.rows) {
      const duplicateHomeworkId = Number(row.id);
      if (!Number.isFinite(duplicateHomeworkId) || duplicateHomeworkId < 1 || duplicateHomeworkId === preferredHomeworkId) continue;
      const duplicateColumn = existingByHomeworkId.get(duplicateHomeworkId);
      if (!duplicateColumn || Number(duplicateColumn.id) === Number(targetColumn.id)) continue;
      await db.run(
        `
          INSERT INTO journal_grades
            (column_id, student_id, score, teacher_comment, graded_by, graded_at, submission_status)
          SELECT ?, student_id, score, teacher_comment, graded_by, graded_at, submission_status
          FROM journal_grades
          WHERE column_id = ?
            AND deleted_at IS NULL
          ON CONFLICT (column_id, student_id) DO NOTHING
        `,
        [targetColumn.id, duplicateColumn.id]
      );
      await db.run(
        `
          UPDATE journal_columns
          SET is_archived = 1,
              updated_at = NOW()
          WHERE id = ?
        `,
        [duplicateColumn.id]
      );
      existingByHomeworkId.delete(duplicateHomeworkId);
    }
  }

  for (const homeworkRow of dedupedHomeworkRows) {
    const homeworkId = Number(homeworkRow.id);
    const isCredit = Number(homeworkRow.is_credit || 0) === 1 ? 1 : 0;
    const isSessionEvent = isSessionHomeworkRow(homeworkRow);
    const columnType = isCredit ? 'credit' : 'homework';
    const title = buildHomeworkJournalTitle(homeworkRow);
    const defaultMaxPoints = parsePositiveDecimal(
      getDefaultMaxPointsByType(gradingSettings, columnType),
      getDefaultMaxPointsByType(DEFAULT_SUBJECT_GRADING_SETTINGS, columnType)
    );
    const existingRow = existingByHomeworkId.get(homeworkId);
    if (existingRow) {
      let targetPosition = Number(existingRow.position || 0);
      if (isSessionEvent && targetPosition < computedSessionBase) {
        targetPosition = isCredit ? (maxSessionCreditPosition + 10) : (maxSessionNonCreditPosition + 10);
        if (isCredit) maxSessionCreditPosition = targetPosition;
        else maxSessionNonCreditPosition = targetPosition;
      } else if (isSessionEvent) {
        if (isCredit && targetPosition > maxSessionCreditPosition) maxSessionCreditPosition = targetPosition;
        if (!isCredit && targetPosition > maxSessionNonCreditPosition) maxSessionNonCreditPosition = targetPosition;
      }
      const existingMaxPoints = parsePositiveDecimal(existingRow.max_points, defaultMaxPoints);
      const needsUpdate = String(existingRow.title || '') !== title
        || String(existingRow.column_type || '') !== columnType
        || Number(existingRow.is_credit || 0) !== isCredit
        || Number(existingMaxPoints) !== Number(defaultMaxPoints)
        || Number(existingRow.position || 0) !== Number(targetPosition || 0);
      if (needsUpdate) {
        await db.run(
          `
            UPDATE journal_columns
            SET title = ?,
                column_type = ?,
                is_credit = ?,
                max_points = ?,
                position = ?,
                updated_at = NOW()
            WHERE id = ?
          `,
          [title, columnType, isCredit, defaultMaxPoints, targetPosition, existingRow.id]
        );
      }
      continue;
    }
    let nextPosition = isCredit ? (maxCreditPosition + 10) : (maxNonCreditPosition + 10);
    if (isSessionEvent) {
      nextPosition = isCredit ? (maxSessionCreditPosition + 10) : (maxSessionNonCreditPosition + 10);
      if (isCredit) maxSessionCreditPosition = nextPosition;
      else maxSessionNonCreditPosition = nextPosition;
    } else if (isCredit) {
      maxCreditPosition = nextPosition;
    } else {
      maxNonCreditPosition = nextPosition;
    }
    const includeInFinalDefault = getGradingTypeEnabled(gradingSettings, columnType) ? 1 : 0;
    await db.run(
      `
        INSERT INTO journal_columns
        (
          subject_id, course_id, semester_id, source_type, source_homework_id,
          title, column_type, max_points, position, is_credit, include_in_final, created_by, created_at, updated_at
        )
        VALUES (?, ?, ?, 'homework', ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
      `,
      [
        subjectId,
        courseId,
        semesterId || null,
        homeworkId,
        title,
        columnType,
        defaultMaxPoints,
        nextPosition,
        isCredit,
        includeInFinalDefault,
        userId || null,
      ]
    );
  }
}

async function trySyncJournalColumnsAfterHomeworkCreate({
  subjectId,
  courseId,
  semesterId,
  actorUserId,
  isTeacherHomework,
}) {
  if (!isTeacherHomework) {
    return false;
  }
  const safeSubjectId = Number(subjectId);
  const safeCourseId = Number(courseId);
  if (!Number.isFinite(safeSubjectId) || safeSubjectId < 1) {
    return false;
  }
  if (!Number.isFinite(safeCourseId) || safeCourseId < 1) {
    return false;
  }
  try {
    const gradingSettings = await ensureSubjectGradingSettings(
      safeSubjectId,
      safeCourseId,
      semesterId || null,
      actorUserId || null
    );
    if (Number(gradingSettings?.is_closed || 0) === 1) {
      return false;
    }
    await syncJournalColumnsFromHomework(
      safeSubjectId,
      safeCourseId,
      semesterId || null,
      gradingSettings,
      actorUserId || null
    );
    return true;
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      console.error('Homework journal sync failed', {
        subject_id: safeSubjectId,
        course_id: safeCourseId,
        semester_id: semesterId || null,
        actor_user_id: actorUserId || null,
        error: err && err.message ? err.message : err,
      });
    }
    return false;
  }
}

async function getTeacherJournalSubjectAccess(userId, subjectId, courseId = null) {
  const runtimeSubjectId = parseNonZeroIntStrict(subjectId);
  const normalizedCourseId = parsePositiveIntStrict(courseId) || null;
  if (runtimeSubjectId && runtimeSubjectId < 0) {
    const rows = await getTeacherAssignedSubjects(userId);
    const subjectRows = (rows || []).filter((row) => {
      const rowRuntimeSubjectId = buildJournalRuntimeSubjectId({
        legacySubjectId: row.subject_id || row.legacy_subject_id,
        groupSubjectId: row.group_subject_id,
        subjectOfferingId: row.subject_offering_id,
      });
      if (Number(rowRuntimeSubjectId || 0) !== Number(runtimeSubjectId)) {
        return false;
      }
      if (normalizedCourseId && Number(row.course_id || 0) !== Number(normalizedCourseId)) {
        return false;
      }
      return true;
    });
    if (!subjectRows.length) {
      return { hasRows: false, allowAll: false, groups: new Set() };
    }
    const groupCount = Math.max(
      1,
      subjectRows.reduce((maxValue, row) => Math.max(maxValue, Number(row.group_count || 1) || 1), 1)
    );
    return buildTeacherSubjectAccess(subjectRows, groupCount, {
      courseId: normalizedCourseId,
    });
  }
  const rows = await teacherTemplateHelpers.listTeacherSubjectMirrorRows(
    getTeacherTemplateStore(),
    userId,
    {
      subjectId,
      courseId: normalizedCourseId,
      includeHidden: true,
    }
  );
  if (!rows || !rows.length) {
    return { hasRows: false, allowAll: false, groups: new Set() };
  }
  return buildTeacherSubjectAccess(rows, Number(rows[0].group_count || 1), {
    courseId: normalizedCourseId,
  });
}

function buildJournalRuntimeSubjectId({
  legacySubjectId = null,
  groupSubjectId = null,
  subjectOfferingId = null,
} = {}) {
  const normalizedLegacySubjectId = parsePositiveIntStrict(legacySubjectId);
  if (normalizedLegacySubjectId) {
    return normalizedLegacySubjectId;
  }
  const normalizedGroupSubjectId = parsePositiveIntStrict(groupSubjectId);
  if (normalizedGroupSubjectId) {
    return 0 - normalizedGroupSubjectId;
  }
  const normalizedSubjectOfferingId = parsePositiveIntStrict(subjectOfferingId);
  if (normalizedSubjectOfferingId) {
    return 0 - (1000000000 + normalizedSubjectOfferingId);
  }
  return null;
}

function resolveJournalStorageSubjectId(subjectOption = null) {
  if (!subjectOption || typeof subjectOption !== 'object') {
    return null;
  }
  const legacySubjectId = parsePositiveIntStrict(subjectOption.legacy_subject_id);
  if (legacySubjectId) {
    return legacySubjectId;
  }
  const runtimeSubjectId = parseNonZeroIntStrict(subjectOption.subject_id);
  if (runtimeSubjectId) {
    return runtimeSubjectId;
  }
  const derivedRuntimeSubjectId = buildJournalRuntimeSubjectId({
    legacySubjectId: subjectOption.legacy_subject_id || subjectOption.subject_id,
    groupSubjectId: subjectOption.group_subject_id,
    subjectOfferingId: subjectOption.subject_offering_id,
  });
  return parseNonZeroIntStrict(derivedRuntimeSubjectId);
}

async function listJournalAcademicV2FallbackSubjects() {
  try {
    return await db.all(
      `
        SELECT
          gs.id AS group_subject_id,
          gs.legacy_subject_id,
          gs.title AS subject_name,
          gs.group_count,
          gs.default_group,
          gs.is_general,
          gs.sort_order,
          g.legacy_course_id AS course_id,
          c.name AS course_name
        FROM academic_v2_group_subjects gs
        JOIN academic_v2_groups g ON g.id = gs.group_id
        LEFT JOIN courses c ON c.id = g.legacy_course_id
        WHERE COALESCE(gs.is_visible, TRUE) = TRUE
          AND COALESCE(g.is_active, TRUE) = TRUE
        ORDER BY COALESCE(g.legacy_course_id, 0) ASC, gs.sort_order ASC, gs.title ASC, gs.id ASC
      `
    );
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return [];
    }
    throw err;
  }
}

function parseJournalTargetGroupNumbers(rawValue, maxGroupCount = null) {
  const rawItems = Array.isArray(rawValue)
    ? rawValue
    : (
      typeof rawValue === 'string'
        ? String(rawValue)
          .replace(/^\{/, '')
          .replace(/\}$/, '')
          .split(',')
        : [rawValue]
    );
  const normalizedMax = parsePositiveIntStrict(maxGroupCount);
  return Array.from(new Set(
    rawItems
      .map((value) => Number(value || 0))
      .filter((value) => Number.isInteger(value) && value > 0)
      .filter((value) => !normalizedMax || value <= normalizedMax)
  )).sort((a, b) => a - b);
}

function mergeStudentJournalSubjectOption(optionsMap, option = {}) {
  const runtimeSubjectId = buildJournalRuntimeSubjectId({
    legacySubjectId: option.legacy_subject_id || option.subject_id,
    groupSubjectId: option.group_subject_id,
  });
  if (!Number.isInteger(runtimeSubjectId) || runtimeSubjectId === 0) {
    return;
  }

  const normalizedLegacySubjectId = parsePositiveIntStrict(option.legacy_subject_id || option.subject_id) || null;
  const normalizedGroupSubjectId = parsePositiveIntStrict(option.group_subject_id) || null;
  const normalizedGroupCount = Math.max(1, Number(option.group_count || 1) || 1);
  const explicitGroups = Array.isArray(option.group_numbers)
    ? option.group_numbers
    : [];
  const normalizedGroups = Array.from(new Set(
    explicitGroups
      .map((value) => Number(value || 0))
      .filter((value) => Number.isInteger(value) && value > 0)
  )).sort((a, b) => a - b);
  const selectedGroup = parsePositiveIntStrict(option.selected_group || option.group_number) || null;
  if (!normalizedGroups.length && selectedGroup) {
    normalizedGroups.push(selectedGroup);
  }

  if (!optionsMap.has(runtimeSubjectId)) {
    optionsMap.set(runtimeSubjectId, {
      subject_id: runtimeSubjectId,
      legacy_subject_id: normalizedLegacySubjectId,
      group_subject_id: normalizedGroupSubjectId,
      subject_name: String(option.subject_name || option.subject_title || option.name || '').trim(),
      group_count: normalizedGroupCount,
      course_id: Number(option.owner_course_id || option.course_id || 1) || 1,
      course_name: String(option.course_name || '').trim(),
      has_all_groups: Boolean(option.has_all_groups) && !normalizedGroups.length,
      group_numbers_set: new Set(normalizedGroups),
      selected_group: selectedGroup,
      default_group: parsePositiveIntStrict(option.default_group) || 1,
      legacy_semester_id: parsePositiveIntStrict(option.legacy_semester_id) || null,
    });
    return;
  }

  const existing = optionsMap.get(runtimeSubjectId);
  if (!existing.legacy_subject_id && normalizedLegacySubjectId) {
    existing.legacy_subject_id = normalizedLegacySubjectId;
  }
  if (!existing.group_subject_id && normalizedGroupSubjectId) {
    existing.group_subject_id = normalizedGroupSubjectId;
  }
  if (!existing.subject_name) {
    existing.subject_name = String(option.subject_name || option.subject_title || option.name || '').trim();
  }
  if (!existing.course_name) {
    existing.course_name = String(option.course_name || '').trim();
  }
  if (!existing.course_id && Number(option.owner_course_id || option.course_id || 0)) {
    existing.course_id = Number(option.owner_course_id || option.course_id || 0);
  }
  existing.group_count = Math.max(existing.group_count || 1, normalizedGroupCount);
  existing.has_all_groups = Boolean(existing.has_all_groups || (Boolean(option.has_all_groups) && !normalizedGroups.length));
  if (!existing.selected_group && selectedGroup) {
    existing.selected_group = selectedGroup;
  }
  if (!existing.default_group && parsePositiveIntStrict(option.default_group)) {
    existing.default_group = parsePositiveIntStrict(option.default_group);
  }
  if (!existing.legacy_semester_id && parsePositiveIntStrict(option.legacy_semester_id)) {
    existing.legacy_semester_id = parsePositiveIntStrict(option.legacy_semester_id);
  }
  normalizedGroups.forEach((groupNumber) => existing.group_numbers_set.add(groupNumber));
}

async function listAcademicV2StudentJournalScheduleOptions(userId) {
  try {
    const store = getAcademicV2Store();
    const scopeState = await academicV2StudentHelpers.resolveStudentAcademicScope(store, userId);
    if (!scopeState || !scopeState.scope || !scopeState.term) {
      return [];
    }

    const catalogState = await academicV2StudentHelpers.loadStudentSubjectCatalog(store, userId, {
      selectedOnly: false,
    }).catch(() => null);
    const visibleSubjects = Array.isArray(catalogState && catalogState.allSubjects)
      ? catalogState.allSubjects
      : (Array.isArray(catalogState && catalogState.subjects) ? catalogState.subjects : []);
    const selectedByLegacySubjectId = new Map(
      visibleSubjects
        .filter((subject) => subject && subject.is_selected)
        .map((subject) => [Number(subject.subject_id || subject.id || 0), subject])
        .filter(([subjectId]) => Number.isInteger(subjectId) && subjectId > 0)
    );
    const visibleByLegacySubjectId = new Map(
      visibleSubjects
        .map((subject) => [Number(subject.subject_id || subject.id || 0), subject])
        .filter(([subjectId]) => Number.isInteger(subjectId) && subjectId > 0)
    );

    const rows = await store.all(
      `
        SELECT
          se.group_subject_id,
          se.group_number,
          se.target_group_numbers,
          se.day_of_week,
          se.class_number,
          se.week_number,
          se.lesson_type,
          activity.activity_type,
          gs.title AS subject_title,
          gs.legacy_subject_id,
          gs.is_visible,
          gs.is_required,
          gs.is_general,
          gs.group_count,
          gs.default_group,
          st.name AS template_name
        FROM academic_v2_schedule_entries se
        JOIN academic_v2_group_subject_activities activity ON activity.id = se.group_subject_activity_id
        JOIN academic_v2_group_subjects gs ON gs.id = activity.group_subject_id
        JOIN academic_v2_subject_templates st ON st.id = gs.subject_template_id
        WHERE gs.group_id = ?
          AND se.term_id = ?
          AND COALESCE(gs.is_visible, TRUE) = TRUE
        ORDER BY
          COALESCE(gs.sort_order, 0) ASC,
          gs.title ASC,
          gs.id ASC,
          se.week_number ASC,
          se.day_of_week ASC,
          se.class_number ASC,
          se.id ASC
      `,
      [scopeState.scope.group_id, scopeState.term.id]
    );

    const optionMap = new Map();
    (rows || []).forEach((row) => {
      const legacySubjectId = parsePositiveIntStrict(row.legacy_subject_id) || null;
      const groupSubjectId = parsePositiveIntStrict(row.group_subject_id) || null;
      const isVisible = normalizeBoolean(row.is_visible, true);
      if (!isVisible) {
        return;
      }

      const selectedSubject = legacySubjectId ? (selectedByLegacySubjectId.get(legacySubjectId) || null) : null;
      const visibleSubject = legacySubjectId ? (visibleByLegacySubjectId.get(legacySubjectId) || null) : null;
      const activityType = String(row.activity_type || row.lesson_type || 'lecture').trim().toLowerCase() || 'lecture';
      const maxGroupCount = Math.max(1, Number((visibleSubject && visibleSubject.group_count) || row.group_count || 1) || 1);
      const targetGroupNumbers = activityType === 'lecture'
        ? []
        : parseJournalTargetGroupNumbers(
          row.target_group_numbers,
          maxGroupCount
        );
      const selectedGroup = selectedSubject
        ? (
          parsePositiveIntStrict(
            selectedSubject.selected_group
            || selectedSubject.group_number
          ) || null
        )
        : null;

      let shouldInclude = false;
      let derivedGroups = [];
      if (activityType === 'lecture') {
        shouldInclude = Boolean(selectedSubject || visibleSubject || !legacySubjectId);
        if (selectedGroup) {
          derivedGroups = [selectedGroup];
        }
      } else if (selectedSubject && visibleSubject && selectedGroup && targetGroupNumbers.includes(selectedGroup)) {
        shouldInclude = true;
        derivedGroups = [selectedGroup];
      }

      if (!shouldInclude) {
        return;
      }

      mergeStudentJournalSubjectOption(optionMap, {
        subject_id: legacySubjectId,
        legacy_subject_id: legacySubjectId,
        group_subject_id: groupSubjectId,
        subject_name: String(
          (selectedSubject && selectedSubject.subject_name)
          || (visibleSubject && visibleSubject.subject_name)
          || row.subject_title
          || row.template_name
          || ''
        ).trim(),
        group_count: maxGroupCount,
        owner_course_id: parsePositiveIntStrict(scopeState.scope.legacy_course_id) || null,
        course_id: parsePositiveIntStrict(scopeState.scope.legacy_course_id) || null,
        course_name: String(scopeState.scope.legacy_course_name || '').trim(),
        has_all_groups: Boolean(
          (selectedSubject && selectedSubject.has_all_groups)
          || (visibleSubject && visibleSubject.has_all_groups)
          || normalizeBoolean(row.is_general, true)
        ),
        group_numbers: derivedGroups,
        selected_group: derivedGroups[0] || null,
        default_group: parsePositiveIntStrict(
          (selectedSubject && selectedSubject.default_group)
          || (visibleSubject && visibleSubject.default_group)
          || row.default_group
        ) || 1,
        legacy_semester_id: parsePositiveIntStrict(scopeState.term.legacy_semester_id) || null,
      });
    });

    return Array.from(optionMap.values())
      .map((item) => {
        const groupNumbers = Array.from(item.group_numbers_set || []).sort((a, b) => a - b);
        let groupLabel = 'Без групи';
        if (item.has_all_groups && !groupNumbers.length) {
          groupLabel = 'Усі групи';
        } else if (groupNumbers.length === 1) {
          groupLabel = `Група ${groupNumbers[0]}`;
        } else if (groupNumbers.length > 1) {
          groupLabel = `Групи ${groupNumbers.join(', ')}`;
        }
        return {
          subject_id: item.subject_id,
          legacy_subject_id: item.legacy_subject_id,
          group_subject_id: item.group_subject_id,
          subject_name: item.subject_name,
          group_count: Math.max(1, Number(item.group_count || 1) || 1),
          course_id: Number(item.course_id || 1) || 1,
          course_name: item.course_name || '',
          has_all_groups: Boolean(item.has_all_groups),
          group_numbers: groupNumbers,
          group_label: groupLabel,
          selected_group: item.selected_group || null,
          default_group: item.default_group || 1,
          legacy_semester_id: item.legacy_semester_id || null,
        };
      })
      .sort((a, b) => {
        const byCourse = Number(a.course_id || 0) - Number(b.course_id || 0);
        if (byCourse !== 0) return byCourse;
        return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk', { sensitivity: 'base' });
      });
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return [];
    }
    throw err;
  }
}

async function getStudentJournalSubjectOptions(userId) {
  try {
    const [{ rows }, scheduleRows] = await Promise.all([
      loadAcademicV2LegacyStudentRows(userId, {
        selectedOnly: true,
        routeKey: 'journal.student-options',
      }),
      listAcademicV2StudentJournalScheduleOptions(userId),
    ]);
    const optionMap = new Map();
    (rows || []).forEach((row) => {
      mergeStudentJournalSubjectOption(optionMap, row);
    });
    (scheduleRows || []).forEach((row) => {
      mergeStudentJournalSubjectOption(optionMap, row);
    });
    if (optionMap.size) {
      return Array.from(optionMap.values())
        .map((item) => {
          const groupNumbers = Array.from(item.group_numbers_set || []).sort((a, b) => a - b);
          let groupLabel = 'Без групи';
          if (item.has_all_groups && !groupNumbers.length) {
            groupLabel = 'Усі групи';
          } else if (groupNumbers.length === 1) {
            groupLabel = `Група ${groupNumbers[0]}`;
          } else if (groupNumbers.length > 1) {
            groupLabel = `Групи ${groupNumbers.join(', ')}`;
          }
          return {
            subject_id: item.subject_id,
            legacy_subject_id: item.legacy_subject_id,
            group_subject_id: item.group_subject_id,
            subject_name: item.subject_name,
            group_count: Math.max(1, Number(item.group_count || 1) || 1),
            course_id: Number(item.course_id || 1) || 1,
            course_name: item.course_name || '',
            has_all_groups: Boolean(item.has_all_groups),
            group_numbers: groupNumbers,
            group_label: groupLabel,
            selected_group: item.selected_group || null,
            default_group: item.default_group || 1,
            legacy_semester_id: item.legacy_semester_id || null,
          };
        })
        .sort((a, b) => {
          const byCourse = Number(a.course_id || 0) - Number(b.course_id || 0);
          if (byCourse !== 0) return byCourse;
          return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk', { sensitivity: 'base' });
        });
    }
    return (rows || []).map((row) => ({
      subject_id: Number(row.subject_id),
      subject_name: row.subject_name,
      group_count: Math.max(1, Number(row.group_count || 1)),
      course_id: Number(row.owner_course_id || row.course_id || 1),
      course_name: row.course_name || '',
      has_all_groups: false,
      group_numbers: [Number(row.group_number || 1)],
      group_label: `Група ${Number(row.group_number || 1)}`,
    }));
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
    const legacyRows = await academicSetupHelpers.listLegacyStudentGroupRows(getAcademicSetupStore(), {
      studentId: userId,
      includeHidden: false,
    }).catch(() => []);
    return (legacyRows || []).map((row) => {
      const groupNumber = Number(row.group_number || 1) || 1;
      return {
        subject_id: Number(row.subject_id),
        subject_name: row.subject_name,
        group_count: Math.max(1, Number(row.group_count || 1)),
        course_id: Number(row.course_id || 1),
        course_name: row.course_name || '',
        has_all_groups: false,
        group_numbers: [groupNumber],
        group_label: `Група ${groupNumber}`,
      };
    });
  }
}

async function getJournalSubjectOptionsForUser(req, journalScope, teacherJournalMode) {
  const userId = Number(req.session.user.id);
  if (isPlainStudentSession(req) || isAdminViewingStudentSelf(req)) {
    return getStudentJournalSubjectOptions(userId);
  }
  if (teacherJournalMode && journalScope.fullAccess) {
    try {
      const rows = await listTeacherOfferingCatalog();
      const fallbackRows = await listJournalAcademicV2FallbackSubjects();
      const map = new Map();
      (rows || []).forEach((row) => {
        const subjectId = buildJournalRuntimeSubjectId({
          legacySubjectId: row.legacy_subject_id || row.subject_id,
          subjectOfferingId: row.subject_offering_id || row.id,
        });
        if (!Number.isInteger(subjectId) || subjectId === 0 || map.has(subjectId)) {
          return;
        }
        const contexts = Array.isArray(row.contexts) ? row.contexts : [];
        const primaryContext = contexts[0] || null;
        const groupCount = Math.max(1, Number(row.group_count || 1));
        map.set(subjectId, {
          subject_id: subjectId,
          legacy_subject_id: parsePositiveIntStrict(row.legacy_subject_id || row.subject_id) || null,
          subject_name: row.name,
          group_count: groupCount,
          course_id: Number(primaryContext && primaryContext.course_id ? primaryContext.course_id : (row.course_id || 0)) || 1,
          course_name: String(primaryContext && primaryContext.course_name ? primaryContext.course_name : row.course_name || ''),
          has_all_groups: true,
          group_numbers: Array.from({ length: groupCount }, (_v, index) => index + 1),
          group_label: 'Усі групи',
        });
      });
      (fallbackRows || []).forEach((row) => {
        const subjectId = buildJournalRuntimeSubjectId({
          legacySubjectId: row.legacy_subject_id,
          groupSubjectId: row.group_subject_id,
        });
        const normalizedLegacySubjectId = parsePositiveIntStrict(row.legacy_subject_id) || null;
        const normalizedCourseId = Number(row.course_id || 0) || 1;
        const normalizedSubjectName = String(row.subject_name || '').trim().toLowerCase();
        const duplicateUnmappedOption = !normalizedLegacySubjectId
          && Array.from(map.values()).some((item) => (
            !parsePositiveIntStrict(item.legacy_subject_id)
            && Number(item.course_id || 0) === normalizedCourseId
            && String(item.subject_name || '').trim().toLowerCase() === normalizedSubjectName
          ));
        if (!Number.isInteger(subjectId) || map.has(subjectId) || duplicateUnmappedOption) {
          return;
        }
        const groupCount = Math.max(1, Number(row.group_count || 1));
        map.set(subjectId, {
          subject_id: subjectId,
          legacy_subject_id: normalizedLegacySubjectId,
          group_subject_id: parsePositiveIntStrict(row.group_subject_id) || null,
          subject_name: String(row.subject_name || ''),
          group_count: groupCount,
          course_id: normalizedCourseId,
          course_name: String(row.course_name || ''),
          has_all_groups: true,
          group_numbers: Array.from({ length: groupCount }, (_v, index) => index + 1),
          group_label: 'Усі групи',
        });
      });
      return Array.from(map.values()).sort((a, b) => {
        const byCourse = Number(a.course_id || 0) - Number(b.course_id || 0);
        if (byCourse !== 0) return byCourse;
        return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk', { sensitivity: 'base' });
      });
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      const rows = await db.all(
        `
          SELECT s.id AS subject_id, s.name AS subject_name, s.group_count, s.course_id, c.name AS course_name
          FROM subjects s
          JOIN courses c ON c.id = s.course_id
          WHERE COALESCE(LOWER(TRIM(CAST(s.visible AS TEXT))), '1') IN ('1', 'true', 't')
          ORDER BY c.id ASC, s.name ASC
        `
      ).catch(() => []);
      return (rows || []).map((row) => ({
        subject_id: Number(row.subject_id),
        subject_name: row.subject_name,
        group_count: Math.max(1, Number(row.group_count || 1)),
        course_id: Number(row.course_id || 1),
        course_name: row.course_name || '',
        has_all_groups: true,
        group_numbers: Array.from({ length: Math.max(1, Number(row.group_count || 1)) }, (_v, index) => index + 1),
        group_label: 'Усі групи',
      }));
    }
  }

  if (teacherJournalMode) {
    const rows = await getTeacherAssignedSubjects(userId);
    if (!rows || !rows.length) {
      return getStudentJournalSubjectOptions(userId);
    }
    const map = new Map();
    (rows || []).forEach((row) => {
      const key = buildJournalRuntimeSubjectId({
        legacySubjectId: row.subject_id || row.legacy_subject_id,
        groupSubjectId: row.group_subject_id,
        subjectOfferingId: row.subject_offering_id,
      });
      if (!Number.isInteger(key)) {
        return;
      }
      if (!map.has(key)) {
        map.set(key, {
          subject_id: key,
          legacy_subject_id: parsePositiveIntStrict(row.subject_id || row.legacy_subject_id) || null,
          group_subject_id: parsePositiveIntStrict(row.group_subject_id) || null,
          subject_offering_id: parsePositiveIntStrict(row.subject_offering_id) || null,
          subject_name: row.subject_name,
          group_count: Math.max(1, Number(row.group_count || 1)),
          course_id: Number(row.course_id || 1),
          course_name: row.course_name || '',
          has_all_groups: false,
          group_numbers_set: new Set(),
        });
      }
      const item = map.get(key);
      if (row.group_number === null || typeof row.group_number === 'undefined') {
        item.has_all_groups = true;
      } else {
        const groupNumber = Number(row.group_number);
        if (Number.isInteger(groupNumber) && groupNumber > 0) {
          item.group_numbers_set.add(groupNumber);
        }
      }
    });
    return Array.from(map.values()).map((item) => {
      const groupNumbers = item.has_all_groups
        ? Array.from({ length: item.group_count }, (_v, index) => index + 1)
        : Array.from(item.group_numbers_set).sort((a, b) => a - b);
      let groupLabel = 'Без груп';
      if (item.has_all_groups) groupLabel = 'Усі групи';
      else if (groupNumbers.length === 1) groupLabel = `Група ${groupNumbers[0]}`;
      else if (groupNumbers.length > 1) groupLabel = `Групи ${groupNumbers.join(', ')}`;
      return {
        subject_id: item.subject_id,
        legacy_subject_id: item.legacy_subject_id,
        group_subject_id: item.group_subject_id,
        subject_offering_id: item.subject_offering_id,
        subject_name: item.subject_name,
        group_count: item.group_count,
        course_id: item.course_id,
        course_name: item.course_name,
        has_all_groups: item.has_all_groups,
        group_numbers: groupNumbers,
        group_label: groupLabel,
      };
    });
  }

  return getStudentJournalSubjectOptions(userId);
}

async function getJournalColumns(subjectId, courseId, semesterId) {
  const params = [subjectId, courseId];
  let sql = `
    SELECT
      jc.*,
      COALESCE(gc.grades_count, 0) AS grades_count,
      h.description AS homework_description,
      h.custom_due_date,
      h.class_date,
      h.group_number AS homework_group_number,
      h.day_of_week AS homework_day_of_week,
      h.class_number AS homework_class_number,
      h.meeting_url AS homework_meeting_url,
      h.link_url AS homework_link_url,
      h.file_path AS homework_file_path,
      h.file_name AS homework_file_name,
      h.is_custom_deadline AS homework_is_custom_deadline,
      h.is_control AS homework_is_control,
      h.is_credit AS homework_is_credit,
      h.is_teacher_homework AS homework_is_teacher_homework,
      h.created_at AS homework_created_at,
      h.created_by AS homework_created_by,
      h.created_by_id AS homework_created_by_id,
      u.full_name AS homework_created_by_name
    FROM journal_columns jc
    LEFT JOIN (
      SELECT column_id, COUNT(*) AS grades_count
      FROM journal_grades
      WHERE deleted_at IS NULL
      GROUP BY column_id
    ) gc ON gc.column_id = jc.id
    LEFT JOIN homework h ON h.id = jc.source_homework_id
    LEFT JOIN users u ON u.id = h.created_by_id
    WHERE jc.subject_id = ?
      AND jc.course_id = ?
      AND COALESCE(jc.is_archived, 0) = 0
  `;
  if (semesterId) {
    sql += ' AND (jc.semester_id = ? OR jc.semester_id IS NULL)';
    params.push(semesterId);
  } else {
    sql += ' AND jc.semester_id IS NULL';
  }
  sql += `
    ORDER BY
      CASE WHEN COALESCE(h.description, '') ILIKE '[Сесія]%' THEN 1 ELSE 0 END ASC,
      CASE WHEN COALESCE(jc.is_credit, 0) = 1 THEN 1 ELSE 0 END ASC,
      COALESCE(jc.position, 0) ASC,
      COALESCE(
        NULLIF(TRIM(CAST(h.custom_due_date AS TEXT)), ''),
        NULLIF(TRIM(CAST(h.class_date AS TEXT)), ''),
        NULLIF(TRIM(CAST(h.created_at AS TEXT)), ''),
        TO_CHAR(jc.created_at AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"')
      ) ASC,
      jc.id ASC
  `;
  let rows = [];
  try {
    rows = await db.all(sql, params);
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
    try {
      const legacyParams = [subjectId, courseId];
      let legacySql = `
        SELECT
          jc.id,
          jc.subject_id,
          jc.course_id,
          jc.semester_id,
          jc.source_type,
          jc.source_homework_id,
          jc.title,
          jc.column_type,
          jc.max_points,
          CASE WHEN LOWER(COALESCE(jc.column_type, '')) = 'credit' THEN 1 ELSE 0 END AS is_credit,
          COALESCE(jc.position, 0) AS position,
          0::int AS grades_count,
          h.description AS homework_description,
          h.custom_due_date,
          h.class_date,
          h.group_number AS homework_group_number,
          h.day_of_week AS homework_day_of_week,
          h.class_number AS homework_class_number,
          h.meeting_url AS homework_meeting_url,
          h.link_url AS homework_link_url,
          h.file_path AS homework_file_path,
          h.file_name AS homework_file_name,
          0::int AS homework_is_custom_deadline,
          0::int AS homework_is_control,
          0::int AS homework_is_credit,
          0::int AS homework_is_teacher_homework,
          h.created_at AS homework_created_at,
          h.created_by AS homework_created_by,
          h.created_by_id AS homework_created_by_id,
          u.full_name AS homework_created_by_name
        FROM journal_columns jc
        LEFT JOIN homework h ON h.id = jc.source_homework_id
        LEFT JOIN users u ON u.id = h.created_by_id
        WHERE jc.subject_id = ?
          AND jc.course_id = ?
      `;
      if (semesterId) {
        legacySql += ' AND (jc.semester_id = ? OR jc.semester_id IS NULL)';
        legacyParams.push(semesterId);
      } else {
        legacySql += ' AND jc.semester_id IS NULL';
      }
      legacySql += ' ORDER BY COALESCE(jc.position, 0) ASC, jc.id ASC';
      rows = await db.all(legacySql, legacyParams);
    } catch (legacyErr) {
      if (!isDbSchemaCompatibilityError(legacyErr)) {
        throw legacyErr;
      }
      rows = [];
    }
  }
  const normalizedRows = (rows || []).map((row) => {
    const sourceHomeworkId = row.source_homework_id ? Number(row.source_homework_id) : null;
    const sourceHomeworkIsTeacher = Number(row.homework_is_teacher_homework || 0) === 1;
    const sourceHomeworkBatchKey = sourceHomeworkId && sourceHomeworkIsTeacher
      ? buildHomeworkBatchKeyFromColumnRow({
          ...row,
          subject_id: row.subject_id,
          course_id: row.course_id,
          semester_id: row.semester_id,
        })
      : '';
    return {
      id: Number(row.id),
      subject_id: Number(row.subject_id),
      source_type: String(row.source_type || 'manual'),
      source_homework_id: sourceHomeworkId,
      source_homework_is_teacher: sourceHomeworkIsTeacher,
      source_homework_batch_key: sourceHomeworkBatchKey,
      title: String(row.title || ''),
      column_type: normalizeColumnType(row.column_type),
      max_points: parsePositiveDecimal(row.max_points, 10),
      include_in_final: Number(row.include_in_final ?? 1) === 1,
      is_locked: Number(row.is_locked || 0) === 1,
      is_credit: Number(row.is_credit || 0) === 1,
      position: Number(row.position || 0),
      homework_description: row.homework_description || null,
      custom_due_date: toDateOnly(row.custom_due_date),
      class_date: toDateOnly(row.class_date),
      homework_group_number: row.homework_group_number ? Number(row.homework_group_number) : null,
      homework_meeting_url: row.homework_meeting_url || null,
      homework_link_url: row.homework_link_url || null,
      homework_file_path: row.homework_file_path || null,
      homework_file_name: normalizeUploadedOriginalName(row.homework_file_name),
      homework_is_custom_deadline: Number(row.homework_is_custom_deadline || 0) === 1,
      homework_created_at: row.homework_created_at || null,
      homework_created_by: row.homework_created_by || null,
      homework_created_by_name: row.homework_created_by_name || null,
      _grades_count: Number(row.grades_count || 0),
    };
  });

  const selectedByKey = new Map();
  const orderedKeys = [];
  normalizedRows.forEach((column) => {
    const dedupeKey = column.source_homework_id && column.source_homework_is_teacher && column.source_homework_batch_key
      ? `teacher:${column.source_homework_batch_key}`
      : `column:${column.id}`;
    if (!selectedByKey.has(dedupeKey)) {
      selectedByKey.set(dedupeKey, column);
      orderedKeys.push(dedupeKey);
      return;
    }
    const existingColumn = selectedByKey.get(dedupeKey);
    const shouldReplace = Number(column._grades_count || 0) > Number(existingColumn._grades_count || 0)
      || (
        Number(column._grades_count || 0) === Number(existingColumn._grades_count || 0)
        && Number(column.id || 0) < Number(existingColumn.id || 0)
      );
    if (shouldReplace) {
      selectedByKey.set(dedupeKey, column);
    }
  });

  return orderedKeys.map((key) => {
    const row = { ...(selectedByKey.get(key) || {}) };
    delete row._grades_count;
    return row;
  });
}

async function getJournalStudents(subjectId, courseId, groupFilterSet = null, userFilterIds = []) {
  const groups = groupFilterSet && groupFilterSet.size
    ? Array.from(groupFilterSet).filter((value) => Number.isInteger(value) && value > 0)
    : [];
  const normalizedSubjectId = parseNonZeroIntStrict(subjectId);
  const normalizedCourseId = parsePositiveIntStrict(courseId);
  if (normalizedSubjectId && normalizedCourseId) {
    try {
      const courseUsers = await academicV2RuntimeHelpers.listCourseUsersByLegacyCourse(
        getAcademicV2Store(),
        normalizedCourseId,
        {
          activeOnly: usersHasIsActive,
          userIds: Array.isArray(userFilterIds) && userFilterIds.length ? userFilterIds : undefined,
        }
      );
      const rows = [];
      for (const userRow of courseUsers || []) {
        const roleKey = normalizeRoleKey(userRow.role || 'student');
        if (roleKey !== 'student' && roleKey !== 'starosta') {
          continue;
        }
        const studentState = await academicV2StudentHelpers.loadStudentSubjectCatalog(
          getAcademicV2Store(),
          userRow,
          { selectedOnly: true }
        ).catch(() => null);
        const subjectRows = Array.isArray(studentState && studentState.subjects) ? studentState.subjects : [];
        const selectedSubject = subjectRows.find((row) => {
          const rowSubjectId = resolveJournalStorageSubjectId({
            subject_id: row.subject_id || row.id,
            legacy_subject_id: row.legacy_subject_id,
            group_subject_id: row.group_subject_id,
            subject_offering_id: row.subject_offering_id,
          });
          return Number(rowSubjectId || 0) === Number(normalizedSubjectId);
        }) || null;
        if (!selectedSubject) {
          continue;
        }
        const selectedGroup = Number(
          selectedSubject.selected_group
          || selectedSubject.default_group
          || (Array.isArray(selectedSubject.group_numbers) && selectedSubject.group_numbers.length
            ? selectedSubject.group_numbers[0]
            : 0)
        ) || 0;
        if (groups.length && !selectedSubject.has_all_groups && (!selectedGroup || !groups.includes(selectedGroup))) {
          continue;
        }
        rows.push({
          id: Number(userRow.id),
          full_name: String(userRow.full_name || ''),
          group_number: selectedSubject.has_all_groups ? 0 : selectedGroup,
        });
      }
      if (rows.length) {
        return rows.sort((a, b) => String(a.full_name || '').localeCompare(String(b.full_name || ''), 'uk'));
      }
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
    }
  }
  const rows = await academicSetupHelpers.listLegacySubjectStudentRows(getAcademicSetupStore(), {
    subjectId,
    courseId,
    groupNumbers: groups,
    userIds: userFilterIds,
    activeOnly: usersHasIsActive,
  });
  return (rows || [])
    .map((row) => ({
      id: Number(row.id),
      full_name: row.full_name,
      group_number: Number(row.group_number || 0),
    }))
    .sort((a, b) => String(a.full_name || '').localeCompare(String(b.full_name || ''), 'uk'));
}

async function getJournalStudentGroup(subjectId, studentId) {
  const normalizedSubjectId = parseNonZeroIntStrict(subjectId);
  if (!normalizedSubjectId) {
    return { group_number: null };
  }
  try {
    const studentState = await academicV2StudentHelpers.loadStudentSubjectCatalog(
      getAcademicV2Store(),
      studentId,
      { selectedOnly: true }
    );
    const subjectRows = Array.isArray(studentState && studentState.subjects) ? studentState.subjects : [];
    const selectedSubject = subjectRows.find((row) => {
      const rowSubjectId = resolveJournalStorageSubjectId({
        subject_id: row.subject_id || row.id,
        legacy_subject_id: row.legacy_subject_id,
        group_subject_id: row.group_subject_id,
        subject_offering_id: row.subject_offering_id,
      });
      return Number(rowSubjectId || 0) === Number(normalizedSubjectId);
    }) || null;
    if (selectedSubject) {
      const selectedGroup = selectedSubject.has_all_groups
        ? null
        : Number(
          selectedSubject.selected_group
          || selectedSubject.default_group
          || (Array.isArray(selectedSubject.group_numbers) && selectedSubject.group_numbers.length
            ? selectedSubject.group_numbers[0]
            : 0)
        ) || null;
      return { group_number: selectedGroup };
    }
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
  }
  if (normalizedSubjectId < 0) {
    return { group_number: null };
  }
  return academicSetupHelpers.getLegacyStudentSubjectGroup(getAcademicSetupStore(), {
    subjectId: normalizedSubjectId,
    studentId,
    activeOnly: usersHasIsActive,
  });
}

async function buildJournalAttendanceContext({
  subjectId,
  courseId,
  semesterId,
  semester = null,
  students = [],
  requestedDate,
  requestedClassNumber,
  studentViewUserId = null,
  allowedGroupNumbers = [],
  hasAllGroups = false,
}) {
  const classOptions = getAttendanceClassOptions();
  const normalizedDate = isValidDateString(String(requestedDate || ''))
    ? String(requestedDate)
    : formatLocalDate(new Date());
  const classNumberRaw = Number(requestedClassNumber);
  const normalizedClassNumber = (
    Number.isInteger(classNumberRaw)
    && classNumberRaw > 0
    && classOptions.some((option) => option.value === classNumberRaw)
  )
    ? classNumberRaw
    : (classOptions[0] ? Number(classOptions[0].value) : 1);

  const safeStudents = Array.isArray(students)
    ? students
      .map((student) => ({
        id: Number(student?.id || 0),
        full_name: String(student?.full_name || '').trim() || 'Студент',
        group_number: Number(student?.group_number || 0),
      }))
      .filter((student) => Number.isFinite(student.id) && student.id > 0)
    : [];
  safeStudents.sort((a, b) => {
    const byName = String(a.full_name || '').localeCompare(String(b.full_name || ''), 'uk');
    return byName !== 0 ? byName : Number(a.id || 0) - Number(b.id || 0);
  });
  const studentIds = safeStudents.map((student) => student.id);

  const semesterFilter = buildExactSemesterCondition('ar', semesterId);
  let recordsByStudentId = new Map();
  if (studentIds.length) {
    try {
      const rows = await db.all(
        `
          SELECT ar.student_id, ar.status, ar.reason, ar.marked_at
          FROM attendance_records ar
          WHERE ar.subject_id = ?
            AND ar.course_id = ?
            ${semesterFilter.clause}
            AND ar.class_date = ?
            AND ar.class_number = ?
            AND ar.student_id = ANY(?::int[])
        `,
        [subjectId, courseId, ...semesterFilter.params, normalizedDate, normalizedClassNumber, studentIds]
      );
      recordsByStudentId = new Map(
        (rows || []).map((row) => [
          Number(row.student_id),
          {
            status: normalizeAttendanceStatus(row.status),
            reason: String(row.reason || ''),
            marked_at: row.marked_at || null,
          },
        ])
      );
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      recordsByStudentId = new Map();
    }
  }

  const summary = {
    present: 0,
    late: 0,
    absent: 0,
    excused: 0,
    unset: 0,
    marked_total: 0,
    students_total: safeStudents.length,
  };

  const rows = safeStudents.map((student) => {
    const record = recordsByStudentId.get(student.id) || null;
    const status = record ? normalizeAttendanceStatus(record.status) : '';
    if (!status) {
      summary.unset += 1;
    } else {
      summary.marked_total += 1;
      summary[status] = Number(summary[status] || 0) + 1;
    }
    return {
      student_id: student.id,
      full_name: student.full_name,
      group_number: Number.isInteger(student.group_number) && student.group_number > 0 ? student.group_number : null,
      status,
      reason: record ? String(record.reason || '') : '',
      marked_at: record ? (record.marked_at || null) : null,
    };
  });

  let studentSummary = null;
  const safeStudentViewId = Number(studentViewUserId || 0);
  if (Number.isFinite(safeStudentViewId) && safeStudentViewId > 0) {
    try {
      const groupedRows = await db.all(
        `
          SELECT ar.status, COUNT(*) AS count
          FROM attendance_records ar
          WHERE ar.subject_id = ?
            AND ar.course_id = ?
            ${semesterFilter.clause}
            AND ar.student_id = ?
          GROUP BY ar.status
        `,
        [subjectId, courseId, ...semesterFilter.params, safeStudentViewId]
      );
      const recentRows = await db.all(
        `
          SELECT ar.class_date, ar.class_number, ar.status, ar.reason, ar.marked_at
          FROM attendance_records ar
          WHERE ar.subject_id = ?
            AND ar.course_id = ?
            ${semesterFilter.clause}
            AND ar.student_id = ?
          ORDER BY ar.class_date DESC, ar.class_number DESC
          LIMIT 8
        `,
        [subjectId, courseId, ...semesterFilter.params, safeStudentViewId]
      );
      const grouped = {
        present: 0,
        late: 0,
        absent: 0,
        excused: 0,
      };
      (groupedRows || []).forEach((row) => {
        const status = normalizeAttendanceStatus(row.status);
        if (!status) return;
        grouped[status] = Number(row.count || 0);
      });
      const attendedTotal = Number(grouped.present || 0) + Number(grouped.late || 0);
      const recordsTotal = attendedTotal + Number(grouped.absent || 0) + Number(grouped.excused || 0);
      studentSummary = {
        ...grouped,
        total: recordsTotal,
        attended_total: attendedTotal,
        attendance_rate: recordsTotal > 0 ? Math.round((attendedTotal / recordsTotal) * 100) : null,
        recent_records: (recentRows || []).map((row) => ({
          class_date: toDateOnly(row.class_date),
          class_number: Number(row.class_number || 0),
          status: normalizeAttendanceStatus(row.status),
          reason: String(row.reason || ''),
          marked_at: row.marked_at || null,
        })),
      };
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      studentSummary = null;
    }
  }

  let quickCurrentSlot = {
    available: false,
    class_date: formatLocalDate(new Date()),
    class_number: null,
    day_of_week: null,
    start: '',
    end: '',
    label: '',
    group_numbers: [],
    is_selected: false,
  };
  if (!(Number.isFinite(safeStudentViewId) && safeStudentViewId > 0)) {
    quickCurrentSlot = await resolveJournalCurrentAttendanceSlot({
      subjectId,
      courseId,
      semesterId,
      semester,
      allowedGroupNumbers,
      hasAllGroups,
    });
    quickCurrentSlot.is_selected = Boolean(
      quickCurrentSlot.available
      && String(quickCurrentSlot.class_date || '') === String(normalizedDate || '')
      && Number(quickCurrentSlot.class_number) === Number(normalizedClassNumber)
    );
  }

  return {
    date: normalizedDate,
    class_number: normalizedClassNumber,
    class_options: classOptions,
    statuses: ATTENDANCE_STATUS_OPTIONS.map((status) => ATTENDANCE_STATUS_META[status]),
    rows,
    summary,
    student_summary: studentSummary,
    reason_max_length: ATTENDANCE_REASON_MAX_LENGTH,
    quick_current_slot: quickCurrentSlot,
  };
}

async function resolveScheduleAttendanceTeacherContext(
  req,
  {
    subjectId,
    courseId = null,
    classDate,
    classNumber,
    groupNumber = null,
    targetGroups = [],
    lessonType = '',
    isGeneral = false,
  } = {}
) {
  const safeSubjectId = parsePositiveIntStrict(subjectId);
  const safeCourseId = parsePositiveIntStrict(courseId);
  const safeClassDate = isValidDateString(String(classDate || ''))
    ? String(classDate).slice(0, 10)
    : '';
  const safeClassNumber = parsePositiveIntStrict(classNumber);

  if (!safeSubjectId || !safeClassDate || !safeClassNumber || !bellSchedule[safeClassNumber]) {
    const error = new Error('Invalid attendance slot');
    error.statusCode = 400;
    throw error;
  }

  const journalScope = await getJournalAccessScope(req);
  const teacherJournalMode = canUseTeacherJournalMode(req, journalScope);
  if (!journalScope.canUseJournal || !teacherJournalMode) {
    const error = new Error('Forbidden (schedule attendance)');
    error.statusCode = 403;
    throw error;
  }

  const subjectOptions = await getJournalSubjectOptionsForUser(req, journalScope, teacherJournalMode);
  const selectedSubject = findJournalSubjectOptionForSchedule(subjectOptions, safeSubjectId, safeCourseId);
  if (!selectedSubject) {
    const error = new Error('Forbidden (schedule attendance)');
    error.statusCode = 403;
    throw error;
  }

  const storageSubjectId = parsePositiveIntStrict(selectedSubject.legacy_subject_id || safeSubjectId);
  if (!storageSubjectId) {
    const error = new Error('Attendance storage binding is not ready for this subject');
    error.statusCode = 409;
    throw error;
  }

  const selectedCourseId = parsePositiveIntStrict(
    selectedSubject.course_id
    || safeCourseId
    || req?.session?.user?.course_id
  );
  if (!selectedCourseId) {
    const error = new Error('Invalid course');
    error.statusCode = 400;
    throw error;
  }

  const selectedSemester = await getActiveSemester(selectedCourseId).catch(() => null);
  const groupScope = resolveScheduleAttendanceGroupScope(selectedSubject, {
    groupNumber,
    targetGroups,
    lessonType,
    isGeneral,
  });
  if (!groupScope.hasAccess) {
    const error = new Error('Forbidden (schedule attendance)');
    error.statusCode = 403;
    throw error;
  }

  const students = await getJournalStudents(
    storageSubjectId,
    selectedCourseId,
    groupScope.groupFilterSet
  );
  return {
    selectedSubject,
    subjectId: storageSubjectId,
    courseId: selectedCourseId,
    semester: selectedSemester || null,
    semesterId: selectedSemester ? Number(selectedSemester.id || 0) : null,
    classDate: safeClassDate,
    classNumber: safeClassNumber,
    groupFilterSet: groupScope.groupFilterSet,
    allowedGroupNumbers: groupScope.allowedGroupNumbers,
    students,
  };
}

async function resolveJournalColumnHomeworkForStudent(columnRow, studentGroupNumber) {
  const sourceHomeworkId = Number(columnRow?.source_homework_id || 0);
  const fallback = {
    homework_id: Number.isFinite(sourceHomeworkId) && sourceHomeworkId > 0 ? sourceHomeworkId : null,
    custom_due_date: toDateOnly(columnRow?.custom_due_date || columnRow?.homework_custom_due_date),
    class_date: toDateOnly(columnRow?.class_date || columnRow?.homework_class_date),
  };
  if (!fallback.homework_id) return fallback;

  const isTeacherHomework = Number(
    columnRow?.source_homework_is_teacher
    || columnRow?.homework_is_teacher_homework
    || 0
  ) === 1;
  if (!isTeacherHomework) return fallback;

  const groupNumber = Number(studentGroupNumber || 0);
  if (!Number.isInteger(groupNumber) || groupNumber < 1) return fallback;

  const batchKey = buildHomeworkBatchKey({
    created_by_id: columnRow?.homework_created_by_id,
    created_by: columnRow?.homework_created_by,
    created_at: columnRow?.homework_created_at,
    subject_id: columnRow?.subject_id,
    course_id: columnRow?.course_id,
    semester_id: columnRow?.semester_id,
    is_custom_deadline: columnRow?.homework_is_custom_deadline,
    is_credit: columnRow?.homework_is_credit,
    is_control: columnRow?.homework_is_control,
    description: columnRow?.homework_description,
    custom_due_date: columnRow?.custom_due_date || columnRow?.homework_custom_due_date,
    class_date: columnRow?.class_date || columnRow?.homework_class_date,
    day_of_week: columnRow?.homework_day_of_week,
    class_number: columnRow?.homework_class_number,
    meeting_url: columnRow?.homework_meeting_url,
    link_url: columnRow?.homework_link_url,
    file_path: columnRow?.homework_file_path,
  });
  if (!batchKey) return fallback;

  const params = [columnRow.subject_id, columnRow.course_id, groupNumber];
  let sql = `
    SELECT
      h.id,
      h.group_number,
      h.subject_id,
      h.course_id,
      h.semester_id,
      h.created_by_id,
      h.created_by,
      h.created_at,
      h.description,
      h.custom_due_date,
      h.class_date,
      h.day_of_week,
      h.class_number,
      h.meeting_url,
      h.link_url,
      h.file_path,
      h.is_custom_deadline,
      h.is_control,
      h.is_credit,
      h.is_teacher_homework
    FROM homework h
    WHERE h.subject_id = ?
      AND h.course_id = ?
      AND h.group_number = ?
      AND COALESCE(h.status, 'published') = 'published'
      AND ${buildTruthyTextCondition('h.is_teacher_homework')}
  `;
  if (columnRow.semester_id) {
    sql += ' AND (h.semester_id = ? OR h.semester_id IS NULL)';
    params.push(columnRow.semester_id);
  } else {
    sql += ' AND h.semester_id IS NULL';
  }
  const rows = await db.all(sql, params);
  const matched = (rows || []).find((row) => buildHomeworkBatchKey(row) === batchKey);
  if (!matched) return fallback;

  return {
    homework_id: Number(matched.id),
    custom_due_date: toDateOnly(matched.custom_due_date),
    class_date: toDateOnly(matched.class_date),
  };
}

async function buildJournalMatrix({
  subjectId,
  courseId,
  semesterId,
  actorUserId,
  groupFilterSet = null,
  studentFilterIds = [],
}) {
  const normalizedSubjectId = parseNonZeroIntStrict(subjectId);
  if (!normalizedSubjectId) {
    return {
      gradingSettings: {
        ...DEFAULT_SUBJECT_GRADING_SETTINGS,
        is_closed: 0,
        closed_by: null,
        closed_at: null,
      },
      columns: [],
      rows: [],
    };
  }
  const supportsLegacyHomeworkSync = normalizedSubjectId > 0;
  const gradingSettings = supportsLegacyHomeworkSync
    ? await ensureSubjectGradingSettings(subjectId, courseId, semesterId, actorUserId)
    : {
        ...DEFAULT_SUBJECT_GRADING_SETTINGS,
        is_closed: 0,
        closed_by: null,
        closed_at: null,
      };
  if (supportsLegacyHomeworkSync && Number(gradingSettings?.is_closed || 0) !== 1) {
    try {
      await syncJournalColumnsFromHomework(subjectId, courseId, semesterId, gradingSettings, actorUserId);
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
    }
  }

  let columns = await getJournalColumns(subjectId, courseId, semesterId);
  const students = await getJournalStudents(subjectId, courseId, groupFilterSet, studentFilterIds);
  if (!students.length) {
    return {
      gradingSettings,
      columns,
      rows: [],
    };
  }

  let teacherBatchLookup = {
    byHomeworkId: new Map(),
    byBatchGroup: new Map(),
  };
  const hasTeacherHomeworkColumns = columns.some((column) => (
    Number(column.source_homework_id || 0) > 0
    && column.source_homework_is_teacher
    && column.source_homework_batch_key
  ));
  if (hasTeacherHomeworkColumns) {
    const teacherHomeworkParams = [subjectId, courseId];
    let teacherHomeworkSql = `
      SELECT
        h.id,
        h.group_number,
        h.subject_id,
        h.course_id,
        h.semester_id,
        h.created_by_id,
        h.created_by,
        h.created_at,
        h.description,
        h.custom_due_date,
        h.class_date,
        h.day_of_week,
        h.class_number,
        h.meeting_url,
        h.link_url,
        h.file_path,
        h.is_custom_deadline,
        h.is_control,
        h.is_credit,
        h.is_teacher_homework
      FROM homework h
      WHERE h.subject_id = ?
        AND h.course_id = ?
        AND COALESCE(h.status, 'published') = 'published'
        AND ${buildTruthyTextCondition('h.is_teacher_homework')}
    `;
    if (semesterId) {
      teacherHomeworkSql += ' AND (h.semester_id = ? OR h.semester_id IS NULL)';
      teacherHomeworkParams.push(semesterId);
    } else {
      teacherHomeworkSql += ' AND h.semester_id IS NULL';
    }
    try {
      const teacherHomeworkRows = await db.all(teacherHomeworkSql, teacherHomeworkParams);
      teacherBatchLookup = buildTeacherHomeworkBatchLookup(teacherHomeworkRows || []);
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      teacherBatchLookup = {
        byHomeworkId: new Map(),
        byBatchGroup: new Map(),
      };
    }
  }

  if (groupFilterSet && groupFilterSet.size) {
    const allowedGroups = Array.from(groupFilterSet)
      .map((value) => Number(value))
      .filter((value) => Number.isInteger(value) && value > 0);
    columns = columns.filter((column) => {
      if (!column.source_homework_id) return true;
      const homeworkGroup = Number(column.homework_group_number || 0);
      if (!column.source_homework_is_teacher) {
        if (!homeworkGroup) return true;
        return allowedGroups.includes(homeworkGroup);
      }
      if (homeworkGroup && allowedGroups.includes(homeworkGroup)) return true;
      if (!column.source_homework_batch_key) return false;
      return allowedGroups.some((groupNumber) => teacherBatchLookup.byBatchGroup.has(`${column.source_homework_batch_key}|${groupNumber}`));
    });
  }

  const columnIds = columns.map((column) => column.id);
  const studentIds = students.map((student) => student.id);
  let gradesByKey = new Map();
  if (columnIds.length && studentIds.length) {
    let rows = [];
    try {
      rows = await db.all(
        `
          SELECT
            jg.column_id,
            jg.student_id,
            jg.score,
            jg.teacher_comment,
            jg.submission_status,
            jg.graded_at,
            jg.graded_by,
            jgm.status AS moderation_status,
            jgm.moderated_score,
            jgm.reviewed_at AS moderation_reviewed_at,
            jgm.reviewed_by AS moderation_reviewed_by
          FROM journal_grades jg
          LEFT JOIN journal_grade_moderations jgm
            ON jgm.column_id = jg.column_id
           AND jgm.student_id = jg.student_id
          WHERE jg.column_id = ANY(?::int[])
            AND jg.student_id = ANY(?::int[])
            AND jg.deleted_at IS NULL
        `,
        [columnIds, studentIds]
      );
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      try {
        rows = await db.all(
          `
            SELECT
              jg.column_id,
              jg.student_id,
              jg.score,
              jg.teacher_comment,
              jg.submission_status,
              jg.graded_at,
              jg.graded_by
            FROM journal_grades jg
            WHERE jg.column_id = ANY(?::int[])
              AND jg.student_id = ANY(?::int[])
          `,
          [columnIds, studentIds]
        );
      } catch (legacyErr) {
        if (!isDbSchemaCompatibilityError(legacyErr)) {
          throw legacyErr;
        }
        rows = [];
      }
    }
    gradesByKey = new Map(
      (rows || []).map((row) => [
        `${Number(row.column_id)}|${Number(row.student_id)}`,
        {
          score: resolveEffectiveGradeScore(
            { score: row.score },
            { status: row.moderation_status, moderated_score: row.moderated_score }
          ),
          original_score: Number(row.score),
          teacher_comment: row.teacher_comment || '',
          submission_status: String(row.submission_status || ''),
          graded_at: row.graded_at || null,
          graded_by: Number.isFinite(Number(row.graded_by)) ? Number(row.graded_by) : null,
          moderation_status: normalizeJournalModerationStatus(row.moderation_status),
          moderation_score: Number.isFinite(Number(row.moderated_score)) ? Number(row.moderated_score) : null,
          moderation_reviewed_at: row.moderation_reviewed_at || null,
          moderation_reviewed_by: Number.isFinite(Number(row.moderation_reviewed_by))
            ? Number(row.moderation_reviewed_by)
            : null,
        },
      ])
    );
  }

  const resolveHomeworkContextForCell = (column, studentGroupNumber) => {
    const fallbackHomeworkId = Number(column?.source_homework_id || 0);
    if (!Number.isFinite(fallbackHomeworkId) || fallbackHomeworkId < 1) {
      return { homework_id: null, due_row: column };
    }
    if (!column.source_homework_is_teacher || !column.source_homework_batch_key) {
      return {
        homework_id: fallbackHomeworkId,
        due_row: teacherBatchLookup.byHomeworkId.get(fallbackHomeworkId) || column,
      };
    }
    const groupNumber = Number(studentGroupNumber || 0);
    if (Number.isInteger(groupNumber) && groupNumber > 0) {
      const mapped = teacherBatchLookup.byBatchGroup.get(`${column.source_homework_batch_key}|${groupNumber}`);
      if (mapped && Number(mapped.id) > 0) {
        return { homework_id: Number(mapped.id), due_row: mapped };
      }
    }
    return {
      homework_id: fallbackHomeworkId,
      due_row: teacherBatchLookup.byHomeworkId.get(fallbackHomeworkId) || column,
    };
  };

  const homeworkIdSet = new Set();
  columns.forEach((column) => {
    const fallbackHomeworkId = Number(column.source_homework_id || 0);
    if (!Number.isFinite(fallbackHomeworkId) || fallbackHomeworkId < 1) return;
    if (!column.source_homework_is_teacher || !column.source_homework_batch_key) {
      homeworkIdSet.add(fallbackHomeworkId);
      return;
    }
    students.forEach((student) => {
      const context = resolveHomeworkContextForCell(column, student.group_number);
      if (Number(context.homework_id) > 0) {
        homeworkIdSet.add(Number(context.homework_id));
      }
    });
  });
  const homeworkIds = Array.from(homeworkIdSet);

  let submissionsByKey = new Map();
  if (homeworkIds.length && studentIds.length) {
    let rows = [];
    try {
      rows = await db.all(
        `
          SELECT homework_id, student_id, submission_text, link_url, file_path, file_name, submitted_at, updated_at
          FROM homework_submissions
          WHERE homework_id = ANY(?::int[])
            AND student_id = ANY(?::int[])
        `,
        [homeworkIds, studentIds]
      );
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      rows = [];
    }
    submissionsByKey = new Map(
      (rows || []).map((row) => [
        `${Number(row.homework_id)}|${Number(row.student_id)}`,
        {
          submission_text: row.submission_text || '',
          link_url: row.link_url || '',
          file_path: row.file_path || '',
          file_name: normalizeUploadedOriginalName(row.file_name),
          submitted_at: row.submitted_at || null,
          updated_at: row.updated_at || null,
        },
      ])
    );
  }

  const scoringColumnIndexesByType = new Map();
  columns.forEach((column, index) => {
    const type = normalizeColumnType(column.column_type);
    if (!JOURNAL_SCORING_TYPES.includes(type)) return;
    if (!column.include_in_final) return;
    if (!getGradingTypeEnabled(gradingSettings, type)) return;
    if (!scoringColumnIndexesByType.has(type)) {
      scoringColumnIndexesByType.set(type, []);
    }
    scoringColumnIndexesByType.get(type).push(index);
  });

  const rows = students.map((student) => {
    const cells = columns.map((column) => {
      const grade = gradesByKey.get(`${column.id}|${student.id}`) || null;
      const homeworkContext = resolveHomeworkContextForCell(column, student.group_number);
      const submission = homeworkContext.homework_id
        ? (submissionsByKey.get(`${homeworkContext.homework_id}|${student.id}`) || null)
        : null;
      let status = 'missing';
      if (homeworkContext.homework_id) {
        status = resolveHomeworkSubmissionStatus(
          {
            custom_due_date: homeworkContext.due_row?.custom_due_date || column.custom_due_date,
            class_date: homeworkContext.due_row?.class_date || column.class_date,
          },
          submission
        );
      } else if (grade && Number.isFinite(grade.score)) {
        status = 'manual';
      }
      if (grade && grade.submission_status) {
        status = grade.submission_status;
      }
      return {
        column_id: column.id,
        student_id: student.id,
        score: grade && Number.isFinite(grade.score) ? Number(grade.score) : null,
        teacher_comment: grade ? grade.teacher_comment : '',
        graded_at: grade ? grade.graded_at : null,
        status,
        submission,
      };
    });
    let rawEarned = 0;
    let rawMax = 0;
    let weightedEarned = 0;
    const typeBreakdown = [];
    JOURNAL_SCORING_TYPES.forEach((type) => {
      const indexes = scoringColumnIndexesByType.get(type) || [];
      if (!indexes.length) return;
      const typeWeight = getGradingTypeWeightPoints(gradingSettings, type);
      const typeRawMax = indexes.reduce((sum, idx) => sum + parsePositiveDecimal(columns[idx]?.max_points, 0), 0);
      const typeRawEarned = indexes.reduce((sum, idx) => {
        const score = Number(cells[idx]?.score);
        return sum + (Number.isFinite(score) ? score : 0);
      }, 0);
      rawEarned += typeRawEarned;
      rawMax += typeRawMax;
      const ratio = typeRawMax > 0 ? Math.max(0, Math.min(1, typeRawEarned / typeRawMax)) : 0;
      const contribution = typeWeight > 0 ? ratio * typeWeight : 0;
      if (typeRawMax > 0 && typeWeight > 0) {
        weightedEarned += contribution;
      }
      typeBreakdown.push({
        type,
        label: JOURNAL_SCORING_TYPE_META[type]?.label || type,
        columns_count: indexes.length,
        weight_points: Math.round(typeWeight * 100) / 100,
        raw_earned: Math.round(typeRawEarned * 100) / 100,
        raw_max: Math.round(typeRawMax * 100) / 100,
        ratio: Math.round(ratio * 10000) / 10000,
        contribution: Math.round(contribution * 100) / 100,
      });
    });
    const finalScore = Math.min(100, weightedEarned);
    return {
      student,
      cells,
      raw_earned: Math.round(rawEarned * 100) / 100,
      raw_max: Math.round(rawMax * 100) / 100,
      weighted_earned: Math.round(weightedEarned * 100) / 100,
      final_score: Math.round(finalScore * 100) / 100,
      type_breakdown: typeBreakdown,
    };
  });

  return {
    gradingSettings,
    columns,
    rows,
  };
}

async function buildJournalInsightsContext({
  req,
  journalScope,
  teacherJournalMode,
  payloadSource = {},
}) {
  const payload = payloadSource && typeof payloadSource === 'object' ? payloadSource : {};
  const lang = getPreferredLang(req);
  const subjectOptions = await getJournalSubjectOptionsForUser(req, journalScope, teacherJournalMode);
  const courseMap = new Map();
  (subjectOptions || []).forEach((item) => {
    const courseId = Number(item.course_id || 0);
    if (!Number.isFinite(courseId) || courseId < 1) return;
    if (!courseMap.has(courseId)) {
      courseMap.set(courseId, {
        course_id: courseId,
        course_name: String(item.course_name || `Course ${courseId}`),
      });
    }
  });
  const courseOptions = Array.from(courseMap.values()).sort((a, b) => Number(a.course_id) - Number(b.course_id));
  const fallbackCourseId = parsePositiveIntStrict(
    req?.session?.user?.course_id,
    courseOptions.length ? Number(courseOptions[0].course_id) : null
  );
  let selectedCourseId = parsePositiveIntStrict(payload.course_id, fallbackCourseId);
  if (!courseOptions.some((item) => Number(item.course_id) === Number(selectedCourseId))) {
    selectedCourseId = courseOptions.length ? Number(courseOptions[0].course_id) : null;
  }
  const selectedCourse = (courseOptions || []).find((item) => Number(item.course_id) === Number(selectedCourseId)) || null;

  const subjectsInCourse = (subjectOptions || []).filter(
    (item) => Number(item.course_id) === Number(selectedCourseId)
  );
  const requestedSubjectId = parseNonZeroIntStrict(payload.subject_id);
  let selectedSubject = requestedSubjectId
    ? ((subjectsInCourse || []).find((item) => Number(item.subject_id) === Number(requestedSubjectId)) || null)
    : null;
  if (!selectedSubject && subjectsInCourse.length) {
    selectedSubject = subjectsInCourse[0];
  }

  const scopeOptionSet = teacherJournalMode
    ? JOURNAL_INSIGHTS_SCOPE_OPTIONS.filter((item) =>
      item.key === 'all-courses' ? courseOptions.length > 1 : true
    )
    : JOURNAL_INSIGHTS_SCOPE_OPTIONS.filter((item) => item.key === 'student');
  const allowedScopeKeys = new Set((scopeOptionSet || []).map((item) => item.key));
  let scopeType = normalizeJournalInsightsScope(
    payload.scope_type,
    teacherJournalMode ? 'subject' : 'student'
  );
  if (!allowedScopeKeys.has(scopeType)) {
    scopeType = scopeOptionSet.length ? scopeOptionSet[0].key : 'student';
  }
  const isCourseAggregateScope = () => (
    scopeType === 'course'
    || scopeType === 'all-courses'
    || scopeType === 'student-course'
  );
  if (!isCourseAggregateScope() && !selectedSubject && subjectsInCourse.length) {
    selectedSubject = subjectsInCourse[0];
  }
  if (!isCourseAggregateScope() && !selectedSubject) {
    if (allowedScopeKeys.has('course')) {
      scopeType = 'course';
    } else if (allowedScopeKeys.has('all-courses')) {
      scopeType = 'all-courses';
    } else {
      scopeType = 'student';
    }
  }
  if (!teacherJournalMode) {
    scopeType = 'student';
  }
  const selectedJournalStorageSubjectId = selectedSubject
    ? resolveJournalStorageSubjectId(selectedSubject)
    : null;
  const selectedJournalHasStorageBinding = Boolean(selectedJournalStorageSubjectId);
  const selectedJournalSupportsLegacyMutations = Number(selectedJournalStorageSubjectId || 0) > 0;

  const period = normalizeJournalInsightsPeriod(payload.period, 'semester');
  const selectedSemester = selectedCourseId ? await getActiveSemester(selectedCourseId) : null;
  const selectedSemesterId = selectedSemester ? Number(selectedSemester.id) : null;
  const activeSemesterByCourseId = new Map();
  if (scopeType === 'all-courses') {
    const allSemesters = await Promise.all(
      (courseOptions || []).map(async (course) => ([
        Number(course.course_id || 0),
        await getActiveSemester(Number(course.course_id || 0)),
      ]))
    );
    (allSemesters || []).forEach(([courseId, semester]) => {
      const safeCourseId = Number(courseId || 0);
      if (Number.isInteger(safeCourseId) && safeCourseId > 0) {
        activeSemesterByCourseId.set(safeCourseId, semester || null);
      }
    });
  } else if (selectedCourseId) {
    activeSemesterByCourseId.set(Number(selectedCourseId), selectedSemester || null);
  }
  const periodSemesterStartDate = (() => {
    if (scopeType !== 'all-courses') {
      return String(selectedSemester?.start_date || '');
    }
    const semesterStartDates = Array.from(activeSemesterByCourseId.values())
      .map((semester) => String(semester?.start_date || '').trim())
      .filter((value) => isValidDateString(value))
      .sort();
    return semesterStartDates.length ? semesterStartDates[0] : '';
  })();
  const periodWindow = resolveJournalInsightsSince(period, periodSemesterStartDate);
  const sinceIso = periodWindow.sinceIso || '';
  const sinceDate = periodWindow.sinceDate || '';

  let selectedGroupNumber = parsePositiveIntStrict(payload.group_number);
  let selectedStudentId = parsePositiveIntStrict(payload.student_id);
  const returnSubjectId = parseNonZeroIntStrict(payload.return_subject_id);
  const returnAttendanceDateRaw = String(payload.return_attendance_date || '').trim();
  const returnAttendanceDate = isValidDateString(returnAttendanceDateRaw) ? returnAttendanceDateRaw : '';
  const returnAttendanceClassNumber = parsePositiveIntStrict(payload.return_attendance_class_number);
  const returnAttendanceQuick = parseBinaryFlag(payload.return_attendance_quick, 0);

  const groupOptionSet = new Set();
  let studentOptions = [];
  let scopeRows = [];
  let rankingRows = [];
  let courseSubjectSummaries = [];
  let selectedStudentProfile = null;
  let activeColumnsCount = 0;

  const stripLeadingAnd = (clause) => String(clause || '').replace(/^\s*AND\s+/i, '').trim();

  const mapRowsToRankingRows = (rows = []) => (
    (rows || []).map((row) => ({
      student_id: Number(row?.student?.id || 0),
      full_name: String(row?.student?.full_name || '').trim() || `Student ${Number(row?.student?.id || 0)}`,
      group_number: Number(row?.student?.group_number || 0),
      final_score: roundToPrecision(row?.final_score, 2),
      weighted_earned: roundToPrecision(row?.weighted_earned, 2),
      raw_earned: roundToPrecision(row?.raw_earned, 2),
      raw_max: roundToPrecision(row?.raw_max, 2),
      subjects_count: 1,
    }))
      .filter((row) => Number.isFinite(row.student_id) && row.student_id > 0)
  );

  if (scopeType === 'course' || scopeType === 'all-courses' || scopeType === 'student-course') {
    const subjects = scopeType === 'all-courses' ? (subjectOptions || []) : (subjectsInCourse || []);
    const studentsById = new Map();
    const subjectRowsBag = [];
    for (const subject of subjects) {
      const matrixSubjectId = resolveJournalStorageSubjectId(subject);
      if (!matrixSubjectId) {
        continue;
      }
      const restrictedGroups = (!journalScope.fullAccess && !subject.has_all_groups)
        ? new Set(
          (subject.group_numbers || [])
            .map((value) => Number(value))
            .filter((value) => Number.isInteger(value) && value > 0)
        )
        : null;
      const matrixSemester = scopeType === 'all-courses'
        ? activeSemesterByCourseId.get(Number(subject.course_id || 0))
        : selectedSemester;
      const matrix = await buildJournalMatrix({
        subjectId: Number(matrixSubjectId),
        courseId: Number(subject.course_id),
        semesterId: matrixSemester && Number(matrixSemester.id) > 0 ? Number(matrixSemester.id) : null,
        actorUserId: Number(req.session.user.id),
        groupFilterSet: restrictedGroups,
        studentFilterIds: !teacherJournalMode ? [Number(req.session.user.id)] : [],
      });
      const rows = Array.isArray(matrix.rows) ? matrix.rows : [];
      subjectRowsBag.push({
        subject,
        rows,
        matrixSubjectId: Number(matrixSubjectId),
      });
      rows.forEach((row) => {
        const groupNumber = Number(row?.student?.group_number || 0);
        if (Number.isInteger(groupNumber) && groupNumber > 0) {
          groupOptionSet.add(groupNumber);
        }
      });
      const scoreList = rows
        .map((row) => Number(row.final_score))
        .filter((value) => Number.isFinite(value));
      const subjectDisplayName = scopeType === 'all-courses'
        ? `${String(subject.course_name || `Course ${Number(subject.course_id || 0)}`)} • ${String(subject.subject_name || '')}`
        : String(subject.subject_name || '');
      courseSubjectSummaries.push({
        course_id: Number(subject.course_id || 0),
        subject_id: Number(matrixSubjectId),
        subject_name: subjectDisplayName,
        students_count: rows.length,
        average_final_score: scoreList.length ? roundToPrecision(scoreList.reduce((sum, value) => sum + value, 0) / scoreList.length, 2) : 0,
        at_risk_students: scoreList.filter((value) => value < 60).length,
      });
      rows.forEach((row) => {
        const studentId = Number(row?.student?.id || 0);
        if (!Number.isFinite(studentId) || studentId < 1) return;
        if (!studentsById.has(studentId)) {
          studentsById.set(studentId, {
            student_id: studentId,
            full_name: String(row?.student?.full_name || '').trim() || `Student ${studentId}`,
            group_number: Number(row?.student?.group_number || 0),
            course_id: Number(subject.course_id || 0),
            course_name: String(subject.course_name || ''),
            total_score: 0,
            subjects_count: 0,
          });
        }
        const target = studentsById.get(studentId);
        target.total_score += Number(row.final_score || 0);
        target.subjects_count += 1;
      });
    }
    studentOptions = Array.from(studentsById.values())
      .map((item) => ({
        id: Number(item.student_id),
        full_name: item.full_name,
        group_number: Number(item.group_number || 0),
        course_id: Number(item.course_id || 0),
        course_name: String(item.course_name || ''),
      }))
      .sort((a, b) => String(a.full_name || '').localeCompare(String(b.full_name || '')));
    rankingRows = Array.from(studentsById.values())
      .map((item) => ({
        student_id: Number(item.student_id),
        full_name: item.full_name,
        group_number: Number(item.group_number || 0),
        course_id: Number(item.course_id || 0),
        course_name: String(item.course_name || ''),
        final_score: item.subjects_count > 0 ? roundToPrecision(item.total_score / item.subjects_count, 2) : 0,
        weighted_earned: 0,
        raw_earned: 0,
        raw_max: 0,
        subjects_count: Number(item.subjects_count || 0),
      }))
      .filter((item) => item.subjects_count > 0);
    if (scopeType === 'student-course') {
      if (!studentOptions.some((item) => Number(item.id) === Number(selectedStudentId))) {
        selectedStudentId = studentOptions.length ? Number(studentOptions[0].id) : null;
      }
      selectedStudentProfile = studentOptions.find((item) => Number(item.id) === Number(selectedStudentId)) || null;
      const selectedRankingRow = rankingRows.find((item) => Number(item.student_id) === Number(selectedStudentId)) || null;
      scopeRows = selectedRankingRow
        ? [{
          final_score: roundToPrecision(selectedRankingRow.final_score, 2),
          student: {
            id: Number(selectedRankingRow.student_id),
            full_name: String(selectedRankingRow.full_name || ''),
            group_number: Number(selectedRankingRow.group_number || 0),
          },
        }]
        : [];
      courseSubjectSummaries = (subjectRowsBag || []).map(({ subject, rows, matrixSubjectId }) => {
        const matchedRow = (rows || []).find((row) => Number(row?.student?.id || 0) === Number(selectedStudentId)) || null;
        const finalScore = matchedRow ? roundToPrecision(matchedRow.final_score, 2) : 0;
        return {
          course_id: Number(subject?.course_id || 0),
          subject_id: Number(matrixSubjectId || 0),
          subject_name: String(subject?.subject_name || ''),
          students_count: matchedRow ? 1 : 0,
          average_final_score: finalScore,
          at_risk_students: matchedRow && finalScore < 60 ? 1 : 0,
        };
      });
    } else {
      scopeRows = rankingRows.map((row) => ({
        final_score: row.final_score,
        student: {
          id: row.student_id,
          full_name: row.full_name,
          group_number: row.group_number,
        },
      }));
    }
  } else if (selectedSubject) {
    const matrixSubjectId = selectedJournalHasStorageBinding
      ? Number(selectedJournalStorageSubjectId)
      : null;
    const restrictedGroups = (!journalScope.fullAccess && !selectedSubject.has_all_groups)
      ? new Set(
        (selectedSubject.group_numbers || [])
          .map((value) => Number(value))
          .filter((value) => Number.isInteger(value) && value > 0)
      )
      : null;

    const matrix = matrixSubjectId
      ? await buildJournalMatrix({
        subjectId: matrixSubjectId,
        courseId: Number(selectedSubject.course_id),
        semesterId: selectedSemesterId,
        actorUserId: Number(req.session.user.id),
        groupFilterSet: restrictedGroups,
        studentFilterIds: !teacherJournalMode ? [Number(req.session.user.id)] : [],
      })
      : {
        columns: [],
        rows: [],
      };
    const baseRows = Array.isArray(matrix.rows) ? matrix.rows : [];
    activeColumnsCount = Array.isArray(matrix.columns) ? matrix.columns.length : 0;
    baseRows.forEach((row) => {
      const groupNumber = Number(row?.student?.group_number || 0);
      if (Number.isInteger(groupNumber) && groupNumber > 0) {
        groupOptionSet.add(groupNumber);
      }
    });

    if (scopeType === 'group') {
      if (!groupOptionSet.has(Number(selectedGroupNumber))) {
        selectedGroupNumber = groupOptionSet.size ? Math.min(...Array.from(groupOptionSet.values())) : null;
      }
      if (!selectedGroupNumber) {
        scopeType = 'subject';
      }
    }

    const rankingBaseRows = (scopeType === 'group' && selectedGroupNumber)
      ? baseRows.filter((row) => Number(row?.student?.group_number || 0) === Number(selectedGroupNumber))
      : baseRows;

    const studentMap = new Map();
    rankingBaseRows.forEach((row) => {
      const studentId = Number(row?.student?.id || 0);
      if (!Number.isFinite(studentId) || studentId < 1) return;
      if (!studentMap.has(studentId)) {
        studentMap.set(studentId, {
          id: studentId,
          full_name: String(row?.student?.full_name || '').trim() || `Student ${studentId}`,
          group_number: Number(row?.student?.group_number || 0),
        });
      }
    });
    studentOptions = Array.from(studentMap.values()).sort((a, b) =>
      String(a.full_name || '').localeCompare(String(b.full_name || ''))
    );

    if (scopeType === 'student') {
      if (!teacherJournalMode) {
        selectedStudentId = Number(req.session.user.id);
      }
      if (!studentOptions.some((item) => Number(item.id) === Number(selectedStudentId))) {
        selectedStudentId = studentOptions.length ? Number(studentOptions[0].id) : null;
      }
      scopeRows = rankingBaseRows.filter((row) => Number(row?.student?.id || 0) === Number(selectedStudentId));
      selectedStudentProfile = studentOptions.find((item) => Number(item.id) === Number(selectedStudentId)) || null;
    } else {
      scopeRows = rankingBaseRows;
    }

    rankingRows = mapRowsToRankingRows(rankingBaseRows);
    const scopeScoreList = scopeRows
      .map((row) => Number(row.final_score))
      .filter((value) => Number.isFinite(value));
    courseSubjectSummaries = [{
      course_id: Number(selectedSubject.course_id || 0),
      subject_id: Number(selectedJournalStorageSubjectId || 0),
      subject_name: String(selectedSubject.subject_name || ''),
      students_count: scopeRows.length,
      average_final_score: scopeScoreList.length ? roundToPrecision(scopeScoreList.reduce((sum, value) => sum + value, 0) / scopeScoreList.length, 2) : 0,
      at_risk_students: scopeScoreList.filter((value) => value < 60).length,
    }];
  }

  const groupOptions = Array.from(groupOptionSet.values())
    .filter((value) => Number.isInteger(value) && value > 0)
    .sort((a, b) => a - b);

  const ranking = buildRankingFromRows(rankingRows);
  if (!selectedStudentProfile && selectedStudentId) {
    const matchedRankingRow = ranking.find((item) => Number(item.student_id) === Number(selectedStudentId));
    if (matchedRankingRow) {
      selectedStudentProfile = {
        id: Number(matchedRankingRow.student_id),
        full_name: String(matchedRankingRow.full_name || ''),
        group_number: Number(matchedRankingRow.group_number || 0),
      };
    }
  }

  const compareOptions = [{ key: 'none', label: 'No compare' }];
  const supportsGroupCompare = ['subject', 'group'].includes(scopeType)
    && rankingRows.some((row) => Number(row.group_number || 0) > 0);
  const supportsCourseCompare = ['course', 'all-courses', 'student-course'].includes(scopeType)
    && rankingRows.some((row) => Number(row.course_id || 0) > 0);
  if (supportsGroupCompare) {
    compareOptions.push({ key: 'group', label: 'Compare groups' });
  }
  if (supportsCourseCompare) {
    compareOptions.push({ key: 'course', label: 'Compare courses' });
  }
  let compareMode = normalizeJournalInsightsCompare(
    payload.compare_mode,
    supportsGroupCompare ? 'group' : (supportsCourseCompare ? 'course' : 'none')
  );
  if (!compareOptions.some((item) => item.key === compareMode)) {
    compareMode = 'none';
  }
  let comparisonRows = [];
  if (compareMode === 'group') {
    const byGroup = new Map();
    rankingRows.forEach((row) => {
      const groupNumber = Number(row.group_number || 0);
      const score = Number(row.final_score || 0);
      if (!Number.isInteger(groupNumber) || groupNumber < 1 || !Number.isFinite(score)) return;
      if (!byGroup.has(groupNumber)) {
        byGroup.set(groupNumber, {
          key: `group_${groupNumber}`,
          label: `Group ${groupNumber}`,
          participants_count: 0,
          score_sum: 0,
          at_risk_count: 0,
          excellent_count: 0,
        });
      }
      const bucket = byGroup.get(groupNumber);
      bucket.participants_count += 1;
      bucket.score_sum += score;
      if (score < 60) bucket.at_risk_count += 1;
      if (score >= 90) bucket.excellent_count += 1;
    });
    comparisonRows = Array.from(byGroup.values())
      .map((item) => ({
        key: item.key,
        label: item.label,
        participants_count: Number(item.participants_count || 0),
        average_score: Number(item.participants_count || 0) > 0
          ? roundToPrecision(item.score_sum / item.participants_count, 2)
          : 0,
        at_risk_count: Number(item.at_risk_count || 0),
        excellent_count: Number(item.excellent_count || 0),
      }))
      .sort((a, b) => Number(b.average_score || 0) - Number(a.average_score || 0));
  } else if (compareMode === 'course') {
    const courseNameById = new Map();
    (courseOptions || []).forEach((item) => {
      const courseId = Number(item.course_id || 0);
      if (!Number.isInteger(courseId) || courseId < 1) return;
      courseNameById.set(courseId, String(item.course_name || `Course ${courseId}`));
    });
    const byCourse = new Map();
    rankingRows.forEach((row) => {
      const courseId = Number(row.course_id || 0);
      const score = Number(row.final_score || 0);
      if (!Number.isInteger(courseId) || courseId < 1 || !Number.isFinite(score)) return;
      if (!byCourse.has(courseId)) {
        byCourse.set(courseId, {
          key: `course_${courseId}`,
          label: String(row.course_name || courseNameById.get(courseId) || `Course ${courseId}`),
          participants_count: 0,
          score_sum: 0,
          at_risk_count: 0,
          excellent_count: 0,
        });
      }
      const bucket = byCourse.get(courseId);
      bucket.participants_count += 1;
      bucket.score_sum += score;
      if (score < 60) bucket.at_risk_count += 1;
      if (score >= 90) bucket.excellent_count += 1;
    });
    comparisonRows = Array.from(byCourse.values())
      .map((item) => ({
        key: item.key,
        label: item.label,
        participants_count: Number(item.participants_count || 0),
        average_score: Number(item.participants_count || 0) > 0
          ? roundToPrecision(item.score_sum / item.participants_count, 2)
          : 0,
        at_risk_count: Number(item.at_risk_count || 0),
        excellent_count: Number(item.excellent_count || 0),
      }))
      .sort((a, b) => Number(b.average_score || 0) - Number(a.average_score || 0));
  }

  const scopeScoreValues = scopeRows
    .map((row) => Number(row.final_score))
    .filter((value) => Number.isFinite(value));
  const participantsCount = scopeRows.length;
  const averageScore = scopeScoreValues.length
    ? roundToPrecision(scopeScoreValues.reduce((sum, value) => sum + value, 0) / scopeScoreValues.length, 2)
    : 0;
  const medianScore = computeMedianScore(scopeScoreValues);
  const topScore = scopeScoreValues.length
    ? roundToPrecision(Math.max(...scopeScoreValues), 2)
    : 0;
  const atRiskCount = scopeScoreValues.filter((value) => value < 60).length;
  const excellentCount = scopeScoreValues.filter((value) => value >= 90).length;

  const trendSubjectIds = (() => {
    if (scopeType === 'course' || scopeType === 'all-courses' || scopeType === 'student-course') {
      return Array.from(
        new Set(
          (courseSubjectSummaries || [])
            .map((item) => Number(item.subject_id || 0))
            .filter((value) => Number.isInteger(value) && value > 0)
        )
      );
    }
    const selectedTrendSubjectId = parsePositiveIntStrict(selectedJournalStorageSubjectId);
    if (selectedTrendSubjectId) {
      return [Number(selectedTrendSubjectId)];
    }
    return [];
  })();
  const trendCourseIds = (() => {
    if (scopeType === 'all-courses') {
      return Array.from(
        new Set(
          (courseSubjectSummaries || [])
            .map((item) => Number(item.course_id || 0))
            .filter((value) => Number.isInteger(value) && value > 0)
        )
      );
    }
    const safeCourseId = Number(selectedCourseId || 0);
    return Number.isInteger(safeCourseId) && safeCourseId > 0 ? [safeCourseId] : [];
  })();

  let gradeTrend = [];
  let attendanceTrend = [];
  if (trendSubjectIds.length && trendCourseIds.length) {
    const gradeBucketExpr = buildJournalInsightsGradeBucketSql(period);
    const gradeWhere = [
      'COALESCE(jc.is_archived, 0) = 0',
      'jg.deleted_at IS NULL',
      'jg.graded_at IS NOT NULL',
    ];
    const gradeParams = [];
    if (trendCourseIds.length === 1) {
      gradeWhere.push('jc.course_id = ?');
      gradeParams.push(Number(trendCourseIds[0]));
    } else {
      gradeWhere.push('jc.course_id = ANY(?::int[])');
      gradeParams.push(trendCourseIds);
    }
    if (scopeType !== 'all-courses') {
      const gradeSemesterFilter = buildJournalMixedSemesterCondition('jc', selectedSemesterId);
      const gradeSemesterClause = stripLeadingAnd(gradeSemesterFilter.clause);
      if (gradeSemesterClause) gradeWhere.push(gradeSemesterClause);
      if (Array.isArray(gradeSemesterFilter.params) && gradeSemesterFilter.params.length) {
        gradeParams.push(...gradeSemesterFilter.params);
      }
    }
    if (trendSubjectIds.length === 1) {
      gradeWhere.push('jc.subject_id = ?');
      gradeParams.push(Number(trendSubjectIds[0]));
    } else {
      gradeWhere.push('jc.subject_id = ANY(?::int[])');
      gradeParams.push(trendSubjectIds);
    }
    if (sinceIso) {
      gradeWhere.push('jg.graded_at >= ?');
      gradeParams.push(sinceIso);
    }
    if ((scopeType === 'student' || scopeType === 'student-course') && selectedStudentId) {
      gradeWhere.push('jg.student_id = ?');
      gradeParams.push(Number(selectedStudentId));
    }
    const gradeNeedsGroupJoin = scopeType === 'group' && selectedGroupNumber;
    const gradeRows = await db.all(
      `
        SELECT
          ${gradeBucketExpr} AS bucket,
          AVG(
            CASE
              WHEN COALESCE(jgm.status, '') IN ('approved', 'adjusted')
                AND jgm.moderated_score IS NOT NULL
                THEN (jgm.moderated_score / NULLIF(jc.max_points, 0)) * 100
              ELSE (jg.score / NULLIF(jc.max_points, 0)) * 100
            END
          ) AS avg_score_percent,
          COUNT(*)::int AS events_count
        FROM journal_grades jg
        JOIN journal_columns jc ON jc.id = jg.column_id
        ${gradeNeedsGroupJoin
    ? 'JOIN student_groups sg ON sg.student_id = jg.student_id AND sg.subject_id = jc.subject_id'
    : ''}
        LEFT JOIN journal_grade_moderations jgm
          ON jgm.column_id = jg.column_id
         AND jgm.student_id = jg.student_id
        WHERE ${gradeWhere.join(' AND ')}
          ${gradeNeedsGroupJoin ? 'AND sg.group_number = ?' : ''}
        GROUP BY bucket
        ORDER BY bucket ASC
      `,
      gradeNeedsGroupJoin
        ? [...gradeParams, Number(selectedGroupNumber)]
        : gradeParams
    );
    gradeTrend = (gradeRows || []).map((row) => ({
      bucket: String(row.bucket || ''),
      avg_score_percent: roundToPrecision(row.avg_score_percent, 2),
      events_count: Number(row.events_count || 0),
    }));

    const attendanceBucketExpr = buildJournalInsightsAttendanceBucketSql(period);
    const attendanceWhere = [];
    const attendanceParams = [];
    if (trendCourseIds.length === 1) {
      attendanceWhere.push('ar.course_id = ?');
      attendanceParams.push(Number(trendCourseIds[0]));
    } else {
      attendanceWhere.push('ar.course_id = ANY(?::int[])');
      attendanceParams.push(trendCourseIds);
    }
    if (scopeType !== 'all-courses') {
      const attendanceSemesterFilter = buildJournalMixedSemesterCondition('ar', selectedSemesterId);
      const attendanceSemesterClause = stripLeadingAnd(attendanceSemesterFilter.clause);
      if (attendanceSemesterClause) attendanceWhere.push(attendanceSemesterClause);
      if (Array.isArray(attendanceSemesterFilter.params) && attendanceSemesterFilter.params.length) {
        attendanceParams.push(...attendanceSemesterFilter.params);
      }
    }
    if (trendSubjectIds.length === 1) {
      attendanceWhere.push('ar.subject_id = ?');
      attendanceParams.push(Number(trendSubjectIds[0]));
    } else {
      attendanceWhere.push('ar.subject_id = ANY(?::int[])');
      attendanceParams.push(trendSubjectIds);
    }
    if (sinceDate) {
      attendanceWhere.push('ar.class_date >= ?');
      attendanceParams.push(sinceDate);
    }
    if (scopeType === 'group' && selectedGroupNumber) {
      attendanceWhere.push('ar.group_number = ?');
      attendanceParams.push(Number(selectedGroupNumber));
    }
    if ((scopeType === 'student' || scopeType === 'student-course') && selectedStudentId) {
      attendanceWhere.push('ar.student_id = ?');
      attendanceParams.push(Number(selectedStudentId));
    }
    const attendanceRows = await db.all(
      `
        SELECT
          ${attendanceBucketExpr} AS bucket,
          COUNT(*) FILTER (WHERE ar.status = 'present')::int AS present_count,
          COUNT(*) FILTER (WHERE ar.status = 'late')::int AS late_count,
          COUNT(*) FILTER (WHERE ar.status = 'absent')::int AS absent_count,
          COUNT(*) FILTER (WHERE ar.status = 'excused')::int AS excused_count,
          COUNT(*)::int AS total_count
        FROM attendance_records ar
        WHERE ${attendanceWhere.join(' AND ')}
        GROUP BY bucket
        ORDER BY bucket ASC
      `,
      attendanceParams
    );
    attendanceTrend = (attendanceRows || []).map((row) => ({
      bucket: String(row.bucket || ''),
      present_count: Number(row.present_count || 0),
      late_count: Number(row.late_count || 0),
      absent_count: Number(row.absent_count || 0),
      excused_count: Number(row.excused_count || 0),
      total_count: Number(row.total_count || 0),
    }));
  }

  const gradeEventsTotal = gradeTrend.reduce((sum, item) => sum + Number(item.events_count || 0), 0);
  const attendanceTotal = attendanceTrend.reduce((sum, item) => sum + Number(item.total_count || 0), 0);
  const attendanceAbsent = attendanceTrend.reduce((sum, item) => sum + Number(item.absent_count || 0), 0);
  const attendanceLate = attendanceTrend.reduce((sum, item) => sum + Number(item.late_count || 0), 0);
  const absentShare = attendanceTotal > 0
    ? roundToPrecision((attendanceAbsent / attendanceTotal) * 100, 2)
    : 0;
  const lateShare = attendanceTotal > 0
    ? roundToPrecision((attendanceLate / attendanceTotal) * 100, 2)
    : 0;
  const gradeDelta = gradeTrend.length >= 2
    ? roundToPrecision(
      Number(gradeTrend[gradeTrend.length - 1].avg_score_percent || 0)
      - Number(gradeTrend[0].avg_score_percent || 0),
      2
    )
    : 0;
  const riskRate = participantsCount > 0
    ? roundToPrecision((atRiskCount / participantsCount) * 100, 2)
    : 0;
  const excellenceRate = participantsCount > 0
    ? roundToPrecision((excellentCount / participantsCount) * 100, 2)
    : 0;
  const scoreConsistency = (() => {
    if (scopeScoreValues.length < 2) {
      return scopeScoreValues.length ? 100 : 0;
    }
    const mean = averageScore;
    if (!Number.isFinite(mean) || mean <= 0) return 0;
    const variance = scopeScoreValues.reduce((sum, value) => sum + ((value - mean) ** 2), 0) / scopeScoreValues.length;
    const stdDev = Math.sqrt(Math.max(0, variance));
    const normalized = 100 - ((stdDev / mean) * 100);
    return roundToPrecision(Math.max(0, Math.min(100, normalized)), 2);
  })();
  const attendanceReliability = roundToPrecision(
    Math.max(0, Math.min(100, 100 - absentShare - (lateShare * 0.5))),
    2
  );
  const momentumScore = roundToPrecision(
    Math.max(0, Math.min(100, 50 + gradeDelta - (absentShare * 0.1))),
    2
  );

  const periodLabel = (
    JOURNAL_INSIGHTS_PERIOD_OPTIONS.find((item) => item.key === period)
    || JOURNAL_INSIGHTS_PERIOD_OPTIONS[1]
  ).label;

  const scopeLabel = (() => {
    if (scopeType === 'all-courses') {
      return 'All courses';
    }
    if (scopeType === 'student-course') {
      if (selectedStudentProfile) {
        return selectedCourse
          ? `${selectedStudentProfile.full_name} • ${selectedCourse.course_name}`
          : `${selectedStudentProfile.full_name} • Course`;
      }
      return selectedCourse ? `Student • ${selectedCourse.course_name}` : 'Student course scope';
    }
    if (scopeType === 'course') {
      return selectedCourse ? `Course ${selectedCourse.course_name}` : 'Course scope';
    }
    if (scopeType === 'group') {
      return `${selectedSubject ? selectedSubject.subject_name : 'Subject'} • Group ${selectedGroupNumber || '-'}`;
    }
    if (scopeType === 'student') {
      return selectedStudentProfile
        ? `${selectedStudentProfile.full_name} • ${selectedSubject ? selectedSubject.subject_name : 'Subject'}`
        : (selectedSubject ? selectedSubject.subject_name : 'Student scope');
    }
    return selectedSubject ? selectedSubject.subject_name : 'Subject scope';
  })();

  let canPublishRating = false;
  let publishDisabledReason = '';
  let publishTarget = null;
  if (!teacherJournalMode) {
    publishDisabledReason = 'Rating publishing is available only in teacher/deanery mode.';
  } else if (!settingsCache.allow_messages) {
    publishDisabledReason = 'Messages are disabled in system settings.';
  } else if (!ranking.length) {
    publishDisabledReason = 'No ranking data to publish.';
  } else if (scopeType === 'student' || scopeType === 'student-course') {
    publishDisabledReason = 'Student scope is personal and cannot be published.';
  } else if (scopeType === 'all-courses') {
    publishDisabledReason = 'All-courses scope cannot be published as a single audience. Select a specific course or group.';
  } else if ((scopeType === 'subject' || scopeType === 'group') && selectedSubject && !selectedJournalSupportsLegacyMutations) {
    publishDisabledReason = 'Publishing for this subject is unavailable until legacy journal storage binding is created.';
  } else if (scopeType === 'course') {
    canPublishRating = true;
    publishTarget = {
      kind: 'course',
      course_id: Number(selectedCourseId || 0),
      semester_id: selectedSemesterId || null,
    };
  } else if (scopeType === 'group' && selectedSubject && selectedGroupNumber) {
    canPublishRating = true;
    publishTarget = {
      kind: 'group',
      course_id: Number(selectedCourseId || 0),
      semester_id: selectedSemesterId || null,
      subject_id: Number(selectedJournalStorageSubjectId || 0),
      group_number: Number(selectedGroupNumber || 0),
    };
  } else if (scopeType === 'subject' && selectedSubject && groupOptions.length === 1) {
    canPublishRating = true;
    publishTarget = {
      kind: 'group',
      course_id: Number(selectedCourseId || 0),
      semester_id: selectedSemesterId || null,
      subject_id: Number(selectedJournalStorageSubjectId || 0),
      group_number: Number(groupOptions[0]),
    };
  } else {
    publishDisabledReason = 'Select group scope to publish a ranking for a specific audience.';
  }

  const publishTargetSummary = journalInsightHelpers.describeRatingPublishTarget({
    publishTarget,
    scopeLabel,
    periodLabel,
    participantsCount,
    lang,
  });
  const snapshotWorkloadKeys = selectedJournalSupportsLegacyMutations
    ? [`${Number(selectedJournalStorageSubjectId || 0)}|${Number((publishTarget && publishTarget.group_number) || selectedGroupNumber || 0) || 'all'}`]
    : [];
  let latestPublishedRating = null;
  try {
    if (selectedCourseId) {
      const snapshotRows = await db.all(
        `
          SELECT *
          FROM rating_publication_snapshots
          WHERE course_id = ?
          ORDER BY published_at DESC, id DESC
          LIMIT 24
        `,
        [selectedCourseId]
      );
      const matchedSnapshot = journalInsightHelpers.findRelevantRatingSnapshot(snapshotRows, {
        courseId: selectedCourseId,
        semesterId: selectedSemesterId,
        subjectId: selectedJournalSupportsLegacyMutations ? Number(selectedJournalStorageSubjectId || 0) : null,
        groupNumber: (publishTarget && publishTarget.group_number) || selectedGroupNumber || null,
        scopeType,
        targetKind: publishTarget ? publishTarget.kind : '',
        workloadKeys: snapshotWorkloadKeys,
      });
      if (matchedSnapshot) {
        latestPublishedRating = journalInsightHelpers.formatRatingSnapshotCard(matchedSnapshot, lang);
      }
    }
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
  }
  const workflowLinks = {
    journalHref: buildJournalRedirectPath({
      subjectId: returnSubjectId || Number(selectedSubject?.subject_id || 0),
      attendanceDate: returnAttendanceDate,
      attendanceClassNumber: returnAttendanceClassNumber,
      attendanceQuick: returnAttendanceQuick,
    }),
    scheduleHref: '/schedule',
    teacherHubHref: teacherJournalMode ? '/teacher/hub' : '',
  };

  return {
    subjectOptions,
    courseOptions,
    selectedCourseId,
    selectedCourse,
    selectedSubject,
    selectedSemester: scopeType === 'all-courses' ? null : selectedSemester,
    scopeCourseCount: trendCourseIds.length,
    period,
    periodLabel,
    periodOptions: JOURNAL_INSIGHTS_PERIOD_OPTIONS,
    scopeType,
    scopeOptions: scopeOptionSet,
    compareMode,
    compareOptions,
    comparisonRows,
    groupOptions,
    selectedGroupNumber,
    studentOptions,
    selectedStudentId,
    selectedStudentProfile,
    ranking,
    rankingTop: ranking.slice(0, 30),
    scopeRows,
    courseSubjectSummaries,
    activeColumnsCount,
    summary: {
      participants_count: participantsCount,
      average_score: averageScore,
      median_score: medianScore,
      top_score: topScore,
      at_risk_count: atRiskCount,
      excellent_count: excellentCount,
      grade_events_total: gradeEventsTotal,
      attendance_records_total: attendanceTotal,
      attendance_absent_share: absentShare,
      attendance_late_share: lateShare,
      grade_delta: gradeDelta,
      risk_rate: riskRate,
      excellence_rate: excellenceRate,
      score_consistency: scoreConsistency,
      attendance_reliability: attendanceReliability,
      momentum_score: momentumScore,
    },
    trends: {
      bucket_mode: getJournalInsightsBucketMode(period),
      since_date: sinceDate,
      grade: gradeTrend,
      attendance: attendanceTrend,
    },
    scopeLabel,
    canPublishRating,
    publishDisabledReason,
    publishTarget,
    publishTargetSummary,
    latestPublishedRating,
    workflowLinks,
    returnJournalContext: {
      subjectId: returnSubjectId || Number(selectedSubject?.subject_id || 0) || null,
      attendanceDate: returnAttendanceDate,
      attendanceClassNumber: returnAttendanceClassNumber || null,
      attendanceQuick: returnAttendanceQuick ? 1 : 0,
    },
    selectedJournalHasStorageBinding,
    selectedJournalSupportsLegacyMutations,
    canManageAllSubjects: Boolean(journalScope.fullAccess),
  };
}

app.get('/journal/insights', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'journal.insights.init');
  }

  try {
    const journalScope = await getJournalAccessScope(req);
    if (!journalScope.canUseJournal) {
      return res.status(403).send('Forbidden (journal)');
    }
    const teacherJournalMode = canUseTeacherJournalMode(req, journalScope);
    const context = await buildJournalInsightsContext({
      req,
      journalScope,
      teacherJournalMode,
      payloadSource: req.query || {},
    });

    const decodeMessage = (rawValue) => {
      if (!rawValue) return '';
      try {
        return decodeURIComponent(String(rawValue));
      } catch (err) {
        return String(rawValue);
      }
    };

    return res.render('journal-insights', {
      username: req.session.user.username,
      role: req.session.role,
      settings: settingsCache,
      teacherJournalMode,
      ...context,
      error: decodeMessage(req.query.error),
      success: decodeMessage(req.query.ok),
    });
  } catch (err) {
    return handleDbError(res, err, 'journal.insights.page');
  }
});

app.get('/journal/insights/export.csv', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'journal.insights.export.init');
  }

  try {
    const journalScope = await getJournalAccessScope(req);
    if (!journalScope.canUseJournal) {
      return res.status(403).send('Forbidden (journal)');
    }
    const teacherJournalMode = canUseTeacherJournalMode(req, journalScope);
    const context = await buildJournalInsightsContext({
      req,
      journalScope,
      teacherJournalMode,
      payloadSource: req.query || {},
    });

    const csv = buildJournalInsightsCsv({
      context,
      teacherJournalMode,
    });
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const fileName = `journal-insights-${timestamp}.csv`;
    res.setHeader('Content-Type', 'text/csv; charset=utf-8');
    res.setHeader('Content-Disposition', `attachment; filename="${fileName}"`);

    logAction(db, req, 'journal_insights_export_csv', {
      scope_type: context.scopeType,
      compare_mode: context.compareMode || 'none',
      period: context.period,
      participants_count: Number(context?.summary?.participants_count || 0),
      ranking_count: Array.isArray(context.ranking) ? context.ranking.length : 0,
    });

    return res.send(csv);
  } catch (err) {
    return handleDbError(res, err, 'journal.insights.export');
  }
});

// Structured rating snapshot publisher. This route intentionally shadows the
// legacy publisher defined below so published rankings are reusable in My Day and Help.
app.post('/journal/insights/publish-rating', requireLogin, writeLimiter, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return res.redirect(buildJournalInsightsUrl({
      courseId: parsePositiveIntStrict(req.body.course_id, req.session?.user?.course_id),
      subjectId: parseNonZeroIntStrict(req.body.subject_id),
      scopeType: req.body.scope_type || 'subject',
      groupNumber: parsePositiveIntStrict(req.body.group_number),
      studentId: parsePositiveIntStrict(req.body.student_id),
      period: req.body.period || 'semester',
      compareMode: req.body.compare_mode || 'none',
      returnSubjectId: parseNonZeroIntStrict(req.body.return_subject_id),
      returnAttendanceDate: String(req.body.return_attendance_date || '').trim(),
      returnAttendanceClassNumber: parsePositiveIntStrict(req.body.return_attendance_class_number),
      returnAttendanceQuick: parseBinaryFlag(req.body.return_attendance_quick, 0),
      error: 'Database error',
    }));
  }

  try {
    const journalScope = await getJournalAccessScope(req);
    const teacherJournalMode = canUseTeacherJournalMode(req, journalScope);
    if (!journalScope.canUseJournal || !teacherJournalMode) {
      return res.status(403).send('Forbidden (journal)');
    }

    const context = await buildJournalInsightsContext({
      req,
      journalScope,
      teacherJournalMode,
      payloadSource: req.body || {},
    });

    const baseRedirect = {
      courseId: Number(context.selectedCourseId || 0),
      subjectId: Number(context.selectedSubject?.subject_id || 0),
      scopeType: context.scopeType,
      groupNumber: Number(context.selectedGroupNumber || 0),
      studentId: Number(context.selectedStudentId || 0),
      period: context.period,
      compareMode: context.compareMode || 'none',
      returnSubjectId: Number(context.returnJournalContext?.subjectId || 0),
      returnAttendanceDate: context.returnJournalContext?.attendanceDate || '',
      returnAttendanceClassNumber: Number(context.returnJournalContext?.attendanceClassNumber || 0),
      returnAttendanceQuick: Number(context.returnJournalContext?.attendanceQuick || 0),
    };

    if (!context.canPublishRating || !context.publishTarget) {
      return res.redirect(buildJournalInsightsUrl({
        ...baseRedirect,
        error: context.publishDisabledReason || 'Rating cannot be published for current scope',
      }));
    }

    const topNRaw = Number(req.body.top_n);
    const topN = Number.isFinite(topNRaw)
      ? Math.max(3, Math.min(30, Math.round(topNRaw)))
      : 10;
    const ratingRows = (context.ranking || []).slice(0, topN);
    if (!ratingRows.length) {
      return res.redirect(buildJournalInsightsUrl({
        ...baseRedirect,
        error: 'No ranking data to publish',
      }));
    }

    const lang = getPreferredLang(req);
    const createdAtIso = new Date().toISOString();
    const targetCourseId = Number(context.publishTarget.course_id || context.selectedCourseId || req.session.user.course_id || 0) || null;
    const targetSemesterId = context.publishTarget.semester_id ? Number(context.publishTarget.semester_id) : null;
    const targetSubjectId = context.publishTarget.subject_id
      ? Number(context.publishTarget.subject_id)
      : ((context.selectedSubject && Number(context.selectedSubject.subject_id || 0)) || null);
    const targetGroupNumber = context.publishTarget.group_number
      ? Number(context.publishTarget.group_number)
      : (Number(context.selectedGroupNumber || 0) || null);
    const ratingPayload = journalInsightHelpers.buildRatingSnapshotPayload({
      context: {
        scopeLabel: context.scopeLabel,
        periodLabel: context.periodLabel,
        scopeType: context.scopeType,
        period: context.period,
        compareMode: context.compareMode || 'none',
        targetKind: context.publishTarget.kind,
        courseId: targetCourseId,
        semesterId: targetSemesterId,
        subjectId: targetSubjectId,
        groupNumber: targetGroupNumber,
        participantsCount: Number(context?.summary?.participants_count || 0),
      },
      ratingRows,
      topN,
      publishedAtIso: createdAtIso,
      lang,
    });

    let publishedMessage = null;
    if (context.publishTarget.kind === 'course') {
      publishedMessage = await db.get(
        `
          INSERT INTO messages
            (subject_id, group_number, target_all, body, created_by_id, created_at, course_id, semester_id, status, scheduled_at, published_at)
          VALUES
            (NULL, NULL, 1, ?, ?, ?, ?, ?, 'published', NULL, ?)
          RETURNING id
        `,
        [
          ratingPayload.messageBody,
          Number(req.session.user.id),
          createdAtIso,
          targetCourseId,
          targetSemesterId,
          createdAtIso,
        ]
      );
    } else {
      publishedMessage = await db.get(
        `
          INSERT INTO messages
            (subject_id, group_number, target_all, body, created_by_id, created_at, course_id, semester_id, status, scheduled_at, published_at)
          VALUES
            (?, ?, 0, ?, ?, ?, ?, ?, 'published', NULL, ?)
          RETURNING id
        `,
        [
          targetSubjectId,
          targetGroupNumber,
          ratingPayload.messageBody,
          Number(req.session.user.id),
          createdAtIso,
          targetCourseId,
          targetSemesterId,
          createdAtIso,
        ]
      );
    }

    await db.run(
      `
        INSERT INTO rating_publication_snapshots
          (
            course_id,
            semester_id,
            subject_id,
            group_number,
            scope_type,
            scope_label,
            period,
            period_label,
            compare_mode,
            target_kind,
            top_n,
            summary_json,
            ranking_json,
            message_id,
            published_by,
            published_at
          )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?::jsonb, ?::jsonb, ?, ?, ?)
      `,
      [
        ratingPayload.snapshot.course_id,
        ratingPayload.snapshot.semester_id,
        ratingPayload.snapshot.subject_id,
        ratingPayload.snapshot.group_number,
        ratingPayload.snapshot.scope_type,
        ratingPayload.snapshot.scope_label,
        ratingPayload.snapshot.period,
        ratingPayload.snapshot.period_label,
        ratingPayload.snapshot.compare_mode,
        ratingPayload.snapshot.target_kind,
        ratingPayload.snapshot.top_n,
        JSON.stringify(ratingPayload.snapshot.summary_json || {}),
        JSON.stringify(ratingPayload.snapshot.ranking_json || []),
        publishedMessage && publishedMessage.id ? Number(publishedMessage.id) : null,
        Number(req.session.user.id),
        createdAtIso,
      ]
    );

    logAction(db, req, 'journal_insights_publish_rating', {
      scope_type: context.scopeType,
      scope_label: context.scopeLabel,
      period: context.period,
      compare_mode: context.compareMode || 'none',
      rating_size: ratingRows.length,
      target_kind: context.publishTarget.kind,
      target_subject_id: context.publishTarget.subject_id || null,
      target_group_number: context.publishTarget.group_number || null,
      target_course_id: context.publishTarget.course_id || context.selectedCourseId || null,
    });

    return res.redirect(buildJournalInsightsUrl({
      ...baseRedirect,
      ok: 'Rating published',
    }));
  } catch (err) {
    return handleDbError(res, err, 'journal.insights.publish.snapshot');
  }
});

app.get('/journal', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'journal.init');
  }

  let journalFallbackState = {
    subjects: [],
    selectedSubject: null,
    selectedSemester: null,
    teacherJournalMode: false,
    canManageAllSubjects: false,
  };

  try {
    const journalLang = getPreferredLang(req);
    const journalShellCopy = getJournalShellCopy(journalLang);
    const journalScope = await getJournalAccessScope(req);
    if (!journalScope.canUseJournal) {
      return res.status(403).send('Forbidden (journal)');
    }
    const teacherJournalMode = canUseTeacherJournalMode(req, journalScope);
    const subjectOptions = await getJournalSubjectOptionsForUser(req, journalScope, teacherJournalMode);
    journalFallbackState = {
      ...journalFallbackState,
      subjects: subjectOptions,
      teacherJournalMode,
      canManageAllSubjects: Boolean(journalScope.fullAccess),
    };
    const requestedSubjectId = Number(req.query.subject_id);
    const selectedSubject = Number.isFinite(requestedSubjectId) && requestedSubjectId !== 0
      ? (subjectOptions.find((item) => Number(item.subject_id) === requestedSubjectId) || null)
      : (subjectOptions[0] || null);
    journalFallbackState.selectedSubject = selectedSubject || null;
    const undoColumnId = Number(req.query.undo_column_id);
    const undoStudentId = Number(req.query.undo_student_id);
    const undoUntilMs = Number(req.query.undo_until);
    const nowMs = Date.now();
    const undoGrade = (
      Number.isFinite(undoColumnId) && undoColumnId > 0
      && Number.isFinite(undoStudentId) && undoStudentId > 0
      && Number.isFinite(undoUntilMs) && undoUntilMs > nowMs
    )
      ? {
          column_id: undoColumnId,
          student_id: undoStudentId,
          until: undoUntilMs,
          seconds_left: Math.max(1, Math.floor((undoUntilMs - nowMs) / 1000)),
        }
      : null;

    if (!selectedSubject) {
      await renderViewToResponse(
        res,
        'journal',
        {
          ...buildJournalEmptyStateViewModel({
            req,
            subjects: subjectOptions,
            teacherJournalMode,
            canManageAllSubjects: Boolean(journalScope.fullAccess),
          }),
          journalPageMeta: buildJournalPageMeta({
            lang: journalLang,
            renderMode: 'full',
            teacherJournalMode,
            canManageAllSubjects: Boolean(journalScope.fullAccess),
            emptyStateKind: 'no-subject',
          }),
        }
      );
      return;
    }

    const selectedCourseId = Number(selectedSubject.course_id || req.session.user.course_id || 1);
    const selectedSemester = await getActiveSemester(selectedCourseId);
    journalFallbackState.selectedSemester = selectedSemester || null;
    const storageSubjectId = resolveJournalStorageSubjectId(selectedSubject);
    if (!storageSubjectId) {
      await renderViewToResponse(
        res,
        'journal',
        {
          ...buildJournalEmptyStateViewModel({
            req,
            subjects: subjectOptions,
            teacherJournalMode,
            canManageAllSubjects: Boolean(journalScope.fullAccess),
          }),
          selectedSubject,
          selectedSemester,
          journalPageMeta: buildJournalPageMeta({
            lang: journalLang,
            renderMode: 'full',
            selectedSubject,
            selectedSemester,
            teacherJournalMode,
            canManageAllSubjects: Boolean(journalScope.fullAccess),
            selectedJournalHasStorageBinding: false,
            emptyStateKind: 'no-storage-binding',
          }),
        }
      );
      return;
    }
    const supportsLegacyJournalMutations = Number(storageSubjectId) > 0;
    const subjectClosure = await getJournalSubjectClosureState(storageSubjectId);
    const canEditJournal = teacherJournalMode && supportsLegacyJournalMutations && !subjectClosure.is_closed;
    const canCloseSubject = Boolean(
      teacherJournalMode
      && supportsLegacyJournalMutations
      && !subjectClosure.is_closed
      && (journalScope.fullAccess || selectedSubject.has_all_groups)
    );
    const canReopenSubject = Boolean(
      teacherJournalMode
      && supportsLegacyJournalMutations
      && subjectClosure.is_closed
      && (journalScope.fullAccess || selectedSubject.has_all_groups)
    );

    let groupFilterSet = null;
    let studentFilterIds = [];

    if (!teacherJournalMode) {
      groupFilterSet = new Set((selectedSubject.group_numbers || []).map((value) => Number(value)).filter((value) => Number.isInteger(value) && value > 0));
      studentFilterIds = [Number(req.session.user.id)];
    } else if (!journalScope.fullAccess && !selectedSubject.has_all_groups) {
      groupFilterSet = new Set((selectedSubject.group_numbers || []).map((value) => Number(value)).filter((value) => Number.isInteger(value) && value > 0));
    }

    const matrix = await buildJournalMatrix({
      subjectId: Number(storageSubjectId),
      courseId: selectedCourseId,
      semesterId: selectedSemester ? Number(selectedSemester.id) : null,
      actorUserId: Number(req.session.user.id),
      groupFilterSet,
      studentFilterIds,
    });
    const attendanceContext = buildJournalEmptyAttendanceContext();
    const journalWorkflowLinks = supportsLegacyJournalMutations
      ? {
          insightsHref: buildJournalInsightsUrl({
            courseId: Number(selectedSubject.course_id || 0),
            subjectId: Number(selectedSubject.subject_id || 0),
            scopeType: 'subject',
            period: 'semester',
            returnSubjectId: Number(selectedSubject.subject_id || 0),
          }),
          closeExportHref: buildJournalCloseExportPathFromRequest(req, Number(selectedSubject.subject_id || 0), {
          }),
        }
      : {};
    const routeMessages = (res.locals && res.locals.messages && typeof res.locals.messages === 'object')
      ? res.locals.messages
      : {};
    let emptyStateKind = 'none';
    if (!matrix.columns.length) {
      emptyStateKind = 'no-columns';
    } else if (!matrix.rows.length) {
      emptyStateKind = 'no-students';
    }
    const healthBanner = routeMessages.error
      ? {
          tone: 'danger',
          title: journalShellCopy.bannerGenericTitle,
          body: String(routeMessages.error),
        }
      : null;

    await renderViewToResponse(res, 'journal', {
      username: req.session.user.username,
      role: req.session.role,
      subjects: subjectOptions,
      selectedSubject,
      columns: matrix.columns,
      journalRows: matrix.rows,
      gradingSettings: matrix.gradingSettings,
      attendanceContext,
      canEditJournal,
      canEditAttendance: false,
      teacherJournalMode,
      attendanceQuickAutoOpen: false,
      canManageAllSubjects: Boolean(journalScope.fullAccess),
      subjectClosure,
      canCloseSubject,
      canReopenSubject,
      selectedSemester,
      undoGrade: canEditJournal ? undoGrade : null,
      gradingTypeMeta: JOURNAL_SCORING_TYPE_META,
      journalWorkflowLinks,
      journalPageMeta: buildJournalPageMeta({
        lang: journalLang,
        renderMode: 'full',
        selectedSubject,
        selectedSemester,
        teacherJournalMode,
        canManageAllSubjects: Boolean(journalScope.fullAccess),
        selectedJournalHasStorageBinding: true,
        subjectClosure,
        columns: matrix.columns,
        journalRows: matrix.rows,
        journalWorkflowLinks,
        canEditJournal,
        emptyStateKind,
        healthBanner,
      }),
    });
    return;
  } catch (err) {
    if (err && err.isViewRenderError) {
      console.error('Journal render failed (journal.page.render)', {
        view: err.viewName || 'journal',
        message: normalizeRuntimeErrorMessage(err && err.message ? err.message : err),
      });
      try {
        await renderViewToResponse(
          res,
          'journal',
          {
            ...buildJournalEmptyStateViewModel({
              req,
              subjects: journalFallbackState.subjects,
              teacherJournalMode: journalFallbackState.teacherJournalMode,
              canManageAllSubjects: journalFallbackState.canManageAllSubjects,
            }),
            selectedSubject: journalFallbackState.selectedSubject,
            selectedSemester: journalFallbackState.selectedSemester,
            journalPageMeta: buildJournalPageMeta({
              lang: getPreferredLang(req),
              renderMode: 'simplified',
              selectedSubject: journalFallbackState.selectedSubject,
              selectedSemester: journalFallbackState.selectedSemester,
              teacherJournalMode: journalFallbackState.teacherJournalMode,
              canManageAllSubjects: journalFallbackState.canManageAllSubjects,
              selectedJournalHasStorageBinding: Boolean(
                parsePositiveIntStrict(
                  journalFallbackState.selectedSubject
                    && (journalFallbackState.selectedSubject.legacy_subject_id || journalFallbackState.selectedSubject.subject_id)
                )
              ),
              emptyStateKind: 'simplified-render',
              healthBanner: {
                tone: 'warning',
                title: getJournalShellCopy(getPreferredLang(req)).bannerSimplifiedTitle,
                body: getJournalShellCopy(getPreferredLang(req)).emptySimplifiedBody,
                actionLabel: getJournalShellCopy(getPreferredLang(req)).bannerActionRefresh,
                actionHref: '/journal',
              },
            }),
          }
        );
        return;
      } catch (fallbackRenderErr) {
        console.error('Journal render fallback failed', fallbackRenderErr);
        return sendJournalPlainFallback(res);
      }
    }
    if (isDbSchemaCompatibilityError(err)) {
      console.error('Journal compatibility fallback (journal.page.compat)', {
        code: err && err.code ? String(err.code) : '',
        message: normalizeRuntimeErrorMessage(err && err.message ? err.message : err),
      });
      try {
        await renderViewToResponse(
          res,
          'journal',
          {
            ...buildJournalEmptyStateViewModel({
              req,
              subjects: journalFallbackState.subjects,
              teacherJournalMode: journalFallbackState.teacherJournalMode,
              canManageAllSubjects: journalFallbackState.canManageAllSubjects,
            }),
            selectedSubject: journalFallbackState.selectedSubject,
            selectedSemester: journalFallbackState.selectedSemester,
            journalPageMeta: buildJournalPageMeta({
              lang: getPreferredLang(req),
              renderMode: 'compatibility',
              selectedSubject: journalFallbackState.selectedSubject,
              selectedSemester: journalFallbackState.selectedSemester,
              teacherJournalMode: journalFallbackState.teacherJournalMode,
              canManageAllSubjects: journalFallbackState.canManageAllSubjects,
              selectedJournalHasStorageBinding: Boolean(
                parsePositiveIntStrict(
                  journalFallbackState.selectedSubject
                    && (journalFallbackState.selectedSubject.legacy_subject_id || journalFallbackState.selectedSubject.subject_id)
                )
              ),
              emptyStateKind: 'compatibility-mode',
              healthBanner: {
                tone: 'warning',
                title: getJournalShellCopy(getPreferredLang(req)).bannerCompatibilityTitle,
                body: getJournalShellCopy(getPreferredLang(req)).emptyCompatibilityBody,
                actionLabel: getJournalShellCopy(getPreferredLang(req)).bannerActionRefresh,
                actionHref: '/journal',
              },
            }),
          }
        );
        return;
      } catch (renderErr) {
        console.error('Journal compatibility render fallback failed', renderErr);
        return sendJournalPlainFallback(res);
      }
    }
    return handleDbError(res, err, 'journal.page');
  }
});

app.post('/journal/attendance/save', requireLogin, writeLimiter, async (req, res) => {
  const subjectId = Number(req.body.subject_id);
  const attendanceDate = String(req.body.attendance_date || '').trim();
  const attendanceClassNumber = Number(req.body.attendance_class_number);
  const rowsRaw = String(req.body.rows_json || '[]').trim() || '[]';
  const baseAttendanceRedirect = (overrides = {}) => buildJournalSubjectRedirectPathFromRequest(req, subjectId, {
    attendanceDate,
    attendanceClassNumber,
    ...overrides,
  });

  if (!Number.isFinite(subjectId) || subjectId < 1) {
    return res.redirect(baseAttendanceRedirect({ err: 'Invalid subject' }));
  }
  if (!isValidDateString(attendanceDate)) {
    return res.redirect(baseAttendanceRedirect({ err: 'Invalid attendance date' }));
  }
  if (!Number.isInteger(attendanceClassNumber) || !bellSchedule[attendanceClassNumber]) {
    return res.redirect(baseAttendanceRedirect({ err: 'Invalid class number' }));
  }

  let parsedRows = [];
  try {
    const parsed = JSON.parse(rowsRaw);
    parsedRows = Array.isArray(parsed) ? parsed : [];
  } catch (err) {
    return res.redirect(baseAttendanceRedirect({ err: 'Invalid attendance payload' }));
  }
  if (!parsedRows.length) {
    return res.redirect(baseAttendanceRedirect({ err: 'No attendance rows' }));
  }
  if (parsedRows.length > 500) {
    return res.redirect(baseAttendanceRedirect({ err: 'Attendance payload is too large' }));
  }

  try {
    await ensureDbReady();
    const journalScope = await getJournalAccessScope(req);
    const teacherJournalMode = canUseTeacherJournalMode(req, journalScope);
    if (!journalScope.canUseJournal || !teacherJournalMode) {
      return res.status(403).send('Forbidden (journal)');
    }

    const subjectOptions = await getJournalSubjectOptionsForUser(req, journalScope, teacherJournalMode);
    const selectedSubject = (subjectOptions || []).find((subject) => Number(subject.subject_id) === subjectId);
    if (!selectedSubject) {
      return res.status(403).send('Forbidden (journal)');
    }

    const selectedCourseId = Number(selectedSubject.course_id || req.session.user.course_id || 1);
    const selectedSemester = await getActiveSemester(selectedCourseId);
    const semesterId = selectedSemester ? Number(selectedSemester.id) : null;
    let groupFilterSet = null;
    if (!journalScope.fullAccess && !selectedSubject.has_all_groups) {
      groupFilterSet = new Set(
        (selectedSubject.group_numbers || [])
          .map((value) => Number(value))
          .filter((value) => Number.isInteger(value) && value > 0)
      );
    }

    const allowedStudents = await getJournalStudents(subjectId, selectedCourseId, groupFilterSet);
    const allowedStudentMap = new Map(
      (allowedStudents || []).map((student) => [Number(student.id), student])
    );

    const normalizedEntries = normalizeAttendancePayloadRows(parsedRows);
    if (!normalizedEntries.length) {
      return res.redirect(baseAttendanceRedirect({ err: 'No attendance rows' }));
    }

    for (const entry of normalizedEntries) {
      if (!allowedStudentMap.has(Number(entry.student_id))) {
        return res.status(403).send('Forbidden (journal)');
      }
    }

    const { updatedCount, deletedCount } = await persistAttendanceRows({
      subjectId,
      courseId: selectedCourseId,
      semesterId,
      attendanceDate,
      attendanceClassNumber,
      normalizedEntries,
      allowedStudentMap,
      actorUserId: Number(req.session.user.id),
    });

    logActivity(
      db,
      req,
      'journal_attendance_save',
      'attendance_record',
      null,
      {
        subject_id: subjectId,
        class_date: attendanceDate,
        class_number: attendanceClassNumber,
        updated_count: updatedCount,
        deleted_count: deletedCount,
      },
      selectedCourseId,
      semesterId
    );
    return res.redirect(baseAttendanceRedirect({ ok: 'Відвідуваність збережено' }));
  } catch (err) {
    return res.redirect(baseAttendanceRedirect({ err: 'Database error' }));
  }
});

app.get('/schedule/attendance/context', requireLogin, async (req, res) => {
  const subjectId = Number(req.query.subject_id);
  const courseId = Number(req.query.course_id);
  const classDate = String(req.query.class_date || '').trim();
  const classNumber = Number(req.query.class_number);
  const groupNumber = Number(req.query.group_number);
  const lessonType = String(req.query.lesson_type || '').trim().toLowerCase();
  const isGeneral = parseBinaryFlag(req.query.is_general, 0) === 1;
  const targetGroups = String(req.query.target_groups || '').trim();

  try {
    await ensureDbReady();
    const contextState = await resolveScheduleAttendanceTeacherContext(req, {
      subjectId,
      courseId,
      classDate,
      classNumber,
      groupNumber,
      targetGroups,
      lessonType,
      isGeneral,
    });
    const attendanceContext = await buildJournalAttendanceContext({
      subjectId: contextState.subjectId,
      courseId: contextState.courseId,
      semesterId: contextState.semesterId,
      semester: contextState.semester,
      students: contextState.students,
      requestedDate: contextState.classDate,
      requestedClassNumber: contextState.classNumber,
      allowedGroupNumbers: contextState.allowedGroupNumbers,
      hasAllGroups: Boolean(contextState.selectedSubject && contextState.selectedSubject.has_all_groups),
    });
    return res.json({
      ok: true,
      subject_id: contextState.subjectId,
      course_id: contextState.courseId,
      class_date: attendanceContext.date,
      class_number: attendanceContext.class_number,
      subject_name: String(contextState.selectedSubject && contextState.selectedSubject.subject_name || ''),
      group_numbers: contextState.allowedGroupNumbers,
      rows: attendanceContext.rows || [],
      summary: attendanceContext.summary || {},
      reason_max_length: Number(attendanceContext.reason_max_length || ATTENDANCE_REASON_MAX_LENGTH),
    });
  } catch (err) {
    if (Number(err && err.statusCode || 0) >= 400) {
      return res.status(Number(err.statusCode)).json({
        ok: false,
        message: String(err && err.message || 'Attendance is unavailable'),
      });
    }
    console.error('Schedule attendance context failed', err);
    return res.status(500).json({
      ok: false,
      message: 'Database error',
    });
  }
});

