app.post('/admin/support-requests/:id/update', requireSupportSectionAccess, writeLimiter, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.supportRequests.init');
  }

  const lang = getPreferredLang(req);
  const requestId = Number(req.params.id);
  const replyBody = String(req.body.reply_body || req.body.admin_note || '')
    .replace(/\r\n/g, '\n')
    .trim();
  const closeRequested = String(req.body.close_request || '') === '1';
  const status = closeRequested ? 'resolved' : normalizeSupportRequestStatus(req.body.status);
  const selectedCourseId = Number(getAdminCourse(req) || req.session.user.course_id || 0);
  const redirectBase = buildAdminTabUrl(req, 'admin-support', {
    support_request: Number.isInteger(requestId) && requestId > 0 ? requestId : null,
  });
  const redirectWith = (kind, message) => appendQueryParamToUrl(
    redirectBase,
    kind,
    String(message || '')
  );

  if (Number.isNaN(requestId) || replyBody.length > 1000) {
    return res.redirect(redirectWith('err', translate(lang, 'admin.supportTicketValidationMessage')));
  }

  try {
    const supportRequestColumns = await getTableColumnSet('support_requests', { refresh: true });
    if (!supportRequestColumns.has('id')) {
      return res.redirect(redirectWith('err', translate(lang, 'admin.supportTicketSchemaMessage')));
    }

    const selectFields = ['id'];
    if (supportRequestColumns.has('course_id')) {
      selectFields.push('course_id');
    }
    if (supportRequestColumns.has('status')) {
      selectFields.push('status');
    }
    if (supportRequestColumns.has('admin_note')) {
      selectFields.push('admin_note');
    }
    const supportRequest = await db.get(
      `SELECT ${selectFields.join(', ')} FROM support_requests WHERE id = ?`,
      [requestId]
    );
    if (!supportRequest) {
      return res.redirect(redirectWith('err', translate(lang, 'admin.supportTicketMissingMessage')));
    }
    if (
      supportRequestColumns.has('course_id')
      && selectedCourseId > 0
      && Number(supportRequest.course_id || 0) !== selectedCourseId
    ) {
      return res.redirect(redirectWith('err', translate(lang, 'admin.supportTicketMissingMessage')));
    }
    const resolvedAt = status === 'resolved' ? new Date().toISOString() : null;
    const resolvedBy = status === 'resolved' ? req.session.user.id : null;
    const updateAssignments = [];
    const updateParams = [];

    if (supportRequestColumns.has('status')) {
      updateAssignments.push('status = ?');
      updateParams.push(status);
    }
    if (supportRequestColumns.has('admin_note') && replyBody) {
      updateAssignments.push('admin_note = ?');
      updateParams.push(replyBody);
    }
    if (supportRequestColumns.has('updated_at')) {
      updateAssignments.push('updated_at = NOW()');
    }
    if (supportRequestColumns.has('resolved_at')) {
      updateAssignments.push('resolved_at = ?');
      updateParams.push(resolvedAt);
    }
    if (supportRequestColumns.has('resolved_by')) {
      updateAssignments.push('resolved_by = ?');
      updateParams.push(resolvedBy);
    }
    if (!updateAssignments.length) {
      return res.redirect(redirectWith('err', translate(lang, 'admin.supportTicketSchemaMessage')));
    }
    updateParams.push(requestId);

    await db.run(
      `UPDATE support_requests SET ${updateAssignments.join(', ')} WHERE id = ?`,
      updateParams
    );
    if (replyBody) {
      await insertSupportRequestMessage({
        requestId,
        authorUserId: req.session.user.id,
        authorRole: 'admin',
        body: replyBody,
      });
    }

    logAction(db, req, 'support_request_update', {
      request_id: requestId,
      status,
      replied: Boolean(replyBody),
    });
    return res.redirect(redirectWith('ok', translate(lang, 'admin.supportTicketUpdatedMessage')));
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return res.redirect(redirectWith('err', translate(lang, 'admin.supportTicketSchemaMessage')));
    }
    return handleDbError(res, err, 'admin.supportRequests.update');
  }
});

app.get('/messages.json', requireLogin, readLimiter, async (req, res) => {
  res.set('Cache-Control', 'no-store, no-cache, must-revalidate, private');
  res.set('Pragma', 'no-cache');
  res.set('Expires', '0');
  if (!settingsCache.allow_messages) {
    return res.json({ messages: [], unread_count: 0 });
  }
  const userId = Number(req.session.user.id || 0);
  const courseId = getSessionAcademicCourseId(req);
  const activeSemester = courseId ? await getActiveSemester(courseId).catch(() => null) : null;
  const filterSubjectId = req.query.subject_id ? Number(req.query.subject_id) : null;
  try {
    const payload = await listVisibleMessagesForUser({
      userId,
      courseId: courseId || null,
      activeSemester,
      subjectId: filterSubjectId,
      limit: 50,
      includeReactions: true,
      staleDays: 45,
      lang: getPreferredLang(req),
      request: req,
    });
    return res.json(payload);
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return res.json({ messages: [], unread_count: 0 });
    }
    return res.status(500).json({ error: 'Database error' });
  }
});

app.post('/messages/read', requireLogin, writeLimiter, (req, res) => {
  if (!settingsCache.allow_messages) {
    return res.status(403).json({ error: 'Messages disabled' });
  }
  const { message_ids } = req.body;
  const ids = Array.isArray(message_ids) ? message_ids : message_ids ? [message_ids] : [];
  const { id: userId } = req.session.user;
  if (!ids.length) {
    return res.json({ ok: true });
  }
  const readAt = new Date().toISOString();
  const stmt = db.prepare(
    'INSERT INTO message_reads (message_id, user_id, read_at) VALUES (?, ?, ?) ON CONFLICT(message_id, user_id) DO NOTHING'
  );
  ids.forEach((mid) => {
    stmt.run(Number(mid), userId, readAt);
  });
  stmt.finalize(() => res.json({ ok: true }));
});

app.get('/admin/api/messages/:id/reads', requireMessagesSectionAccess, readLimiter, async (req, res) => {
  if (!settingsCache.allow_messages) {
    return res.status(403).json({ error: 'Messages disabled' });
  }
  try {
    await ensureDbReady();
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
  const messageId = Number(req.params.id);
  if (Number.isNaN(messageId)) {
    return res.status(400).json({ error: 'Invalid message' });
  }
  const courseId = getSessionAcademicCourseId(req);
  let activeSemester = null;
  try {
    activeSemester = courseId ? await getActiveSemester(courseId) : null;
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
  try {
    const globalBroadcastScope = 'target_all = 1 AND subject_id IS NULL AND group_number IS NULL';
    const message = await db.get(
      `SELECT id, subject_id, group_number, target_all, course_id, semester_id
       FROM messages
       WHERE id = ?
         AND (
           course_id = ?
           OR (${globalBroadcastScope} AND course_id IS NULL)
         )${activeSemester
          ? ` AND (
              semester_id = ?
              OR (${globalBroadcastScope} AND semester_id IS NULL)
            )`
          : ''}`,
      activeSemester ? [messageId, courseId, activeSemester.id] : [messageId, courseId]
    );
    if (!message) {
      return res.status(404).json({ error: 'Not found' });
    }
    const courseUsers = courseId
      ? await academicV2RuntimeHelpers.listCourseUsersByLegacyCourse(getAcademicV2Store(), courseId, {
          activeOnly: usersHasIsActive,
        }).catch(() => [])
      : [];
    const courseUserMap = new Map(
      (Array.isArray(courseUsers) ? courseUsers : [])
        .map((row) => [Number(row.id || 0), row])
        .filter(([userId]) => Number.isInteger(userId) && userId > 0)
    );
    let recipients = [];
    if (message.target_all === 1) {
      recipients = Array.from(courseUserMap.values())
        .filter((row) => normalizeRoleKey(row.role || 'student') === 'student')
        .map((row) => ({
          id: Number(row.id || 0),
          full_name: row.full_name,
        }))
        .sort((a, b) => String(a.full_name || '').localeCompare(String(b.full_name || '')));
    } else if (message.subject_id) {
      recipients = (await getJournalStudents(
        message.subject_id,
        courseId,
        parsePositiveIntStrict(message.group_number) ? new Set([Number(message.group_number)]) : null,
        []
      )).map((row) => ({
        id: Number(row.id),
        full_name: row.full_name,
      }));
    } else {
      const directTargetRows = await db.all(
        `
          SELECT mt.user_id
          FROM message_targets mt
          WHERE mt.message_id = ?
        `,
        [message.id]
      );
      recipients = (directTargetRows || [])
        .map((row) => courseUserMap.get(Number(row.user_id || 0)))
        .filter(Boolean)
        .map((row) => ({
          id: Number(row.id || 0),
          full_name: row.full_name,
        }))
        .sort((a, b) => String(a.full_name || '').localeCompare(String(b.full_name || '')));
    }
    const recipientIds = new Set((recipients || []).map((row) => String(row.id)));
    const readRows = await db.all(
      `SELECT mr.user_id, mr.read_at, u.full_name
       FROM message_reads mr
       JOIN users u ON u.id = mr.user_id
       WHERE mr.message_id = ?
       ORDER BY mr.read_at DESC`,
      [message.id]
    );
    const reads = (readRows || [])
      .filter((row) => recipientIds.has(String(row.user_id)))
      .map((row) => ({
        user_id: row.user_id,
        full_name: row.full_name,
        read_at: row.read_at,
      }));
    const readIdSet = new Set(reads.map((row) => String(row.user_id)));
    const unread = (recipients || [])
      .filter((row) => !readIdSet.has(String(row.id)))
      .map((row) => ({ user_id: row.id, full_name: row.full_name }));
    return res.json({
      message_id: message.id,
      target_count: recipients.length,
      read_count: reads.length,
      reads,
      unread,
    });
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
});

async function getTeamworkReactionAccess(req, taskId) {
  const normalizedTaskId = Number(taskId || 0);
  const userId = Number(req?.session?.user?.id || 0);
  if (!Number.isInteger(normalizedTaskId) || normalizedTaskId < 1 || !Number.isInteger(userId) || userId < 1) {
    return { status: 'invalid', task: null };
  }
  const task = await db.get(
    `
      SELECT
        t.id,
        t.subject_id,
        t.course_id,
        t.semester_id,
        t.created_by,
        t.lesson_scope,
        t.seminar_group_numbers,
        s.group_count AS subject_group_count
      FROM teamwork_tasks t
      JOIN subjects s ON s.id = t.subject_id
      WHERE t.id = ?
      LIMIT 1
    `,
    [normalizedTaskId]
  );
  if (!task) {
    return { status: 'not_found', task: null };
  }
  if (!(await isCurrentOwnerSemesterRow(task.course_id, task.semester_id))) {
    return { status: 'not_found', task: null };
  }

  if (hasSessionRole(req, 'teacher')) {
    if (Number(task.created_by || 0) !== userId) {
      return { status: 'forbidden', task: null };
    }
    const teacherRows = await teacherTemplateHelpers.listTeacherSubjectMirrorRows(
      getTeacherTemplateStore(),
      userId,
      {
        subjectId: task.subject_id,
        courseId: task.course_id,
        includeHidden: true,
      }
    );
    return teacherRows && teacherRows.length
      ? { status: 'ok', task }
      : { status: 'forbidden', task: null };
  }

  const courseId = Number(req?.session?.user?.course_id || 1);
  if (!Number.isInteger(courseId) || courseId < 1) {
    return { status: 'forbidden', task: null };
  }
  const subjectRow = await getSubjectForCourse(task.subject_id, courseId, { includeHidden: true });
  if (!subjectRow) {
    return { status: 'not_found', task: null };
  }
  const studentRows = await db.all(
    `
      SELECT group_number
      FROM student_groups
      WHERE student_id = ? AND subject_id = ?
    `,
    [userId, task.subject_id]
  );
  const studentGroups = Array.from(new Set(
    (studentRows || [])
      .map((row) => Number(row.group_number || 0))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));
  if (!studentGroups.length) {
    return { status: 'forbidden', task: null };
  }
  const teacherRows = await teacherTemplateHelpers.listTeacherSubjectMirrorRows(
    getTeacherTemplateStore(),
    task.created_by,
    {
      subjectId: task.subject_id,
      courseId: task.course_id,
      includeHidden: true,
    }
  );
  if (!teacherRows || !teacherRows.length) {
    return { status: 'forbidden', task: null };
  }
  const teacherAccess = buildTeacherSubjectAccess(teacherRows, task.subject_group_count || 1, {
    courseId: task.course_id,
  });
  const audience = buildTeamworkTaskAudience(task, teacherAccess, task.subject_group_count || 1);
  const canViewTask = audience.allowAll || studentGroups.some((groupNum) => audience.groups.has(Number(groupNum)));
  return canViewTask ? { status: 'ok', task } : { status: 'forbidden', task: null };
}

const allowedReactions = new Set(['🔥', '👍']);

app.post('/homework/react', requireLogin, writeLimiter, async (req, res) => {
  const homeworkId = Number(req.body.homework_id);
  const emoji = req.body.emoji;
  const { id: userId } = req.session.user;
  if (Number.isNaN(homeworkId) || !allowedReactions.has(emoji)) {
    return res.status(400).json({ error: 'Invalid data' });
  }
  try {
    const access = await getHomeworkReactionAccess(req, homeworkId);
    if (access.status === 'not_found') {
      return res.status(404).json({ error: 'Not found' });
    }
    if (access.status !== 'ok') {
      return res.status(403).json({ error: 'Forbidden' });
    }
    const existing = await db.get(
      'SELECT 1 FROM homework_reactions WHERE homework_id = ? AND user_id = ? AND emoji = ?',
      [homeworkId, userId, emoji]
    );
    if (existing) {
      await db.run('DELETE FROM homework_reactions WHERE homework_id = ? AND user_id = ? AND emoji = ?', [
        homeworkId,
        userId,
        emoji,
      ]);
    } else {
      await db.run(
        'INSERT INTO homework_reactions (homework_id, user_id, emoji, created_at) VALUES (?, ?, ?, ?)',
        [homeworkId, userId, emoji, new Date().toISOString()]
      );
    }
    const reactionRows = await db.all(
      'SELECT emoji, COUNT(*) AS count FROM homework_reactions WHERE homework_id = ? GROUP BY emoji',
      [homeworkId]
    );
    const reactedRows = await db.all(
      'SELECT emoji FROM homework_reactions WHERE homework_id = ? AND user_id = ?',
      [homeworkId, userId]
    );
    const reactions = {};
    reactionRows.forEach((row) => {
      reactions[row.emoji] = Number(row.count || 0);
    });
    const reacted = {};
    reactedRows.forEach((row) => {
      reacted[row.emoji] = true;
    });
    return res.json({ ok: true, reactions, reacted });
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
});

