app.post('/admin/pathways/moderation/:id/resolve', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const queueId = parsePositiveIntStrict(req.params.id);
  const redirectState = getPathwaysRedirectState(req);
  const action = String(req.body.action || '').trim().toLowerCase();
  const helperAction = action === 'ignore'
    ? 'ignored'
    : (action === 'mark_reviewing'
      ? 'reviewing'
      : (action === 'reopen' ? 'open' : 'resolved'));
  const assignedStudyContextId = parsePositiveIntStrict(req.body.study_context_id);

  if (!queueId) {
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      error: msg.moderationItemNotFound,
    }));
  }
  if (!['assign_context', 'ignore', 'mark_resolved', 'mark_reviewing', 'reopen'].includes(action)) {
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      error: msg.moderationActionInvalid,
    }));
  }
  if (action === 'assign_context' && !assignedStudyContextId) {
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      error: msg.moderationAssignContextRequired,
    }));
  }

  try {
    const result = await academicSetupHelpers.resolveAcademicModerationItem({
      db,
      queueId,
      action: helperAction,
      resolvedBy: req.session && req.session.user ? parsePositiveIntStrict(req.session.user.id) : null,
      assignedStudyContextId: action === 'assign_context' ? assignedStudyContextId : null,
      assignUserStudyContext: (userId, studyContextId) => assignUserStudyContext(userId, studyContextId),
    });
    if (!result) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        error: msg.moderationItemNotFound,
      }));
    }
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      studyContextId: action === 'assign_context' ? assignedStudyContextId : redirectState.studyContextId,
      ok: action === 'reopen'
        ? (getPreferredLang(req) === 'uk' ? 'Елемент черги знову відкрито' : 'Queue item reopened')
        : (action === 'mark_reviewing'
          ? (getPreferredLang(req) === 'uk' ? 'Елемент позначено як reviewing' : 'Queue item marked as reviewing')
          : msg.moderationResolved),
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.moderation.resolve');
  }
});

app.post('/admin/pathways/contexts/:id/semesters/add', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const contextId = parsePositiveIntStrict(req.params.id);
  const courseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  let programId = parsePositiveIntStrict(req.body.program_id);
  let admissionId = parsePositiveIntStrict(req.body.admission_id);
  const studyContextId = parsePositiveIntStrict(req.body.study_context_id, contextId) || contextId;
  const semesterNumber = parsePositiveIntStrict(req.body.semester_number);
  const title = sanitizeCompactText(req.body.title, 120);
  const startDate = String(req.body.start_date || '').trim();
  const weeksCount = Number(req.body.weeks_count || 0);
  const isActive = parseBooleanFlag(req.body.is_active, false);

  if (!contextId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      studyContextId,
      error: msg.invalidStudyContext,
    }));
  }
  if (!title) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.studyContextSemesterTitleRequired,
    }));
  }
  if (!semesterNumber) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemesterNumber,
    }));
  }
  if (!Number.isFinite(weeksCount) || weeksCount < 1 || weeksCount > 30) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemesterWeeks,
    }));
  }
  if (startDate && !isValidDateString(startDate)) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemesterDate,
    }));
  }

  try {
    const context = await getStudyContextById(contextId);
    if (!context) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        studyContextId,
        error: msg.invalidStudyContext,
      }));
    }
    programId = programId || parsePositiveIntStrict(context.program_id);
    admissionId = admissionId || parsePositiveIntStrict(context.admission_id);

    await withTransaction(async (client) => {
      const existing = await txGet(
        client,
        `
          SELECT id
          FROM study_context_semesters
          WHERE study_context_id = ?
            AND semester_number = ?
          LIMIT 1
        `,
        [contextId, semesterNumber]
      );
      if (existing && existing.id) {
        const conflict = new Error('PATHWAYS_CONTEXT_SEMESTER_EXISTS');
        throw conflict;
      }
      if (isActive) {
        await txRun(
          client,
          `
            UPDATE study_context_semesters
            SET is_active = false,
                updated_at = NOW()
            WHERE study_context_id = ?
          `,
          [contextId]
        );
      }
      await txRun(
        client,
        `
          INSERT INTO study_context_semesters
            (study_context_id, semester_number, title, start_date, weeks_count, is_active, is_archived, created_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, false, NOW(), NOW())
        `,
        [
          contextId,
          semesterNumber,
          title,
          startDate || null,
          Math.round(weeksCount),
          isActive,
        ]
      );
    });

    await syncSubjectOfferingsForStudyContext(contextId);
    logAction(db, req, 'pathways_context_semester_add', {
      study_context_id: contextId,
      semester_number: semesterNumber,
      title,
      start_date: startDate || null,
      weeks_count: Math.round(weeksCount),
      is_active: isActive ? 1 : 0,
    });

    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId: contextId,
      ok: msg.studyContextSemesterAdded,
    }));
  } catch (err) {
    if (err && err.message === 'PATHWAYS_CONTEXT_SEMESTER_EXISTS') {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        studyContextId: contextId,
        error: msg.studyContextSemesterExists,
      }));
    }
    return handleDbError(res, err, 'admin.pathways.contextSemesters.add');
  }
});

app.post('/admin/pathways/contexts/:contextId/semesters/:semesterId/update', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const contextId = parsePositiveIntStrict(req.params.contextId);
  const semesterId = parsePositiveIntStrict(req.params.semesterId);
  const courseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  let programId = parsePositiveIntStrict(req.body.program_id);
  let admissionId = parsePositiveIntStrict(req.body.admission_id);
  const studyContextId = parsePositiveIntStrict(req.body.study_context_id, contextId) || contextId;
  const semesterNumber = parsePositiveIntStrict(req.body.semester_number);
  const title = sanitizeCompactText(req.body.title, 120);
  const startDate = String(req.body.start_date || '').trim();
  const weeksCount = Number(req.body.weeks_count || 0);
  const isArchived = parseBooleanFlag(req.body.is_archived, false);
  const isActive = !isArchived && parseBooleanFlag(req.body.is_active, false);

  if (!contextId || !semesterId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemester,
    }));
  }
  if (!title) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.studyContextSemesterTitleRequired,
    }));
  }
  if (!semesterNumber) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemesterNumber,
    }));
  }
  if (!Number.isFinite(weeksCount) || weeksCount < 1 || weeksCount > 30) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemesterWeeks,
    }));
  }
  if (startDate && !isValidDateString(startDate)) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId,
      error: msg.invalidStudyContextSemesterDate,
    }));
  }

  try {
    const context = await getStudyContextById(contextId);
    if (!context) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        studyContextId,
        error: msg.invalidStudyContext,
      }));
    }
    programId = programId || parsePositiveIntStrict(context.program_id);
    admissionId = admissionId || parsePositiveIntStrict(context.admission_id);

    await withTransaction(async (client) => {
      const existing = await txGet(
        client,
        `
          SELECT id
          FROM study_context_semesters
          WHERE id = ?
            AND study_context_id = ?
          LIMIT 1
        `,
        [semesterId, contextId]
      );
      if (!existing || !existing.id) {
        const missing = new Error('PATHWAYS_CONTEXT_SEMESTER_NOT_FOUND');
        throw missing;
      }
      if (isActive) {
        await txRun(
          client,
          `
            UPDATE study_context_semesters
            SET is_active = false,
                updated_at = NOW()
            WHERE study_context_id = ?
              AND id <> ?
          `,
          [contextId, semesterId]
        );
      }
      await txRun(
        client,
        `
          UPDATE study_context_semesters
          SET
            semester_number = ?,
            title = ?,
            start_date = ?,
            weeks_count = ?,
            is_active = ?,
            is_archived = ?,
            updated_at = NOW()
          WHERE id = ?
            AND study_context_id = ?
        `,
        [
          semesterNumber,
          title,
          startDate || null,
          Math.round(weeksCount),
          isActive,
          isArchived,
          semesterId,
          contextId,
        ]
      );
    });

    await syncSubjectOfferingsForStudyContext(contextId);
    logAction(db, req, 'pathways_context_semester_update', {
      study_context_id: contextId,
      semester_id: semesterId,
      semester_number: semesterNumber,
      title,
      start_date: startDate || null,
      weeks_count: Math.round(weeksCount),
      is_active: isActive ? 1 : 0,
      is_archived: isArchived ? 1 : 0,
    });

    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      studyContextId: contextId,
      ok: msg.studyContextSemesterUpdated,
    }));
  } catch (err) {
    if (err && err.message === 'PATHWAYS_CONTEXT_SEMESTER_NOT_FOUND') {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        studyContextId: contextId,
        error: msg.invalidStudyContextSemester,
      }));
    }
    if (err && err.code === '23505') {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        studyContextId: contextId,
        error: msg.studyContextSemesterExists,
      }));
    }
    return handleDbError(res, err, 'admin.pathways.contextSemesters.update');
  }
});

