app.post('/admin/pathways/admissions/:id/delete', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const redirectState = getPathwaysRedirectState(req, {
    programId: parsePositiveIntStrict(req.body.program_id),
    admissionId,
  });
  if (!admissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      error: msg.invalidAdmissionYear,
    }));
  }

  try {
    const admissionRow = await getAdmissionPathwayContext(admissionId);
    if (!admissionRow) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        error: msg.admissionNotFound,
      }));
    }
    const redirectProgramId = Number(admissionRow.program_id || redirectState.programId || 0);
    const deletionSummary = await getAdmissionDeletionSummary(admissionId);
    const linkedUsersCount = Math.max(
      Number(deletionSummary && deletionSummary.users_count || 0),
      Number(deletionSummary && deletionSummary.context_user_count || 0)
    );
    if (linkedUsersCount > 0) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        programId: redirectProgramId,
        admissionId,
        error: msg.admissionDeleteBlockedUsers(linkedUsersCount),
      }));
    }

    await withTransaction(async (client) => {
      const offeringRows = await txAll(
        client,
        `
          SELECT DISTINCT soc.subject_offering_id
          FROM cohorts coh
          JOIN study_contexts sc ON sc.cohort_id = coh.id
          JOIN subject_offering_contexts soc ON soc.study_context_id = sc.id
          WHERE coh.legacy_admission_id = ?
        `,
        [admissionId]
      );
      const candidateOfferingIds = (offeringRows || [])
        .map((row) => parsePositiveIntStrict(row.subject_offering_id))
        .filter((value) => Number.isInteger(value) && value > 0);
      await client.query(
        convertPlaceholders('DELETE FROM cohorts WHERE legacy_admission_id = ?'),
        [admissionId]
      );
      await client.query(
        convertPlaceholders('DELETE FROM program_admissions WHERE id = ?'),
        [admissionId]
      );
      await deleteOrphanSubjectOfferingsInTransaction(client, candidateOfferingIds);
    });

    invalidateRegistrationPathwaysCache();
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      programId: redirectProgramId,
      admissionId: null,
      studyContextId: null,
      ok: msg.admissionDeleted,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.admission.delete');
  }
});

app.post('/admin/pathways/admissions/:id/courses/save', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const courseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  const programId = parsePositiveIntStrict(req.body.program_id);

  if (!admissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      error: msg.invalidAdmissionYear,
    }));
  }

  try {
    const admissionRow = await getAdmissionPathwayContext(admissionId);
    if (!admissionRow) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        error: msg.admissionNotFound,
      }));
    }
    const resolvedProgramId = Number(admissionRow.program_id || 0);
    if (programId && Number(programId) !== resolvedProgramId) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: msg.admissionNotInSelectedProgram,
      }));
    }
    const { compatibleCourses } = await getAdmissionCourseScope(admissionId, admissionRow.track_key);
    await academicSetupHelpers.upsertLegacyAdmissionCourseMappings({
      run: (sql, params) => db.run(sql, params),
    }, {
      admissionId,
      mappings: (compatibleCourses || []).map((course) => ({
        course_id: course.id,
        is_visible: parseBooleanFlag(req.body[`course_${course.id}`], false),
      })),
    });
    await syncStudyContextsForAdmission(admissionId);
    await syncSubjectOfferingsForAdmission(admissionId);
    invalidateRegistrationPathwaysCache();
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId: resolvedProgramId,
      admissionId,
      ok: msg.courseMappingSaved,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.courses.save');
  }
});

app.post('/admin/pathways/admissions/:id/courses/copy', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const sourceAdmissionId = parsePositiveIntStrict(req.body.source_admission_id);
  const courseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  const programId = parsePositiveIntStrict(req.body.program_id);

  if (!admissionId || !sourceAdmissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      error: msg.selectSourceAndTargetAdmissions,
    }));
  }
  if (admissionId === sourceAdmissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      error: msg.sourceTargetAdmissionsDifferent,
    }));
  }

  try {
    const pair = await db.all(
      `
        SELECT
          a.id,
          a.program_id,
          p.track_key
        FROM program_admissions a
        JOIN study_programs p ON p.id = a.program_id
        WHERE a.id = ANY(?::int[])
      `,
      [[admissionId, sourceAdmissionId]]
    );
    const targetRow = (pair || []).find((row) => Number(row.id || 0) === Number(admissionId)) || null;
    const sourceRow = (pair || []).find((row) => Number(row.id || 0) === Number(sourceAdmissionId)) || null;
    if (!targetRow || !sourceRow) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        error: msg.admissionNotFound,
      }));
    }
    if (Number(targetRow.program_id || 0) !== Number(sourceRow.program_id || 0)) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId,
        admissionId,
        error: msg.sourceAdmissionSameProgram,
      }));
    }
    if (programId && Number(programId) !== Number(targetRow.program_id || 0)) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: Number(targetRow.program_id || 0),
        admissionId,
        error: msg.admissionNotInSelectedProgram,
      }));
    }

    const { compatibleCourseIds } = await getAdmissionCourseScope(admissionId, targetRow.track_key);
    if (!compatibleCourseIds.length) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: Number(targetRow.program_id || 0),
        admissionId,
        error: msg.selectedCoursesDoNotMatchTrack,
      }));
    }

    await academicSetupHelpers.copyLegacyAdmissionCourseMappings({
      run: (sql, params) => db.run(sql, params),
    }, {
      sourceAdmissionId,
      targetAdmissionId: admissionId,
      courseIds: compatibleCourseIds,
    });

    await syncStudyContextsForAdmission(admissionId);
    await syncSubjectOfferingsForAdmission(admissionId);
    invalidateRegistrationPathwaysCache();
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId: Number(targetRow.program_id || 0),
      admissionId,
      ok: msg.courseMappingCopied,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.courses.copy');
  }
});

app.post('/admin/pathways/admissions/:id/courses/legacy-map', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const courseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  const programId = parsePositiveIntStrict(req.body.program_id);

  if (!admissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      error: msg.invalidAdmissionYear,
    }));
  }

  try {
    const admissionRow = await db.get(
      `
        SELECT
          a.id,
          a.program_id,
          a.admission_year,
          p.track_key
        FROM program_admissions a
        JOIN study_programs p ON p.id = a.program_id
        WHERE a.id = ?
      `,
      [admissionId]
    );
    if (!admissionRow) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        error: msg.admissionNotFound,
      }));
    }

    const resolvedProgramId = Number(admissionRow.program_id || 0);
    const trackKey = normalizeRegistrationTrack(admissionRow.track_key, 'bachelor');
    const programAdmissions = await db.all(
      `
        SELECT id
        FROM program_admissions
        WHERE program_id = ?
        ORDER BY admission_year DESC, id DESC
      `,
      [resolvedProgramId]
    );
    const legacyOrdinal = (programAdmissions || []).findIndex((row) => Number(row.id || 0) === admissionId) + 1;
    if (trackKey !== 'teacher' && (!Number.isInteger(legacyOrdinal) || legacyOrdinal < 1)) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: msg.cannotResolveLegacyCourseYear,
      }));
    }

    const courses = await getCoursesCached();
    const compatibleCourses = (courses || []).filter((course) => courseMatchesRegistrationTrack(course, trackKey));
    const targetCourseIds = compatibleCourses
      .filter((course) => (
        trackKey === 'teacher'
          ? true
          : inferLegacyCourseOrdinal(course.name) === legacyOrdinal
      ))
      .map((course) => Number(course.id || 0))
      .filter((value) => Number.isInteger(value) && value > 0);

    if (!targetCourseIds.length) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: trackKey === 'teacher'
          ? msg.noTeacherCoursesFound
          : msg.noLegacyCoursesMatchedYear(legacyOrdinal),
      }));
    }

    const targetCourseSet = new Set(targetCourseIds);
    await academicSetupHelpers.upsertLegacyAdmissionCourseMappings({
      run: (sql, params) => db.run(sql, params),
    }, {
      admissionId,
      mappings: compatibleCourses.map((scopedCourse) => ({
        course_id: scopedCourse.id,
        is_visible: targetCourseSet.has(Number(scopedCourse.id || 0)),
      })),
    });

    await syncStudyContextsForAdmission(admissionId);
    await syncSubjectOfferingsForAdmission(admissionId);
    invalidateRegistrationPathwaysCache();
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId: resolvedProgramId,
      admissionId,
      ok: trackKey === 'teacher'
        ? msg.mappedTeacherCourses(targetCourseIds.length)
        : msg.mappedLegacyYearCourses(legacyOrdinal, Number(admissionRow.admission_year || 0)),
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.courses.legacy-map');
  }
});

app.post('/admin/pathways/admissions/:id/users/migrate', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const courseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  const programId = parsePositiveIntStrict(req.body.program_id);
  const rawSourceCourseIds = Array.isArray(req.body.source_course_ids)
    ? req.body.source_course_ids
    : (req.body.source_course_ids ? [req.body.source_course_ids] : []);
  const sourceCourseIds = Array.from(new Set(
    rawSourceCourseIds
      .map((value) => parsePositiveIntStrict(value))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));

  if (!admissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      error: msg.invalidAdmissionYear,
    }));
  }
  if (!sourceCourseIds.length) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId,
      admissionId,
      error: msg.selectAtLeastOneSourceCourse,
    }));
  }

  try {
    const admissionRow = await db.get(
      `
        SELECT
          a.id,
          a.program_id,
          a.admission_year,
          p.track_key
        FROM program_admissions a
        JOIN study_programs p ON p.id = a.program_id
        WHERE a.id = ?
      `,
      [admissionId]
    );
    if (!admissionRow) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        error: msg.admissionNotFound,
      }));
    }

    const resolvedProgramId = Number(admissionRow.program_id || 0);
    if (programId && Number(programId) !== resolvedProgramId) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: msg.admissionNotInSelectedProgram,
      }));
    }

    const sourceRows = await db.all(
      `
        SELECT id, is_teacher_course
        FROM courses
        WHERE id = ANY(?::int[])
      `,
      [sourceCourseIds]
    );
    const validSourceCourseIds = (sourceRows || [])
      .filter((row) => courseMatchesRegistrationTrack(row, admissionRow.track_key))
      .map((row) => Number(row.id || 0))
      .filter((value) => Number.isInteger(value) && value > 0);

    if (validSourceCourseIds.length !== sourceCourseIds.length) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: msg.selectedCoursesDoNotMatchTrack,
      }));
    }

    await syncStudyContextsForAdmission(admissionId);
    let migratedCount = 0;
    const missingContextCourseIds = [];
    for (const sourceCourseId of validSourceCourseIds) {
      const targetContextId = await ensureStudyContextForLegacyPlacement({
        courseId: sourceCourseId,
        admissionId,
        programId: resolvedProgramId,
        trackKey: admissionRow.track_key,
      });
      if (!targetContextId) {
        missingContextCourseIds.push(sourceCourseId);
        continue;
      }
      const usersToMigrate = await db.all(
        `
          SELECT id
          FROM users
          WHERE course_id = ?
            AND LOWER(COALESCE(role, '')) <> 'admin'
        `,
        [sourceCourseId]
      );
      for (const userRow of usersToMigrate || []) {
        await assignUserStudyContext(Number(userRow.id || 0), targetContextId, {
          courseId: sourceCourseId,
          trackKey: admissionRow.track_key,
          programId: resolvedProgramId,
          admissionId,
        });
        if (Number(userRow.id || 0) > 0) {
          migratedCount += 1;
        }
      }
    }

    if (missingContextCourseIds.length) {
      try {
        for (const missingCourseId of missingContextCourseIds) {
          await queueAcademicModerationItem(academicSetupHelpers.buildMissingTargetContextIssue({
            admissionId,
            courseId: missingCourseId,
            programId: resolvedProgramId,
            trackKey: admissionRow.track_key,
          }));
        }
      } catch (queueErr) {
        if (!isDbSchemaCompatibilityError(queueErr)) {
          throw queueErr;
        }
      }
    }
    logAction(db, req, 'pathways_user_migrate', {
      admission_id: admissionId,
      program_id: resolvedProgramId,
      study_track: admissionRow.track_key,
      source_course_ids: validSourceCourseIds,
      migrated_count: migratedCount,
      missing_context_course_ids: missingContextCourseIds,
    });
    broadcast('users_updated');

    return res.redirect(buildAdminPathwaysUrl({
      courseId,
      track: trackFilter,
      programId: resolvedProgramId,
      admissionId,
      ok: migratedCount > 0
        ? msg.migratedUsers(migratedCount, Number(admissionRow.admission_year || 0))
        : msg.noEligibleUsersFound,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.users.migrate');
  }
});

app.post('/admin/pathways/admissions/:id/promote', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const redirectState = getPathwaysRedirectState(req, {
    admissionId,
  });

  if (!admissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      error: msg.invalidAdmissionYear,
    }));
  }

  try {
    const admissionRow = await db.get(
      `
        SELECT
          a.id,
          a.program_id,
          a.admission_year,
          p.track_key
        FROM program_admissions a
        JOIN study_programs p ON p.id = a.program_id
        WHERE a.id = ?
      `,
      [admissionId]
    );
    if (!admissionRow) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        error: msg.admissionNotFound,
      }));
    }

    await syncStudyContextsForAdmission(admissionId);
    const cohortRow = await db.get(
      `
        SELECT id
        FROM cohorts
        WHERE legacy_admission_id = ?
        LIMIT 1
      `,
      [admissionId]
    ).catch((err) => {
      if (isDbSchemaCompatibilityError(err)) {
        return null;
      }
      throw err;
    });
    const cohortId = parsePositiveIntStrict(cohortRow && cohortRow.id);
    if (!cohortId) {
      return res.redirect(buildAdminPathwaysUrl({
        ...redirectState,
        programId: Number(admissionRow.program_id || 0),
        error: getPreferredLang(req) === 'uk'
          ? 'Для цієї когорти ще не створено study contexts'
          : 'No study contexts exist for this cohort yet',
      }));
    }
    const users = await db.all(
      `
        SELECT
          u.id,
          u.course_id,
          u.admission_id,
          u.study_program_id,
          u.study_track,
          u.study_context_id,
          u.role
        FROM users u
        LEFT JOIN study_contexts sc ON sc.id = u.study_context_id
        WHERE (
            sc.cohort_id = ?
            OR (u.study_context_id IS NULL AND u.admission_id = ?)
          )
          AND LOWER(COALESCE(u.role, '')) <> 'admin'
      `,
      [cohortId, admissionId]
    );
    let promotedCount = 0;
    let skippedCount = 0;
    for (const user of users || []) {
      const placement = await resolveUserAcademicPlacement(user);
      if (!placement || !placement.study_context_id) {
        await queueAcademicModerationItem(academicSetupHelpers.buildFailedPromotionTargetIssue({
          userId: Number(user.id || 0) || null,
          admissionId,
          programId: Number(admissionRow.program_id || 0) || null,
          trackKey: admissionRow.track_key || null,
          courseId: Number(user.course_id || 0) || null,
          studyContextId: Number(user.study_context_id || 0) || null,
          missingPlacement: true,
        }));
        skippedCount += 1;
        continue;
      }
      const nextContextId = await ensureNextStudyContextForPromotion(placement);
      if (!nextContextId) {
        await queueAcademicModerationItem(academicSetupHelpers.buildFailedPromotionTargetIssue({
          userId: Number(user.id || 0) || null,
          admissionId,
          programId: Number(admissionRow.program_id || 0) || null,
          trackKey: placement.track_key || admissionRow.track_key || null,
          courseId: Number(placement.course_id || 0) || null,
          studyContextId: Number(placement.study_context_id || 0) || null,
          campusKey: placement.campus_key || null,
          stageNumber: Number(placement.stage || 0) || null,
        }));
        skippedCount += 1;
        continue;
      }
      await assignUserStudyContext(user.id, nextContextId);
      promotedCount += 1;
    }

    logAction(db, req, 'pathways_users_promote', {
      admission_id: admissionId,
      program_id: Number(admissionRow.program_id || 0),
      promoted_count: promotedCount,
      skipped_count: skippedCount,
    });
    broadcast('users_updated');
    return res.redirect(buildAdminPathwaysUrl({
      ...redirectState,
      programId: Number(admissionRow.program_id || 0),
      admissionId,
      ok: getPreferredLang(req) === 'uk'
        ? `Підвищено ${promotedCount} користувачів, пропущено ${skippedCount}`
        : `Promoted ${promotedCount} users, skipped ${skippedCount}`,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.admission.promote');
  }
});

app.post('/admin/pathways/admissions/:id/subjects/save', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const selectedCourseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  const programId = parsePositiveIntStrict(req.body.program_id);

  if (!admissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId: selectedCourseId,
      track: trackFilter,
      programId,
      error: msg.invalidAdmissionYear,
    }));
  }
  if (!selectedCourseId) {
    return res.redirect(buildAdminPathwaysUrl({
      track: trackFilter,
      programId,
      admissionId,
      error: msg.invalidCourse,
    }));
  }

  try {
    const admissionRow = await getAdmissionPathwayContext(admissionId);
    if (!admissionRow) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId,
        admissionId,
        error: msg.admissionNotFound,
      }));
    }
    const resolvedProgramId = Number(admissionRow.program_id || 0);
    if (programId && Number(programId) !== resolvedProgramId) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: msg.admissionNotInSelectedProgram,
      }));
    }
    const { compatibleCourseIds, mappedCourseIdSet } = await getAdmissionCourseScope(admissionId, admissionRow.track_key);
    if (!compatibleCourseIds.includes(Number(selectedCourseId))) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: msg.selectedCoursesDoNotMatchTrack,
      }));
    }
    if (!mappedCourseIdSet.has(Number(selectedCourseId))) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId: resolvedProgramId,
        admissionId,
        error: getPreferredLang(req) === 'uk'
          ? 'Обраний курс не належить цьому admission-контексту'
          : 'Selected course does not belong to this admission context',
      }));
    }
    const subjects = await getSubjectsCached(selectedCourseId, { visibleOnly: false });
    for (const subject of subjects || []) {
      const subjectId = parsePositiveIntStrict(subject.id);
      if (!subjectId) continue;
      const baseVisible = subject.visible === true || Number(subject.visible) === 1;
      if (!baseVisible) {
        await academicSetupHelpers.writeLegacySubjectVisibility({
          run: (sql, params) => db.run(sql, params),
        }, {
          admissionId,
          subjectId,
          mode: 'delete',
        });
        continue;
      }
      const visibilityFlag = parseBooleanFlag(req.body[`subject_${subjectId}`], false);
      await academicSetupHelpers.writeLegacySubjectVisibility({
        run: (sql, params) => db.run(sql, params),
      }, {
        admissionId,
        subjectId,
        isVisible: visibilityFlag,
      });
    }
    await syncSubjectOfferingsForAdmission(admissionId);
    invalidateRegistrationPathwaysCache();
    invalidateSubjectsCache(selectedCourseId);
    return res.redirect(buildAdminPathwaysUrl({
      courseId: selectedCourseId,
      track: trackFilter,
      programId: resolvedProgramId,
      admissionId,
      ok: msg.subjectVisibilitySaved,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.subjects.save');
  }
});

app.post('/admin/pathways/admissions/:id/subjects/copy', requirePathwaysSectionAccess, writeLimiter, async (req, res) => {
  const msg = getPathwaysRouteMessages(req);
  const admissionId = parsePositiveIntStrict(req.params.id);
  const sourceAdmissionId = parsePositiveIntStrict(req.body.source_admission_id);
  const selectedCourseId = parsePositiveIntStrict(req.body.course_id, getAdminCourse(req));
  const trackFilter = normalizePathwayTrackFilter(req.body.track, 'all');
  const programId = parsePositiveIntStrict(req.body.program_id);

  if (!admissionId || !sourceAdmissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId: selectedCourseId,
      track: trackFilter,
      programId,
      admissionId,
      error: msg.selectSourceAndTargetAdmissions,
    }));
  }
  if (admissionId === sourceAdmissionId) {
    return res.redirect(buildAdminPathwaysUrl({
      courseId: selectedCourseId,
      track: trackFilter,
      programId,
      admissionId,
      error: msg.sourceTargetAdmissionsDifferent,
    }));
  }
  if (!selectedCourseId) {
    return res.redirect(buildAdminPathwaysUrl({
      track: trackFilter,
      programId,
      admissionId,
      error: msg.invalidCourse,
    }));
  }

  try {
    const pair = await db.all(
      `
        SELECT
          a.id,
          a.program_id,
          p.track_key
        FROM program_admissions a
        JOIN study_programs p ON p.id = a.program_id
        WHERE a.id = ANY(?::int[])
      `,
      [[admissionId, sourceAdmissionId]]
    );
    const targetRow = (pair || []).find((row) => Number(row.id || 0) === Number(admissionId)) || null;
    const sourceRow = (pair || []).find((row) => Number(row.id || 0) === Number(sourceAdmissionId)) || null;
    if (!targetRow || !sourceRow) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId,
        admissionId,
        error: msg.admissionNotFound,
      }));
    }
    if (Number(targetRow.program_id || 0) !== Number(sourceRow.program_id || 0)) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId,
        admissionId,
        error: msg.sourceAdmissionSameProgram,
      }));
    }
    if (programId && Number(programId) !== Number(targetRow.program_id || 0)) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId: Number(targetRow.program_id || 0),
        admissionId,
        error: msg.admissionNotInSelectedProgram,
      }));
    }
    const [targetScope, sourceScope] = await Promise.all([
      getAdmissionCourseScope(admissionId, targetRow.track_key),
      getAdmissionCourseScope(sourceAdmissionId, sourceRow.track_key),
    ]);
    if (!targetScope.compatibleCourseIds.includes(Number(selectedCourseId))) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId: Number(targetRow.program_id || 0),
        admissionId,
        error: msg.selectedCoursesDoNotMatchTrack,
      }));
    }
    if (!targetScope.mappedCourseIdSet.has(Number(selectedCourseId)) || !sourceScope.mappedCourseIdSet.has(Number(selectedCourseId))) {
      return res.redirect(buildAdminPathwaysUrl({
        courseId: selectedCourseId,
        track: trackFilter,
        programId: Number(targetRow.program_id || 0),
        admissionId,
        error: getPreferredLang(req) === 'uk'
          ? 'Обраний курс має бути замаплений і в source, і в target admission'
          : 'Selected course must be mapped in both source and target admissions',
      }));
    }

    await academicSetupHelpers.copyLegacySubjectVisibilityForCourse({
      run: (sql, params) => db.run(sql, params),
    }, {
      sourceAdmissionId,
      targetAdmissionId: admissionId,
      courseId: selectedCourseId,
    });

    await syncSubjectOfferingsForAdmission(admissionId);
    invalidateRegistrationPathwaysCache();
    invalidateSubjectsCache(selectedCourseId);
    return res.redirect(buildAdminPathwaysUrl({
      courseId: selectedCourseId,
      track: trackFilter,
      programId: Number(targetRow.program_id || 0),
      admissionId,
      ok: msg.subjectVisibilityCopied,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.pathways.subjects.copy');
  }
});

app.post('/admin/activity/reset-points', requireActivitySectionAccess, writeLimiter, async (req, res) => {
  const redirectWith = (kind, message) => buildAdminScopedNoticeUrl(req, kind, message, {
    tab: 'admin-overview',
  });
  try {
    await ensureDbReady();
  } catch (err) {
    return res.redirect(redirectWith('err', 'Database error'));
  }
  const courseId = hasSessionRole(req, 'admin')
    ? getAdminCourse(req)
    : Number(req.session.user.course_id || 1);
  let activeSemester = null;
  try {
    activeSemester = await getActiveSemester(courseId);
  } catch (err) {
    return res.redirect(redirectWith('err', 'Database error'));
  }
  const semesterId = activeSemester ? Number(activeSemester.id) : null;
  const actorId = Number(req.session.user.id);
  const actorName = req.session.user.username || 'admin';
  const resetScope = String(req.body.reset_scope || '').trim().toLowerCase();
  const createdAt = new Date().toISOString();

  const resolveUserPoints = async (targetUserId) => {
    const row = await db.get(
      `
        SELECT COALESCE(SUM(${ACTIVITY_POINTS_CASE}), 0) AS points
        FROM activity_log
        WHERE user_id = ? AND course_id = ?${activeSemester ? ' AND semester_id = ?' : ''}
      `,
      activeSemester ? [targetUserId, courseId, activeSemester.id] : [targetUserId, courseId]
    );
    return row ? Number(row.points || 0) : 0;
  };

  const createPointsResetEntry = async (targetUserId, targetUserName, previousPoints, reasonKey) => {
    const normalizedPrevious = Math.round(Number(previousPoints || 0) * 100) / 100;
    const delta = Math.round((0 - normalizedPrevious) * 100) / 100;
    if (!Number.isFinite(delta) || Math.abs(delta) < 0.0001) {
      return null;
    }
    const details = {
      reason: reasonKey,
      delta,
      previous_points: normalizedPrevious,
      reset_by_id: actorId,
      reset_by: actorName,
    };
    await db.run(
      `
        INSERT INTO activity_log (user_id, user_name, action_type, target_type, target_id, details, created_at, course_id, semester_id)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
      `,
      [
        targetUserId,
        targetUserName || `User ${targetUserId}`,
        'activity_points_adjust',
        'user',
        targetUserId,
        JSON.stringify(details),
        createdAt,
        courseId,
        semesterId,
      ]
    );
    return details;
  };

  try {
    if (resetScope === 'course') {
      const users = await db.all(
        `
          SELECT id, full_name
          FROM users
          WHERE course_id = ?${usersHasIsActive ? ' AND is_active = 1' : ''}
          ORDER BY full_name
        `,
        [courseId]
      );
      let affectedUsers = 0;
      let totalResetPoints = 0;
      for (const user of users || []) {
        const userId = Number(user.id);
        if (!Number.isFinite(userId) || userId < 1) continue;
        const currentPoints = await resolveUserPoints(userId);
        const details = await createPointsResetEntry(
          userId,
          user.full_name || `User ${userId}`,
          currentPoints,
          'course_reset'
        );
        if (!details) continue;
        affectedUsers += 1;
        totalResetPoints += Math.abs(Number(details.previous_points || 0));
      }
      logAction(db, req, 'activity_points_reset_course', {
        course_id: courseId,
        semester_id: semesterId,
        affected_users: affectedUsers,
        total_points_reset: Math.round(totalResetPoints * 100) / 100,
      });
      if (affectedUsers < 1) {
        return res.redirect(redirectWith('ok', 'No activity points to reset for this course'));
      }
      return res.redirect(redirectWith('ok', `Activity points reset for ${affectedUsers} users`));
    }

    if (resetScope === 'user') {
      const targetUserId = Number(req.body.user_id);
      if (!Number.isFinite(targetUserId) || targetUserId < 1) {
        return res.redirect(redirectWith('err', 'Select a user'));
      }
      const targetUser = await db.get(
        `
          SELECT id, full_name
          FROM users
          WHERE id = ? AND course_id = ?${usersHasIsActive ? ' AND is_active = 1' : ''}
          LIMIT 1
        `,
        [targetUserId, courseId]
      );
      if (!targetUser) {
        return res.redirect(redirectWith('err', 'User not found in current course'));
      }
      const currentPoints = await resolveUserPoints(targetUserId);
      const details = await createPointsResetEntry(
        targetUserId,
        targetUser.full_name || `User ${targetUserId}`,
        currentPoints,
        'user_reset'
      );
      logAction(db, req, 'activity_points_reset_user', {
        target_user_id: targetUserId,
        target_user_name: targetUser.full_name || null,
        course_id: courseId,
        semester_id: semesterId,
        previous_points: Math.round(currentPoints * 100) / 100,
      });
      if (!details) {
        return res.redirect(redirectWith('ok', 'User already has 0 activity points'));
      }
      const targetUserName = targetUser.full_name || `User ${targetUserId}`;
      return res.redirect(redirectWith('ok', `Activity points reset for ${targetUserName}`));
    }

    return res.redirect(redirectWith('err', 'Invalid reset scope'));
  } catch (err) {
    return res.redirect(redirectWith('err', 'Database error'));
  }
});

app.get('/admin/schedule-list', requireScheduleSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleList.init');
  }
  const roleKeys = getSessionRoleList(req);
  let courses = [];
  let courseId = getStaffCourse(req);
  let allowCourseSelect = false;
  try {
    courses = await getCoursesCached();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleList.courses');
  }
  {
    const baseCourseId = Number(req.session.user.course_id || 1);
    const { allowedCourseIds, allowedCourses } = await buildStaffCourseAccess(baseCourseId, courses, roleKeys);
    if (!allowedCourses.length) {
      return res.status(403).send('Forbidden (course access)');
    }
    courses = allowedCourses;
    const requestedCourse = Number(req.query.course);
    if (allowedCourseIds.has(requestedCourse)) {
      courseId = requestedCourse;
    } else if (!allowedCourseIds.has(courseId)) {
      courseId = Number(allowedCourses[0].id);
    }
    req.session.adminCourse = courseId;
    allowCourseSelect = allowedCourses.length > 1;
  }
  const {
    group_number,
    day,
    subject,
    schedule_date,
    sort_schedule,
    page,
  } = req.query;

  let activeSemester = null;
  try {
    activeSemester = await getActiveSemester(courseId);
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleList.semester');
  }
  let activeScheduleDays = [];
  try {
    const studyDays = await getCourseStudyDays(courseId);
    activeScheduleDays = (studyDays || [])
      .filter((d) => d.is_active)
      .map((d) => d.day_name)
      .filter(Boolean);
  } catch (err) {
    console.error('Failed to load study days', err);
  }
  if (!activeScheduleDays.length) {
    activeScheduleDays = [...daysOfWeek];
  }

  let courseSubjectScope;
  try {
    courseSubjectScope = await getCourseSubjectAccessScope(courseId, { visibleOnly: false });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleList.subjectScope');
  }
  if (courseSubjectScope.source === 'academic_v2') {
    return res.redirect(buildAcademicV2NoticeUrl(
      'err',
      getLegacyAcademicScheduleMovedMessage(req),
      parseAcademicV2Focus(req.query)
    ));
  }
  const scheduleFilters = [];
  const scheduleParams = [];
  if (courseSubjectScope.subject_ids.length) {
    scheduleFilters.push('se.subject_id = ANY(?::int[])');
    scheduleParams.push(courseSubjectScope.subject_ids);
    if (courseSubjectScope.owner_course_ids.length) {
      scheduleFilters.push('se.course_id = ANY(?::int[])');
      scheduleParams.push(courseSubjectScope.owner_course_ids);
    }
    if (courseSubjectScope.owner_semester_ids.length) {
      scheduleFilters.push('(se.semester_id = ANY(?::int[]) OR se.semester_id IS NULL)');
      scheduleParams.push(courseSubjectScope.owner_semester_ids);
    } else if (activeSemester) {
      scheduleFilters.push('(se.semester_id = ? OR se.semester_id IS NULL)');
      scheduleParams.push(activeSemester.id);
    }
  } else {
    scheduleFilters.push('1 = 0');
  }
  if (group_number) {
    scheduleFilters.push('se.group_number = ?');
    scheduleParams.push(group_number);
  }
  if (day) {
    scheduleFilters.push('se.day_of_week = ?');
    scheduleParams.push(day);
  }
  if (subject) {
    scheduleFilters.push('s.name LIKE ?');
    scheduleParams.push(`%${subject}%`);
  }
  if (schedule_date && activeSemester && activeSemester.start_date) {
    const mapped = getWeekDayForDate(schedule_date, activeSemester.start_date);
    if (mapped) {
      scheduleFilters.push('se.week_number = ?');
      scheduleParams.push(mapped.weekNumber);
      scheduleFilters.push('se.day_of_week = ?');
      scheduleParams.push(mapped.dayName);
    }
  }

  const scheduleWhere = scheduleFilters.length ? `WHERE ${scheduleFilters.join(' AND ')}` : '';
  let orderClause = 'se.week_number, se.day_of_week, se.class_number';
  if (sort_schedule === 'group') {
    orderClause = 'se.group_number, se.day_of_week, se.class_number';
  } else if (sort_schedule === 'day') {
    orderClause = 'se.day_of_week, se.class_number, se.group_number';
  } else if (sort_schedule === 'time') {
    orderClause = 'se.class_number, se.day_of_week, se.group_number';
  }

  const perPage = 30;
  const rawPage = Number(page || 1);
  let currentPage = Number.isNaN(rawPage) || rawPage < 1 ? 1 : rawPage;

  try {
    const countRow = await db.get(
      `
        SELECT COUNT(*) AS count
        FROM schedule_entries se
        JOIN subjects s ON s.id = se.subject_id
        ${scheduleWhere}
      `,
      scheduleParams
    );
    const totalCount = Number(countRow?.count || 0);
    const totalPages = Math.max(1, Math.ceil(totalCount / perPage));
    if (currentPage > totalPages) currentPage = totalPages;
    const offset = (currentPage - 1) * perPage;
    const rows = await db.all(
      `
        SELECT se.*,
          s.name AS subject_name,
          (
            SELECT COUNT(*)
            FROM schedule_entries se2
            WHERE se2.subject_id = se.subject_id
              AND se2.day_of_week = se.day_of_week
              AND se2.class_number = se.class_number
              AND se2.week_number = se.week_number
              AND COALESCE(se2.semester_id, 0) = COALESCE(se.semester_id, 0)
              AND COALESCE(se2.course_id, 0) = COALESCE(se.course_id, 0)
              AND COALESCE(se2.lesson_type, '') = COALESCE(se.lesson_type, '')
          ) AS slot_group_count,
          (
            SELECT string_agg(DISTINCT se2.group_number::text, ', ' ORDER BY se2.group_number::text)
            FROM schedule_entries se2
            WHERE se2.subject_id = se.subject_id
              AND se2.day_of_week = se.day_of_week
              AND se2.class_number = se.class_number
              AND se2.week_number = se.week_number
              AND COALESCE(se2.semester_id, 0) = COALESCE(se.semester_id, 0)
              AND COALESCE(se2.course_id, 0) = COALESCE(se.course_id, 0)
              AND COALESCE(se2.lesson_type, '') = COALESCE(se.lesson_type, '')
          ) AS slot_group_list
        FROM schedule_entries se
        JOIN subjects s ON s.id = se.subject_id
        ${scheduleWhere}
        ORDER BY ${orderClause}
        LIMIT ? OFFSET ?
      `,
      [...scheduleParams, perPage, offset]
    );

    const semesters = await getSemestersCached(courseId);
    const subjects = await getSubjectsCached(courseId);

    const queryParams = new URLSearchParams();
    if (courseId) queryParams.set('course', courseId);
    if (group_number) queryParams.set('group_number', group_number);
    if (day) queryParams.set('day', day);
    if (subject) queryParams.set('subject', subject);
    if (schedule_date) queryParams.set('schedule_date', schedule_date);
    if (sort_schedule) queryParams.set('sort_schedule', sort_schedule);
    const baseQuery = queryParams.toString();
    const pageBase = baseQuery ? `?${baseQuery}&page=` : '?page=';

    return res.render('admin-schedule-list', {
      username: req.session.user.username,
      role: normalizeRoleKey(req.session.role || 'student'),
      adminHomeHref: getStaffPanelBase(req, courseId),
      courses,
      subjects,
      semesters,
      activeSemester,
      selectedCourseId: courseId,
      allowCourseSelect,
      activeScheduleDays,
      schedule: rows || [],
      perPage,
      filters: {
        group_number: group_number || '',
        day: day || '',
        subject: subject || '',
        schedule_date: schedule_date || '',
      },
      sorts: {
        schedule: sort_schedule || '',
      },
      pagination: {
        page: currentPage,
        totalPages,
        pageBase,
      },
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleList');
  }
});

app.post('/admin/schedule-windows', requireScheduleSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleWindows.init');
  }
  const courseIdsRaw = req.body.course_ids || req.body.course_id || [];
  const courseIds = (Array.isArray(courseIdsRaw) ? courseIdsRaw : [courseIdsRaw])
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value > 0);
  const weekNumber = Number(req.body.week_number || req.body.week);
  if (!courseIds.length || !Number.isFinite(weekNumber) || weekNumber < 1) {
    return res.status(400).json({ ok: false, error: 'Invalid input' });
  }
  try {
    const roleKeys = getSessionRoleList(req);
    const isAdmin = roleKeys.includes('admin');
    const courses = await getCoursesCached();
    let scopedCourseIds = courseIds;
    if (!isAdmin) {
      const baseCourseId = Number(req.session.user.course_id || 1);
      const { allowedCourseIds } = await buildStaffCourseAccess(baseCourseId, courses, roleKeys);
      scopedCourseIds = courseIds.filter((courseId) => allowedCourseIds.has(Number(courseId)));
      if (!scopedCourseIds.length) {
        return res.status(403).json({ ok: false, error: 'Forbidden (course access)' });
      }
    }
    const courseMap = new Map((courses || []).map((c) => [Number(c.id), c]));
    const warnings = [];
    const freeSets = [];
    const validCourses = [];
    for (const courseId of scopedCourseIds) {
      const course = courseMap.get(Number(courseId));
      if (!course) {
        warnings.push(`Курс ${courseId} не знайдено.`);
        continue;
      }
      const semester = await getActiveSemester(courseId);
      if (!semester) {
        warnings.push(`${course.name}: немає активного семестру.`);
        continue;
      }
      if (Number(weekNumber) > Number(semester.weeks_count || 0)) {
        warnings.push(`${course.name}: тиждень ${weekNumber} поза межами семестру (${semester.weeks_count}).`);
      }
      let activeDays = [];
      try {
        const studyDays = await getCourseStudyDays(courseId);
        activeDays = (studyDays || [])
          .filter((d) => d.is_active)
          .map((d) => normalizeWeekdayName(d.day_name))
          .filter(Boolean);
      } catch (dayErr) {
        activeDays = [];
      }
      if (!activeDays.length) {
        activeDays = [...daysOfWeek];
      }
      const rows = await db.all(
        `
          SELECT day_of_week, class_number
          FROM schedule_entries
          WHERE course_id = ? AND semester_id = ? AND week_number = ?
        `,
        [courseId, semester.id, weekNumber]
      );
      const busy = new Set(
        (rows || [])
          .map((row) => {
            const day = normalizeWeekdayName(row.day_of_week);
            const classNum = Number(row.class_number);
            if (!day || !Number.isFinite(classNum)) return null;
            return `${day}|${classNum}`;
          })
          .filter(Boolean)
      );
      const free = new Set();
      activeDays.forEach((day) => {
        for (let classNum = 1; classNum <= 7; classNum += 1) {
          const key = `${day}|${classNum}`;
          if (!busy.has(key)) free.add(key);
        }
      });
      freeSets.push(free);
      validCourses.push({ id: courseId, name: course.name });
    }
    if (!freeSets.length) {
      return res.status(200).json({ ok: false, error: 'No valid courses', warnings });
    }
    let commonSet = null;
    freeSets.forEach((set) => {
      if (!commonSet) {
        commonSet = new Set(set);
      } else {
        commonSet = new Set([...commonSet].filter((key) => set.has(key)));
      }
    });
    const dayOrder = fullWeekDays || daysOfWeek;
    const dayIndex = new Map(dayOrder.map((day, idx) => [day, idx]));
    const slots = [...(commonSet || [])]
      .map((key) => {
        const [day, classNumRaw] = key.split('|');
        const classNum = Number(classNumRaw);
        const time = bellSchedule[classNum]
          ? `${bellSchedule[classNum].start}–${bellSchedule[classNum].end}`
          : `${classNum} пара`;
        return { day, class_number: classNum, time };
      })
      .sort((a, b) => {
        const idxA = dayIndex.get(a.day) ?? 99;
        const idxB = dayIndex.get(b.day) ?? 99;
        if (idxA !== idxB) return idxA - idxB;
        return a.class_number - b.class_number;
      });
    const windows = [];
    const grouped = new Map();
    slots.forEach((slot) => {
      if (!grouped.has(slot.day)) grouped.set(slot.day, []);
      grouped.get(slot.day).push(slot);
    });
    dayOrder.forEach((day) => {
      if (!grouped.has(day)) return;
      windows.push({ day, slots: grouped.get(day) });
    });
    const summaryCourses = validCourses.map((c) => c.name).join(' · ');
    const summary = `Курси: ${summaryCourses} · Тиждень ${weekNumber} · Спільних вікон: ${slots.length}`;
    return res.json({
      ok: true,
      summary,
      warnings,
      windows,
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleWindows');
  }
});

const SEMESTER_SUMMARY_LESSON_TYPE_LABELS = Object.freeze({
  lecture: 'Лекція',
  seminar: 'Семінар',
  practice: 'Практика',
  lab: 'Лабораторна',
});

const formatSemesterSummaryNumericRanges = (values = []) => {
  const safeValues = Array.from(new Set((values || [])
    .map((value) => Number(value))
    .filter((value) => Number.isInteger(value) && value > 0)))
    .sort((a, b) => a - b);
  if (!safeValues.length) return '';
  const ranges = [];
  let rangeStart = safeValues[0];
  let rangeEnd = safeValues[0];
  for (let index = 1; index < safeValues.length; index += 1) {
    const current = safeValues[index];
    if (current === rangeEnd + 1) {
      rangeEnd = current;
      continue;
    }
    ranges.push(rangeStart === rangeEnd ? String(rangeStart) : `${rangeStart}-${rangeEnd}`);
    rangeStart = current;
    rangeEnd = current;
  }
  ranges.push(rangeStart === rangeEnd ? String(rangeStart) : `${rangeStart}-${rangeEnd}`);
  return ranges.join(', ');
};

const formatSemesterSummaryWeekLabel = (weekNumbers = []) =>
  formatSemesterSummaryNumericRanges(weekNumbers) || '—';

const formatSemesterSummaryGroupLabel = (groupNumbers = []) => {
  const safeGroups = Array.from(new Set((groupNumbers || [])
    .map((value) => Number(value))
    .filter((value) => Number.isInteger(value) && value > 0)))
    .sort((a, b) => a - b);
  if (!safeGroups.length) return '';
  const rendered = formatSemesterSummaryNumericRanges(safeGroups);
  return safeGroups.length === 1 ? `група ${rendered}` : `групи ${rendered}`;
};

const buildSemesterSummaryTable = async ({ courseId, semester }) => {
  const normalizedCourseId = Number(courseId || 0);
  const semesterId = Number(semester && semester.id || 0);
  if (!Number.isInteger(normalizedCourseId) || normalizedCourseId < 1) {
    return {
      dayBuckets: [],
      activeSubjects: [],
      unscheduledActiveSubjects: [],
      stats: {
        active_subjects_total: 0,
        scheduled_subjects_total: 0,
        table_rows_total: 0,
      },
    };
  }
  if (!Number.isInteger(semesterId) || semesterId < 1) {
    return {
      dayBuckets: [],
      activeSubjects: [],
      unscheduledActiveSubjects: [],
      stats: {
        active_subjects_total: 0,
        scheduled_subjects_total: 0,
        table_rows_total: 0,
      },
    };
  }

  const scopedSubjects = await listAcademicV2LegacySubjectIdsForCourseSemester(normalizedCourseId, semesterId);
  let activeSubjectIds = Array.from(new Set((scopedSubjects && scopedSubjects.subject_ids ? scopedSubjects.subject_ids : [])
    .map((value) => Number(value))
    .filter((value) => Number.isInteger(value) && value > 0)));

  let activeSubjects = activeSubjectIds.length
    ? await db.all(
        `
          SELECT id, name
          FROM subjects
          WHERE id = ANY(?::int[])
            AND COALESCE(LOWER(TRIM(CAST(visible AS TEXT))), '1') IN ('1', 'true', 't', 'yes', 'on', '')
          ORDER BY name ASC
        `,
        [activeSubjectIds]
      )
    : [];

  const scheduleRows = activeSubjectIds.length
    ? await db.all(
        `
          SELECT
            se.id,
            se.subject_id,
            se.group_number,
            se.day_of_week,
            se.class_number,
            se.week_number,
            COALESCE(se.lesson_type, '') AS lesson_type,
            se.room_id,
            s.name AS subject_name,
            r.label AS room_name,
            r.code AS room_code,
            r.building AS room_building
          FROM schedule_entries se
          JOIN subjects s ON s.id = se.subject_id
          LEFT JOIN rooms r ON r.id = se.room_id
          WHERE se.course_id = ?
            AND se.semester_id = ?
            AND se.subject_id = ANY(?::int[])
            AND COALESCE(LOWER(TRIM(CAST(s.visible AS TEXT))), '1') IN ('1', 'true', 't', 'yes', 'on', '')
          ORDER BY se.day_of_week ASC,
                   se.class_number ASC,
                   COALESCE(se.week_number, 0) ASC,
                   s.name ASC,
                   COALESCE(se.group_number, 0) ASC,
                   se.id ASC
        `,
        [normalizedCourseId, semesterId, activeSubjectIds]
      )
    : [];

  const teacherSubjectIds = Array.from(new Set([
    ...activeSubjectIds,
    ...(scheduleRows || [])
      .map((row) => Number(row && row.subject_id || 0))
      .filter((value) => Number.isInteger(value) && value > 0),
  ]));
  const teacherMapBySubject = teacherSubjectIds.length
    ? await getSessionSubjectTeacherMap(teacherSubjectIds)
    : new Map();

  const summaryBuckets = new Map();
  (scheduleRows || []).forEach((row) => {
    const dayName = normalizeWeekdayName(row && row.day_of_week) || String(row && row.day_of_week || '').trim();
    const classNumber = Number(row && row.class_number || 0);
    const subjectId = Number(row && row.subject_id || 0);
    if (!dayName || !Number.isInteger(classNumber) || classNumber < 1 || !Number.isInteger(subjectId) || subjectId < 1) {
      return;
    }

    const lessonType = String(row && row.lesson_type || '').trim().toLowerCase();
    const groupNumber = Number(row && row.group_number || 0);
    const resolvedTeachers = resolveSessionTeachersForGroup(
      teacherMapBySubject,
      subjectId,
      Number.isInteger(groupNumber) && groupNumber > 0 ? groupNumber : null
    );
    const teacherNames = resolvedTeachers
      .map((teacher) => String(teacher && teacher.name || '').trim())
      .filter(Boolean)
      .sort((a, b) => a.localeCompare(b, 'uk'));
    const roomLabel = row && row.room_id
      ? roomHelpers.buildRoomLabel({
          label: row.room_name,
          code: row.room_code,
          building: row.room_building,
        })
      : '';
    const bucketKey = [
      dayName,
      classNumber,
      subjectId,
      lessonType || 'lesson',
      teacherNames.join('|') || 'no-teacher',
      roomLabel || 'no-room',
    ].join('::');

    if (!summaryBuckets.has(bucketKey)) {
      summaryBuckets.set(bucketKey, {
        subject_id: subjectId,
        subject_name: String(row && row.subject_name || `Предмет ${subjectId}`),
        lesson_type: lessonType,
        day_name: dayName,
        class_number: classNumber,
        week_numbers: new Set(),
        group_numbers: new Set(),
        teacher_names: new Set(teacherNames),
        room_labels: new Set(roomLabel ? [roomLabel] : []),
      });
    }

    const bucket = summaryBuckets.get(bucketKey);
    const weekNumber = Number(row && row.week_number || 0);
    if (Number.isInteger(weekNumber) && weekNumber > 0) {
      bucket.week_numbers.add(weekNumber);
    }
    if (Number.isInteger(groupNumber) && groupNumber > 0) {
      bucket.group_numbers.add(groupNumber);
    }
    teacherNames.forEach((teacherName) => {
      if (teacherName) bucket.teacher_names.add(teacherName);
    });
    if (roomLabel) {
      bucket.room_labels.add(roomLabel);
    }
  });

  const renderedRows = Array.from(summaryBuckets.values())
    .map((bucket) => {
      const lessonTypeLabel = SEMESTER_SUMMARY_LESSON_TYPE_LABELS[bucket.lesson_type]
        || (bucket.lesson_type
          ? `${bucket.lesson_type.charAt(0).toUpperCase()}${bucket.lesson_type.slice(1)}`
          : 'Заняття');
      const groupLabel = bucket.lesson_type === 'lecture'
        ? ''
        : formatSemesterSummaryGroupLabel(Array.from(bucket.group_numbers));
      const slot = bellSchedule[bucket.class_number] || null;
      const teacherLabel = Array.from(bucket.teacher_names)
        .filter(Boolean)
        .sort((a, b) => a.localeCompare(b, 'uk'))
        .join(', ') || '—';
      const roomLabel = Array.from(bucket.room_labels)
        .filter(Boolean)
        .sort((a, b) => a.localeCompare(b, 'uk'))
        .join(', ') || '—';
      const metaParts = [lessonTypeLabel];
      if (groupLabel) metaParts.push(groupLabel);
      return {
        subject_id: bucket.subject_id,
        subject_name: bucket.subject_name,
        subject_meta: metaParts.join(' • '),
        day_name: bucket.day_name,
        class_number: bucket.class_number,
        time_label: slot ? `${slot.start}-${slot.end}` : `#${bucket.class_number}`,
        teacher_label: teacherLabel,
        weeks_label: formatSemesterSummaryWeekLabel(Array.from(bucket.week_numbers)),
        room_label: roomLabel,
      };
    })
    .sort((a, b) => {
      const dayOrder = (fullWeekDays || daysOfWeek || []).indexOf(a.day_name) - (fullWeekDays || daysOfWeek || []).indexOf(b.day_name);
      if (dayOrder !== 0) return dayOrder;
      if (a.class_number !== b.class_number) return a.class_number - b.class_number;
      return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
    });

  const scheduledSubjectIds = new Set(renderedRows.map((row) => Number(row.subject_id || 0)).filter((value) => Number.isInteger(value) && value > 0));
  const dayOrder = Array.isArray(fullWeekDays) && fullWeekDays.length ? fullWeekDays : [...daysOfWeek];
  const dayBuckets = dayOrder
    .map((dayName) => {
      const rows = renderedRows.filter((row) => row.day_name === dayName);
      return {
        day_name: dayName,
        day_short: String(getStudyDayShortLabel(dayName) || dayName).toUpperCase(),
        rows,
      };
    })
    .filter((bucket) => bucket.rows.length);

  const unscheduledActiveSubjects = (activeSubjects || [])
    .filter((subject) => !scheduledSubjectIds.has(Number(subject && subject.id || 0)))
    .sort((a, b) => String(a && a.name || '').localeCompare(String(b && b.name || ''), 'uk'));

  return {
    dayBuckets,
    activeSubjects: (activeSubjects || [])
      .map((subject) => ({
        id: Number(subject && subject.id || 0),
        name: String(subject && subject.name || ''),
      }))
      .filter((subject) => Number.isInteger(subject.id) && subject.id > 0 && subject.name)
      .sort((a, b) => a.name.localeCompare(b.name, 'uk')),
    unscheduledActiveSubjects,
    stats: {
      active_subjects_total: activeSubjects.length,
      scheduled_subjects_total: scheduledSubjectIds.size,
      table_rows_total: renderedRows.length,
    },
  };
};

app.get('/admin/schedule-summary', requireScheduleSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleSummary.init');
  }
  const roleKeys = getSessionRoleList(req);
  let courses = [];
  let courseId = getStaffCourse(req);
  let allowCourseSelect = false;
  try {
    courses = await getCoursesCached();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleSummary.courses');
  }
  {
    const baseCourseId = Number(req.session.user.course_id || 1);
    const { allowedCourses } = await buildStaffCourseAccess(baseCourseId, courses, roleKeys);
    if (!allowedCourses.length) {
      return res.status(403).send('Forbidden (course access)');
    }
    const filteredAllowedCourses = (allowedCourses || []).filter((course) => !isGeneratorPlaceholderCourseName(course && course.name));
    courses = filteredAllowedCourses.length ? filteredAllowedCourses : allowedCourses;
    const effectiveAllowedCourseIds = new Set((courses || [])
      .map((course) => Number(course && course.id || 0))
      .filter((value) => Number.isInteger(value) && value > 0));
    const requestedCourse = Number(req.query.course_id || req.query.course);
    if (effectiveAllowedCourseIds.has(requestedCourse)) {
      courseId = requestedCourse;
    } else if (!effectiveAllowedCourseIds.has(courseId)) {
      courseId = Number((courses[0] || {}).id || 0);
    }
    req.session.adminCourse = courseId;
    allowCourseSelect = courses.length > 1;
  }
  let activeSemester = null;
  try {
    const rawSemesterList = await getSemestersCached(courseId);
    const academicV2TermNumberBySemesterId = await listAcademicV2LegacyTermNumbersBySemesterId(courseId);
    let semesterList = Array.isArray(rawSemesterList) ? [...rawSemesterList] : [];
    if (semesterList.length) {
      const normalizedSemesters = semesterList
        .map((semester) => {
          const semesterId = Number(semester && semester.id ? semester.id : 0);
          if (!Number.isInteger(semesterId) || semesterId < 1) return null;
          const mappedTermNumber = Number(academicV2TermNumberBySemesterId.get(semesterId) || 0) || null;
          const titleTermNumber = parseAcademicTermNumberFromSemesterTitle(semester.title);
          const resolvedTermNumber = mappedTermNumber || titleTermNumber || null;
          const displayTitle = Number.isInteger(resolvedTermNumber) && resolvedTermNumber > 0
            ? `Term ${resolvedTermNumber}`
            : String(semester.title || `Semester ${semesterId}`);
          return {
            ...semester,
            term_number: resolvedTermNumber,
            display_title: displayTitle,
          };
        })
        .filter(Boolean);
      const canonicalSemesters = normalizedSemesters
        .filter((semester) => Number.isInteger(Number(semester.term_number || 0)) && Number(semester.term_number || 0) >= 1 && Number(semester.term_number || 0) <= 3);
      if (canonicalSemesters.length) {
        const byTermNumber = new Map();
        canonicalSemesters.forEach((semester) => {
          const termNumber = Number(semester.term_number || 0);
          const existing = byTermNumber.get(termNumber);
          if (!existing) {
            byTermNumber.set(termNumber, semester);
            return;
          }
          const currentMapped = academicV2TermNumberBySemesterId.has(Number(semester.id || 0));
          const existingMapped = academicV2TermNumberBySemesterId.has(Number(existing.id || 0));
          if (currentMapped && !existingMapped) {
            byTermNumber.set(termNumber, semester);
          }
        });
        semesterList = Array.from(byTermNumber.entries())
          .sort((left, right) => Number(left[0] || 0) - Number(right[0] || 0))
          .map(([, semester]) => semester);
      } else {
        semesterList = normalizedSemesters.sort((left, right) => Number(left.id || 0) - Number(right.id || 0));
      }
    }
    const selectedCourse = (courses || []).find((course) => Number(course.id) === Number(courseId)) || null;
    const requestedSemesterId = Number(req.query.semester_id);
    if (Number.isFinite(requestedSemesterId) && requestedSemesterId > 0) {
      activeSemester = semesterList.find((sem) => Number(sem.id) === requestedSemesterId) || null;
    }
    if (!activeSemester) {
      const fallbackActiveSemester = await getActiveSemester(courseId);
      if (fallbackActiveSemester) {
        activeSemester = semesterList.find((sem) => Number(sem.id) === Number(fallbackActiveSemester.id)) || null;
      }
    }
    if (!activeSemester && semesterList.length) {
      activeSemester = semesterList[0];
    }
    const semesterSummaryTable = activeSemester
      ? await buildSemesterSummaryTable({
          courseId,
          semester: activeSemester,
        })
      : {
          dayBuckets: [],
          activeSubjects: [],
          unscheduledActiveSubjects: [],
          stats: {
            active_subjects_total: 0,
            scheduled_subjects_total: 0,
            table_rows_total: 0,
          },
        };
    return res.render('admin-schedule-summary', {
      username: req.session.user.username,
      role: normalizeRoleKey(req.session.role || 'student'),
      adminHomeHref: getStaffPanelBase(req, courseId),
      courses,
      selectedCourse,
      semesters: semesterList,
      activeSemester,
      selectedCourseId: courseId,
      allowCourseSelect,
      semesterSummaryDays: semesterSummaryTable.dayBuckets || [],
      semesterSummarySubjects: semesterSummaryTable.activeSubjects || [],
      semesterSummaryUnscheduledSubjects: semesterSummaryTable.unscheduledActiveSubjects || [],
      semesterSummaryStats: semesterSummaryTable.stats || {
        active_subjects_total: 0,
        scheduled_subjects_total: 0,
        table_rows_total: 0,
      },
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleSummary');
  }
});

