app.get('/admin/schedule-generator', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.init');
  }
  const userId = req.session.user.id;
  const runId = Number(req.query.run);
  let run = null;
  try {
    if (Number.isFinite(runId) && runId > 0) {
      run = await db.get('SELECT * FROM schedule_generator_runs WHERE id = ?', [runId]);
    }
    if (!run) {
      run = await db.get(
        'SELECT * FROM schedule_generator_runs WHERE created_by_id = ? ORDER BY created_at DESC LIMIT 1',
        [userId]
      );
    }
    if (!run) {
      const insert = await db.run(
        'INSERT INTO schedule_generator_runs (status, created_by_id, config) VALUES (?, ?, ?) RETURNING id',
        ['draft', userId, serializeGeneratorConfig(DEFAULT_GENERATOR_CONFIG)]
      );
      const newId = insert.lastID;
      return res.redirect(buildScheduleGeneratorUrl(req, newId));
    }

    const parsedConfig = parseGeneratorConfig(run.config);
    const config = parsedConfig && typeof parsedConfig === 'object'
      ? { ...DEFAULT_GENERATOR_CONFIG, ...parsedConfig }
      : { ...DEFAULT_GENERATOR_CONFIG };
    const requestedLocation = String(
      (req.body && req.body.active_location)
      || (req.query && req.query.location)
      || ''
    );
    let activeLocation = requestedLocation.toLowerCase() === 'munich'
      ? 'munich'
      : requestedLocation
      ? 'kyiv'
      : config.active_location === 'munich'
      ? 'munich'
      : 'kyiv';
    if (activeLocation !== config.active_location) {
      config.active_location = activeLocation;
    }
    const requestedGeneratorModeRaw = String((req.query && req.query.mode) || '').trim().toLowerCase();
    const generatorViewMode = requestedGeneratorModeRaw === 'manual' ? 'manual' : 'auto';
    const coursesByLocation = {
      kyiv: await getCoursesByLocation('kyiv'),
      munich: await getCoursesByLocation('munich'),
    };
    const courseSemestersByLocation = { kyiv: [], munich: [] };
    const courseDaysByLocation = { kyiv: {}, munich: {} };
    const subjectsByCourse = {};
    const semestersByCourse = {};
    const selectedSemestersByLocation = { kyiv: {}, munich: {} };
    for (const location of ['kyiv', 'munich']) {
      const courses = coursesByLocation[location] || [];
      for (const course of courses) {
        const semesters = await getSemestersCached(course.id);
        semestersByCourse[course.id] = semesters || [];
        const configuredId = config.course_semesters_by_location
          ? config.course_semesters_by_location[location]?.[course.id]
            || config.course_semesters_by_location[location]?.[String(course.id)]
          : null;
        let semester = null;
        if (configuredId) {
          semester = (semesters || []).find((s) => Number(s.id) === Number(configuredId)) || null;
        }
        if (!semester) {
          semester = await getActiveSemester(course.id);
        }
        if (semester) {
          selectedSemestersByLocation[location][course.id] = semester.id;
        }
        courseSemestersByLocation[location].push({ course, semester });
        const studyDays = await getCourseStudyDays(course.id);
        const activeDays = (studyDays || [])
          .filter((d) => d.is_active)
          .map((d) => d.day_name)
          .filter(Boolean);
        courseDaysByLocation[location][course.id] = activeDays.length ? activeDays : [...daysOfWeek];
        subjectsByCourse[course.id] = await getSubjectsCached(course.id);
      }
    }

    const teachers = await db.all(
      "SELECT id, full_name FROM users WHERE role = 'teacher' ORDER BY full_name"
    );
    const items = await db.all(
      `
        SELECT sgi.*, s.name AS subject_name, s.group_count, s.is_general, u.full_name AS teacher_name
        FROM schedule_generator_items sgi
        JOIN subjects s ON s.id = sgi.subject_id
        LEFT JOIN users u ON u.id = sgi.teacher_id
        WHERE sgi.run_id = ?
        ORDER BY sgi.id DESC
      `,
      [run.id]
    );
    const courseLocationMap = {};
    Object.entries(coursesByLocation).forEach(([location, list]) => {
      (list || []).forEach((course) => {
        courseLocationMap[course.id] = location;
      });
    });
    const limitsRows = await db.all(
      'SELECT * FROM schedule_generator_teacher_limits WHERE run_id = ?',
      [run.id]
    );
    const limitsByTeacher = {};
    limitsRows.forEach((row) => {
      limitsByTeacher[row.teacher_id] = {
        allowed_weekdays: row.allowed_weekdays ? row.allowed_weekdays.split(',') : [],
        max_pairs_per_week: row.max_pairs_per_week,
      };
    });
    const lastConflicts = Array.isArray(config.last_conflicts) ? config.last_conflicts : [];
    const lastStats = config.last_stats || null;
    const allCourses = Object.values(coursesByLocation).flat();
    const courseById = {};
    allCourses.forEach((course) => {
      courseById[course.id] = course.name;
    });
    const courseMetaById = {};
    ['kyiv', 'munich'].forEach((location) => {
      (courseSemestersByLocation[location] || []).forEach((row) => {
        courseMetaById[row.course.id] = {
          weeks_count: row.semester ? Number(row.semester.weeks_count || 0) : 0,
          active_days: courseDaysByLocation[location][row.course.id] || [],
          location,
        };
      });
    });
    const itemsByLocation = { kyiv: [], munich: [] };
    const itemsById = {};
    (items || []).forEach((item) => {
      itemsById[item.id] = item;
      const location = courseLocationMap[item.course_id] || 'kyiv';
      itemsByLocation[location].push(item);
    });
    const mirrorSummaryByLocation = {
      kyiv: buildMirrorSummary(itemsByLocation.kyiv, courseById),
      munich: buildMirrorSummary(itemsByLocation.munich, courseById),
    };
    const validationByLocation = {
      kyiv: buildGeneratorValidation({
        items: itemsByLocation.kyiv,
        courseMetaById,
        teacherLimits: limitsByTeacher,
        config,
        locationLabel: 'Kyiv',
      }),
      munich: buildGeneratorValidation({
        items: itemsByLocation.munich,
        courseMetaById,
        teacherLimits: limitsByTeacher,
        config,
        locationLabel: 'Munich',
      }),
    };
    const { conflictDetails, conflictItemIds } = buildConflictContext(
      lastConflicts,
      itemsById,
      courseById,
      courseLocationMap
    );
    const problemItemLookupByLocation = { kyiv: {}, munich: {} };
    ['kyiv', 'munich'].forEach((location) => {
      const validationItems = validationByLocation[location].itemIssues || {};
      Object.entries(validationItems).forEach(([itemId, info]) => {
        problemItemLookupByLocation[location][itemId] = info.level;
      });
      conflictItemIds[location].forEach((itemId) => {
        if (!problemItemLookupByLocation[location][itemId]) {
          problemItemLookupByLocation[location][itemId] = 'warn';
        }
      });
    });
    const entryRows = await db.all(
      'SELECT course_id, day_of_week, class_number FROM schedule_generator_entries WHERE run_id = ?',
      [run.id]
    );
    const entriesByLocation = { kyiv: [], munich: [] };
    (entryRows || []).forEach((row) => {
      const location = courseLocationMap[row.course_id] || 'kyiv';
      entriesByLocation[location].push(row);
    });
    const heatmapByLocation = {
      kyiv: buildHeatmap(entriesByLocation.kyiv, fullWeekDays, [1, 2, 3, 4, 5, 6, 7]),
      munich: buildHeatmap(entriesByLocation.munich, fullWeekDays, [1, 2, 3, 4, 5, 6, 7]),
    };
    const isSeminarType = (lessonType) => {
      const raw = String(lessonType || '').toLowerCase();
      return raw.includes('seminar') || raw.includes('сем');
    };
    const isGeneralSubject = (item) => {
      if (!item) return true;
      if (item.is_general === true || Number(item.is_general) === 1) return true;
      if (item.is_general === false || Number(item.is_general) === 0) return false;
      const normalized = String(item.is_general ?? '').trim().toLowerCase();
      if (['1', 'true', 't', 'yes', 'y', 'on'].includes(normalized)) return true;
      if (['0', 'false', 'f', 'no', 'n', 'off'].includes(normalized)) return false;
      return true;
    };
    const autoMirrorCandidatesByLocation = { kyiv: [], munich: [] };
    const autoMirrorExclusionsByLocation = { kyiv: [], munich: [] };
    Object.entries(itemsByLocation).forEach(([location, list]) => {
      const buckets = new Map();
      const matchedIds = new Set();
      const sameSubjectOnly = new Set();
      (list || []).forEach((item) => {
        const groupNum = Number(item.group_number);
        const generalFlag = isGeneralSubject(item);
        const baseEligible = isSeminarType(item.lesson_type)
          && (groupNum === 1 || groupNum === 2)
          && !item.mirror_key
          && !(item.fixed_day || item.fixed_class_number || item.weeks_set)
          && generalFlag;
        if (!baseEligible) return;
        const key = `${item.course_id}|${item.semester_id || ''}|${String(item.lesson_type || '')}|${item.pairs_count || 0}`;
        if (!buckets.has(key)) {
          buckets.set(key, { group1: [], group2: [] });
        }
        const bucket = buckets.get(key);
        if (groupNum === 1) bucket.group1.push(item);
        if (groupNum === 2) bucket.group2.push(item);
      });
      const candidates = [];
      buckets.forEach((bucket) => {
        const group1 = [...bucket.group1].sort((a, b) => a.subject_name.localeCompare(b.subject_name) || a.id - b.id);
        const group2 = [...bucket.group2].sort((a, b) => a.subject_name.localeCompare(b.subject_name) || a.id - b.id);
        const used = new Set();
        group1.forEach((a) => {
          const idx = group2.findIndex((b, i) => !used.has(i) && Number(b.subject_id) !== Number(a.subject_id));
          if (idx === -1) return;
          const b = group2[idx];
          used.add(idx);
          matchedIds.add(a.id);
          matchedIds.add(b.id);
          candidates.push({
            a,
            b,
            course_name: courseById[a.course_id] || '',
            lesson_type: a.lesson_type,
            pairs_count: a.pairs_count,
          });
        });
      });
      buckets.forEach((bucket) => {
        bucket.group1.forEach((a) => {
          if (matchedIds.has(a.id)) return;
          const hasSame = bucket.group2.some((b) => Number(b.subject_id) === Number(a.subject_id));
          if (hasSame) sameSubjectOnly.add(a.id);
        });
        bucket.group2.forEach((b) => {
          if (matchedIds.has(b.id)) return;
          const hasSame = bucket.group1.some((a) => Number(a.subject_id) === Number(b.subject_id));
          if (hasSame) sameSubjectOnly.add(b.id);
        });
      });
      const exclusions = [];
      (list || []).forEach((item) => {
        const reasons = [];
        const groupNum = Number(item.group_number);
        const generalFlag = isGeneralSubject(item);
        if (!isSeminarType(item.lesson_type)) reasons.push('Не семінар');
        if (!(groupNum === 1 || groupNum === 2)) reasons.push('Не група 1/2');
        if (item.mirror_key) reasons.push('Вже має ключ дзеркала');
        if (item.fixed_day || item.fixed_class_number || item.weeks_set) reasons.push('Є фіксований день/слот/тижні');
        if (!generalFlag) reasons.push('Не загальний предмет');
        if (!reasons.length && !matchedIds.has(item.id)) {
          if (sameSubjectOnly.has(item.id)) {
            reasons.push('У іншій групі лише такий самий предмет');
          } else {
            reasons.push('Немає пари для групи 1/2');
          }
        }
        if (!reasons.length) return;
        exclusions.push({
          id: item.id,
          subject_name: item.subject_name,
          course_name: courseById[item.course_id] || '',
          group_number: item.group_number,
          lesson_type: item.lesson_type,
          pairs_count: item.pairs_count,
          reasons,
        });
      });
      autoMirrorCandidatesByLocation[location] = candidates;
      autoMirrorExclusionsByLocation[location] = exclusions;
    });
    const generationInsightsByLocation = buildGenerationInsights({
      validationByLocation,
      conflictDetails,
      heatmapByLocation,
      mirrorSummaryByLocation,
      config,
    });

    const activeLocationCourses = coursesByLocation[activeLocation] || [];
    const requestedCourseId = parsePositiveIntStrict(
      (req.query && (req.query.course_id || req.query.selected_course_id))
      || null
    );
    const selectedGlobalCourse = requestedCourseId
      ? ((activeLocationCourses || []).find((course) => Number(course.id) === Number(requestedCourseId)) || null)
      : null;
    const fallbackGlobalCourse = selectedGlobalCourse || (activeLocationCourses[0] || null);
    const selectedGlobalCourseId = fallbackGlobalCourse ? Number(fallbackGlobalCourse.id) : null;
    const requestedSemesterId = parsePositiveIntStrict(
      (req.query && (req.query.semester_id || req.query.selected_semester_id))
      || null
    );
    const configuredSemesterId = selectedGlobalCourseId
      ? parsePositiveIntStrict(
        getConfiguredCourseSemesterId(config, selectedGlobalCourseId, activeLocation)
      )
      : null;
    const selectedSemesterFromLocationMap = selectedGlobalCourseId
      ? parsePositiveIntStrict(
        selectedSemestersByLocation
          && selectedSemestersByLocation[activeLocation]
          && selectedSemestersByLocation[activeLocation][selectedGlobalCourseId]
      )
      : null;
    const academicV2TermNumberBySemesterId = selectedGlobalCourseId
      ? await listAcademicV2LegacyTermNumbersBySemesterId(selectedGlobalCourseId)
      : new Map();
    let selectedGlobalSemesters = selectedGlobalCourseId
      ? (semestersByCourse[selectedGlobalCourseId] || [])
      : [];
    if (selectedGlobalSemesters.length) {
      const normalizedSemesters = selectedGlobalSemesters
        .map((semester) => {
          const semesterId = Number(semester && semester.id ? semester.id : 0);
          if (!Number.isInteger(semesterId) || semesterId < 1) return null;
          const mappedTermNumber = Number(academicV2TermNumberBySemesterId.get(semesterId) || 0) || null;
          const titleTermNumber = parseAcademicTermNumberFromSemesterTitle(semester.title);
          const resolvedTermNumber = mappedTermNumber || titleTermNumber || null;
          const displayTitle = Number.isInteger(resolvedTermNumber) && resolvedTermNumber > 0
            ? `Term ${resolvedTermNumber}`
            : String(semester.title || `Semester ${semesterId}`);
          return {
            ...semester,
            term_number: resolvedTermNumber,
            display_title: displayTitle,
          };
        })
        .filter(Boolean);

      const canonicalSemesters = normalizedSemesters
        .filter((semester) => Number.isInteger(Number(semester.term_number || 0)) && Number(semester.term_number || 0) >= 1 && Number(semester.term_number || 0) <= 3);
      if (canonicalSemesters.length) {
        const byTermNumber = new Map();
        canonicalSemesters.forEach((semester) => {
          const termNumber = Number(semester.term_number || 0);
          const existing = byTermNumber.get(termNumber);
          if (!existing) {
            byTermNumber.set(termNumber, semester);
            return;
          }
          const currentMapped = academicV2TermNumberBySemesterId.has(Number(semester.id || 0));
          const existingMapped = academicV2TermNumberBySemesterId.has(Number(existing.id || 0));
          if (currentMapped && !existingMapped) {
            byTermNumber.set(termNumber, semester);
          }
        });
        selectedGlobalSemesters = Array.from(byTermNumber.entries())
          .sort((left, right) => Number(left[0] || 0) - Number(right[0] || 0))
          .map(([, semester]) => semester);
      } else if (normalizedSemesters.length) {
        selectedGlobalSemesters = normalizedSemesters;
      }
    }
    let selectedGlobalSemester = null;
    if (selectedGlobalSemesters.length && requestedSemesterId) {
      selectedGlobalSemester = selectedGlobalSemesters.find((semester) => Number(semester.id) === Number(requestedSemesterId)) || null;
    }
    if (!selectedGlobalSemester && selectedGlobalSemesters.length && configuredSemesterId) {
      selectedGlobalSemester = selectedGlobalSemesters.find((semester) => Number(semester.id) === Number(configuredSemesterId)) || null;
    }
    if (!selectedGlobalSemester && selectedGlobalSemesters.length && selectedSemesterFromLocationMap) {
      selectedGlobalSemester = selectedGlobalSemesters.find((semester) => Number(semester.id) === Number(selectedSemesterFromLocationMap)) || null;
    }
    if (!selectedGlobalSemester && selectedGlobalSemesters.length) {
      selectedGlobalSemester = selectedGlobalSemesters[0];
    }
    const selectedGlobalSemesterId = selectedGlobalSemester ? Number(selectedGlobalSemester.id) : null;

    const selectedGlobalSubjects = selectedGlobalCourseId
      ? await listScheduleGeneratorScopedVisibleSubjects(selectedGlobalCourseId, selectedGlobalSemesterId)
      : [];
    const selectedGlobalSubjectIds = selectedGlobalSubjects
      .map((subject) => Number(subject.id || 0))
      .filter((value) => Number.isInteger(value) && value > 0);
    const selectedGlobalTeacherMap = selectedGlobalSubjectIds.length
      ? await getSessionSubjectTeacherMap(selectedGlobalSubjectIds)
      : new Map();
    const selectedGlobalTeacherOptionsBySubject = {};
    selectedGlobalSubjectIds.forEach((subjectId) => {
      selectedGlobalTeacherOptionsBySubject[String(subjectId)] = resolveSessionTeachersForGroup(
        selectedGlobalTeacherMap,
        subjectId,
        null
      );
    });
    const selectedGlobalItems = (items || []).filter((item) => (
      Number(item.course_id || 0) === Number(selectedGlobalCourseId || 0)
      && (!selectedGlobalSemesterId || Number(item.semester_id || 0) === Number(selectedGlobalSemesterId))
    ));
    const selectedGlobalItemMap = new Map();
    selectedGlobalItems.forEach((item) => {
      const lessonType = String(item.lesson_type || '').trim().toLowerCase();
      if (!(lessonType === 'lecture' || lessonType === 'seminar')) return;
      if (!(item.group_number === null || typeof item.group_number === 'undefined')) return;
      const key = `${Number(item.subject_id || 0)}|${lessonType}`;
      if (!selectedGlobalItemMap.has(key)) {
        selectedGlobalItemMap.set(key, item);
      }
    });
    const selectedGlobalMatrixRows = [];
    selectedGlobalSubjects.forEach((subject) => {
      const subjectId = Number(subject.id || 0);
      if (!Number.isInteger(subjectId) || subjectId < 1) return;
      ['lecture', 'seminar'].forEach((lessonType) => {
        const key = `${subjectId}|${lessonType}`;
        const existingItem = selectedGlobalItemMap.get(key);
        selectedGlobalMatrixRows.push({
          subject_id: subjectId,
          subject_name: String(subject.name || ''),
          lesson_type: lessonType,
          pairs_count: Number(existingItem && existingItem.pairs_count ? existingItem.pairs_count : 0) || 0,
          teacher_id: existingItem && Number(existingItem.teacher_id || 0) > 0
            ? Number(existingItem.teacher_id)
            : null,
          fixed_day: existingItem && existingItem.fixed_day ? String(existingItem.fixed_day) : '',
          fixed_class_number: existingItem && Number(existingItem.fixed_class_number || 0) > 0
            ? Number(existingItem.fixed_class_number)
            : null,
        });
      });
    });
    const selectedGlobalExtraItemsCount = selectedGlobalItems.filter((item) => {
      const lessonType = String(item.lesson_type || '').trim().toLowerCase();
      if (!(lessonType === 'lecture' || lessonType === 'seminar')) return true;
      return !(item.group_number === null || typeof item.group_number === 'undefined');
    }).length;

    const selectedGlobalSemesterWeeksCount = Number(selectedGlobalSemester && selectedGlobalSemester.weeks_count || 0) || 0;
    const manualScopeKey = buildScheduleGeneratorManualScopeKey({
      location: activeLocation,
      courseId: selectedGlobalCourseId,
      semesterId: selectedGlobalSemesterId,
    });
    const manualScopeSlotsRaw = getScheduleGeneratorManualScopeSlotsFromConfig(config, manualScopeKey, {
      allowedSubjectIds: selectedGlobalSubjectIds,
      maxSlots: SCHEDULE_GENERATOR_MANUAL_SLOTS_LIMIT,
    });
    const manualSlotsByRowKey = new Map();
    (manualScopeSlotsRaw || []).forEach((slot) => {
      const rowKey = buildScheduleGeneratorManualRowKey(slot.subject_id, slot.lesson_type);
      if (!manualSlotsByRowKey.has(rowKey)) {
        manualSlotsByRowKey.set(rowKey, []);
      }
      manualSlotsByRowKey.get(rowKey).push(slot);
    });
    const manualMatrixRowsAll = (selectedGlobalMatrixRows || []).map((row) => {
      const rowKey = buildScheduleGeneratorManualRowKey(row.subject_id, row.lesson_type);
      const rowSlots = manualSlotsByRowKey.get(rowKey) || [];
      const targetPairs = Math.max(0, Number(row.pairs_count || 0) || 0);
      const requiredSlots = selectedGlobalSemesterWeeksCount > 0
        ? Math.ceil(targetPairs / selectedGlobalSemesterWeeksCount)
        : 0;
      const assignedSlots = rowSlots.length;
      const coveredPairs = assignedSlots * selectedGlobalSemesterWeeksCount;
      const remainingPairs = targetPairs - coveredPairs;
      return {
        ...row,
        row_key: rowKey,
        target_pairs: targetPairs,
        required_slots: requiredSlots,
        assigned_slots: assignedSlots,
        covered_pairs: coveredPairs,
        remaining_pairs: remainingPairs,
        slots: rowSlots,
      };
    });
    const manualMatrixRows = manualMatrixRowsAll.filter((row) => Number(row.target_pairs || 0) > 0);
    const manualVisibleRowKeySet = new Set(
      (manualMatrixRows || [])
        .map((row) => String(row && row.row_key || '').trim())
        .filter(Boolean)
    );
    const manualScopeSlots = (manualScopeSlotsRaw || []).filter((slot) => {
      const rowKey = buildScheduleGeneratorManualRowKey(slot && slot.subject_id, slot && slot.lesson_type);
      return manualVisibleRowKeySet.has(rowKey);
    });
    const manualSummary = manualMatrixRows.reduce((acc, row) => {
      acc.rows_total += 1;
      acc.target_pairs_total += Number(row.target_pairs || 0);
      acc.covered_pairs_total += Number(row.covered_pairs || 0);
      acc.required_slots_total += Number(row.required_slots || 0);
      acc.assigned_slots_total += Number(row.assigned_slots || 0);
      if (Number(row.target_pairs || 0) > 0 && Number(row.remaining_pairs || 0) <= 0) {
        acc.closed_rows_total += 1;
      }
      return acc;
    }, {
      rows_total: 0,
      target_pairs_total: 0,
      covered_pairs_total: 0,
      required_slots_total: 0,
      assigned_slots_total: 0,
      closed_rows_total: 0,
    });
    manualSummary.remaining_pairs_total = manualSummary.target_pairs_total - manualSummary.covered_pairs_total;

    if (generatorViewMode === 'manual') {
      return res.render('admin-schedule-generator-manual', {
        username: req.session.user.username,
        role: req.session.role,
        run,
        config,
        activeLocation,
        coursesByLocation,
        selectedGlobalCourseId,
        selectedGlobalSemesterId,
        selectedGlobalCourse: fallbackGlobalCourse,
        selectedGlobalSemester,
        selectedGlobalSemesters,
        selectedGlobalSemesterWeeksCount,
        selectedGlobalSubjects,
        selectedGlobalMatrixRows,
        selectedGlobalTeacherOptionsBySubject,
        selectedGlobalExtraItemsCount,
        manualScopeKey,
        manualScopeSlots,
        manualMatrixRows,
        manualSummary,
        dayOptions: fullWeekDays,
        dayLabels: studyDayLabels,
        classOptions: [1, 2, 3, 4, 5, 6, 7],
        generatorViewMode,
      });
    }

    return res.render('admin-schedule-generator', {
      username: req.session.user.username,
      role: req.session.role,
      run,
      config,
      activeLocation,
      coursesByLocation,
      courseSemestersByLocation,
      courseDaysByLocation,
      subjectsByCourse,
      semestersByCourse,
      selectedSemestersByLocation,
      courseLocationMap,
      courseById,
      teachers,
      items,
      limitsByTeacher,
      lastConflicts,
      lastStats,
      mirrorSummaryByLocation,
      validationByLocation,
      conflictDetails,
      conflictItemIds,
      problemItemLookupByLocation,
      heatmapByLocation,
      generationInsightsByLocation,
      autoMirrorCandidatesByLocation,
      autoMirrorExclusionsByLocation,
      dayOptions: fullWeekDays,
      dayLabels: studyDayLabels,
      classOptions: [1, 2, 3, 4, 5, 6, 7],
      selectedGlobalCourseId,
      selectedGlobalSemesterId,
      selectedGlobalCourse: fallbackGlobalCourse,
      selectedGlobalSemester,
      selectedGlobalSemesters,
      selectedGlobalSubjects,
      selectedGlobalMatrixRows,
      selectedGlobalTeacherOptionsBySubject,
      selectedGlobalExtraItemsCount,
      generatorViewMode,
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.render');
  }
});

app.get('/admin/schedule-generator/merge-preview', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.mergePreview');
  }
  const courseIdRaw = Number(req.query.course_id);
  const courseId = Number.isFinite(courseIdRaw) && courseIdRaw > 0 ? courseIdRaw : null;
  try {
    const preview = await buildSubjectMergePreview(courseId);
    return res.json({
      generated_at: new Date().toISOString(),
      total: preview.length,
      course_id: courseId,
      merges: preview,
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.mergePreview');
  }
});

app.post('/admin/schedule-generator/new', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.create');
  }
  const userId = req.session.user.id;
  try {
    const insert = await db.run(
      'INSERT INTO schedule_generator_runs (status, created_by_id, config) VALUES (?, ?, ?) RETURNING id',
      ['draft', userId, serializeGeneratorConfig(DEFAULT_GENERATOR_CONFIG)]
    );
    const runId = insert.lastID;
    return res.redirect(buildScheduleGeneratorUrl(req, runId));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.create');
  }
});

app.post('/admin/schedule-generator/config', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.config');
  }
  const runId = Number(req.body.run_id);
  if (!Number.isFinite(runId) || runId <= 0) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid run'));
  }
  try {
    const run = await db.get('SELECT * FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Run not found'));
    const existing = parseGeneratorConfig(run.config);
    const maxDailyRaw = Number(req.body.max_daily_pairs);
    const targetDailyRaw = Number(req.body.target_daily_pairs);
    const evennessRaw = Number(req.body.evenness_bias);
    const lateSlotRaw = Number(req.body.late_slot_weight);
    const maxDailyPairs = Number.isNaN(maxDailyRaw)
      ? existing.max_daily_pairs
      : Math.min(Math.max(maxDailyRaw, 1), 7);
    const targetDailyPairs = Number.isNaN(targetDailyRaw)
      ? existing.target_daily_pairs
      : Math.min(Math.max(targetDailyRaw, 1), 7);
    const evennessBias = Number.isNaN(evennessRaw)
      ? existing.evenness_bias
      : Math.min(Math.max(evennessRaw, 0), 100);
    const lateSlotWeight = Number.isNaN(lateSlotRaw)
      ? existing.late_slot_weight
      : Math.min(Math.max(lateSlotRaw, 0), 100);
    const activeLocation = String(req.body.active_location || existing.active_location || 'kyiv').toLowerCase() === 'munich'
      ? 'munich'
      : 'kyiv';
    const selectedLocationRaw = String(req.body.location || activeLocation).toLowerCase();
    const selectedLocation = selectedLocationRaw === 'munich' ? 'munich' : 'kyiv';
    const selectedCourseId = parsePositiveIntStrict(req.body.course_id);
    const selectedSemesterId = parsePositiveIntStrict(req.body.semester_id);
    const courseSemesterInput = req.body.course_semesters && typeof req.body.course_semesters === 'object'
      ? req.body.course_semesters
      : {};
    const existingCourseSemesters = {
      ...((existing.course_semesters_by_location && existing.course_semesters_by_location[activeLocation]) || {}),
    };
    const sanitizedCourseSemesters = { ...existingCourseSemesters };
    const entries = Object.entries(courseSemesterInput);
    for (const [courseIdRaw, semesterIdRaw] of entries) {
      const courseId = Number(courseIdRaw);
      const semesterId = Number(semesterIdRaw);
      if (!Number.isFinite(courseId) || !Number.isFinite(semesterId)) continue;
      const row = await db.get('SELECT id FROM semesters WHERE id = ? AND course_id = ?', [semesterId, courseId]);
      if (row) {
        sanitizedCourseSemesters[String(courseId)] = semesterId;
      }
    }
    if (selectedCourseId && selectedSemesterId) {
      const scopedSemesterRow = await db.get(
        'SELECT id FROM semesters WHERE id = ? AND course_id = ?',
        [selectedSemesterId, selectedCourseId]
      );
      if (scopedSemesterRow) {
        sanitizedCourseSemesters[String(selectedCourseId)] = selectedSemesterId;
      }
    }
    const specialWeeksMode = String(req.body.special_weeks_mode || existing.special_weeks_mode || 'block') === 'overlay'
      ? 'overlay'
      : 'block';
    const nextCourseSemestersByLocation = {
      ...(existing.course_semesters_by_location || { kyiv: {}, munich: {} }),
      [activeLocation]: sanitizedCourseSemesters,
    };
    const nextConfig = {
      ...existing,
      active_location: activeLocation,
      distribution: normalizeDistribution(req.body.distribution, existing.distribution || 'even'),
      seminar_distribution: normalizeDistribution(req.body.seminar_distribution, existing.seminar_distribution || 'even'),
      max_daily_pairs: maxDailyPairs || 7,
      target_daily_pairs: targetDailyPairs || 4,
      evenness_bias: evennessBias,
      late_slot_weight: Number.isFinite(lateSlotWeight) ? lateSlotWeight : 0,
      blocked_weeks: String(req.body.blocked_weeks || ''),
      special_weeks_mode: specialWeeksMode,
      prefer_compactness: String(req.body.prefer_compactness || '') === 'on',
      strict_no_evening: String(req.body.strict_no_evening || '') === 'on',
      mirror_groups: String(req.body.mirror_groups || '') === 'on',
      auto_subject_days: String(req.body.auto_subject_days || '') === 'on',
      subject_single_day: String(req.body.subject_single_day || '') === 'on',
      lecture_seminar_same_day: String(req.body.lecture_seminar_same_day || '') === 'on',
      lecture_before_seminar: String(req.body.lecture_before_seminar || '') === 'on',
      course_semesters: sanitizedCourseSemesters,
      course_semesters_by_location: nextCourseSemestersByLocation,
    };
    await db.run(
      'UPDATE schedule_generator_runs SET config = ?, updated_at = NOW() WHERE id = ?',
      [serializeGeneratorConfig(nextConfig), runId]
    );
    const semesterPairs = Object.entries(sanitizedCourseSemesters);
    for (const [courseId, semesterId] of semesterPairs) {
      await db.run(
        'UPDATE schedule_generator_items SET semester_id = ? WHERE run_id = ? AND course_id = ?',
        [Number(semesterId), runId, Number(courseId)]
      );
    }
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'ok', 'Settings saved', runId, {
      location: selectedLocation,
      course_id: selectedCourseId,
      semester_id: selectedSemesterId,
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.config.save');
  }
});

app.post('/admin/schedule-generator/config/autotune', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.config.autotune');
  }
  const runId = Number(req.body.run_id);
  if (!Number.isFinite(runId) || runId <= 0) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid run'));
  }
  try {
    const run = await db.get('SELECT * FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Run not found'));
    const existing = parseGeneratorConfig(run.config);
    const activeLocation = String(req.body.active_location || existing.active_location || 'kyiv').toLowerCase() === 'munich'
      ? 'munich'
      : 'kyiv';

    const coursesByLocation = {
      kyiv: await getCoursesByLocation('kyiv'),
      munich: await getCoursesByLocation('munich'),
    };
    const courseMetaById = {};
    const courseById = {};
    const courseLocationMap = {};
    for (const location of ['kyiv', 'munich']) {
      const courses = coursesByLocation[location] || [];
      for (const course of courses) {
        const semesters = await getSemestersCached(course.id);
        const configuredId = existing.course_semesters_by_location
          ? existing.course_semesters_by_location[location]?.[course.id]
            || existing.course_semesters_by_location[location]?.[String(course.id)]
          : null;
        let semester = null;
        if (configuredId) {
          semester = (semesters || []).find((s) => Number(s.id) === Number(configuredId)) || null;
        }
        if (!semester) {
          semester = await getActiveSemester(course.id);
        }
        const studyDays = await getCourseStudyDays(course.id);
        const activeDays = (studyDays || [])
          .filter((d) => d.is_active)
          .map((d) => d.day_name)
          .filter(Boolean);
        courseMetaById[course.id] = {
          weeks_count: semester ? Number(semester.weeks_count || 0) : 0,
          active_days: activeDays.length ? activeDays : [...daysOfWeek],
          location,
        };
        courseById[course.id] = course.name;
        courseLocationMap[course.id] = location;
      }
    }

    const items = await db.all(
      `
        SELECT sgi.*, s.name AS subject_name, s.group_count, s.is_general, u.full_name AS teacher_name
        FROM schedule_generator_items sgi
        JOIN subjects s ON s.id = sgi.subject_id
        LEFT JOIN users u ON u.id = sgi.teacher_id
        WHERE sgi.run_id = ?
        ORDER BY sgi.id DESC
      `,
      [run.id]
    );
    const itemsByLocation = { kyiv: [], munich: [] };
    const itemsById = {};
    (items || []).forEach((item) => {
      itemsById[item.id] = item;
      const location = courseLocationMap[item.course_id] || 'kyiv';
      itemsByLocation[location].push(item);
    });

    const limitsRows = await db.all(
      'SELECT * FROM schedule_generator_teacher_limits WHERE run_id = ?',
      [run.id]
    );
    const limitsByTeacher = {};
    limitsRows.forEach((row) => {
      limitsByTeacher[row.teacher_id] = {
        allowed_weekdays: row.allowed_weekdays ? row.allowed_weekdays.split(',') : [],
        max_pairs_per_week: row.max_pairs_per_week,
      };
    });

    const validationByLocation = {
      kyiv: buildGeneratorValidation({
        items: itemsByLocation.kyiv,
        courseMetaById,
        teacherLimits: limitsByTeacher,
        config: existing,
        locationLabel: 'Kyiv',
      }),
      munich: buildGeneratorValidation({
        items: itemsByLocation.munich,
        courseMetaById,
        teacherLimits: limitsByTeacher,
        config: existing,
        locationLabel: 'Munich',
      }),
    };
    const mirrorSummaryByLocation = {
      kyiv: buildMirrorSummary(itemsByLocation.kyiv, courseById),
      munich: buildMirrorSummary(itemsByLocation.munich, courseById),
    };
    const lastConflicts = Array.isArray(existing.last_conflicts) ? existing.last_conflicts : [];
    const { conflictDetails } = buildConflictContext(
      lastConflicts,
      itemsById,
      courseById,
      courseLocationMap
    );
    const entryRows = await db.all(
      'SELECT course_id, day_of_week, class_number FROM schedule_generator_entries WHERE run_id = ?',
      [run.id]
    );
    const entriesByLocation = { kyiv: [], munich: [] };
    (entryRows || []).forEach((row) => {
      const location = courseLocationMap[row.course_id] || 'kyiv';
      entriesByLocation[location].push(row);
    });
    const heatmapByLocation = {
      kyiv: buildHeatmap(entriesByLocation.kyiv, fullWeekDays, [1, 2, 3, 4, 5, 6, 7]),
      munich: buildHeatmap(entriesByLocation.munich, fullWeekDays, [1, 2, 3, 4, 5, 6, 7]),
    };
    const insightsByLocation = buildGenerationInsights({
      validationByLocation,
      conflictDetails,
      heatmapByLocation,
      mirrorSummaryByLocation,
      config: existing,
    });
    const patch = buildSafeAutoTunePatch(existing, insightsByLocation[activeLocation]);
    const nextConfig = {
      ...existing,
      ...patch,
      active_location: activeLocation,
    };
    await db.run(
      'UPDATE schedule_generator_runs SET config = ?, updated_at = NOW() WHERE id = ?',
      [serializeGeneratorConfig(nextConfig), runId]
    );
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'ok', 'Safe auto-tune applied', runId));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.config.autotune.save');
  }
});

app.post('/admin/schedule-generator/items/add', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.item');
  }
  const runId = Number(req.body.run_id);
  const courseId = Number(req.body.course_id);
  const subjectId = Number(req.body.subject_id);
  const teacherIdRaw = req.body.teacher_id ? Number(req.body.teacher_id) : null;
  const lessonTypeRaw = String(req.body.lesson_type || 'lecture').trim();
  const lessonType = lessonTypeRaw || 'lecture';
  const groupRaw = String(req.body.group_number || 'all');
  const groupNumber = groupRaw === 'all' || groupRaw === '0' ? null : Number(groupRaw);
  const pairsCount = Number(req.body.pairs_count);
  const weeksSet = String(req.body.weeks_set || '').trim();
  const fixedDay = normalizeWeekdayName(req.body.fixed_day);
  const fixedClass = req.body.fixed_class_number ? Number(req.body.fixed_class_number) : null;
  const mirrorKeyRaw = String(req.body.mirror_key || '').trim();
  const mirrorKey = mirrorKeyRaw || null;

  if (!Number.isFinite(runId) || runId <= 0 || !Number.isFinite(courseId) || !Number.isFinite(subjectId)) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid data', runId));
  }
  if (!Number.isFinite(pairsCount) || pairsCount <= 0) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid pairs', runId));
  }
  if (groupNumber && (Number.isNaN(groupNumber) || groupNumber < 1)) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid group', runId));
  }
  if (fixedClass && (fixedClass < 1 || fixedClass > 7)) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid slot', runId));
  }

  try {
    const subjectRow = await resolveSubjectCourseContext(subjectId, courseId, { includeHidden: true });
    if (!subjectRow) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Subject not found', runId));
    }
    const storageCourseId = Number(subjectRow.owner_course_id || subjectRow.course_id || courseId || 1);
    if (groupNumber && Number(groupNumber) > Number(subjectRow.group_count || 1)) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid group', runId));
    }
    const run = await db.get('SELECT config FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Run not found', runId));
    }
    const runConfig = parseGeneratorConfig(run.config);
    const courseRow = await db.get('SELECT location FROM courses WHERE id = ?', [storageCourseId]);
    const courseLocation = String(courseRow?.location || 'kyiv').toLowerCase() === 'munich' ? 'munich' : 'kyiv';
    const configuredSemesterId = runConfig.course_semesters_by_location
      ? runConfig.course_semesters_by_location[courseLocation]?.[storageCourseId]
        || runConfig.course_semesters_by_location[courseLocation]?.[String(storageCourseId)]
      : null;
    let semester = null;
    if (configuredSemesterId) {
      semester = await db.get('SELECT id FROM semesters WHERE id = ? AND course_id = ?', [configuredSemesterId, storageCourseId]);
    }
    if (!semester) {
      semester = await getActiveSemester(storageCourseId);
    }
    if (!semester) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Semester not found', runId));
    }
    const lessonTypeLower = String(lessonType || '').toLowerCase();
    const isSeminar = lessonTypeLower.includes('seminar') || lessonTypeLower.includes('сем');
    const totalGroups = Math.max(1, Number(subjectRow.group_count || 1));
    const shouldSplitAllGroups = !groupNumber && isSeminar && totalGroups > 1;
    if (shouldSplitAllGroups) {
      const stmt = db.prepare(
        `
          INSERT INTO schedule_generator_items
            (run_id, course_id, semester_id, subject_id, teacher_id, lesson_type, group_number, pairs_count, weeks_set, fixed_day, fixed_class_number, mirror_key)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `
      );
      for (let g = 1; g <= totalGroups; g += 1) {
        stmt.run(
          runId,
          storageCourseId,
          semester.id,
          subjectId,
          teacherIdRaw || null,
          lessonType,
          g,
          pairsCount,
          weeksSet || null,
          fixedDay,
          fixedClass || null,
          mirrorKey
        );
      }
      await stmt.finalize();
    } else {
      await db.run(
        `
          INSERT INTO schedule_generator_items
            (run_id, course_id, semester_id, subject_id, teacher_id, lesson_type, group_number, pairs_count, weeks_set, fixed_day, fixed_class_number, mirror_key)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `,
        [
          runId,
          storageCourseId,
          semester.id,
          subjectId,
          teacherIdRaw || null,
          lessonType,
          groupNumber,
          pairsCount,
          weeksSet || null,
          fixedDay,
          fixedClass || null,
          mirrorKey,
        ]
      );
    }
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'ok', 'Item added', runId));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.item.add');
  }
});

app.post('/admin/schedule-generator/items/bulk-sync', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.items.bulkSync.init');
  }
  const runId = Number(req.body.run_id);
  const courseId = Number(req.body.course_id);
  const semesterId = Number(req.body.semester_id);
  const activeLocation = normalizeGeneratorLocation(req.body.active_location || 'kyiv');
  const syncMode = String(req.body.sync_mode || '').trim().toLowerCase();
  const silentSync = syncMode === 'auto';
  if (
    !Number.isFinite(runId) || runId <= 0
    || !Number.isFinite(courseId) || courseId <= 0
    || !Number.isFinite(semesterId) || semesterId <= 0
  ) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid scope', runId || null));
  }

  const toArray = (value) => {
    if (Array.isArray(value)) return value;
    if (value === undefined || value === null) return [];
    return [value];
  };
  const subjectRows = toArray(req.body.row_subject_id);
  const lessonTypeRows = toArray(req.body.row_lesson_type);
  const pairsRows = toArray(req.body.row_pairs_count);
  const teacherRows = toArray(req.body.row_teacher_id);
  const fixedDayRows = toArray(req.body.row_fixed_day);
  const fixedClassRows = toArray(req.body.row_fixed_class_number);
  const rowCount = Math.max(
    subjectRows.length,
    lessonTypeRows.length,
    pairsRows.length,
    teacherRows.length,
    fixedDayRows.length,
    fixedClassRows.length
  );

  try {
    const run = await db.get('SELECT config FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Run not found', runId));
    }
    const semester = await db.get('SELECT id FROM semesters WHERE id = ? AND course_id = ?', [semesterId, courseId]);
    if (!semester) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Semester not found', runId));
    }
    const subjectRowsForCourse = await getSubjectsCached(courseId, { visibleOnly: true });
    const subjectMap = new Map(
      (subjectRowsForCourse || [])
        .filter((subject) => Number(subject.visible || 1) !== 0)
        .map((subject) => [Number(subject.id || 0), subject])
    );
    const teacherMapBySubject = subjectMap.size
      ? await getSessionSubjectTeacherMap(Array.from(subjectMap.keys()))
      : new Map();
    const resolveDefaultTeacherId = (subjectId) => {
      let candidates = resolveSessionTeachersForGroup(teacherMapBySubject, subjectId, null);
      if ((!Array.isArray(candidates) || !candidates.length) && teacherMapBySubject.has(Number(subjectId))) {
        const subjectTeacherMap = teacherMapBySubject.get(Number(subjectId));
        const flattened = new Map();
        if (subjectTeacherMap && subjectTeacherMap.byGroup && typeof subjectTeacherMap.byGroup.forEach === 'function') {
          subjectTeacherMap.byGroup.forEach((groupMap) => {
            if (!groupMap || typeof groupMap.forEach !== 'function') return;
            groupMap.forEach((teacherName, teacherIdRaw) => {
              const teacherId = Number(teacherIdRaw || 0);
              if (!Number.isFinite(teacherId) || teacherId < 1) return;
              flattened.set(teacherId, String(teacherName || `ID ${teacherId}`));
            });
          });
        }
        candidates = Array.from(flattened.entries())
          .map(([id, name]) => ({ id, name }))
          .sort((a, b) => String(a.name || '').localeCompare(String(b.name || ''), 'uk'));
      }
      if (!Array.isArray(candidates) || !candidates.length) return null;
      const defaultId = Number(candidates[0] && candidates[0].id ? candidates[0].id : 0);
      return Number.isFinite(defaultId) && defaultId > 0 ? defaultId : null;
    };

    const normalizedRows = [];
    for (let idx = 0; idx < rowCount; idx += 1) {
      const subjectId = Number(subjectRows[idx]);
      if (!Number.isFinite(subjectId) || subjectId < 1 || !subjectMap.has(subjectId)) continue;
      const lessonTypeRaw = String(lessonTypeRows[idx] || '').trim().toLowerCase();
      const lessonType = lessonTypeRaw === 'seminar' ? 'seminar' : lessonTypeRaw === 'lecture' ? 'lecture' : '';
      if (!lessonType) continue;
      const pairsCount = Number(pairsRows[idx]);
      if (!Number.isFinite(pairsCount) || pairsCount <= 0) continue;
      const fixedDay = normalizeWeekdayName(String(fixedDayRows[idx] || '').trim()) || null;
      const fixedClassRaw = Number(fixedClassRows[idx]);
      const fixedClass = Number.isFinite(fixedClassRaw) && fixedClassRaw > 0
        ? Math.floor(fixedClassRaw)
        : null;
      if (fixedClass !== null && (fixedClass < 1 || fixedClass > 7)) {
        return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid slot', runId, {
          location: activeLocation,
          course_id: courseId,
          semester_id: semesterId,
        }));
      }
      let teacherId = Number(teacherRows[idx]);
      if (!Number.isFinite(teacherId) || teacherId < 1) {
        teacherId = resolveDefaultTeacherId(subjectId);
      }
      normalizedRows.push({
        subject_id: subjectId,
        lesson_type: lessonType,
        pairs_count: Math.max(1, Math.min(120, Math.floor(pairsCount))),
        teacher_id: Number.isFinite(teacherId) && teacherId > 0 ? Math.floor(teacherId) : null,
        fixed_day: fixedDay,
        fixed_class_number: fixedClass,
      });
    }

    const dedupedRows = Array.from(new Map(
      normalizedRows.map((row) => [`${row.subject_id}|${row.lesson_type}`, row])
    ).values());
    const runConfig = parseGeneratorConfig(run.config);
    const nextCourseSemestersByLocation = {
      ...(runConfig.course_semesters_by_location || { kyiv: {}, munich: {} }),
      [activeLocation]: {
        ...((runConfig.course_semesters_by_location && runConfig.course_semesters_by_location[activeLocation]) || {}),
        [String(courseId)]: semesterId,
      },
    };
    const nextConfig = {
      ...runConfig,
      active_location: activeLocation,
      course_semesters_by_location: nextCourseSemestersByLocation,
    };

    await withTransaction(async (client) => {
      await txRun(
        client,
        'DELETE FROM schedule_generator_items WHERE run_id = ? AND course_id = ? AND semester_id = ?',
        [runId, courseId, semesterId]
      );
      const insertSql = `
        INSERT INTO schedule_generator_items
          (run_id, course_id, semester_id, subject_id, teacher_id, lesson_type, group_number, pairs_count, weeks_set, fixed_day, fixed_class_number, mirror_key)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `;
      for (const row of dedupedRows) {
        await txRun(client, insertSql, [
          runId,
          courseId,
          semesterId,
          row.subject_id,
          row.teacher_id,
          row.lesson_type,
          null,
          row.pairs_count,
          null,
          row.fixed_day,
          row.fixed_class_number,
          null,
        ]);
      }
      await txRun(
        client,
        'UPDATE schedule_generator_runs SET config = ?, updated_at = NOW() WHERE id = ?',
        [serializeGeneratorConfig(nextConfig), runId]
      );
    });

    if (silentSync) {
      return res.redirect(buildScheduleGeneratorUrl(req, runId, {
        location: activeLocation,
        course_id: courseId,
        semester_id: semesterId,
      }));
    }
    return res.redirect(buildScheduleGeneratorNoticeUrl(
      req,
      'ok',
      `Plan synced (${dedupedRows.length}).`,
      runId,
      {
        location: activeLocation,
        course_id: courseId,
        semester_id: semesterId,
      }
    ));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.items.bulkSync');
  }
});

app.post('/admin/schedule-generator/manual-slots/save', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return res.status(500).json({ ok: false, error: 'db_init_failed' });
  }
  try {
    const runId = parsePositiveIntStrict(req.body.run_id);
    const courseId = parsePositiveIntStrict(req.body.course_id);
    const semesterId = parsePositiveIntStrict(req.body.semester_id);
    const activeLocation = normalizeGeneratorLocation(req.body.active_location || req.body.location || 'kyiv');
    if (!runId || !courseId || !semesterId) {
      return res.status(400).json({ ok: false, error: 'invalid_scope' });
    }
    const run = await db.get('SELECT config FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) {
      return res.status(404).json({ ok: false, error: 'run_not_found' });
    }
    const semester = await db.get('SELECT id FROM semesters WHERE id = ? AND course_id = ?', [semesterId, courseId]);
    if (!semester) {
      return res.status(400).json({ ok: false, error: 'semester_not_found' });
    }
    const scopedSubjects = await listScheduleGeneratorScopedVisibleSubjects(courseId, semesterId);
    const scopedSubjectIds = (scopedSubjects || [])
      .map((subject) => parsePositiveIntStrict(subject && subject.id))
      .filter((value) => Number.isInteger(value) && value > 0);
    const scopeKey = buildScheduleGeneratorManualScopeKey({
      location: activeLocation,
      courseId,
      semesterId,
    });
    const manualScopeSlotsRaw = parseScheduleGeneratorManualSlots(req.body.slots_json, {
      allowedSubjectIds: scopedSubjectIds,
      maxSlots: SCHEDULE_GENERATOR_MANUAL_SLOTS_LIMIT,
    });
    const manualActiveRowKeySet = await listScheduleGeneratorManualActiveRowKeySet(runId, courseId, semesterId, {
      allowedSubjectIds: scopedSubjectIds,
    });
    const manualScopeSlots = (manualScopeSlotsRaw || []).filter((slot) => {
      const rowKey = buildScheduleGeneratorManualRowKey(slot && slot.subject_id, slot && slot.lesson_type);
      return manualActiveRowKeySet.has(rowKey);
    });
    const runConfig = parseGeneratorConfig(run.config);
    const manualScopeBag = runConfig && runConfig.manual_scope_slots && typeof runConfig.manual_scope_slots === 'object'
      ? { ...runConfig.manual_scope_slots }
      : {};
    if (manualScopeSlots.length) {
      manualScopeBag[scopeKey] = manualScopeSlots;
    } else if (Object.prototype.hasOwnProperty.call(manualScopeBag, scopeKey)) {
      delete manualScopeBag[scopeKey];
    }
    const nextCourseSemestersByLocation = {
      ...(runConfig.course_semesters_by_location || { kyiv: {}, munich: {} }),
      [activeLocation]: {
        ...((runConfig.course_semesters_by_location && runConfig.course_semesters_by_location[activeLocation]) || {}),
        [String(courseId)]: semesterId,
      },
    };
    const nextConfig = {
      ...runConfig,
      active_location: activeLocation,
      course_semesters_by_location: nextCourseSemestersByLocation,
      manual_scope_slots: manualScopeBag,
    };
    await db.run(
      'UPDATE schedule_generator_runs SET config = ?, updated_at = NOW() WHERE id = ?',
      [serializeGeneratorConfig(nextConfig), runId]
    );
    return res.json({
      ok: true,
      run_id: runId,
      scope_key: scopeKey,
      slots_total: manualScopeSlots.length,
    });
  } catch (err) {
    return res.status(500).json({ ok: false, error: 'save_failed' });
  }
});

app.post('/admin/schedule-generator/manual-run', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.manualRun.init');
  }
  const runId = parsePositiveIntStrict(req.body.run_id);
  const courseId = parsePositiveIntStrict(req.body.course_id);
  const semesterId = parsePositiveIntStrict(req.body.semester_id);
  const activeLocation = normalizeGeneratorLocation(req.body.active_location || req.body.location || 'kyiv');
  const redirectManualNotice = (kind, message) => res.redirect(
    buildScheduleGeneratorNoticeUrl(req, kind, message, runId, {
      location: activeLocation,
      course_id: courseId,
      semester_id: semesterId,
      mode: 'manual',
    })
  );
  if (!runId || !courseId || !semesterId) {
    return redirectManualNotice('err', 'Invalid scope');
  }
  try {
    const run = await db.get('SELECT * FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) {
      return redirectManualNotice('err', 'Run not found');
    }
    const semester = await db.get('SELECT * FROM semesters WHERE id = ? AND course_id = ?', [semesterId, courseId]);
    if (!semester) {
      return redirectManualNotice('err', 'Semester not found');
    }
    const weeksCount = Number(semester.weeks_count || 0);
    if (!Number.isInteger(weeksCount) || weeksCount < 1) {
      return redirectManualNotice('err', 'Semester weeks are not configured');
    }

    const scopedSubjects = await listScheduleGeneratorScopedVisibleSubjects(courseId, semesterId);
    const scopedSubjectMap = new Map(
      (scopedSubjects || [])
        .map((subject) => [parsePositiveIntStrict(subject && subject.id), subject])
        .filter(([subjectId]) => Number.isInteger(subjectId) && subjectId > 0)
    );
    if (!scopedSubjectMap.size) {
      return redirectManualNotice('err', 'No subjects in selected scope');
    }
    const scopedSubjectIds = Array.from(scopedSubjectMap.keys());
    const scopeKey = buildScheduleGeneratorManualScopeKey({
      location: activeLocation,
      courseId,
      semesterId,
    });
    const runConfig = parseGeneratorConfig(run.config);
    const bodySlots = parseScheduleGeneratorManualSlots(req.body.slots_json, {
      allowedSubjectIds: scopedSubjectIds,
      maxSlots: SCHEDULE_GENERATOR_MANUAL_SLOTS_LIMIT,
    });
    const configSlots = getScheduleGeneratorManualScopeSlotsFromConfig(runConfig, scopeKey, {
      allowedSubjectIds: scopedSubjectIds,
      maxSlots: SCHEDULE_GENERATOR_MANUAL_SLOTS_LIMIT,
    });
    const scopedManualScopeSlots = bodySlots.length ? bodySlots : configSlots;
    const manualActiveRowKeySet = await listScheduleGeneratorManualActiveRowKeySet(runId, courseId, semesterId, {
      allowedSubjectIds: scopedSubjectIds,
    });
    const manualScopeSlots = (scopedManualScopeSlots || []).filter((slot) => {
      const rowKey = buildScheduleGeneratorManualRowKey(slot && slot.subject_id, slot && slot.lesson_type);
      return manualActiveRowKeySet.has(rowKey);
    });
    if (!manualScopeSlots.length) {
      return redirectManualNotice('err', 'Manual slot plan is empty');
    }

    const matrixItemsRaw = await db.all(
      `
        SELECT
          sgi.id,
          sgi.subject_id,
          sgi.teacher_id,
          sgi.lesson_type,
          sgi.group_number,
          sgi.pairs_count,
          s.name AS subject_name,
          s.group_count,
          s.is_general
        FROM schedule_generator_items sgi
        JOIN subjects s ON s.id = sgi.subject_id
        WHERE sgi.run_id = ?
          AND sgi.course_id = ?
          AND sgi.semester_id = ?
          AND sgi.group_number IS NULL
      `,
      [runId, courseId, semesterId]
    );
    const matrixItemMap = new Map();
    (matrixItemsRaw || []).forEach((item) => {
      const subjectId = parsePositiveIntStrict(item && item.subject_id);
      if (!subjectId || !scopedSubjectMap.has(subjectId)) return;
      const lessonType = normalizeScheduleGeneratorLessonType(item && item.lesson_type);
      const rowKey = buildScheduleGeneratorManualRowKey(subjectId, lessonType);
      if (!matrixItemMap.has(rowKey)) {
        matrixItemMap.set(rowKey, {
          ...item,
          subject_id: subjectId,
          lesson_type: lessonType,
          pairs_count: Math.max(0, Number(item && item.pairs_count || 0) || 0),
          group_count: Math.max(1, Number(item && item.group_count || 1) || 1),
        });
      }
    });

    const teacherMapBySubject = scopedSubjectIds.length
      ? await getSessionSubjectTeacherMap(scopedSubjectIds)
      : new Map();
    const defaultTeacherBySubject = new Map();
    scopedSubjectIds.forEach((subjectId) => {
      const candidates = resolveSessionTeachersForGroup(teacherMapBySubject, subjectId, null);
      const teacherId = Number(candidates && candidates[0] && candidates[0].id ? candidates[0].id : 0);
      if (Number.isFinite(teacherId) && teacherId > 0) {
        defaultTeacherBySubject.set(subjectId, teacherId);
      }
    });

    const manualMatrixMap = new Map();
    scopedSubjectMap.forEach((subject, subjectId) => {
      ['lecture', 'seminar'].forEach((lessonType) => {
        const rowKey = buildScheduleGeneratorManualRowKey(subjectId, lessonType);
        const item = matrixItemMap.get(rowKey);
        const teacherIdRaw = Number(item && item.teacher_id || 0);
        const teacherId = Number.isFinite(teacherIdRaw) && teacherIdRaw > 0
          ? teacherIdRaw
          : (defaultTeacherBySubject.get(subjectId) || null);
        manualMatrixMap.set(rowKey, {
          row_key: rowKey,
          item_id: parsePositiveIntStrict(item && item.id) || null,
          subject_id: subjectId,
          subject_name: String(subject && subject.name || ''),
          lesson_type: lessonType,
          pairs_count: Math.max(0, Number(item && item.pairs_count || 0) || 0),
          teacher_id: teacherId,
          group_number: parsePositiveIntStrict(item && item.group_number) || null,
          group_count: Math.max(1, Number(subject && subject.group_count || 1) || 1),
          is_general: subject && (subject.is_general === true || Number(subject.is_general) === 1),
        });
      });
    });

    const slotCountByRow = new Map();
    (manualScopeSlots || []).forEach((slot) => {
      const rowKey = buildScheduleGeneratorManualRowKey(slot.subject_id, slot.lesson_type);
      slotCountByRow.set(rowKey, (slotCountByRow.get(rowKey) || 0) + 1);
    });

    const entries = [];
    const groupSlotMap = new Map();
    const teacherSlotMap = new Map();
    const slotCollisionSamples = [];
    const teacherCollisionSamples = [];
    const pushSlotCollision = (payload) => {
      if (slotCollisionSamples.length >= 8) return;
      slotCollisionSamples.push(payload);
    };
    const pushTeacherCollision = (payload) => {
      if (teacherCollisionSamples.length >= 8) return;
      teacherCollisionSamples.push(payload);
    };

    for (const slot of manualScopeSlots) {
      const rowKey = buildScheduleGeneratorManualRowKey(slot.subject_id, slot.lesson_type);
      const row = manualMatrixMap.get(rowKey);
      if (!row) continue;
      const groupList = row.group_number
        ? [Number(row.group_number)]
        : Array.from({ length: Math.max(1, Number(row.group_count || 1)) }, (_value, index) => index + 1);
      const teacherId = parsePositiveIntStrict(row.teacher_id) || null;
      for (let week = 1; week <= weeksCount; week += 1) {
        for (const groupNumber of groupList) {
          const groupSlotKey = `${week}|${slot.day_of_week}|${slot.class_number}|${groupNumber}`;
          const existingGroupSlot = groupSlotMap.get(groupSlotKey);
          if (existingGroupSlot && existingGroupSlot.row_key !== rowKey) {
            pushSlotCollision({
              week_number: week,
              day_of_week: slot.day_of_week,
              class_number: slot.class_number,
              group_number: groupNumber,
              current_subject: row.subject_name,
              existing_subject: existingGroupSlot.subject_name,
            });
            continue;
          }
          groupSlotMap.set(groupSlotKey, {
            row_key: rowKey,
            subject_name: row.subject_name,
          });

          if (teacherId) {
            const teacherSlotKey = `${teacherId}|${week}|${slot.day_of_week}|${slot.class_number}`;
            const existingTeacherSlot = teacherSlotMap.get(teacherSlotKey);
            if (existingTeacherSlot && existingTeacherSlot.row_key !== rowKey) {
              pushTeacherCollision({
                week_number: week,
                day_of_week: slot.day_of_week,
                class_number: slot.class_number,
                current_subject: row.subject_name,
                existing_subject: existingTeacherSlot.subject_name,
              });
              continue;
            }
            teacherSlotMap.set(teacherSlotKey, {
              row_key: rowKey,
              subject_name: row.subject_name,
            });
          }

          entries.push({
            item_id: row.item_id || null,
            course_id: courseId,
            semester_id: semesterId,
            subject_id: row.subject_id,
            teacher_id: teacherId,
            lesson_type: row.lesson_type,
            group_number: groupNumber,
            day_of_week: slot.day_of_week,
            class_number: slot.class_number,
            week_number: week,
            is_mirror: false,
            mirror_key: null,
          });
        }
      }
    }

    if (slotCollisionSamples.length) {
      const sample = slotCollisionSamples[0];
      return redirectManualNotice(
        'err',
        `Slot conflict: week ${sample.week_number}, ${sample.day_of_week} #${sample.class_number}, group ${sample.group_number}`
      );
    }
    if (teacherCollisionSamples.length) {
      const sample = teacherCollisionSamples[0];
      return redirectManualNotice(
        'err',
        `Teacher conflict: week ${sample.week_number}, ${sample.day_of_week} #${sample.class_number}`
      );
    }
    if (!entries.length) {
      return redirectManualNotice('err', 'No entries produced from manual plan');
    }

    const totalTargetPairs = Array.from(manualMatrixMap.values())
      .reduce((sum, row) => sum + Math.max(0, Number(row.pairs_count || 0)), 0);
    const totalCoveredPairs = Array.from(manualMatrixMap.values())
      .reduce((sum, row) => sum + ((slotCountByRow.get(row.row_key) || 0) * weeksCount), 0);
    const totalRemainingPairs = totalTargetPairs - totalCoveredPairs;
    const manualCoverageConflicts = Array.from(manualMatrixMap.values())
      .filter((row) => Number(row.pairs_count || 0) > 0)
      .map((row) => {
        const covered = (slotCountByRow.get(row.row_key) || 0) * weeksCount;
        const target = Math.max(0, Number(row.pairs_count || 0));
        if (covered >= target) return null;
        return {
          item_id: row.item_id || null,
          subject: row.subject_name,
          reason: 'partial_schedule',
          scheduled: covered,
          target,
        };
      })
      .filter(Boolean);

    const operationId = randomUUID();
    const diffResult = await buildScheduleDiff(entries);
    const manualScopeBag = runConfig && runConfig.manual_scope_slots && typeof runConfig.manual_scope_slots === 'object'
      ? { ...runConfig.manual_scope_slots }
      : {};
    manualScopeBag[scopeKey] = manualScopeSlots;
    const nextCourseSemestersByLocation = {
      ...(runConfig.course_semesters_by_location || { kyiv: {}, munich: {} }),
      [activeLocation]: {
        ...((runConfig.course_semesters_by_location && runConfig.course_semesters_by_location[activeLocation]) || {}),
        [String(courseId)]: semesterId,
      },
    };
    const nextConfig = {
      ...runConfig,
      active_location: activeLocation,
      course_semesters_by_location: nextCourseSemestersByLocation,
      manual_scope_slots: manualScopeBag,
      last_stats: {
        generated_at: new Date().toISOString(),
        items: manualMatrixMap.size,
        entries: entries.length,
        conflicts: manualCoverageConflicts.length,
        diff: diffResult.diff,
        operation_id: operationId,
        scope: {
          type: 'manual_all_weeks',
          location: activeLocation,
          course_id: courseId,
          semester_id: semesterId,
        },
      },
      last_conflicts: manualCoverageConflicts,
    };

    await withTransaction(async (client) => {
      await txRun(
        client,
        'DELETE FROM schedule_generator_entries WHERE run_id = ? AND course_id = ?',
        [runId, courseId]
      );
      const insertSql = `
        INSERT INTO schedule_generator_entries
          (run_id, item_id, course_id, semester_id, subject_id, teacher_id, lesson_type, group_number, day_of_week, class_number, week_number, is_mirror, mirror_key)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `;
      for (const entry of entries) {
        await txRun(client, insertSql, [
          runId,
          entry.item_id,
          entry.course_id,
          entry.semester_id,
          entry.subject_id,
          entry.teacher_id,
          entry.lesson_type,
          entry.group_number,
          entry.day_of_week,
          entry.class_number,
          entry.week_number,
          false,
          null,
        ]);
      }
      await txRun(
        client,
        'UPDATE schedule_generator_runs SET config = ?, updated_at = NOW() WHERE id = ?',
        [serializeGeneratorConfig(nextConfig), runId]
      );
    });

    const coverageSuffix = totalRemainingPairs > 0
      ? ` Coverage: ${totalCoveredPairs}/${totalTargetPairs}`
      : ` Coverage complete: ${totalCoveredPairs}/${totalTargetPairs}`;
    const okMessage = `Manual preview generated.${coverageSuffix}`;
    return res.redirect(buildScheduleGeneratorPreviewUrl(req, runId, {
      courseId,
      week: 1,
      ok: okMessage,
      extraParams: {
        location: activeLocation,
        course_id: courseId,
        semester_id: semesterId,
        mode: 'manual',
      },
    }));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.manualRun');
  }
});

app.post('/admin/schedule-generator/mirror-auto', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.mirrorAuto');
  }
  const runId = Number(req.body.run_id);
  if (!Number.isFinite(runId) || runId <= 0) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid run'));
  }
  const pairsRaw = req.body.mirror_pairs || [];
  const pairs = Array.isArray(pairsRaw) ? pairsRaw : pairsRaw ? [pairsRaw] : [];
  if (!pairs.length) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'No pairs selected', runId));
  }
  const run = await db.get('SELECT id FROM schedule_generator_runs WHERE id = ?', [runId]);
  if (!run) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Run not found'));
  }
  let updated = 0;
  for (const pair of pairs) {
    const [aRaw, bRaw] = String(pair || '').split(':');
    const aId = Number(aRaw);
    const bId = Number(bRaw);
    if (!Number.isFinite(aId) || !Number.isFinite(bId)) continue;
    const items = await db.all(
      `
        SELECT sgi.*, s.name AS subject_name, s.is_general
        FROM schedule_generator_items sgi
        JOIN subjects s ON s.id = sgi.subject_id
        WHERE sgi.run_id = ? AND sgi.id IN (?, ?)
      `,
      [runId, aId, bId]
    );
    if (!items || items.length < 2) continue;
    const a = items.find((row) => Number(row.id) === aId);
    const b = items.find((row) => Number(row.id) === bId);
    if (!a || !b) continue;
    if (Number(a.group_number) !== 1 || Number(b.group_number) !== 2) continue;
    if (Number(a.course_id) !== Number(b.course_id)) continue;
    if (Number(a.semester_id || 0) !== Number(b.semester_id || 0)) continue;
    if (String(a.lesson_type || '') !== String(b.lesson_type || '')) continue;
    if (Number(a.pairs_count || 0) !== Number(b.pairs_count || 0)) continue;
    if (a.fixed_day || a.fixed_class_number || a.weeks_set) continue;
    if (b.fixed_day || b.fixed_class_number || b.weeks_set) continue;
    if (a.mirror_key || b.mirror_key) continue;
    const lessonType = String(a.lesson_type || '').toLowerCase();
    if (!(lessonType.includes('seminar') || lessonType.includes('сем'))) continue;
    if (Number(a.subject_id) === Number(b.subject_id)) continue;
    const key = `AUTO-${aId.toString(36).toUpperCase()}${bId.toString(36).toUpperCase()}`;
    await db.run(
      'UPDATE schedule_generator_items SET mirror_key = ? WHERE run_id = ? AND id IN (?, ?)',
      [key, runId, aId, bId]
    );
    updated += 1;
  }
  if (!updated) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'No pairs updated', runId));
  }
  return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'ok', 'Auto mirror pairs applied', runId));
});

app.post('/admin/schedule-generator/items/edit/:id', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.item.edit');
  }
  const itemId = Number(req.params.id);
  const runId = Number(req.body.run_id);
  const courseId = Number(req.body.course_id);
  const subjectId = Number(req.body.subject_id);
  const teacherIdRaw = req.body.teacher_id ? Number(req.body.teacher_id) : null;
  const lessonTypeRaw = String(req.body.lesson_type || 'lecture').trim();
  const lessonType = lessonTypeRaw || 'lecture';
  const groupRaw = String(req.body.group_number || 'all');
  const groupNumber = groupRaw === 'all' || groupRaw === '0' ? null : Number(groupRaw);
  const pairsCount = Number(req.body.pairs_count);
  const weeksSet = String(req.body.weeks_set || '').trim();
  const fixedDay = normalizeWeekdayName(req.body.fixed_day);
  const fixedClass = req.body.fixed_class_number ? Number(req.body.fixed_class_number) : null;
  const mirrorKeyRaw = String(req.body.mirror_key || '').trim();
  const mirrorKey = mirrorKeyRaw || null;

  if (!Number.isFinite(itemId) || !Number.isFinite(runId) || runId <= 0) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid item'));
  }
  if (!Number.isFinite(pairsCount) || pairsCount <= 0) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid pairs', runId));
  }
  if (groupNumber && (Number.isNaN(groupNumber) || groupNumber < 1)) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid group', runId));
  }
  if (fixedClass && (fixedClass < 1 || fixedClass > 7)) {
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid slot', runId));
  }

  try {
    const subjectRow = await resolveSubjectCourseContext(subjectId, courseId, { includeHidden: true });
    if (!subjectRow) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Subject not found', runId));
    }
    const storageCourseId = Number(subjectRow.owner_course_id || subjectRow.course_id || courseId || 1);
    if (groupNumber && Number(groupNumber) > Number(subjectRow.group_count || 1)) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Invalid group', runId));
    }
    const run = await db.get('SELECT config FROM schedule_generator_runs WHERE id = ?', [runId]);
    if (!run) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Run not found', runId));
    }
    const runConfig = parseGeneratorConfig(run.config);
    const courseRow = await db.get('SELECT location FROM courses WHERE id = ?', [storageCourseId]);
    const courseLocation = String(courseRow?.location || 'kyiv').toLowerCase() === 'munich' ? 'munich' : 'kyiv';
    const configuredSemesterId = runConfig.course_semesters_by_location
      ? runConfig.course_semesters_by_location[courseLocation]?.[storageCourseId]
        || runConfig.course_semesters_by_location[courseLocation]?.[String(storageCourseId)]
      : null;
    let semester = null;
    if (configuredSemesterId) {
      semester = await db.get('SELECT id FROM semesters WHERE id = ? AND course_id = ?', [configuredSemesterId, storageCourseId]);
    }
    if (!semester) {
      semester = await getActiveSemester(storageCourseId);
    }
    if (!semester) {
      return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'err', 'Semester not found', runId));
    }
    await db.run(
      `
        UPDATE schedule_generator_items
        SET course_id = ?, semester_id = ?, subject_id = ?, teacher_id = ?, lesson_type = ?, group_number = ?, pairs_count = ?, weeks_set = ?, fixed_day = ?, fixed_class_number = ?, mirror_key = ?
        WHERE id = ? AND run_id = ?
      `,
      [
        storageCourseId,
        semester.id,
        subjectId,
        teacherIdRaw || null,
        lessonType,
        groupNumber,
        pairsCount,
        weeksSet || null,
        fixedDay,
        fixedClass || null,
        mirrorKey,
        itemId,
        runId,
      ]
    );
    return res.redirect(buildScheduleGeneratorNoticeUrl(req, 'ok', 'Item saved', runId));
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.item.edit');
  }
});

