app.get('/admin/users/:id/roles.json', requireRoleAccessSectionAccess, async (req, res) => {
  const userId = Number(req.params.id);
  if (!Number.isFinite(userId) || userId < 1) {
    return res.status(400).json({ error: 'Invalid user' });
  }
  try {
    await ensureDbReady();
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
  const courseId = getAdminCourse(req);
  try {
    const userRow = await academicSetupHelpers.getLegacyCourseUser(getAcademicSetupStore(), {
      userId,
      courseId,
    });
    if (!userRow) {
      return res.status(404).json({ error: 'User not found' });
    }
    const [roles, assignment] = await Promise.all([
      getRbacRolesDetailed(),
      getUserRoleAssignmentsForUserIds([userId]),
    ]);
    const roleKeys = assignment.roleKeysByUser[userId] || [normalizeRoleKey(userRow.role || 'student')];
    const primaryRole = assignment.primaryRoleByUser[userId] || normalizeRoleKey(userRow.role || roleKeys[0] || 'student');
    return res.json({
      user_id: userId,
      role_keys: roleKeys,
      primary_role: primaryRole,
      roles,
    });
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
});

app.post('/admin/users/roles', requireRoleAccessSectionAccess, requireSensitiveActionReauth({ tab: 'admin-users' }), async (req, res) => {
  const userId = Number(req.body.user_id);
  const courseId = getAdminCourse(req);
  const redirectWith = (kind, message) => buildAdminScopedNoticeUrl(req, kind, message, {
    tab: 'admin-users',
  });
  const selectedRoles = normalizeRoleList(
    Array.isArray(req.body.role_keys) ? req.body.role_keys : (req.body.role_keys ? [req.body.role_keys] : [])
  );
  if (!Number.isFinite(userId) || userId < 1 || !selectedRoles.length) {
    return res.redirect(redirectWith('err', 'Invalid role selection'));
  }
  if (!isStepUpPhraseValid(req.body.stepup_code, STEPUP_CODE_ROLE)) {
    return res.redirect(redirectWith('err', 'Type ROLE to confirm'));
  }
  try {
    await ensureDbReady();
    const user = await academicSetupHelpers.getLegacyCourseUser(getAcademicSetupStore(), {
      userId,
      courseId,
    });
    if (!user) {
      return res.redirect(redirectWith('err', 'User not found'));
    }
    if (Number(userId) === Number(req.session.user.id) && !selectedRoles.includes('admin')) {
      return res.redirect(redirectWith('err', 'Cannot remove your own admin role'));
    }
    const beforeSnapshot = await getUserRoleSnapshot(userId, user.role || 'student');
    const requestedPrimary = normalizeRoleKey(req.body.primary_role || '');
    const currentPrimary = normalizeRoleKey(beforeSnapshot.primary_role || user.role || 'student');
    let preferredPrimary = currentPrimary;
    if (!selectedRoles.includes(preferredPrimary)) {
      preferredPrimary = selectedRoles.includes(requestedPrimary)
        ? requestedPrimary
        : (selectedRoles.find((roleKey) => LEGACY_SESSION_ROLES.has(roleKey)) || selectedRoles[0] || 'student');
    }
    const result = await assignUserRoles(userId, selectedRoles, { preferredPrimary });
    await recordUserRoleChangeEvent({
      userId,
      actorUserId: Number(req.session.user.id),
      actorName: req.session.user.username,
      courseId,
      source: 'admin_users_roles',
      reason: 'Role Studio update',
      beforeRoles: beforeSnapshot.role_keys,
      afterRoles: result.roleKeys,
      beforePrimaryRole: beforeSnapshot.primary_role,
      afterPrimaryRole: result.primaryRoleKey,
      targetFullName: user.full_name || null,
    });
    const operationId = randomUUID();
    await createAdminAuditEntry(req, {
      scopeKey: ADMIN_AUDIT_SCOPE_ROLE_STUDIO,
      actionType: 'user_roles_change',
      targetType: 'user_roles_assignment',
      targetId: userId,
      targetKey: String(userId),
      summary: `User roles changed: ${user.full_name || userId}`,
      beforeState: beforeSnapshot,
      afterState: {
        role_keys: result.roleKeys,
        primary_role: result.primaryRoleKey,
      },
      operationId,
      courseId,
      metadata: {
        user_id: userId,
        full_name: user.full_name || null,
        primary_role: result.primaryRoleKey,
      },
      isCritical: true,
    });
    await recomputeUserSecurityCase(userId, { courseId, allowAutoQuarantine: false });
    logAction(db, req, 'user_roles_change', {
      operation_id: operationId,
      user_id: userId,
      role_keys: result.roleKeys,
      primary_role: result.primaryRoleKey,
    });
    broadcast('users_updated');
    return res.redirect(redirectWith('ok', 'Roles updated'));
  } catch (err) {
    if (String(err.message || '').includes('At least one admin required')) {
      return res.redirect(redirectWith('err', 'At least one admin required'));
    }
    if (String(err.message || '').includes('Invalid role')) {
      return res.redirect(redirectWith('err', 'Invalid role selection'));
    }
    return res.redirect(redirectWith('err', 'Database error'));
  }
});

