app.post('/admin/users/reset-password', requireUsersSectionAccess, (req, res) => {
  return (async () => {
    const userId = parsePositiveIntStrict(req.body.user_id);
    const newPassword = String(req.body.new_password || '');
    const adminAcademicScope = await buildAdminAcademicScopeState(req);
    const redirectBase = buildStaffPanelScopeUrl(req, adminAcademicScope || {});
    if (!userId || !newPassword) {
      return res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'Password required'));
    }
    if (newPassword.length < PASSWORD_MIN_LENGTH) {
      return res.redirect(appendQueryParamToUrl(redirectBase, 'err', `Password must be at least ${PASSWORD_MIN_LENGTH} characters`));
    }
    const targetUser = await getAdminScopedUser(adminAcademicScope, userId, {
      selectClause: 'u.id',
    });
    if (!targetUser) {
      return res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'User not found'));
    }
    const hash = bcrypt.hashSync(newPassword, 10);
    db.run(
      'UPDATE users SET password_hash = ? WHERE id = ?',
      [hash, userId],
      (err) => {
        if (err) {
          return res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'Database error'));
        }
        logAction(db, req, 'user_password_reset', { user_id: userId });
        broadcast('users_updated');
        return res.redirect(appendQueryParamToUrl(redirectBase, 'ok', 'Password updated'));
      }
    );
  })().catch((err) => {
    console.error('User password reset failed', err);
    return res.redirect(appendQueryParamToUrl(buildStaffPanelScopeUrl(req, getStoredAdminAcademicScope(req)), 'err', 'Database error'));
  });
});

app.post('/admin/homework/migrate', requireHomeworkSectionAccess, (req, res) => {
  const redirectWith = (kind, message) => buildAdminScopedNoticeUrl(req, kind, message, {
    tab: 'admin-homework',
  });
  const timeToClass = (time) => {
    if (!time) return null;
    const start = time.split('-')[0].trim();
    const match = Object.entries(bellSchedule).find(([, slot]) => slot.start === start);
    return match ? Number(match[0]) : null;
  };

  db.all(
    `
      SELECT id, subject, day, time, subject_id, group_number, day_of_week, class_number
      FROM homework
      WHERE subject_id IS NULL OR group_number IS NULL OR day_of_week IS NULL OR class_number IS NULL
    `,
    (err, rows) => {
      if (err) {
        return res.redirect(redirectWith('err', 'Database error'));
      }
      if (!rows.length) {
        return res.redirect(redirectWith('ok', 'Nothing to migrate'));
      }
      db.all('SELECT id, name FROM subjects', (sErr, subjects) => {
        if (sErr) {
          return res.redirect(redirectWith('err', 'Database error'));
        }
        const subjectMap = new Map(subjects.map((s) => [s.name, s.id]));
        const stmt = db.prepare(
          `
            UPDATE homework
            SET subject_id = COALESCE(subject_id, ?),
                group_number = COALESCE(group_number, ?),
                day_of_week = COALESCE(day_of_week, ?),
                class_number = COALESCE(class_number, ?)
            WHERE id = ?
          `
        );
        rows.forEach((row) => {
          const subjectId = subjectMap.get(row.subject) || row.subject_id;
          const classNum = row.class_number || timeToClass(row.time);
          const day = row.day_of_week || row.day;
          stmt.run(subjectId || null, 1, day || null, classNum || null, row.id);
        });
        stmt.finalize(() => {
          logAction(db, req, 'homework_migrate', { count: rows.length });
          return res.redirect(redirectWith('ok', 'Homework migrated'));
        });
      });
    }
  );
});

app.post('/admin/users/delete-multiple', requireUsersSectionAccess, requireSensitiveActionReauth({ tab: 'admin-users' }), (req, res) => {
  const ids = req.body.delete_user_ids;
  const courseId = getAdminCourse(req);
  const redirectBase = buildStaffPanelScopeUrl(req, getStoredAdminAcademicScope(req));
  if (!ids) {
    return res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'No users selected'));
  }
  const list = Array.isArray(ids) ? ids : [ids];
  academicSetupHelpers.listLegacyCourseUsers(getAcademicSetupStore(), {
    courseId,
    userIds: list,
    excludeRoles: ['admin'],
  }).then((rows) => {
    const deleteIds = (rows || []).map((u) => Number(u.id || 0)).filter((id) => id > 0);
    if (!deleteIds.length) {
      return res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'No students to delete'));
    }
    const delPlaceholders = deleteIds.map(() => '?').join(',');
    db.run(`UPDATE users SET is_active = 0 WHERE id IN (${delPlaceholders})`, deleteIds, (delErr) => {
      if (delErr) {
        return res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'Database error'));
      }
      logAction(db, req, 'users_deactivate_multiple', { ids: deleteIds });
      broadcast('users_updated');
      return res.redirect(appendQueryParamToUrl(redirectBase, 'ok', 'Users deactivated'));
    });
  }).catch(() => res.redirect(appendQueryParamToUrl(redirectBase, 'err', 'Database error')));
});

